{
  "name": "NHL Face-Off Fever",
  "description": "A real-time hockey play-along game where you pick positions before every face-off to earn points based on live events like goals, hits, and saves."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type Position = 'C' | 'LW' | 'RW' | 'LD' | 'RD' | 'G';

export interface GameEvent {
  id: string;
  timestamp: number;
  gameTime: string;
  team: 'home' | 'away';
  position: Position;
  type: 'GOAL' | 'ASSIST' | 'HIT' | 'SHOT' | 'BLOCKED_SHOT' | 'TAKEAWAY' | 'PASS' | 'GIVEAWAY' | 'SAVE' | 'GOAL_AGAINST';
  description: string;
  points: number;
}

export interface TeamInfo {
  name: string;
  city: string;
  score: number;
  color: string;
  logo: string;
}

export interface GameState {
  period: number;
  timeRemaining: string;
  isPaused: boolean;
  waitingForPicks: boolean;
  homeTeam: TeamInfo;
  awayTeam: TeamInfo;
  userPicks: {
    home: Position | null;
    away: Position | null;
  };
  totalPoints: number;
  rank: number;
  totalPlayers: number;
  events: GameEvent[];
}

import { Position } from './types';

export const SCORING_RULES = {
  SKATER: {
    GOAL: 5000,
    ASSIST: 1000,
    HIT: 500,
    SHOT: 200,
    BLOCKED_SHOT: 200,
    TAKEAWAY: 200,
    PASS: 100,
    GIVEAWAY: -200,
  },
  GOALIE: {
    SAVE: 250,
    GOAL_AGAINST: -1000,
  }
};

export const POSITIONS: { value: Position; label: string }[] = [
  { value: 'C', label: 'Center' },
  { value: 'LW', label: 'Left Wing' },
  { value: 'RW', label: 'Right Wing' },
  { value: 'LD', label: 'Left Defense' },
  { value: 'RD', label: 'Right Defense' },
  { value: 'G', label: 'Goalie' },
];

export const INITIAL_TEAMS = {
  home: {
    name: 'Rangers',
    city: 'New York',
    score: 0,
    color: '#0038A8',
    logo: '🗽'
  },
  away: {
    name: 'Bruins',
    city: 'Boston',
    score: 0,
    color: '#FFB81C',
    logo: '🐻'
  }
};

import { GoogleGenAI, Type } from "@google/genai";
import { GameEvent, Position } from "../types";
import { SCORING_RULES } from "../constants";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const fetchSimulatedEvents = async (
  period: number, 
  timeRemaining: string, 
  homeTeamName: string, 
  awayTeamName: string
): Promise<{ events: Partial<GameEvent>[], nextFaceoffTrigger: boolean }> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Simulate 2-4 play-by-play events for an NHL game between ${homeTeamName} and ${awayTeamName}. 
      Current Time: Period ${period}, ${timeRemaining} remaining.
      Include the position responsible for each event (C, LW, RW, LD, RD, G).
      Event types allowed: GOAL, ASSIST, HIT, SHOT, BLOCKED_SHOT, TAKEAWAY, PASS, GIVEAWAY, SAVE, GOAL_AGAINST.
      Decide if a new face-off should happen after these events (usually after a goal, whistle, or period end).`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            events: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  team: { type: Type.STRING, enum: ['home', 'away'] },
                  position: { type: Type.STRING, enum: ['C', 'LW', 'RW', 'LD', 'RD', 'G'] },
                  type: { type: Type.STRING, enum: ['GOAL', 'ASSIST', 'HIT', 'SHOT', 'BLOCKED_SHOT', 'TAKEAWAY', 'PASS', 'GIVEAWAY', 'SAVE', 'GOAL_AGAINST'] },
                  description: { type: Type.STRING },
                  gameTime: { type: Type.STRING }
                },
                required: ['team', 'position', 'type', 'description', 'gameTime']
              }
            },
            nextFaceoffTrigger: { type: Type.BOOLEAN }
          },
          required: ['events', 'nextFaceoffTrigger']
        }
      }
    });

    const data = JSON.parse(response.text || '{"events":[], "nextFaceoffTrigger": false}');

    // Attach point values based on rules
    const eventsWithPoints = data.events.map((e: any) => {
      let points = 0;
      if (e.position === 'G') {
        points = e.type === 'SAVE' ? SCORING_RULES.GOALIE.SAVE : SCORING_RULES.GOALIE.GOAL_AGAINST;
      } else {
        points = (SCORING_RULES.SKATER as any)[e.type] || 0;
      }
      return { ...e, points, id: Math.random().toString(36).substr(2, 9), timestamp: Date.now() };
    });

    return { events: eventsWithPoints, nextFaceoffTrigger: data.nextFaceoffTrigger };
  } catch (error) {
    console.error("Error fetching simulated events:", error);
    return { events: [], nextFaceoffTrigger: false };
  }
};

import React from 'react';
import { TeamInfo } from '../types';

interface ScoreBoardProps {
  home: TeamInfo;
  away: TeamInfo;
  period: number;
  time: string;
}

const ScoreBoard: React.FC<ScoreBoardProps> = ({ home, away, period, time }) => {
  return (
    <div className="bg-slate-900 border-b border-slate-700 p-4 sticky top-0 z-50 shadow-2xl">
      <div className="max-w-4xl mx-auto flex items-center justify-between">
        {/* Away Team */}
        <div className="flex items-center gap-4 flex-1">
          <div className="text-right hidden sm:block">
            <div className="text-xs text-slate-400 font-bold uppercase tracking-wider">{away.city}</div>
            <div className="text-xl font-black oswald uppercase">{away.name}</div>
          </div>
          <div 
            className="w-12 h-12 rounded-full flex items-center justify-center text-3xl shadow-lg"
            style={{ backgroundColor: away.color }}
