import React, { useState } from 'react';
import { Position, TeamInfo } from '../types';
import { POSITIONS } from '../constants';

interface SelectionOverlayProps {
  homeTeam: TeamInfo;
  awayTeam: TeamInfo;
  onConfirm: (picks: { home: Position; away: Position }) => void;
}

const SelectionOverlay: React.FC<SelectionOverlayProps> = ({ homeTeam, awayTeam, onConfirm }) => {
  const [awayPick, setAwayPick] = useState<Position | null>(null);
  const [homePick, setHomePick] = useState<Position | null>(null);

  const handleConfirm = () => {
    if (awayPick && homePick) {
      onConfirm({ home: homePick, away: awayPick });
    }
  };

  return (
    <div className="fixed inset-0 z-[100] bg-slate-950/90 backdrop-blur-md flex items-center justify-center p-4">
      <div className="bg-slate-900 border border-slate-700 w-full max-w-2xl rounded-2xl shadow-2xl overflow-hidden animate-in fade-in zoom-in duration-300">
        <div className="bg-gradient-to-r from-blue-600 to-indigo-600 p-6 text-center">
          <h2 className="text-3xl font-black oswald uppercase tracking-tight text-white">Face-Off Upcoming!</h2>
          <p className="text-blue-100 text-sm font-medium mt-1 uppercase tracking-widest">Pick 1 position from each team</p>
        </div>

        <div className="p-8 space-y-8">
          {/* Away Team Selection */}
          <div className="space-y-4">
            <div className="flex items-center gap-3">
              <span className="text-2xl">{awayTeam.logo}</span>
              <h3 className="text-xl font-black oswald uppercase text-slate-200">{awayTeam.name}</h3>
            </div>
            <div className="grid grid-cols-3 sm:grid-cols-6 gap-2">
              {POSITIONS.map((pos) => (
                <button
                  key={`away-${pos.value}`}
                  onClick={() => setAwayPick(pos.value)}
                  className={`py-3 px-1 rounded-lg font-bold text-xs transition-all border-2 ${
                    awayPick === pos.value
                      ? 'bg-amber-500 border-amber-300 text-slate-950 scale-105'
                      : 'bg-slate-800 border-slate-700 text-slate-400 hover:border-slate-500'
                  }`}
                >
                  {pos.value}
                  <div className="text-[9px] opacity-70 truncate">{pos.label}</div>
                </button>
              ))}
            </div>
          </div>

          {/* Home Team Selection */}
          <div className="space-y-4">
            <div className="flex items-center gap-3">
              <span className="text-2xl">{homeTeam.logo}</span>
              <h3 className="text-xl font-black oswald uppercase text-slate-200">{homeTeam.name}</h3>
            </div>
            <div className="grid grid-cols-3 sm:grid-cols-6 gap-2">
              {POSITIONS.map((pos) => (
                <button
                  key={`home-${pos.value}`}
                  onClick={() => setHomePick(pos.value)}
                  className={`py-3 px-1 rounded-lg font-bold text-xs transition-all border-2 ${
                    homePick === pos.value
                      ? 'bg-blue-500 border-blue-300 text-white scale-105'
                      : 'bg-slate-800 border-slate-700 text-slate-400 hover:border-slate-500'
                  }`}
                >
                  {pos.value}
                  <div className="text-[9px] opacity-70 truncate">{pos.label}</div>
                </button>
              ))}
            </div>
          </div>
        </div>

        <div className="p-6 bg-slate-800/50 border-t border-slate-700">
          <button
            disabled={!awayPick || !homePick}
            onClick={handleConfirm}
            className={`w-full py-4 rounded-xl font-black oswald text-xl uppercase tracking-widest transition-all ${
              awayPick && homePick
                ? 'bg-green-600 hover:bg-green-500 text-white shadow-lg shadow-green-900/20 active:scale-95'
                : 'bg-slate-700 text-slate-500 cursor-not-allowed'
            }`}
          >
            Drop the Puck!
          </button>
        </div>
      </div>
    </div>
  );
};

export default SelectionOverlay;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { GameState, Position, GameEvent } from './types';
import { INITIAL_TEAMS } from './constants';
import ScoreBoard from './components/ScoreBoard';
import SelectionOverlay from './components/SelectionOverlay';
import { fetchSimulatedEvents } from './services/geminiService';

const App: React.FC = () => {
  const [game, setGame] = useState<GameState>({
    period: 1,
    timeRemaining: '20:00',
    isPaused: false,
    waitingForPicks: true,
    homeTeam: INITIAL_TEAMS.home,
    awayTeam: INITIAL_TEAMS.away,
    userPicks: { home: null, away: null },
    totalPoints: 0,
    rank: 124,
    totalPlayers: 1542,
    events: [],
  });

  const [loadingEvents, setLoadingEvents] = useState(false);
  const tickerRef = useRef<NodeJS.Timeout | null>(null);

  const processEvents = useCallback(async () => {
    if (loadingEvents || game.waitingForPicks) return;

    setLoadingEvents(true);
    const result = await fetchSimulatedEvents(
      game.period,
      game.timeRemaining,
      game.homeTeam.name,
      game.awayTeam.name
    );

    let newPoints = 0;
    const processedEvents = result.events.map(event => {
      // Check if user earns points
      const userPickForTeam = event.team === 'home' ? game.userPicks.home : game.userPicks.away;
      const earned = event.position === userPickForTeam ? (event.points || 0) : 0;
      newPoints += earned;
      return { ...event, userEarned: earned } as GameEvent & { userEarned: number };
    });

    // Update Scores
    let homeScoreDelta = result.events.filter(e => e.team === 'home' && e.type === 'GOAL').length;
    let awayScoreDelta = result.events.filter(e => e.team === 'away' && e.type === 'GOAL').length;

    setGame(prev => ({
      ...prev,
      totalPoints: prev.totalPoints + newPoints,
      events: [...processedEvents, ...prev.events].slice(0, 50),
      homeTeam: { ...prev.homeTeam, score: prev.homeTeam.score + homeScoreDelta },
      awayTeam: { ...prev.awayTeam, score: prev.awayTeam.score + awayScoreDelta },
      waitingForPicks: result.nextFaceoffTrigger,
      // Simple rank simulation
      rank: Math.max(1, prev.rank + (newPoints > 0 ? -1 : newPoints < 0 ? 1 : 0))
    }));

    setLoadingEvents(false);
  }, [game.period, game.timeRemaining, game.homeTeam.name, game.awayTeam.name, game.userPicks, game.waitingForPicks, loadingEvents]);

  // Game Clock Ticker
  useEffect(() => {
    if (game.waitingForPicks || game.isPaused) return;

    tickerRef.current = setInterval(() => {
      setGame(prev => {
        const [mins, secs] = prev.timeRemaining.split(':').map(Number);
        let totalSecs = mins * 60 + secs - 12; // Speed up game time: 1 real second = 12 game seconds

        if (totalSecs <= 0) {
          if (prev.period < 3) {
            return { ...prev, period: prev.period + 1, timeRemaining: '20:00', waitingForPicks: true };
          } else {
            return { ...prev, isPaused: true, timeRemaining: '00:00' };
          }
        }

        const newMins = Math.floor(totalSecs / 60);
        const newSecs = totalSecs % 60;
        return {
          ...prev,
          timeRemaining: `${newMins.toString().padStart(2, '0')}:${newSecs.toString().padStart(2, '0')}`
        };
      });
    }, 1000);

    return () => {
      if (tickerRef.current) clearInterval(tickerRef.current);
    };
  }, [game.waitingForPicks, game.isPaused]);

  // Periodic AI event fetcher
  useEffect(() => {
    if (game.waitingForPicks || game.isPaused) return;

    const eventInterval = setInterval(() => {
      processEvents();
    }, 8000); // Check for new events every 8 seconds

    return () => clearInterval(eventInterval);
  }, [game.waitingForPicks, game.isPaused, processEvents]);

  const handlePicks = (picks: { home: Position; away: Position }) => {
    setGame(prev => ({
      ...prev,
      userPicks: picks,
      waitingForPicks: false
    }));
  };

  return (
    <div className="min-h-screen bg-slate-950 text-slate-100 flex flex-col pb-24">
      <ScoreBoard 
        home={game.homeTeam} 
        away={game.awayTeam} 
        period={game.period} 
        time={game.timeRemaining} 
      />

      {game.waitingForPicks && (
        <SelectionOverlay 
          homeTeam={game.homeTeam} 
          awayTeam={game.awayTeam} 
          onConfirm={handlePicks} 
        />
      )}

      {/* Main Content Area */}
      <main className="flex-1 max-w-4xl mx-auto w-full p-4 space-y-6">

        {/* Stats Row */}
        <div className="grid grid-cols-2 sm:grid-cols-4 gap-4">
          <div className="bg-slate-900 border border-slate-800 p-4 rounded-xl shadow-lg">
            <div className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-1">Score</div>
            <div className="text-3xl font-black text-amber-500 oswald">{game.totalPoints.toLocaleString()}</div>
          </div>
          <div className="bg-slate-900 border border-slate-800 p-4 rounded-xl shadow-lg">
            <div className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-1">Rank</div>
            <div className="text-3xl font-black text-blue-400 oswald">#{game.rank}</div>
          </div>
          <div className="bg-slate-900 border border-slate-800 p-4 rounded-xl shadow-lg hidden sm:block">
            <div className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-1">Picks</div>
            <div className="flex gap-2 text-xl font-black oswald">
              <span className="text-amber-500">{game.userPicks.away || '--'}</span>
              <span className="text-slate-600">/</span>
              <span className="text-blue-500">{game.userPicks.home || '--'}</span>
            </div>
          </div>
          <div className="bg-slate-900 border border-slate-800 p-4 rounded-xl shadow-lg hidden sm:block">
            <div className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-1">Total Users</div>
            <div className="text-3xl font-black text-slate-300 oswald">{game.totalPlayers.toLocaleString()}</div>
          </div>
        </div>

        {/* Live Feed */}
        <div className="bg-slate-900/50 border border-slate-800 rounded-2xl overflow-hidden flex flex-col min-h-[400px]">
          <div className="bg-slate-800 px-6 py-4 border-b border-slate-700 flex justify-between items-center">
            <h2 className="text-sm font-black uppercase tracking-widest text-slate-300 flex items-center gap-2">
              <i className="fa-solid fa-satellite-dish text-red-500 animate-pulse"></i>
              Live Play-by-Play
            </h2>
            {loadingEvents && (
              <div className="text-[10px] font-bold text-slate-500 uppercase animate-pulse">Scanning Rink...</div>
            )}
          </div>

          <div className="flex-1 overflow-y-auto p-4 space-y-4 max-h-[60vh]">
            {game.events.length === 0 ? (
              <div className="h-full flex flex-col items-center justify-center text-slate-600 py-20">
                <i className="fa-solid fa-hockey-puck text-4xl mb-4 opacity-20"></i>
                <p className="font-bold uppercase tracking-wider text-xs">Waiting for opening face-off...</p>
              </div>
            ) : (
              game.events.map((event) => {
                const isUserPositive = (event as any).userEarned > 0;
                const isUserNegative = (event as any).userEarned < 0;

                return (
                  <div 
                    key={event.id} 
                    className={`flex items-start gap-4 p-4 rounded-xl border transition-all animate-in slide-in-from-left duration-500 ${
                      isUserPositive ? 'bg-green-900/10 border-green-500/30' : 
                      isUserNegative ? 'bg-red-900/10 border-red-500/30' : 
                      'bg-slate-800/40 border-slate-700'
                    }`}
                  >
                    <div className={`w-10 h-10 rounded-full flex-shrink-0 flex items-center justify-center font-black text-xs border-2 ${
                      event.team === 'home' ? 'bg-blue-600 border-blue-400' : 'bg-amber-600 border-amber-400'
                    }`}>
                      {event.position}
                    </div>
                    <div className="flex-1">
                      <div className="flex items-center justify-between mb-1">
                        <span className="text-[10px] font-bold text-slate-500 uppercase">{event.gameTime}</span>
                        {event.type === 'GOAL' && (
                          <span className="bg-red-600 text-[10px] font-black px-2 py-0.5 rounded text-white uppercase tracking-tighter">Big Play</span>
                        )}
                      </div>
                      <p className="text-sm text-slate-200 leading-relaxed">
                        <span className="font-bold text-white mr-1 uppercase">
                          {event.team === 'home' ? game.homeTeam.name : game.awayTeam.name}:
                        </span>
                        {event.description}
                      </p>
                    </div>
                    {(event as any).userEarned !== 0 && (
                      <div className={`text-right font-black oswald text-xl ${isUserPositive ? 'text-green-400' : 'text-red-400'}`}>
                        {isUserPositive ? '+' : ''}{(event as any).userEarned}
                      </div>
                    )}
                  </div>
                );
              })
            )}
          </div>
        </div>
      </main>

      {/* Persistent Bottom Controls */}
      <footer className="fixed bottom-0 left-0 right-0 bg-slate-900 border-t border-slate-800 p-4 sm:p-6 shadow-2xl z-40">
        <div className="max-w-4xl mx-auto flex items-center justify-between gap-4">
          <div className="flex items-center gap-4">
            <div className="hidden sm:block">
              <div className="text-[10px] font-bold text-slate-500 uppercase">Your Picks</div>
              <div className="flex gap-1">
                <div className="bg-amber-600 px-2 rounded font-black text-xs">{game.userPicks.away || '?'}</div>
                <div className="bg-blue-600 px-2 rounded font-black text-xs">{game.userPicks.home || '?'}</div>
              </div>
            </div>
            <div className="h-8 w-[1px] bg-slate-800 hidden sm:block"></div>
            <div>
              <div className="text-[10px] font-bold text-slate-500 uppercase">Total Score</div>
              <div className="text-2xl font-black oswald text-amber-500 leading-none">{game.totalPoints.toLocaleString()}</div>
            </div>
          </div>

          <div className="flex gap-2">
            <button 
              onClick={() => setGame(prev => ({ ...prev, waitingForPicks: true }))}
              className="bg-slate-800 hover:bg-slate-700 text-slate-300 px-4 py-2 rounded-lg font-bold text-xs uppercase tracking-widest transition-colors border border-slate-700"
            >
              Change Picks
            </button>
            <button className="bg-blue-600 hover:bg-blue-500 text-white px-4 py-2 rounded-lg font-bold text-xs uppercase tracking-widest transition-all shadow-lg shadow-blue-900/20">
              Leaderboard
            </button>
          </div>
        </div>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { GameState, Position, GameEvent } from './types';
import { INITIAL_TEAMS } from './constants';
import ScoreBoard from './components/ScoreBoard';
import SelectionOverlay from './components/SelectionOverlay';
import { fetchSimulatedEvents } from './services/geminiService';

