import { GoogleGenAI, Type } from "@google/genai";
import { GameEvent, Position } from "../types";
import { SCORING_RULES } from "../constants";

// Use process.env.API_KEY directly when initializing the client
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const fetchSimulatedEvents = async (
  period: number, 
  timeRemaining: string, 
  homeTeamName: string, 
  awayTeamName: string
): Promise<{ events: Partial<GameEvent>[], nextFaceoffTrigger: boolean }> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Simulate 2-4 play-by-play events for an NHL game between ${homeTeamName} and ${awayTeamName}. 
      Current Time: Period ${period}, ${timeRemaining} remaining.
      Include the position responsible for each event (C, LW, RW, LD, RD, G).
      Event types allowed: GOAL, ASSIST, HIT, SHOT, BLOCKED_SHOT, TAKEAWAY, PASS, GIVEAWAY, SAVE, GOAL_AGAINST.
      Decide if a new face-off should happen after these events (usually after a goal, whistle, or period end).`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            events: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  team: { type: Type.STRING, enum: ['home', 'away'] },
                  position: { type: Type.STRING, enum: ['C', 'LW', 'RW', 'LD', 'RD', 'G'] },
                  type: { type: Type.STRING, enum: ['GOAL', 'ASSIST', 'HIT', 'SHOT', 'BLOCKED_SHOT', 'TAKEAWAY', 'PASS', 'GIVEAWAY', 'SAVE', 'GOAL_AGAINST'] },
                  description: { type: Type.STRING },
                  gameTime: { type: Type.STRING }
                },
                required: ['team', 'position', 'type', 'description', 'gameTime']
              }
            },
            nextFaceoffTrigger: { type: Type.BOOLEAN }
          },
          required: ['events', 'nextFaceoffTrigger']
        }
      }
    });

    const data = JSON.parse(response.text || '{"events":[], "nextFaceoffTrigger": false}');

    // Attach point values based on rules
    const eventsWithPoints = data.events.map((e: any) => {
      let points = 0;
      if (e.position === 'G') {
        points = e.type === 'SAVE' ? SCORING_RULES.GOALIE.SAVE : SCORING_RULES.GOALIE.GOAL_AGAINST;
      } else {
        points = (SCORING_RULES.SKATER as any)[e.type] || 0;
      }
      return { ...e, points, id: Math.random().toString(36).substr(2, 9), timestamp: Date.now() };
    });

    return { events: eventsWithPoints, nextFaceoffTrigger: data.nextFaceoffTrigger };
  } catch (error) {
    console.error("Error fetching simulated events:", error);
    return { events: [], nextFaceoffTrigger: false };
  }
};

export type Position = 'C' | 'LW' | 'RW' | 'LD' | 'RD' | 'G';

export interface GameEvent {
  id: string;
  timestamp: number;
  gameTime: string;
  team: 'home' | 'away';
  position: Position;
  type: 'GOAL' | 'ASSIST' | 'HIT' | 'SHOT' | 'BLOCKED_SHOT' | 'TAKEAWAY' | 'PASS' | 'GIVEAWAY' | 'SAVE' | 'GOAL_AGAINST';
  description: string;
  points: number;
  homeScoreAtEvent?: number;
  awayScoreAtEvent?: number;
  userEarned?: number;
  period: number;
}

export interface TeamInfo {
  name: string;
  city: string;
  score: number;
  color: string;
  logo: string;
}

export interface GameState {
  period: number;
  timeRemaining: string;
  isPaused: boolean;
  waitingForPicks: boolean;
  homeTeam: TeamInfo;
  awayTeam: TeamInfo;
  userPicks: {
    home: Position | null;
    away: Position | null;
  };
  totalPoints: number;
  rank: number;
  totalPlayers: number;
  events: GameEvent[];
}

