                      </div>

                      {/* Points Impact */}
                      {event.userEarned !== 0 && (
                        <div className={`flex flex-col items-end min-w-[70px]`}>
                          <div className={`text-xs font-black oswald ${isUserPositive ? 'text-green-400' : 'text-red-400'}`}>
                            {isUserPositive ? '+' : ''}{event.userEarned}
