export default PickStatus;

export type Position = 'C' | 'LW' | 'RW' | 'LD' | 'RD' | 'G';

export interface GameEvent {
  id: string;
  timestamp: number;
  gameTime: string;
  team: 'home' | 'away';
  position: Position;
  type: 'GOAL' | 'ASSIST' | 'HIT' | 'SHOT' | 'BLOCKED_SHOT' | 'TAKEAWAY' | 'PASS' | 'GIVEAWAY' | 'SAVE' | 'GOAL_AGAINST';
  description: string;
  points: number;
  homeScoreAtEvent?: number;
  awayScoreAtEvent?: number;
  userEarned?: number;
  period: number;
}

export interface FloatingPoint {
  id: string;
  points: number;
  team: 'home' | 'away';
  isUser: boolean;
  xOffset: number; // For visual variety
}

export interface GoalExplosion {
  id: string;
  team: 'home' | 'away';
  color: string;
}

export interface TeamInfo {
  name: string;
  city: string;
  score: number;
  color: string;
  logo: string;
}

export interface GameState {
  period: number;
  timeRemaining: string;
  isPaused: boolean;
  waitingForPicks: boolean;
  homeTeam: TeamInfo;
  awayTeam: TeamInfo;
  userPicks: {
    home: Position | null;
    away: Position | null;
  };
  totalPoints: number;
  rank: number;
  totalPlayers: number;
  events: GameEvent[];
}

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { GameState, Position, GameEvent, FloatingPoint, GoalExplosion } from './types';
import { INITIAL_TEAMS } from './constants';
import ScoreBoard from './components/ScoreBoard';
import SelectionOverlay from './components/SelectionOverlay';
import GameLog from './components/GameLog';
import PickStatus from './components/PickStatus';
import { fetchSimulatedEvents } from './services/geminiService';

const App: React.FC = () => {
  const [game, setGame] = useState<GameState>({
    period: 1,
    timeRemaining: '20:00',
    isPaused: false,
    waitingForPicks: true,
    homeTeam: INITIAL_TEAMS.home,
    awayTeam: INITIAL_TEAMS.away,
    userPicks: { home: null, away: null },
    totalPoints: 0,
    rank: 124,
    totalPlayers: 1542,
    events: [],
  });

  const [floatingPoints, setFloatingPoints] = useState<FloatingPoint[]>([]);
  const [explosions, setExplosions] = useState<GoalExplosion[]>([]);
  const [loadingEvents, setLoadingEvents] = useState(false);
  const tickerRef = useRef<any>(null);

  // Trigger goal explosion animation
  const triggerGoalExplosion = (team: 'home' | 'away') => {
    const id = Math.random().toString(36).substr(2, 9);
    const color = team === 'home' ? game.homeTeam.color : game.awayTeam.color;

    setExplosions(prev => [...prev, { id, team, color }]);

    // Remove after animation finishes (3 seconds)
    setTimeout(() => {
      setExplosions(prev => prev.filter(e => e.id !== id));
    }, 3000);
  };

  // Trigger floating points animation
  const triggerPointsAnimation = (points: number, team: 'home' | 'away', isUser: boolean) => {
    const id = Math.random().toString(36).substr(2, 9);
    const newFloatingPoint: FloatingPoint = {
      id,
      points,
      team,
      isUser,
      xOffset: (Math.random() - 0.5) * 40 // Random spread
    };

    setFloatingPoints(prev => [...prev, newFloatingPoint]);

    // Remove after animation finishes
    setTimeout(() => {
      setFloatingPoints(prev => prev.filter(fp => fp.id !== id));
    }, 1600);
  };

  const processEvents = useCallback(async () => {
    if (loadingEvents || game.waitingForPicks) return;

    setLoadingEvents(true);
    const result = await fetchSimulatedEvents(
      game.period,
      game.timeRemaining,
      game.homeTeam.name,
      game.awayTeam.name
    );

    let newPoints = 0;
    let currentHomeScore = game.homeTeam.score;
    let currentAwayScore = game.awayTeam.score;
    let goalScored = false;
    let scoringTeam: 'home' | 'away' | null = null;

    const processedEvents = result.events.map(event => {
      if (event.type === 'GOAL') {
        goalScored = true;
        scoringTeam = event.team as 'home' | 'away';
        if (event.team === 'home') currentHomeScore++;
        else currentAwayScore++;
      }

      const userPickForTeam = event.team === 'home' ? game.userPicks.home : game.userPicks.away;
      const isUserPick = event.position === userPickForTeam;
      const earned = isUserPick ? (event.points || 0) : 0;

      if (earned !== 0) {
        newPoints += earned;
        triggerPointsAnimation(earned, event.team!, true);
      } else if (event.points !== 0) {
        triggerPointsAnimation(event.points!, event.team!, false);
      }

      return { 
        ...event, 
        userEarned: earned, 
        homeScoreAtEvent: currentHomeScore, 
        awayScoreAtEvent: currentAwayScore,
        period: game.period 
      } as GameEvent;
    });

    if (goalScored && scoringTeam) {
      triggerGoalExplosion(scoringTeam);
    }

    setGame(prev => ({
      ...prev,
      totalPoints: prev.totalPoints + newPoints,
      events: [...processedEvents, ...prev.events].slice(0, 100),
      homeTeam: { ...prev.homeTeam, score: currentHomeScore },
      awayTeam: { ...prev.awayTeam, score: currentAwayScore },
      waitingForPicks: result.nextFaceoffTrigger,
      rank: Math.max(1, prev.rank + (newPoints > 0 ? -1 : newPoints < 0 ? 1 : 0))
    }));

    setLoadingEvents(false);
  }, [game.period, game.timeRemaining, game.homeTeam.name, game.awayTeam.name, game.userPicks, game.waitingForPicks, loadingEvents, game.homeTeam.score, game.awayTeam.score, game.homeTeam.color, game.awayTeam.color]);

  useEffect(() => {
    if (game.waitingForPicks || game.isPaused) return;

    tickerRef.current = setInterval(() => {
      setGame(prev => {
        const [mins, secs] = prev.timeRemaining.split(':').map(Number);
        let totalSecs = mins * 60 + secs - 12;

        if (totalSecs <= 0) {
          if (prev.period < 3) {
            return { ...prev, period: prev.period + 1, timeRemaining: '20:00', waitingForPicks: true };
          } else {
            return { ...prev, isPaused: true, timeRemaining: '00:00' };
          }
        }

        const newMins = Math.floor(totalSecs / 60);
        const newSecs = totalSecs % 60;
        return {
          ...prev,
          timeRemaining: `${newMins.toString().padStart(2, '0')}:${newSecs.toString().padStart(2, '0')}`
        };
      });
    }, 1000);

    return () => {
      if (tickerRef.current) clearInterval(tickerRef.current);
    };
  }, [game.waitingForPicks, game.isPaused]);

  useEffect(() => {
    if (game.waitingForPicks || game.isPaused) return;

    const eventInterval = setInterval(() => {
      processEvents();
    }, 8000);

    return () => clearInterval(eventInterval);
  }, [game.waitingForPicks, game.isPaused, processEvents]);

  const handlePicks = (picks: { home: Position; away: Position }) => {
    setGame(prev => ({
      ...prev,
      userPicks: picks,
      waitingForPicks: false
    }));
  };

  return (
    <div className="min-h-screen bg-slate-950 text-slate-100 flex flex-col pb-24 relative overflow-hidden">
      {/* Goal Explosion Overlays */}
      {explosions.map(exp => (
        <div key={exp.id} className="fixed inset-0 z-[100] pointer-events-none flex items-center justify-center">
          <div 
            className="absolute inset-0 bg-white/10 animate-screen-flash"
            style={{ backgroundColor: `${exp.color}22` }}
          />
          <div className="relative">
            <div className="text-8xl font-black oswald uppercase text-white animate-goal-text drop-shadow-[0_0_20px_rgba(255,255,255,0.8)]">
              GOAL!
            </div>
            <div 
              className="absolute inset-0 animate-goal-explosion"
              style={{ background: `radial-gradient(circle, ${exp.color} 0%, transparent 70%)` }}
            />
          </div>
          {/* Confetti Particles Simulation */}
          <div className="absolute inset-0 overflow-hidden">
             {[...Array(30)].map((_, i) => (
               <div 
                 key={i}
                 className="absolute w-2 h-2 rounded-full animate-particle"
                 style={{
