            >
              Leaderboard
            </button>
          </div>
        </div>
      </footer>

      <style>{`
        @keyframes screen-flash {
          0% { opacity: 0; }
          10% { opacity: 1; }
          100% { opacity: 0; }
        }
        @keyframes goal-text {
          0% { transform: scale(0.5); opacity: 0; filter: blur(10px); }
          20% { transform: scale(1.2); opacity: 1; filter: blur(0); }
          80% { transform: scale(1.1); opacity: 1; }
          100% { transform: scale(1.5); opacity: 0; filter: blur(20px); }
        }
        @keyframes goal-explosion {
          0% { transform: scale(0); opacity: 0.8; }
          100% { transform: scale(4); opacity: 0; }
        }
        @keyframes particle {
          0% { transform: translate(0, 0); opacity: 1; }
          100% { transform: translate(var(--tx), var(--ty)); opacity: 0; }
        }
        @keyframes goal-card-glow {
          0% { border-color: rgba(239, 68, 68, 0.4); box-shadow: 0 0 0px rgba(239, 68, 68, 0); }
          50% { border-color: rgba(239, 68, 68, 1); box-shadow: 0 0 20px rgba(239, 68, 68, 0.4); }
          100% { border-color: rgba(239, 68, 68, 0.4); box-shadow: 0 0 0px rgba(239, 68, 68, 0); }
        }
        @keyframes shimmer {
          0% { transform: translateX(-100%); }
          100% { transform: translateX(100%); }
        }
        .animate-screen-flash { animation: screen-flash 1.5s ease-out forwards; }
        .animate-goal-text { animation: goal-text 2s cubic-bezier(0.17, 0.67, 0.83, 0.67) forwards; }
