import React from 'react';
import { Position, TeamInfo, FloatingPoint } from '../types';

interface PickStatusProps {
  homeTeam: TeamInfo;
  awayTeam: TeamInfo;
  userPicks: { home: Position | null; away: Position | null };
  floatingPoints: FloatingPoint[];
}

const PickStatus: React.FC<PickStatusProps> = ({ homeTeam, awayTeam, userPicks, floatingPoints }) => {
  const getPointStyles = (points: number) => {
    const absPoints = Math.abs(points);

    // Default styles
    let color = 'text-green-400';
    let size = 'text-lg';
    let glow = '';
    let weight = 'font-bold';

    if (points < 0) {
      color = 'text-red-500';
      size = absPoints >= 1000 ? 'text-2xl' : 'text-lg';
      weight = 'font-black';
    } else if (points >= 5000) {
      color = 'text-yellow-400';
      size = 'text-4xl';
      glow = 'drop-shadow-[0_0_10px_rgba(250,204,21,0.8)]';
      weight = 'font-black';
    } else if (points >= 1000) {
      color = 'text-blue-400';
      size = 'text-2xl';
      glow = 'drop-shadow-[0_0_5px_rgba(96,165,250,0.5)]';
      weight = 'font-black';
    } else if (points >= 500) {
      color = 'text-green-300';
      size = 'text-xl';
      weight = 'font-bold';
    }

    return { color, size, glow, weight };
  };

  const getAnimationClass = (fp: FloatingPoint) => {
    if (fp.points < 0) return 'animate-shake-fade';
    if (fp.variant === 1) return 'animate-float-left';
    if (fp.variant === 2) return 'animate-float-right';
    return 'animate-float-up';
  };

  return (
    <div className="flex justify-center gap-6 sm:gap-12 py-2">
      {/* Away Pick */}
      <div className="relative group">
        <div className="text-[10px] font-black text-slate-500 uppercase tracking-widest text-center mb-1">Away Pick</div>
        <div 
          className={`w-16 h-16 sm:w-20 sm:h-20 rounded-2xl border-2 flex flex-col items-center justify-center transition-all shadow-xl ${
            userPicks.away ? 'bg-amber-600/10 border-amber-500 shadow-amber-900/20' : 'bg-slate-900 border-slate-800'
          }`}
        >
          <span className="text-xl sm:text-2xl font-black oswald text-amber-500">
            {userPicks.away || '--'}
          </span>
          <span className="text-[9px] font-bold text-amber-500/60 uppercase">{awayTeam.name}</span>
        </div>

        {/* Floating Points Container */}
        {floatingPoints.filter(fp => fp.team === 'away').map(fp => {
          const { color, size, glow, weight } = getPointStyles(fp.points);
          return (
            <div 
              key={fp.id}
              style={{ left: `calc(50% + ${fp.xOffset}px)` }}
              className={`absolute bottom-full mb-4 pointer-events-none oswald whitespace-nowrap z-[60] ${color} ${size} ${glow} ${weight} ${getAnimationClass(fp)}`}
            >
              {fp.points > 0 ? '+' : ''}{fp.points}
            </div>
          );
        })}
      </div>

      <div className="flex items-center">
        <div className="w-px h-12 bg-slate-800"></div>
      </div>

      {/* Home Pick */}
      <div className="relative group">
        <div className="text-[10px] font-black text-slate-500 uppercase tracking-widest text-center mb-1">Home Pick</div>
        <div 
          className={`w-16 h-16 sm:w-20 sm:h-20 rounded-2xl border-2 flex flex-col items-center justify-center transition-all shadow-xl ${
            userPicks.home ? 'bg-blue-600/10 border-blue-500 shadow-blue-900/20' : 'bg-slate-900 border-slate-800'
          }`}
        >
          <span className="text-xl sm:text-2xl font-black oswald text-blue-500">
            {userPicks.home || '--'}
          </span>
          <span className="text-[9px] font-bold text-blue-500/60 uppercase">{homeTeam.name}</span>
        </div>

        {/* Floating Points Container */}
        {floatingPoints.filter(fp => fp.team === 'home').map(fp => {
          const { color, size, glow, weight } = getPointStyles(fp.points);
          return (
            <div 
              key={fp.id}
              style={{ left: `calc(50% + ${fp.xOffset}px)` }}
              className={`absolute bottom-full mb-4 pointer-events-none oswald whitespace-nowrap z-[60] ${color} ${size} ${glow} ${weight} ${getAnimationClass(fp)}`}
            >
              {fp.points > 0 ? '+' : ''}{fp.points}
            </div>
          );
        })}
      </div>

      <style>{`
        @keyframes float-up {
          0% { transform: translateY(0) scale(0.8); opacity: 0; }
          20% { transform: translateY(-10px) scale(1.1); opacity: 1; }
          100% { transform: translateY(-80px) scale(1); opacity: 0; }
        }
        @keyframes float-left {
          0% { transform: translate(0, 0) scale(0.8); opacity: 0; }
          20% { transform: translate(-10px, -15px) scale(1.1); opacity: 1; }
          100% { transform: translate(-30px, -90px) scale(1); opacity: 0; }
        }
        @keyframes float-right {
          0% { transform: translate(0, 0) scale(0.8); opacity: 0; }
          20% { transform: translate(10px, -15px) scale(1.1); opacity: 1; }
          100% { transform: translate(30px, -90px) scale(1); opacity: 0; }
        }
        @keyframes shake-fade {
          0% { transform: translate(0, 0); opacity: 0; }
          10% { transform: translate(-2px, 0); opacity: 1; }
          20% { transform: translate(2px, 0); }
          30% { transform: translate(-2px, 0); }
          40% { transform: translate(2px, 0); }
          100% { transform: translateY(-40px); opacity: 0; }
        }
        .animate-float-up { animation: float-up 2s ease-out forwards; }
        .animate-float-left { animation: float-left 2s ease-out forwards; }
        .animate-float-right { animation: float-right 2s ease-out forwards; }
        .animate-shake-fade { animation: shake-fade 2s ease-in-out forwards; }
      `}</style>
    </div>
  );
};

