import React from 'react';
import { Position, TeamInfo, FloatingPoint } from '../types';

interface PickStatusProps {
  homeTeam: TeamInfo;
  awayTeam: TeamInfo;
  userPicks: { home: Position | null; away: Position | null };
  floatingPoints: FloatingPoint[];
}

const PickStatus: React.FC<PickStatusProps> = ({ homeTeam, awayTeam, userPicks, floatingPoints }) => {
  const getPointStyles = (points: number) => {
    const absPoints = Math.abs(points);

    // Base style configuration
    let color = 'text-green-400';
    let size = 'text-lg';
    let glow = '';
    let weight = 'font-bold';
    let animationName = 'float-up';
    let duration = '2s';

    if (points < 0) {
      color = 'text-red-500';
      size = absPoints >= 1000 ? 'text-2xl' : 'text-lg';
      weight = 'font-black';
      animationName = 'shake-sink';
      duration = '1.5s';
    } else if (points >= 5000) {
      // Goal logic - most explosive
      color = 'text-yellow-300';
      size = 'text-5xl';
      glow = 'drop-shadow-[0_0_15px_rgba(253,224,71,0.9)]';
      weight = 'font-black';
      animationName = 'pop-float';
      duration = '2.5s';
    } else if (points >= 1000) {
      // Assist logic
      color = 'text-blue-400';
      size = 'text-3xl';
      glow = 'drop-shadow-[0_0_10px_rgba(96,165,250,0.6)]';
      weight = 'font-black';
      animationName = 'float-sway';
      duration = '2.2s';
    } else if (points >= 500) {
      // Grit logic
      color = 'text-emerald-300';
      size = 'text-xl';
      weight = 'font-extrabold';
      animationName = 'float-up';
      duration = '1.8s';
    } else {
      // Minor plays (passes, shots)
      color = 'text-slate-300';
      size = 'text-base';
      weight = 'font-bold';
      animationName = 'float-up-fast';
      duration = '1.2s';
