        {floatingPoints.filter(fp => fp.team === 'away').map(fp => {
          const { color, size, glow, weight, animationName, duration } = getPointStyles(fp.points);
          // Apply horizontal variance based on fp.variant and fp.xOffset
          const swayOffset = fp.variant === 1 ? -20 : fp.variant === 2 ? 20 : 0;

          return (
            <div 
              key={fp.id}
              style={{ 
                left: `calc(50% + ${fp.xOffset}px)`,
                animationName: animationName,
                animationDuration: duration,
                animationFillMode: 'forwards',
                '--sway-x': `${swayOffset}px`
              } as React.CSSProperties}
              className={`absolute bottom-full mb-4 pointer-events-none oswald whitespace-nowrap z-[60] ${color} ${size} ${glow} ${weight} animate-floating-base`}
            >
              {fp.points > 0 ? '+' : ''}{fp.points}
            </div>
          );
        })}
      </div>

      <div className="flex items-center">
        <div className="w-px h-12 bg-slate-800"></div>
      </div>

      {/* Home Pick */}
      <div className="relative group">
        <div className="text-[10px] font-black text-slate-500 uppercase tracking-widest text-center mb-1">Home Pick</div>
        <div 
          className={`w-16 h-16 sm:w-20 sm:h-20 rounded-2xl border-2 flex flex-col items-center justify-center transition-all shadow-xl ${
            userPicks.home ? 'bg-blue-600/10 border-blue-500 shadow-blue-900/20' : 'bg-slate-900 border-slate-800'
          }`}
        >
          <span className="text-xl sm:text-2xl font-black oswald text-blue-500">
            {userPicks.home || '--'}
          </span>
          <span className="text-[9px] font-bold text-blue-500/60 uppercase">{homeTeam.name}</span>
        </div>

        {/* Floating Points Container */}
        {floatingPoints.filter(fp => fp.team === 'home').map(fp => {
          const { color, size, glow, weight, animationName, duration } = getPointStyles(fp.points);
          const swayOffset = fp.variant === 1 ? -20 : fp.variant === 2 ? 20 : 0;

          return (
            <div 
              key={fp.id}
              style={{ 
                left: `calc(50% + ${fp.xOffset}px)`,
                animationName: animationName,
                animationDuration: duration,
                animationFillMode: 'forwards',
                '--sway-x': `${swayOffset}px`
              } as React.CSSProperties}
              className={`absolute bottom-full mb-4 pointer-events-none oswald whitespace-nowrap z-[60] ${color} ${size} ${glow} ${weight} animate-floating-base`}
            >
              {fp.points > 0 ? '+' : ''}{fp.points}
            </div>
          );
        })}
      </div>

      <style>{`
        .animate-floating-base {
            animation-timing-function: cubic-bezier(0.22, 1, 0.36, 1);
        }

        @keyframes float-up {
          0% { transform: translateY(0) scale(0.8); opacity: 0; }
          15% { transform: translateY(-10px) scale(1.1); opacity: 1; }
          100% { transform: translateY(-100px) scale(1) translateX(var(--sway-x)); opacity: 0; }
        }

        @keyframes float-up-fast {
          0% { transform: translateY(0) scale(0.7); opacity: 0; }
          20% { transform: translateY(-5px) scale(1); opacity: 0.8; }
          100% { transform: translateY(-60px) scale(0.9); opacity: 0; }
        }

        @keyframes float-sway {
          0% { transform: translateY(0) scale(0.8); opacity: 0; }
          20% { transform: translateY(-15px) scale(1.2) translateX(calc(var(--sway-x) * 0.5)); opacity: 1; }
          50% { transform: translateY(-50px) scale(1.1) translateX(calc(var(--sway-x) * -0.5)); }
          100% { transform: translateY(-120px) scale(1) translateX(var(--sway-x)); opacity: 0; }
        }

        @keyframes pop-float {
          0% { transform: translateY(0) scale(0) rotate(-5deg); opacity: 0; }
          15% { transform: translateY(-20px) scale(1.5) rotate(5deg); opacity: 1; filter: brightness(1.5); }
          30% { transform: translateY(-35px) scale(1.3) rotate(-3deg); filter: brightness(1.2); }
          100% { transform: translateY(-150px) scale(1) rotate(0deg); opacity: 0; }
        }

        @keyframes shake-sink {
          0% { transform: translate(0, 0) scale(1); opacity: 0; }
          10% { transform: translate(-4px, 0) scale(1.1); opacity: 1; }
          20% { transform: translate(4px, 0); }
          30% { transform: translate(-4px, 0); }
          40% { transform: translate(4px, 0); }
          50% { transform: translate(-2px, 0); }
          100% { transform: translateY(40px) scale(0.8); opacity: 0; }
        }
      `}</style>
    </div>
  );
};

