import React, { useState } from 'react';
import { Position, TeamInfo } from '../types';
import { POSITIONS } from '../constants';

interface SelectionOverlayProps {
  homeTeam: TeamInfo;
  awayTeam: TeamInfo;
  onConfirm: (picks: { home: Position; away: Position }) => void;
}

const SelectionOverlay: React.FC<SelectionOverlayProps> = ({ homeTeam, awayTeam, onConfirm }) => {
  const [awayPick, setAwayPick] = useState<Position | null>(null);
  const [homePick, setHomePick] = useState<Position | null>(null);

  const handleConfirm = () => {
    if (awayPick && homePick) {
      onConfirm({ home: homePick, away: awayPick });
    }
  };

  // Helper to get positioning on the tactical rink
  const getPosCoords = (pos: Position, isHome: boolean) => {
    const baseCoords: Record<Position, { top: string; left: string }> = {
      'G': { top: '50%', left: isHome ? '90%' : '10%' },
      'LD': { top: '30%', left: isHome ? '70%' : '30%' },
      'RD': { top: '70%', left: isHome ? '70%' : '30%' },
      'LW': { top: '25%', left: isHome ? '55%' : '45%' },
      'RW': { top: '75%', left: isHome ? '55%' : '45%' },
      'C': { top: '50%', left: isHome ? '60%' : '40%' },
    };
    return baseCoords[pos];
  };

  return (
    <div className="fixed inset-0 z-[100] bg-slate-950/95 backdrop-blur-xl flex items-center justify-center p-4 overflow-y-auto">
      <div className="bg-slate-900 border border-slate-700 w-full max-w-5xl rounded-3xl shadow-[0_0_50px_rgba(0,0,0,0.5)] overflow-hidden animate-in fade-in zoom-in duration-500 my-auto">

        {/* Header */}
        <div className="bg-slate-800/50 p-6 border-b border-slate-700 flex flex-col items-center text-center">
          <div className="flex items-center gap-4 mb-2">
            <span className="text-3xl animate-bounce">{awayTeam.logo}</span>
            <div className="h-px w-12 bg-slate-700"></div>
            <h2 className="text-3xl font-black oswald uppercase tracking-tighter text-white">Lineup Selection</h2>
            <div className="h-px w-12 bg-slate-700"></div>
            <span className="text-3xl animate-bounce">{homeTeam.logo}</span>
          </div>
          <p className="text-slate-400 text-[10px] font-black uppercase tracking-[0.3em]">Pick 1 key player from each roster</p>
        </div>

        {/* Rink Container */}
        <div className="relative p-4 sm:p-8 bg-slate-950">
          {/* Stylized Rink Background */}
          <div className="relative w-full aspect-[2/1] bg-slate-900 rounded-[100px] border-[4px] border-slate-800 overflow-hidden shadow-inner">
            {/* Center Line */}
            <div className="absolute inset-y-0 left-1/2 w-1 bg-red-600/40 -translate-x-1/2"></div>
            {/* Center Circle */}
            <div className="absolute top-1/2 left-1/2 w-32 h-32 border-2 border-red-600/30 rounded-full -translate-x-1/2 -translate-y-1/2"></div>
            {/* Blue Lines */}
            <div className="absolute inset-y-0 left-[30%] w-1.5 bg-blue-600/40"></div>
            <div className="absolute inset-y-0 right-[30%] w-1.5 bg-blue-600/40"></div>
            {/* Creases */}
            <div className="absolute top-1/2 left-0 w-8 h-16 border-2 border-red-500/20 rounded-r-full -translate-y-1/2 bg-red-500/5"></div>
            <div className="absolute top-1/2 right-0 w-8 h-16 border-2 border-red-500/20 rounded-l-full -translate-y-1/2 bg-red-500/5"></div>

            {/* Labels */}
            <div className="absolute top-4 left-12 oswald font-black text-slate-700 uppercase tracking-widest text-xl opacity-30 pointer-events-none">{awayTeam.name}</div>
            <div className="absolute top-4 right-12 oswald font-black text-slate-700 uppercase tracking-widest text-xl opacity-30 pointer-events-none text-right">{homeTeam.name}</div>

            {/* Away Positions */}
            {POSITIONS.map((pos) => {
              const coords = getPosCoords(pos.value, false);
              const isSelected = awayPick === pos.value;
              return (
                <button
                  key={`tactical-away-${pos.value}`}
                  onClick={() => setAwayPick(pos.value)}
                  style={{ top: coords.top, left: coords.left }}
                  className={`absolute -translate-x-1/2 -translate-y-1/2 w-12 h-12 sm:w-16 sm:h-16 rounded-full flex flex-col items-center justify-center transition-all z-10 ${
                    isSelected
                      ? 'bg-amber-500 text-slate-950 border-4 border-amber-300 scale-110 shadow-[0_0_20px_rgba(245,158,11,0.5)]'
                      : 'bg-slate-800/80 text-slate-400 border-2 border-slate-700 hover:border-amber-500/50 backdrop-blur-sm'
                  }`}
                >
                  <span className="text-sm sm:text-lg font-black oswald leading-none">{pos.value}</span>
                  <span className="text-[7px] sm:text-[9px] font-bold uppercase opacity-60 leading-none">{pos.label.split(' ')[0]}</span>
                </button>
              );
            })}

            {/* Home Positions */}
            {POSITIONS.map((pos) => {
              const coords = getPosCoords(pos.value, true);
              const isSelected = homePick === pos.value;
              return (
                <button
                  key={`tactical-home-${pos.value}`}
                  onClick={() => setHomePick(pos.value)}
                  style={{ top: coords.top, left: coords.left }}
                  className={`absolute -translate-x-1/2 -translate-y-1/2 w-12 h-12 sm:w-16 sm:h-16 rounded-full flex flex-col items-center justify-center transition-all z-10 ${
                    isSelected
                      ? 'bg-blue-600 text-white border-4 border-blue-400 scale-110 shadow-[0_0_20px_rgba(37,99,235,0.5)]'
                      : 'bg-slate-800/80 text-slate-400 border-2 border-slate-700 hover:border-blue-400/50 backdrop-blur-sm'
                  }`}
                >
                  <span className="text-sm sm:text-lg font-black oswald leading-none">{pos.value}</span>
                  <span className="text-[7px] sm:text-[9px] font-bold uppercase opacity-60 leading-none">{pos.label.split(' ')[0]}</span>
                </button>
              );
            })}
          </div>
        </div>

        {/* Footer Actions */}
        <div className="p-8 bg-slate-800/30 border-t border-slate-700 flex flex-col sm:flex-row items-center justify-between gap-6">
          <div className="flex gap-4">
            <div className="flex items-center gap-2">
              <div className={`w-3 h-3 rounded-full ${awayPick ? 'bg-amber-500 animate-pulse' : 'bg-slate-700'}`}></div>
              <span className="text-[10px] font-bold text-slate-500 uppercase">Away: <span className="text-white ml-1">{awayPick || 'NONE'}</span></span>
            </div>
            <div className="flex items-center gap-2">
              <div className={`w-3 h-3 rounded-full ${homePick ? 'bg-blue-500 animate-pulse' : 'bg-slate-700'}`}></div>
              <span className="text-[10px] font-bold text-slate-500 uppercase">Home: <span className="text-white ml-1">{homePick || 'NONE'}</span></span>
            </div>
          </div>

          <button
            disabled={!awayPick || !homePick}
            onClick={handleConfirm}
            className={`w-full sm:w-64 py-4 rounded-2xl font-black oswald text-xl uppercase tracking-widest transition-all ${
              awayPick && homePick
                ? 'bg-gradient-to-r from-green-600 to-emerald-600 hover:from-green-500 hover:to-emerald-500 text-white shadow-[0_10px_30px_rgba(5,150,105,0.3)] active:scale-95'
                : 'bg-slate-800 text-slate-600 cursor-not-allowed border border-slate-700'
            }`}
          >
            {awayPick && homePick ? 'Drop the Puck!' : 'Finish Lineup'}
          </button>
        </div>
      </div>
    </div>
  );
};

export default SelectionOverlay;

export type Position = 'C' | 'LW' | 'RW' | 'LD' | 'RD' | 'G';

export interface GameEvent {
  id: string;
  timestamp: number;
  gameTime: string;
  team: 'home' | 'away';
  position: Position;
  type: 'GOAL' | 'ASSIST' | 'HIT' | 'SHOT' | 'BLOCKED_SHOT' | 'TAKEAWAY' | 'PASS' | 'GIVEAWAY' | 'SAVE' | 'GOAL_AGAINST' | 'PENALTY';
  description: string;
  points: number;
  homeScoreAtEvent?: number;
  awayScoreAtEvent?: number;
  userEarned?: number;
  period: number;
}

export interface FloatingPoint {
  id: string;
  points: number;
  team: 'home' | 'away';
  isUser: boolean;
  xOffset: number;
  variant: number; // For varied animation paths
}

export interface GoalExplosion {
  id: string;
  team: 'home' | 'away';
  color: string;
}

export interface LeaderboardPlayer {
  id: string;
  name: string;
  points: number;
  isUser?: boolean;
}

export interface TeamInfo {
  name: string;
  city: string;
  score: number;
  color: string;
  logo: string;
}

export interface GameState {
  period: number;
  timeRemaining: string;
  isPaused: boolean;
  waitingForPicks: boolean;
  homeTeam: TeamInfo;
  awayTeam: TeamInfo;
  userPicks: {
    home: Position | null;
    away: Position | null;
    homeNumber: number | null;
    awayNumber: number | null;
  };
  totalPoints: number;
  rank: number;
  totalPlayers: number;
  events: GameEvent[];
}

import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { GameState, Position, GameEvent, FloatingPoint, GoalExplosion, LeaderboardPlayer } from './types';
import { INITIAL_TEAMS } from './constants';
import ScoreBoard from './components/ScoreBoard';
import SelectionOverlay from './components/SelectionOverlay';
import GameLog from './components/GameLog';
import PickStatus from './components/PickStatus';
import PerformanceSummary from './components/PerformanceSummary';
import Leaderboard from './components/Leaderboard';
import { fetchSimulatedEvents } from './services/geminiService';
import { requestNotificationPermission, sendGameNotification, getNotificationStatus } from './services/notificationService';

const App: React.FC = () => {
  const [game, setGame] = useState<GameState>({
    period: 1,
    timeRemaining: '20:00',
    isPaused: false,
    waitingForPicks: true,
    homeTeam: INITIAL_TEAMS.home,
    awayTeam: INITIAL_TEAMS.away,
    userPicks: { home: null, away: null, homeNumber: null, awayNumber: null },
    totalPoints: 0,
    rank: 124,
    totalPlayers: 1542,
    events: [],
  });

  const [competitors, setCompetitors] = useState<LeaderboardPlayer[]>(() => {
    return Array.from({ length: 49 }, (_, i) => ({
      id: `comp-${i}`,
      name: `User_${Math.floor(Math.random() * 9000) + 1000}`,
      points: Math.max(0, 15000 - (i * 300) + (Math.random() * 500)),
    }));
  });

  const [floatingPoints, setFloatingPoints] = useState<FloatingPoint[]>([]);
  const [explosions, setExplosions] = useState<GoalExplosion[]>([]);
  const [loadingEvents, setLoadingEvents] = useState(false);
  const [notifPermission, setNotifPermission] = useState<NotificationPermission>(getNotificationStatus());
  const tickerRef = useRef<any>(null);

  const leaderboardData = useMemo(() => {
    const userPlayer: LeaderboardPlayer = {
      id: 'user-main',
      name: 'PuckMaster99',
      points: game.totalPoints,
      isUser: true
    };
    return [...competitors, userPlayer];
  }, [competitors, game.totalPoints]);

  useEffect(() => {
    const sorted = [...leaderboardData].sort((a, b) => b.points - a.points);
    const userIndex = sorted.findIndex(p => p.isUser);
    setGame(prev => ({ ...prev, rank: userIndex + 1 }));
  }, [leaderboardData]);

  const updateCompetitors = useCallback(() => {
    setCompetitors(prev => prev.map(comp => {
      const gain = Math.random() > 0.7 ? Math.floor(Math.random() * 1000) : 0;
      return { ...comp, points: comp.points + gain };
    }));
  }, []);

  const triggerGoalExplosion = (team: 'home' | 'away') => {
    const id = Math.random().toString(36).substr(2, 9);
    const color = team === 'home' ? game.homeTeam.color : game.awayTeam.color;
    setExplosions(prev => [...prev, { id, team, color }]);
    setTimeout(() => {
      setExplosions(prev => prev.filter(e => e.id !== id));
    }, 3000);
  };

  const triggerPointsAnimation = (points: number, team: 'home' | 'away', isUser: boolean) => {
    const id = Math.random().toString(36).substr(2, 9);
    const newFloatingPoint: FloatingPoint = {
      id,
      points,
      team,
      isUser,
      xOffset: (Math.random() - 0.5) * 50,
      variant: Math.floor(Math.random() * 3), // 0, 1, or 2 for varied paths
    };
    setFloatingPoints(prev => [...prev, newFloatingPoint]);
    setTimeout(() => {
      setFloatingPoints(prev => prev.filter(fp => fp.id !== id));
    }, 2000);
  };

  const processEvents = useCallback(async () => {
    if (loadingEvents || game.waitingForPicks) return;

    setLoadingEvents(true);
    const result = await fetchSimulatedEvents(
      game.period,
      game.timeRemaining,
      game.homeTeam.name,
      game.awayTeam.name
    );

    let newPoints = 0;
    let currentHomeScore = game.homeTeam.score;
    let currentAwayScore = game.awayTeam.score;
    let goalScored = false;
    let scoringTeamName = "";
    let scoringTeamType: 'home' | 'away' | null = null;

    const processedEvents = result.events.map(event => {
      if (event.type === 'GOAL') {
        goalScored = true;
        scoringTeamType = event.team as 'home' | 'away';
        scoringTeamName = event.team === 'home' ? game.homeTeam.name : game.awayTeam.name;
        if (event.team === 'home') currentHomeScore++;
        else currentAwayScore++;
      }

      if (event.type === 'PENALTY') {
        const teamName = event.team === 'home' ? game.homeTeam.name : game.awayTeam.name;
        sendGameNotification(
          `Whistle! Penalty for ${teamName}`,
          `${event.description}`
        );
      }

      const userPickForTeam = event.team === 'home' ? game.userPicks.home : game.userPicks.away;
      const isUserPick = event.position === userPickForTeam;
      const earned = isUserPick ? (event.points || 0) : 0;

      if (earned !== 0) {
        newPoints += earned;
        triggerPointsAnimation(earned, event.team!, true);
      } else if (event.points !== 0) {
        triggerPointsAnimation(event.points!, event.team!, false);
      }

      return { 
        ...event, 
        userEarned: earned, 
        homeScoreAtEvent: currentHomeScore, 
        awayScoreAtEvent: currentAwayScore,
        period: game.period 
      } as GameEvent;
    });

    if (goalScored && scoringTeamType) {
      triggerGoalExplosion(scoringTeamType);
      sendGameNotification(
        `GOAL! ${scoringTeamName} Scores!`,
        `Current Score: ${game.awayTeam.name} ${currentAwayScore} - ${game.homeTeam.name} ${currentHomeScore}`
      );
    }

    if (result.nextFaceoffTrigger) {
      sendGameNotification(
        "Next Face-Off!",
        "Picks reset soon. Get back in the game to choose your positions!"
      );
    }

    setGame(prev => ({
      ...prev,
      totalPoints: prev.totalPoints + newPoints,
      events: [...processedEvents, ...prev.events].slice(0, 100),
      homeTeam: { ...prev.homeTeam, score: currentHomeScore },
      awayTeam: { ...prev.awayTeam, score: currentAwayScore },
      waitingForPicks: result.nextFaceoffTrigger,
    }));

    updateCompetitors();
    setLoadingEvents(false);
  }, [game.period, game.timeRemaining, game.homeTeam.name, game.awayTeam.name, game.userPicks, game.waitingForPicks, loadingEvents, game.homeTeam.score, game.awayTeam.score, game.homeTeam.color, game.awayTeam.color, updateCompetitors]);

  useEffect(() => {
    if (game.waitingForPicks || game.isPaused) return;

    tickerRef.current = setInterval(() => {
      setGame(prev => {
        const [mins, secs] = prev.timeRemaining.split(':').map(Number);
        let totalSecs = mins * 60 + secs - 12;

        if (totalSecs <= 0) {
          if (prev.period < 3) {
            return { ...prev, period: prev.period + 1, timeRemaining: '20:00', waitingForPicks: true };
          } else {
            return { ...prev, isPaused: true, timeRemaining: '00:00' };
          }
        }

        const newMins = Math.floor(totalSecs / 60);
        const newSecs = totalSecs % 60;
        return {
          ...prev,
          timeRemaining: `${newMins.toString().padStart(2, '0')}:${newSecs.toString().padStart(2, '0')}`
        };
      });
    }, 1000);

    return () => {
      if (tickerRef.current) clearInterval(tickerRef.current);
    };
  }, [game.waitingForPicks, game.isPaused]);

  useEffect(() => {
    if (game.waitingForPicks || game.isPaused) return;

    const eventInterval = setInterval(() => {
      processEvents();
    }, 8000);

    return () => clearInterval(eventInterval);
  }, [game.waitingForPicks, game.isPaused, processEvents]);

  const handlePicks = async (picks: { home: Position; away: Position; homeNumber: number; awayNumber: number }) => {
    if (notifPermission === 'default') {
      const granted = await requestNotificationPermission();
      setNotifPermission(granted ? 'granted' : 'denied');
    }

    setGame(prev => ({
      ...prev,
      userPicks: picks,
      waitingForPicks: false
    }));
  };

  return (
    <div className="min-h-screen bg-slate-950 text-slate-100 flex flex-col pb-24 relative overflow-hidden">
      {explosions.map(exp => (
        <div key={exp.id} className="fixed inset-0 z-[100] pointer-events-none flex items-center justify-center">
          <div 
            className="absolute inset-0 animate-screen-flash"
            style={{ backgroundColor: `${exp.color}22` }}
          />
          <div className="relative">
            <div className="text-8xl font-black oswald uppercase text-white animate-goal-text drop-shadow-[0_0_20px_rgba(255,255,255,0.8)]">
              GOAL!
            </div>
            <div 
              className="absolute inset-0 animate-goal-explosion"
              style={{ background: `radial-gradient(circle, ${exp.color} 0%, transparent 70%)` }}
            />
          </div>
          <div className="absolute inset-0 overflow-hidden">
             {[...Array(30)].map((_, i) => (
               <div 
                 key={i}
                 className="absolute w-2 h-2 rounded-full animate-particle"
                 style={{
                   backgroundColor: i % 2 === 0 ? exp.color : '#fff',
                   left: '50%',
                   top: '50%',
                   '--tx': `${(Math.random() - 0.5) * 1000}px`,
                   '--ty': `${(Math.random() - 0.5) * 1000}px`,
                   animationDelay: `${Math.random() * 0.5}s`
                 } as any}
               />
             ))}
          </div>
        </div>
      ))}

      <ScoreBoard 
        home={game.homeTeam} 
        away={game.awayTeam} 
        period={game.period} 
        time={game.timeRemaining} 
      />

      {game.waitingForPicks && (
        <SelectionOverlay 
          homeTeam={game.homeTeam} 
          awayTeam={game.awayTeam} 
          onConfirm={handlePicks} 
        />
      )}

      <main className="flex-1 max-w-6xl mx-auto w-full p-4">
        <div className="flex flex-col lg:flex-row gap-8">

          <div className="flex-1 space-y-10 order-2 lg:order-1">
            <div className="bg-slate-900/80 border border-slate-800 rounded-2xl p-6 shadow-2xl backdrop-blur-sm">
              <div className="flex justify-between items-center mb-4">
                 <div className="text-[10px] font-bold text-slate-500 uppercase tracking-widest flex items-center gap-2">
                    Active Session
                    {notifPermission === 'granted' ? (
                       <span className="text-green-500 flex items-center gap-1"><i className="fa-solid fa-bell text-[8px]"></i> Notifications Active</span>
                    ) : notifPermission === 'denied' ? (
                       <span className="text-red-500 flex items-center gap-1"><i className="fa-solid fa-bell-slash text-[8px]"></i> Alerts Blocked</span>
                    ) : null}
                 </div>
              </div>
              <PickStatus 
                homeTeam={game.homeTeam} 
                awayTeam={game.awayTeam} 
                userPicks={game.userPicks} 
                floatingPoints={floatingPoints}
              />
            </div>

            <div className="grid grid-cols-2 sm:grid-cols-4 gap-4">
              <div className="bg-slate-900 border border-slate-800 p-4 rounded-xl shadow-lg relative overflow-hidden group">
                <div className="absolute top-0 right-0 p-2 opacity-10 group-hover:opacity-20 transition-opacity">
                  <i className="fa-solid fa-star text-4xl"></i>
                </div>
                <div className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-1">Score</div>
                <div className="text-3xl font-black text-amber-500 oswald">{game.totalPoints.toLocaleString()}</div>
              </div>
              <div className="bg-slate-900 border border-slate-800 p-4 rounded-xl shadow-lg relative overflow-hidden group">
                <div className="absolute top-0 right-0 p-2 opacity-10 group-hover:opacity-20 transition-opacity">
                  <i className="fa-solid fa-trophy text-4xl"></i>
                </div>
                <div className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-1">Rank</div>
                <div className="text-3xl font-black text-blue-400 oswald">#{game.rank}</div>
              </div>
              <div className="bg-slate-900 border border-slate-800 p-4 rounded-xl shadow-lg hidden sm:block relative overflow-hidden">
                <div className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-1">Active Positions</div>
                <div className="flex gap-2 text-xl font-black oswald">
                  <div className="flex items-center gap-1.5">
                    <span className="text-amber-500">{game.userPicks.awayNumber ? `#${game.userPicks.awayNumber}` : ''} {game.userPicks.away || '--'}</span>
                    <span className="text-[10px] text-slate-600">AWY</span>
                  </div>
                  <span className="text-slate-700">|</span>
                  <div className="flex items-center gap-1.5">
                    <span className="text-blue-500">{game.userPicks.homeNumber ? `#${game.userPicks.homeNumber}` : ''} {game.userPicks.home || '--'}</span>
                    <span className="text-[10px] text-slate-600">HME</span>
                  </div>
                </div>
              </div>
              <div className="bg-slate-900 border border-slate-800 p-4 rounded-xl shadow-lg hidden sm:block relative overflow-hidden">
                <div className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-1">Live Players</div>
                <div className="text-3xl font-black text-slate-300 oswald">{game.totalPlayers.toLocaleString()}</div>
              </div>
            </div>

            <div className="bg-slate-900/50 border border-slate-800 rounded-2xl overflow-hidden flex flex-col">
              <div className="bg-slate-800 px-6 py-4 border-b border-slate-700 flex justify-between items-center">
                <h2 className="text-sm font-black uppercase tracking-widest text-slate-200 flex items-center gap-2">
                  <i className="fa-solid fa-satellite-dish text-red-500 animate-pulse"></i>
                  Live Rink Action
                </h2>
                {loadingEvents && (
                  <div className="text-[10px] font-bold text-slate-500 uppercase animate-pulse flex items-center gap-1">
                    <i className="fa-solid fa-spinner fa-spin"></i>
                    Simulating...
                  </div>
                )}
              </div>

              <div className="overflow-y-auto p-4 space-y-4 max-h-[300px] scroll-smooth">
                {game.events.length === 0 ? (
                  <div className="h-40 flex flex-col items-center justify-center text-slate-600">
                    <i className="fa-solid fa-hockey-puck text-4xl mb-4 opacity-20"></i>
                    <p className="font-bold uppercase tracking-wider text-[10px]">Waiting for game to start...</p>
                  </div>
                ) : (
                  game.events.slice(0, 10).map((event) => {
                    const isUserPositive = (event.userEarned || 0) > 0;
                    const isUserNegative = (event.userEarned || 0) < 0;
                    const isGoal = event.type === 'GOAL';

                    return (
                      <div 
                        key={`live-${event.id}`} 
                        className={`flex items-start gap-4 p-4 rounded-xl border transition-all animate-in slide-in-from-right duration-500 relative overflow-hidden ${
                          isGoal ? 'animate-goal-card-glow' : ''
                        } ${
                          isUserPositive ? 'bg-green-900/20 border-green-500/40' : 
                          isUserNegative ? 'bg-red-900/20 border-red-500/40' : 
                          'bg-slate-800/40 border-slate-700'
                        }`}
                      >
                        {isGoal && (
                          <div className="absolute inset-0 bg-gradient-to-r from-red-500/10 via-amber-500/10 to-red-500/10 animate-shimmer pointer-events-none" />
                        )}
                        <div className={`w-10 h-10 rounded-full flex-shrink-0 flex items-center justify-center font-black text-xs border-2 shadow-lg z-10 ${
                          event.team === 'home' ? 'bg-blue-600 border-blue-400' : 'bg-amber-600 border-amber-400'
                        }`}>
                          {event.position}
                        </div>
                        <div className="flex-1 z-10">
                          <div className="flex items-center justify-between mb-1">
                            <span className="text-[9px] font-bold text-slate-500 uppercase">
                              {event.gameTime} • {event.type.replace('_', ' ')}
                            </span>
                            {isGoal && (
                              <span className="bg-red-600 text-[9px] font-black px-2 py-0.5 rounded text-white uppercase tracking-tighter animate-bounce shadow-lg shadow-red-900/50">Goal!</span>
                            )}
                          </div>
                          <p className="text-sm text-slate-100 font-medium">
                            <span className="font-bold text-white mr-1 opacity-70">
                              {event.team === 'home' ? game.homeTeam.name : game.awayTeam.name}:
                            </span>
                            {event.description}
                          </p>
                        </div>
                        {(event.userEarned !== 0) && (
                          <div className={`text-right font-black oswald text-xl min-w-[60px] z-10 ${isUserPositive ? 'text-green-400' : 'text-red-400'}`}>
                            {isUserPositive ? '+' : ''}{event.userEarned}
                          </div>
                        )}
                      </div>
                    );
                  })
                )}
              </div>
            </div>

            <PerformanceSummary events={game.events} />

            <GameLog 
              events={game.events} 
              homeTeam={game.homeTeam} 
              awayTeam={game.awayTeam} 
            />
          </div>

          <div className="lg:w-80 order-1 lg:order-2">
            <div className="lg:sticky lg:top-24 space-y-6">
              <Leaderboard 
                players={leaderboardData} 
                userPoints={game.totalPoints} 
                userRank={game.rank} 
              />

              <div className="hidden lg:block bg-blue-600/10 border border-blue-500/20 p-4 rounded-xl">
                <div className="text-[10px] font-black text-blue-500 uppercase tracking-widest mb-2 flex items-center gap-1.5">
                  <i className="fa-solid fa-circle-info"></i>
                  Strategy Tip
                </div>
                <p className="text-xs text-blue-300 leading-relaxed font-medium">
                  Watch for penalties! A penalty (PEN) deduced points from your picked player's total. Stay alert for defensive switches.
                </p>
              </div>
            </div>
          </div>

        </div>
      </main>

      <footer className="fixed bottom-0 left-0 right-0 bg-slate-900 border-t border-slate-800 p-4 sm:p-6 shadow-2xl z-40">
        <div className="max-w-6xl mx-auto flex items-center justify-between gap-4">
          <div className="flex items-center gap-4">
            <div className="hidden sm:block">
              <div className="text-[10px] font-bold text-slate-500 uppercase">Selected Lineup</div>
              <div className="flex gap-1 mt-0.5">
                <div className="bg-amber-600/20 text-amber-500 px-2 border border-amber-600/40 rounded font-black text-xs">
                  {game.userPicks.awayNumber ? `#${game.userPicks.awayNumber}` : ''} {game.userPicks.away || '?'}
                </div>
                <div className="bg-blue-600/20 text-blue-500 px-2 border border-blue-600/40 rounded font-black text-xs">
                  {game.userPicks.homeNumber ? `#${game.userPicks.homeNumber}` : ''} {game.userPicks.home || '?'}
                </div>
              </div>
            </div>
            <div className="h-8 w-[1px] bg-slate-800 hidden sm:block"></div>
            <div>
              <div className="text-[10px] font-bold text-slate-500 uppercase">Points</div>
              <div className="text-2xl font-black oswald text-amber-500 leading-none">{game.totalPoints.toLocaleString()}</div>
            </div>
          </div>

          <div className="flex gap-2">
            <button 
              onClick={() => setGame(prev => ({ ...prev, waitingForPicks: true }))}
              className="bg-slate-800 hover:bg-slate-700 text-slate-300 px-4 py-2 rounded-lg font-bold text-xs uppercase tracking-widest transition-all border border-slate-700 active:scale-95"
            >
              Update Picks
            </button>
            <button 
              onClick={() => {
                const leaderboardEl = document.querySelector('.lg\\:w-80');
                leaderboardEl?.scrollIntoView({ behavior: 'smooth' });
              }}
              className="bg-blue-600 hover:bg-blue-500 text-white px-4 py-2 rounded-lg font-bold text-xs uppercase tracking-widest transition-all shadow-lg shadow-blue-900/20 active:scale-95"
            >
              Leaderboard
            </button>
          </div>
        </div>
      </footer>

      <style>{`
        @keyframes screen-flash {
          0% { opacity: 0; }
          10% { opacity: 1; }
          100% { opacity: 0; }
        }
        @keyframes goal-text {
          0% { transform: scale(0.5); opacity: 0; filter: blur(10px); }
          20% { transform: scale(1.2); opacity: 1; filter: blur(0); }
          80% { transform: scale(1.1); opacity: 1; }
          100% { transform: scale(1.5); opacity: 0; filter: blur(20px); }
        }
        @keyframes goal-explosion {
          0% { transform: scale(0); opacity: 0.8; }
          100% { transform: scale(4); opacity: 0; }
        }
        @keyframes particle {
          0% { transform: translate(0, 0); opacity: 1; }
          100% { transform: translate(var(--tx), var(--ty)); opacity: 0; }
        }
        @keyframes goal-card-glow {
          0% { border-color: rgba(239, 68, 68, 0.4); box-shadow: 0 0 0px rgba(239, 68, 68, 0); }
          50% { border-color: rgba(239, 68, 68, 1); box-shadow: 0 0 20px rgba(239, 68, 68, 0.4); }
          100% { border-color: rgba(239, 68, 68, 0.4); box-shadow: 0 0 0px rgba(239, 68, 68, 0); }
        }
        @keyframes shimmer {
          0% { transform: translateX(-100%); }
          100% { transform: translateX(100%); }
        }
        .animate-screen-flash { animation: screen-flash 1.5s ease-out forwards; }
        .animate-goal-text { animation: goal-text 2s cubic-bezier(0.17, 0.67, 0.83, 0.67) forwards; }
        .animate-goal-explosion { animation: goal-explosion 1s ease-out forwards; }
        .animate-particle { animation: particle 1.5s ease-out forwards; }
        .animate-goal-card-glow { animation: goal-card-glow 2s ease-in-out infinite; }
        .animate-shimmer { animation: shimmer 2s linear infinite; }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { Position, TeamInfo } from '../types';
import { POSITIONS } from '../constants';

interface SelectionOverlayProps {
  homeTeam: TeamInfo;
  awayTeam: TeamInfo;
  onConfirm: (picks: { home: Position; away: Position; homeNumber: number; awayNumber: number }) => void;
}

const SelectionOverlay: React.FC<SelectionOverlayProps> = ({ homeTeam, awayTeam, onConfirm }) => {
  const [awayPick, setAwayPick] = useState<Position | null>(null);
  const [homePick, setHomePick] = useState<Position | null>(null);

  // Generate stable random jersey numbers for this session
  const awayNumbers = useMemo(() => {
    return POSITIONS.reduce((acc, pos) => {
      acc[pos.value] = Math.floor(Math.random() * 98) + 1;
      return acc;
    }, {} as Record<Position, number>);
  }, []);

  const homeNumbers = useMemo(() => {
    return POSITIONS.reduce((acc, pos) => {
      acc[pos.value] = Math.floor(Math.random() * 98) + 1;
      return acc;
    }, {} as Record<Position, number>);
  }, []);

  const handleConfirm = () => {
    if (awayPick && homePick) {
      onConfirm({ 
        home: homePick, 
        away: awayPick, 
        homeNumber: homeNumbers[homePick], 
        awayNumber: awayNumbers[awayPick] 
      });
    }
  };

  // Helper to get positioning on the tactical rink
  const getPosCoords = (pos: Position, isHome: boolean) => {
    const baseCoords: Record<Position, { top: string; left: string }> = {
      'G': { top: '50%', left: isHome ? '90%' : '10%' },
      'LD': { top: '30%', left: isHome ? '70%' : '30%' },
      'RD': { top: '70%', left: isHome ? '70%' : '30%' },
      'LW': { top: '25%', left: isHome ? '55%' : '45%' },
      'RW': { top: '75%', left: isHome ? '55%' : '45%' },
      'C': { top: '50%', left: isHome ? '60%' : '40%' },
    };
    return baseCoords[pos];
  };

  return (
    <div className="fixed inset-0 z-[100] bg-slate-950/95 backdrop-blur-xl flex items-center justify-center p-4 overflow-y-auto">
      <div className="bg-slate-900 border border-slate-700 w-full max-w-5xl rounded-3xl shadow-[0_0_50px_rgba(0,0,0,0.5)] overflow-hidden animate-in fade-in zoom-in duration-500 my-auto">

        {/* Header */}
        <div className="bg-slate-800/50 p-6 border-b border-slate-700 flex flex-col items-center text-center">
          <div className="flex items-center gap-4 mb-2">
            <span className="text-3xl animate-bounce">{awayTeam.logo}</span>
            <div className="h-px w-12 bg-slate-700"></div>
            <h2 className="text-3xl font-black oswald uppercase tracking-tighter text-white">Lineup Selection</h2>
            <div className="h-px w-12 bg-slate-700"></div>
            <span className="text-3xl animate-bounce">{homeTeam.logo}</span>
          </div>
          <p className="text-slate-400 text-[10px] font-black uppercase tracking-[0.3em]">Pick 1 key player from each roster</p>
        </div>

        {/* Rink Container */}
        <div className="relative p-4 sm:p-8 bg-slate-950">
          {/* Stylized Rink Background */}
          <div className="relative w-full aspect-[2/1] bg-slate-900 rounded-[100px] border-[4px] border-slate-800 overflow-hidden shadow-inner">
            {/* Center Line */}
            <div className="absolute inset-y-0 left-1/2 w-1 bg-red-600/40 -translate-x-1/2"></div>
            {/* Center Circle */}
            <div className="absolute top-1/2 left-1/2 w-32 h-32 border-2 border-red-600/30 rounded-full -translate-x-1/2 -translate-y-1/2"></div>
            {/* Blue Lines */}
            <div className="absolute inset-y-0 left-[30%] w-1.5 bg-blue-600/40"></div>
            <div className="absolute inset-y-0 right-[30%] w-1.5 bg-blue-600/40"></div>
            {/* Creases */}
            <div className="absolute top-1/2 left-0 w-8 h-16 border-2 border-red-500/20 rounded-r-full -translate-y-1/2 bg-red-500/5"></div>
            <div className="absolute top-1/2 right-0 w-8 h-16 border-2 border-red-500/20 rounded-l-full -translate-y-1/2 bg-red-500/5"></div>

            {/* Labels */}
            <div className="absolute top-4 left-12 oswald font-black text-slate-700 uppercase tracking-widest text-xl opacity-30 pointer-events-none">{awayTeam.name}</div>
            <div className="absolute top-4 right-12 oswald font-black text-slate-700 uppercase tracking-widest text-xl opacity-30 pointer-events-none text-right">{homeTeam.name}</div>

            {/* Away Positions */}
            {POSITIONS.map((pos) => {
              const coords = getPosCoords(pos.value, false);
              const isSelected = awayPick === pos.value;
              return (
                <button
                  key={`tactical-away-${pos.value}`}
                  onClick={() => setAwayPick(pos.value)}
                  style={{ top: coords.top, left: coords.left }}
                  className={`absolute -translate-x-1/2 -translate-y-1/2 w-12 h-12 sm:w-16 sm:h-16 rounded-full flex flex-col items-center justify-center transition-all z-10 ${
                    isSelected
                      ? 'bg-amber-500 text-slate-950 border-4 border-amber-300 scale-110 shadow-[0_0_20px_rgba(245,158,11,0.5)]'
                      : 'bg-slate-800/80 text-slate-400 border-2 border-slate-700 hover:border-amber-500/50 backdrop-blur-sm'
                  }`}
                >
                  <div className="absolute -top-1 -right-1 bg-slate-950 text-amber-500 text-[8px] font-black px-1.5 py-0.5 rounded-full border border-amber-500/50">#{awayNumbers[pos.value]}</div>
                  <span className="text-sm sm:text-lg font-black oswald leading-none">{pos.value}</span>
                  <span className="text-[7px] sm:text-[9px] font-bold uppercase opacity-60 leading-none">{pos.label.split(' ')[0]}</span>
                </button>
              );
            })}

            {/* Home Positions */}
            {POSITIONS.map((pos) => {
              const coords = getPosCoords(pos.value, true);
              const isSelected = homePick === pos.value;
              return (
                <button
                  key={`tactical-home-${pos.value}`}
                  onClick={() => setHomePick(pos.value)}
                  style={{ top: coords.top, left: coords.left }}
                  className={`absolute -translate-x-1/2 -translate-y-1/2 w-12 h-12 sm:w-16 sm:h-16 rounded-full flex flex-col items-center justify-center transition-all z-10 ${
                    isSelected
                      ? 'bg-blue-600 text-white border-4 border-blue-400 scale-110 shadow-[0_0_20px_rgba(37,99,235,0.5)]'
                      : 'bg-slate-800/80 text-slate-400 border-2 border-slate-700 hover:border-blue-400/50 backdrop-blur-sm'
                  }`}
                >
                  <div className="absolute -top-1 -right-1 bg-slate-950 text-blue-400 text-[8px] font-black px-1.5 py-0.5 rounded-full border border-blue-400/50">#{homeNumbers[pos.value]}</div>
                  <span className="text-sm sm:text-lg font-black oswald leading-none">{pos.value}</span>
                  <span className="text-[7px] sm:text-[9px] font-bold uppercase opacity-60 leading-none">{pos.label.split(' ')[0]}</span>
                </button>
              );
            })}
          </div>
        </div>

        {/* Footer Actions */}
        <div className="p-8 bg-slate-800/30 border-t border-slate-700 flex flex-col sm:flex-row items-center justify-between gap-6">
          <div className="flex gap-4">
            <div className="flex items-center gap-2">
              <div className={`w-3 h-3 rounded-full ${awayPick ? 'bg-amber-500 animate-pulse' : 'bg-slate-700'}`}></div>
              <span className="text-[10px] font-bold text-slate-500 uppercase">Away: <span className="text-white ml-1">{awayPick ? `#${awayNumbers[awayPick]} ${awayPick}` : 'NONE'}</span></span>
            </div>
            <div className="flex items-center gap-2">
              <div className={`w-3 h-3 rounded-full ${homePick ? 'bg-blue-500 animate-pulse' : 'bg-slate-700'}`}></div>
              <span className="text-[10px] font-bold text-slate-500 uppercase">Home: <span className="text-white ml-1">{homePick ? `#${homeNumbers[homePick]} ${homePick}` : 'NONE'}</span></span>
            </div>
          </div>

          <button
            disabled={!awayPick || !homePick}
            onClick={handleConfirm}
            className={`w-full sm:w-64 py-4 rounded-2xl font-black oswald text-xl uppercase tracking-widest transition-all ${
              awayPick && homePick
                ? 'bg-gradient-to-r from-green-600 to-emerald-600 hover:from-green-500 hover:to-emerald-500 text-white shadow-[0_10px_30px_rgba(5,150,105,0.3)] active:scale-95'
                : 'bg-slate-800 text-slate-600 cursor-not-allowed border border-slate-700'
            }`}
          >
            {awayPick && homePick ? 'Drop the Puck!' : 'Finish Lineup'}
          </button>
        </div>
      </div>
    </div>
  );
};

export default SelectionOverlay;

import React from 'react';
import { Position, TeamInfo, FloatingPoint } from '../types';

interface PickStatusProps {
  homeTeam: TeamInfo;
  awayTeam: TeamInfo;
  userPicks: { home: Position | null; away: Position | null; homeNumber: number | null; awayNumber: number | null };
  floatingPoints: FloatingPoint[];
}

const PickStatus: React.FC<PickStatusProps> = ({ homeTeam, awayTeam, userPicks, floatingPoints }) => {
  const getPointStyles = (points: number) => {
    const absPoints = Math.abs(points);

    // Base style configuration
    let color = 'text-green-400';
    let size = 'text-lg';
    let glow = '';
    let weight = 'font-bold';
    let animationName = 'float-up';
    let duration = '2s';

    if (points < 0) {
      color = 'text-red-500';
      size = absPoints >= 1000 ? 'text-2xl' : 'text-lg';
      weight = 'font-black';
      animationName = 'shake-sink';
      duration = '1.5s';
    } else if (points >= 5000) {
      // Goal logic - most explosive
      color = 'text-yellow-300';
      size = 'text-5xl';
      glow = 'drop-shadow-[0_0_15px_rgba(253,224,71,0.9)]';
      weight = 'font-black';
      animationName = 'pop-float';
      duration = '2.5s';
    } else if (points >= 1000) {
      // Assist logic
      color = 'text-blue-400';
      size = 'text-3xl';
      glow = 'drop-shadow-[0_0_10px_rgba(96,165,250,0.6)]';
      weight = 'font-black';
      animationName = 'float-sway';
      duration = '2.2s';
    } else if (points >= 500) {
      // Grit logic
      color = 'text-emerald-300';
      size = 'text-xl';
      weight = 'font-extrabold';
      animationName = 'float-up';
      duration = '1.8s';
    } else {
      // Minor plays (passes, shots)
      color = 'text-slate-300';
      size = 'text-base';
      weight = 'font-bold';
      animationName = 'float-up-fast';
      duration = '1.2s';
    }

    return { color, size, glow, weight, animationName, duration };
  };

  return (
    <div className="flex justify-center gap-6 sm:gap-12 py-2">
      {/* Away Pick */}
      <div className="relative group">
        <div className="text-[10px] font-black text-slate-500 uppercase tracking-widest text-center mb-1">Away Pick</div>
        <div 
          className={`w-16 h-16 sm:w-20 sm:h-20 rounded-2xl border-2 flex flex-col items-center justify-center transition-all shadow-xl relative ${
            userPicks.away ? 'bg-amber-600/10 border-amber-500 shadow-amber-900/20' : 'bg-slate-900 border-slate-800'
          }`}
        >
          {userPicks.awayNumber && (
            <div className="absolute -top-2 -left-2 bg-amber-500 text-slate-950 font-black text-[10px] px-1.5 py-0.5 rounded shadow-lg">#{userPicks.awayNumber}</div>
          )}
          <span className="text-xl sm:text-2xl font-black oswald text-amber-500">
            {userPicks.away || '--'}
          </span>
          <span className="text-[9px] font-bold text-amber-500/60 uppercase">{awayTeam.name}</span>
        </div>

        {/* Floating Points Container */}
        {floatingPoints.filter(fp => fp.team === 'away').map(fp => {
          const { color, size, glow, weight, animationName, duration } = getPointStyles(fp.points);
          // Apply horizontal variance based on fp.variant and fp.xOffset
          const swayOffset = fp.variant === 1 ? -20 : fp.variant === 2 ? 20 : 0;

          return (
            <div 
              key={fp.id}
              style={{ 
                left: `calc(50% + ${fp.xOffset}px)`,
                animationName: animationName,
                animationDuration: duration,
                animationFillMode: 'forwards',
                '--sway-x': `${swayOffset}px`
              } as React.CSSProperties}
              className={`absolute bottom-full mb-4 pointer-events-none oswald whitespace-nowrap z-[60] ${color} ${size} ${glow} ${weight} animate-floating-base`}
            >
              {fp.points > 0 ? '+' : ''}{fp.points}
            </div>
          );
        })}
      </div>

      <div className="flex items-center">
        <div className="w-px h-12 bg-slate-800"></div>
      </div>

      {/* Home Pick */}
      <div className="relative group">
        <div className="text-[10px] font-black text-slate-500 uppercase tracking-widest text-center mb-1">Home Pick</div>
        <div 
          className={`w-16 h-16 sm:w-20 sm:h-20 rounded-2xl border-2 flex flex-col items-center justify-center transition-all shadow-xl relative ${
            userPicks.home ? 'bg-blue-600/10 border-blue-500 shadow-blue-900/20' : 'bg-slate-900 border-slate-800'
          }`}
        >
          {userPicks.homeNumber && (
            <div className="absolute -top-2 -right-2 bg-blue-600 text-white font-black text-[10px] px-1.5 py-0.5 rounded shadow-lg">#{userPicks.homeNumber}</div>
          )}
          <span className="text-xl sm:text-2xl font-black oswald text-blue-500">
            {userPicks.home || '--'}
          </span>
          <span className="text-[9px] font-bold text-blue-500/60 uppercase">{homeTeam.name}</span>
        </div>

        {/* Floating Points Container */}
        {floatingPoints.filter(fp => fp.team === 'home').map(fp => {
          const { color, size, glow, weight, animationName, duration } = getPointStyles(fp.points);
          const swayOffset = fp.variant === 1 ? -20 : fp.variant === 2 ? 20 : 0;

          return (
            <div 
              key={fp.id}
              style={{ 
                left: `calc(50% + ${fp.xOffset}px)`,
                animationName: animationName,
                animationDuration: duration,
                animationFillMode: 'forwards',
