import React from 'react';
import { Position, TeamInfo, FloatingPoint, GameEvent } from '../types';
import { POSITIONS } from '../constants';

interface PickStatusProps {
  homeTeam: TeamInfo;
  awayTeam: TeamInfo;
  userPicks: { home: Position | null; away: Position | null; homeNumber: number | null; awayNumber: number | null };
  floatingPoints: FloatingPoint[];
  events: GameEvent[];
  onPlaceholderClick?: () => void;
}

const PickStatus: React.FC<PickStatusProps> = ({ homeTeam, awayTeam, userPicks, floatingPoints, events, onPlaceholderClick }) => {
  const getPointsForPick = (team: 'home' | 'away', pos: Position | null) => {
    if (!pos) return 0;
    return events
      .filter(e => e.team === team && e.position === pos)
      .reduce((sum, e) => sum + (e.userEarned || 0), 0);
  };

  const awayPoints = getPointsForPick('away', userPicks.away);
  const homePoints = getPointsForPick('home', userPicks.home);

  const getPointStyles = (points: number) => {
    const absPoints = Math.abs(points);
    let color = 'text-green-400';
    let size = 'text-lg';
    let glow = '';
    let weight = 'font-bold';
    let animationName = 'float-up';
    let duration = '2s';

    if (points < 0) {
      color = 'text-red-500';
      size = absPoints >= 1000 ? 'text-2xl' : 'text-lg';
      weight = 'font-black';
      animationName = 'shake-sink';
      duration = '1.5s';
    } else if (points >= 5000) {
      color = 'text-yellow-300';
      size = 'text-5xl';
      glow = 'drop-shadow-[0_0_15px_rgba(253,224,71,0.9)]';
      weight = 'font-black';
      animationName = 'pop-float';
      duration = '2.5s';
    } else if (points >= 1000) {
      color = 'text-blue-400';
      size = 'text-3xl';
      glow = 'drop-shadow-[0_0_10px_rgba(96,165,250,0.6)]';
      weight = 'font-black';
      animationName = 'float-sway';
      duration = '2.2s';
    } else if (points >= 500) {
      color = 'text-emerald-300';
      size = 'text-xl';
      weight = 'font-extrabold';
      animationName = 'float-up';
      duration = '1.8s';
    } else {
      color = 'text-slate-300';
      size = 'text-base';
      weight = 'font-bold';
      animationName = 'float-up-fast';
      duration = '1.2s';
    }

    return { color, size, glow, weight, animationName, duration };
  };

  const PositionRibbon = ({ selectedPos, teamColor }: { selectedPos: Position | null, teamColor: string }) => (
    <div className="flex gap-1 w-full overflow-x-auto no-scrollbar py-1">
      {POSITIONS.map(p => {
