          <div 
            key={p.value}
            className={`flex-1 min-w-[32px] py-1 text-center rounded text-[8px] font-black uppercase tracking-tighter transition-all border ${
              isActive 
                ? 'text-white border-transparent' 
                : 'text-slate-600 border-slate-800 bg-slate-900/40'
            }`}
            style={{ backgroundColor: isActive ? teamColor : undefined }}
          >
            {p.value}
          </div>
        );
      })}
    </div>
  );

  return (
    <div className="flex flex-col sm:flex-row justify-center gap-6 sm:gap-12 py-2">
      {/* Away Section */}
      <div className="flex-1 max-w-[280px] flex flex-col gap-3 relative">
        <div className="flex items-center gap-3">
          <div className="w-8 h-8 rounded-full bg-amber-500/20 border border-amber-500/40 flex items-center justify-center text-xl shadow-lg">
            {awayTeam.logo}
          </div>
          <div className="flex flex-col">
            <span className="text-[9px] font-black text-slate-500 uppercase leading-none tracking-widest">{awayTeam.city}</span>
            <span className="text-sm font-black oswald text-white uppercase leading-none">{awayTeam.name}</span>
          </div>
        </div>

        <PositionRibbon selectedPos={userPicks.away} teamColor={awayTeam.color} />

        <div className="relative group">
          {userPicks.away ? (
            <div className="bg-slate-900 border border-slate-800 rounded-xl p-4 flex items-center justify-between transition-all hover:bg-slate-800/80 shadow-inner">
              <div className="flex flex-col">
                <span className="text-[10px] font-bold text-slate-500 uppercase mb-1">Jersey #</span>
                <span className="text-3xl font-black oswald text-white leading-none">#{userPicks.awayNumber}</span>
              </div>
              <div className="flex flex-col items-end">
                <span className="text-[10px] font-bold text-slate-500 uppercase mb-1">Pick Score</span>
                <span className="text-2xl font-black oswald text-amber-500 leading-none">+{awayPoints.toLocaleString()}</span>
              </div>
            </div>
          ) : (
            <button 
              onClick={onPlaceholderClick}
              className="w-full py-6 rounded-xl border-2 border-dashed border-slate-800 bg-slate-900/50 flex flex-col items-center justify-center text-center transition-all hover:border-amber-500/50 group active:scale-95"
            >
              <i className="fa-solid fa-plus text-slate-700 group-hover:text-amber-500/50 mb-1"></i>
              <span className="text-[10px] font-black uppercase text-slate-500 group-hover:text-slate-300">Tap to Select Away</span>
            </button>
          )}

          {/* Floating Points (Anchor to the card) */}
          <div className="absolute inset-0 pointer-events-none flex items-center justify-center">
            {floatingPoints.filter(fp => fp.team === 'away').map(fp => {
              const { color, size, glow, weight, animationName, duration } = getPointStyles(fp.points);
              const swayOffset = fp.variant === 1 ? -20 : fp.variant === 2 ? 20 : 0;
              return (
                <div 
                  key={fp.id}
                  style={{ 
                    left: `calc(50% + ${fp.xOffset}px)`,
                    animationName: animationName,
                    animationDuration: duration,
                    animationFillMode: 'forwards',
                    '--sway-x': `${swayOffset}px`
                  } as React.CSSProperties}
                  className={`absolute bottom-full mb-4 oswald whitespace-nowrap z-[60] ${color} ${size} ${glow} ${weight} animate-floating-base`}
                >
                  {fp.points > 0 ? '+' : ''}{fp.points}
                </div>
              );
            })}
          </div>
        </div>
      </div>

      <div className="hidden sm:flex items-center">
        <div className="w-px h-24 bg-slate-800/50"></div>
      </div>

      {/* Home Section */}
      <div className="flex-1 max-w-[280px] flex flex-col gap-3 relative">
        <div className="flex items-center gap-3">
          <div className="w-8 h-8 rounded-full bg-blue-600/20 border border-blue-600/40 flex items-center justify-center text-xl shadow-lg">
            {homeTeam.logo}
          </div>
          <div className="flex flex-col">
