            <span className="text-sm font-black oswald text-white uppercase leading-none">{homeTeam.name}</span>
          </div>
        </div>

        <PositionRibbon selectedPos={userPicks.home} teamColor={homeTeam.color} />

        <div className="relative group">
          {userPicks.home ? (
            <div className="bg-slate-900 border border-slate-800 rounded-xl p-4 flex items-center justify-between transition-all hover:bg-slate-800/80 shadow-inner">
              <div className="flex flex-col">
                <span className="text-[10px] font-bold text-slate-500 uppercase mb-1">Jersey #</span>
                <span className="text-3xl font-black oswald text-white leading-none">#{userPicks.homeNumber}</span>
              </div>
              <div className="flex flex-col items-end">
                <span className="text-[10px] font-bold text-slate-500 uppercase mb-1">Pick Score</span>
