          )}

          <div className="absolute inset-0 pointer-events-none flex items-center justify-center">
            {floatingPoints.filter(fp => fp.team === 'home').map(fp => {
              const { color, size, glow, weight, animationName, duration } = getPointStyles(fp.points);
              const swayOffset = fp.variant === 1 ? -20 : fp.variant === 2 ? 20 : 0;
              return (
                <div 
                  key={fp.id}
                  style={{ 
                    left: `calc(50% + ${fp.xOffset}px)`,
                    animationName: animationName,
                    animationDuration: duration,
                    animationFillMode: 'forwards',
                    '--sway-x': `${swayOffset}px`
                  } as React.CSSProperties}
                  className={`absolute bottom-full mb-4 oswald whitespace-nowrap z-[60] ${color} ${size} ${glow} ${weight} animate-floating-base`}
                >
                  {fp.points > 0 ? '+' : ''}{fp.points}
                </div>
              );
            })}
          </div>
        </div>
      </div>

      <style>{`
        .no-scrollbar::-webkit-scrollbar { display: none; }
        .no-scrollbar { -ms-overflow-style: none; scrollbar-width: none; }

        .animate-floating-base {
            animation-timing-function: cubic-bezier(0.22, 1, 0.36, 1);
        }

        @keyframes float-up {
          0% { transform: translateY(0) scale(0.8); opacity: 0; }
          15% { transform: translateY(-10px) scale(1.1); opacity: 1; }
          100% { transform: translateY(-100px) scale(1) translateX(var(--sway-x)); opacity: 0; }
