import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { GameState, Position, GameEvent, FloatingPoint, GoalExplosion, LeaderboardPlayer } from './types';
import { INITIAL_TEAMS } from './constants';
import ScoreBoard from './components/ScoreBoard';
import GameLog from './components/GameLog';
import PickStatus from './components/PickStatus';
import PerformanceSummary from './components/PerformanceSummary';
import Leaderboard from './components/Leaderboard';
import { fetchSimulatedEvents } from './services/geminiService';
import { requestNotificationPermission, sendGameNotification, getNotificationStatus } from './services/notificationService';

const App: React.FC = () => {
  const [game, setGame] = useState<GameState>({
    period: 1,
    timeRemaining: '20:00',
    isPaused: false,
    waitingForPicks: true,
    homeTeam: INITIAL_TEAMS.home,
    awayTeam: INITIAL_TEAMS.away,
    userPicks: { home: null, away: null, homeNumber: null, awayNumber: null },
    totalPoints: 0,
    rank: 124,
    totalPlayers: 1542,
    events: [],
  });

  const [competitors, setCompetitors] = useState<LeaderboardPlayer[]>(() => {
    return Array.from({ length: 49 }, (_, i) => ({
      id: `comp-${i}`,
      name: `User_${Math.floor(Math.random() * 9000) + 1000}`,
      points: Math.max(0, 15000 - (i * 300) + (Math.random() * 500)),
    }));
  });

  const [floatingPoints, setFloatingPoints] = useState<FloatingPoint[]>([]);
  const [explosions, setExplosions] = useState<GoalExplosion[]>([]);
  const [loadingEvents, setLoadingEvents] = useState(false);
  const [notifPermission, setNotifPermission] = useState<NotificationPermission>(getNotificationStatus());
  const tickerRef = useRef<any>(null);

  const leaderboardData = useMemo(() => {
    const userPlayer: LeaderboardPlayer = {
      id: 'user-main',
      name: 'PuckMaster99',
      points: game.totalPoints,
      isUser: true
    };
    return [...competitors, userPlayer];
  }, [competitors, game.totalPoints]);

  useEffect(() => {
    const sorted = [...leaderboardData].sort((a, b) => b.points - a.points);
    const userIndex = sorted.findIndex(p => p.isUser);
    setGame(prev => ({ ...prev, rank: userIndex + 1 }));
  }, [leaderboardData]);

  const updateCompetitors = useCallback(() => {
    setCompetitors(prev => prev.map(comp => {
      const gain = Math.random() > 0.7 ? Math.floor(Math.random() * 1000) : 0;
      return { ...comp, points: comp.points + gain };
    }));
  }, []);

  const triggerGoalExplosion = (team: 'home' | 'away') => {
    const id = Math.random().toString(36).substr(2, 9);
    const color = team === 'home' ? game.homeTeam.color : game.awayTeam.color;
    setExplosions(prev => [...prev, { id, team, color }]);
    setTimeout(() => {
      setExplosions(prev => prev.filter(e => e.id !== id));
    }, 3000);
  };

  const triggerPointsAnimation = (points: number, team: 'home' | 'away', isUser: boolean) => {
    const id = Math.random().toString(36).substr(2, 9);
    const newFloatingPoint: FloatingPoint = {
      id,
      points,
      team,
      isUser,
      xOffset: (Math.random() - 0.5) * 50,
      variant: Math.floor(Math.random() * 3),
    };
    setFloatingPoints(prev => [...prev, newFloatingPoint]);
    setTimeout(() => {
      setFloatingPoints(prev => prev.filter(fp => fp.id !== id));
    }, 2000);
  };

  const processEvents = useCallback(async () => {
    if (loadingEvents || game.waitingForPicks) return;

    setLoadingEvents(true);
    const result = await fetchSimulatedEvents(
      game.period,
      game.timeRemaining,
      game.homeTeam.name,
      game.awayTeam.name
    );

    let newPoints = 0;
    let currentHomeScore = game.homeTeam.score;
    let currentAwayScore = game.awayTeam.score;
    let goalScored = false;
    let scoringTeamName = "";
    let scoringTeamType: 'home' | 'away' | null = null;

    const processedEvents = result.events.map(event => {
      if (event.type === 'GOAL') {
        goalScored = true;
        scoringTeamType = event.team as 'home' | 'away';
        scoringTeamName = event.team === 'home' ? game.homeTeam.name : game.awayTeam.name;
        if (event.team === 'home') currentHomeScore++;
        else currentAwayScore++;
      }

      if (event.type === 'PENALTY') {
        const teamName = event.team === 'home' ? game.homeTeam.name : game.awayTeam.name;
        sendGameNotification(
          `Whistle! Penalty for ${teamName}`,
          `${event.description}`
        );
      }

      const userPickForTeam = event.team === 'home' ? game.userPicks.home : game.userPicks.away;
      const isUserPick = event.position === userPickForTeam;
      const earned = isUserPick ? (event.points || 0) : 0;

      if (earned !== 0) {
        newPoints += earned;
        triggerPointsAnimation(earned, event.team!, true);
      } else if (event.points !== 0) {
        triggerPointsAnimation(event.points!, event.team!, false);
      }

      return { 
        ...event, 
        userEarned: earned, 
        homeScoreAtEvent: currentHomeScore, 
        awayScoreAtEvent: currentAwayScore,
        period: game.period 
      } as GameEvent;
    });

    if (goalScored && scoringTeamType) {
      triggerGoalExplosion(scoringTeamType);
      sendGameNotification(
        `GOAL! ${scoringTeamName} Scores!`,
        `Current Score: ${game.awayTeam.name} ${currentAwayScore} - ${game.homeTeam.name} ${currentHomeScore}`
      );
    }

    if (result.nextFaceoffTrigger) {
      sendGameNotification(
        "Next Face-Off!",
        "Picks reset soon. Get back in the game to choose your positions!"
      );
    }

    setGame(prev => ({
      ...prev,
      totalPoints: prev.totalPoints + newPoints,
      events: [...processedEvents, ...prev.events].slice(0, 100),
      homeTeam: { ...prev.homeTeam, score: currentHomeScore },
      awayTeam: { ...prev.awayTeam, score: currentAwayScore },
      waitingForPicks: result.nextFaceoffTrigger,
    }));

    updateCompetitors();
    setLoadingEvents(false);
  }, [game.period, game.timeRemaining, game.homeTeam.name, game.awayTeam.name, game.userPicks, game.waitingForPicks, loadingEvents, game.homeTeam.score, game.awayTeam.score, updateCompetitors]);

  useEffect(() => {
    if (game.waitingForPicks || game.isPaused) return;

    tickerRef.current = setInterval(() => {
      setGame(prev => {
        const [mins, secs] = prev.timeRemaining.split(':').map(Number);
        let totalSecs = mins * 60 + secs - 12;

        if (totalSecs <= 0) {
          if (prev.period < 3) {
            return { ...prev, period: prev.period + 1, timeRemaining: '20:00', waitingForPicks: true };
          } else {
            return { ...prev, isPaused: true, timeRemaining: '00:00' };
          }
        }

        const newMins = Math.floor(totalSecs / 60);
        const newSecs = totalSecs % 60;
        return {
          ...prev,
          timeRemaining: `${newMins.toString().padStart(2, '0')}:${newSecs.toString().padStart(2, '0')}`
        };
      });
    }, 1000);

    return () => {
      if (tickerRef.current) clearInterval(tickerRef.current);
    };
  }, [game.waitingForPicks, game.isPaused]);

  useEffect(() => {
    if (game.waitingForPicks || game.isPaused) return;

    const eventInterval = setInterval(() => {
      processEvents();
    }, 8000);

    return () => clearInterval(eventInterval);
  }, [game.waitingForPicks, game.isPaused, processEvents]);

  const handlePicks = async (picks: { home: Position; away: Position; homeNumber: number; awayNumber: number }) => {
    if (notifPermission === 'default') {
      const granted = await requestNotificationPermission();
      setNotifPermission(granted ? 'granted' : 'denied');
    }

    setGame(prev => ({
      ...prev,
      userPicks: picks,
      waitingForPicks: false
    }));
  };

  const openPicks = () => {
    setGame(prev => ({ ...prev, waitingForPicks: true }));
  };

  return (
    <div className="min-h-screen bg-slate-950 text-slate-100 flex flex-col pb-24 relative overflow-hidden">
      {explosions.map(exp => (
        <div key={exp.id} className="fixed inset-0 z-[100] pointer-events-none flex items-center justify-center">
          <div 
            className="absolute inset-0 animate-screen-flash"
            style={{ backgroundColor: `${exp.color}22` }}
          />
          <div className="relative">
            <div className="text-8xl font-black oswald uppercase text-white animate-goal-text drop-shadow-[0_0_20px_rgba(255,255,255,0.8)]">
              GOAL!
            </div>
            <div 
              className="absolute inset-0 animate-goal-explosion"
              style={{ background: `radial-gradient(circle, ${exp.color} 0%, transparent 70%)` }}
            />
          </div>
        </div>
      ))}

      <ScoreBoard 
        home={game.homeTeam} 
        away={game.awayTeam} 
        period={game.period} 
        time={game.timeRemaining} 
      />

      <main className="flex-1 max-w-6xl mx-auto w-full p-4">
        <div className="flex flex-col lg:flex-row gap-8">

          <div className="flex-1 space-y-10 order-2 lg:order-1">
            <div className={`bg-slate-900/80 border border-slate-800 rounded-3xl p-6 shadow-2xl backdrop-blur-sm transition-all duration-500 ${game.waitingForPicks ? 'ring-2 ring-amber-500/30' : ''}`}>
              <div className="flex justify-between items-center mb-6">
                 <div className="text-[10px] font-black text-slate-500 uppercase tracking-widest flex items-center gap-2">
                    {game.waitingForPicks ? 'Selection Phase' : 'Lineup Performance'}
                    <span className={`w-2 h-2 rounded-full ${game.waitingForPicks ? 'bg-amber-500 animate-pulse' : 'bg-green-500'}`}></span>
                 </div>
                 {notifPermission === 'granted' && (
                   <span className="text-[9px] font-bold text-slate-600 uppercase flex items-center gap-1">
                     <i className="fa-solid fa-bell"></i> Alerts Active
                   </span>
                 )}
              </div>

              <PickStatus 
                homeTeam={game.homeTeam} 
                awayTeam={game.awayTeam} 
                userPicks={game.userPicks} 
                floatingPoints={floatingPoints}
                events={game.events}
                isSelecting={game.waitingForPicks}
                onConfirmPicks={handlePicks}
              />
            </div>

            <div className="grid grid-cols-2 sm:grid-cols-4 gap-4">
              <div className="bg-slate-900 border border-slate-800 p-4 rounded-xl shadow-lg relative overflow-hidden group">
                <div className="absolute top-0 right-0 p-2 opacity-10 group-hover:opacity-20 transition-opacity">
                  <i className="fa-solid fa-star text-4xl"></i>
                </div>
                <div className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-1">Score</div>
                <div className="text-3xl font-black text-amber-500 oswald">{game.totalPoints.toLocaleString()}</div>
              </div>
              <div className="bg-slate-900 border border-slate-800 p-4 rounded-xl shadow-lg relative overflow-hidden group">
                <div className="absolute top-0 right-0 p-2 opacity-10 group-hover:opacity-20 transition-opacity">
                  <i className="fa-solid fa-trophy text-4xl"></i>
                </div>
                <div className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-1">Rank</div>
                <div className="text-3xl font-black text-blue-400 oswald">#{game.rank}</div>
              </div>
              <div className="bg-slate-900 border border-slate-800 p-4 rounded-xl shadow-lg hidden sm:block">
                <div className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-1">Pick Status</div>
                <div className="flex flex-col gap-0.5 text-xs font-black oswald uppercase">
                  <div className="flex justify-between items-center">
                    <span className="text-amber-500">{game.userPicks.away || '---'}</span>
                    <span className="text-[8px] text-slate-600">AWY</span>
                  </div>
                  <div className="flex justify-between items-center">
                    <span className="text-blue-500">{game.userPicks.home || '---'}</span>
                    <span className="text-[8px] text-slate-600">HME</span>
                  </div>
                </div>
              </div>
              <div className="bg-slate-900 border border-slate-800 p-4 rounded-xl shadow-lg hidden sm:block relative overflow-hidden">
                <div className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-1">Live Players</div>
                <div className="text-3xl font-black text-slate-300 oswald">{game.totalPlayers.toLocaleString()}</div>
              </div>
            </div>

            <div className="bg-slate-900/50 border border-slate-800 rounded-2xl overflow-hidden flex flex-col">
              <div className="bg-slate-800 px-6 py-4 border-b border-slate-700 flex justify-between items-center">
                <h2 className="text-sm font-black uppercase tracking-widest text-slate-200 flex items-center gap-2">
                  <i className="fa-solid fa-satellite-dish text-red-500 animate-pulse"></i>
                  Live Rink Action
                </h2>
                {loadingEvents && (
                  <div className="text-[10px] font-bold text-slate-500 uppercase animate-pulse flex items-center gap-1">
                    <i className="fa-solid fa-spinner fa-spin"></i>
                    Simulating...
                  </div>
                )}
              </div>

              <div className="overflow-y-auto p-4 space-y-4 max-h-[350px] scroll-smooth">
                {game.events.length === 0 ? (
                  <div className="h-40 flex flex-col items-center justify-center text-slate-600">
                    <i className="fa-solid fa-hockey-puck text-4xl mb-4 opacity-20"></i>
                    <p className="font-bold uppercase tracking-wider text-[10px]">Puck is currently in the air...</p>
                  </div>
                ) : (
                  game.events.slice(0, 10).map((event) => {
                    const isUserPositive = (event.userEarned || 0) > 0;
                    const isUserNegative = (event.userEarned || 0) < 0;
                    const isGoal = event.type === 'GOAL';

                    return (
                      <div 
                        key={`live-${event.id}`} 
                        className={`flex items-start gap-4 p-4 rounded-xl border transition-all animate-in slide-in-from-right duration-500 relative overflow-hidden ${
                          isGoal ? 'animate-goal-card-glow' : ''
                        } ${
                          isUserPositive ? 'bg-green-900/10 border-green-500/40' : 
                          isUserNegative ? 'bg-red-900/10 border-red-500/40' : 
                          'bg-slate-800/40 border-slate-700'
                        }`}
                      >
                        <div className={`w-10 h-10 rounded-full flex-shrink-0 flex items-center justify-center font-black text-xs border-2 shadow-lg z-10 ${
                          event.team === 'home' ? 'bg-blue-600 border-blue-400 text-white' : 'bg-amber-500 border-amber-300 text-slate-950'
                        }`}>
                          {event.position}
                        </div>
                        <div className="flex-1 z-10">
                          <div className="flex items-center justify-between mb-1">
                            <span className="text-[9px] font-bold text-slate-500 uppercase">
                              {event.gameTime} • {event.type.replace('_', ' ')}
                            </span>
                          </div>
                          <p className="text-sm text-slate-100 font-medium">
                            {event.description}
                          </p>
                        </div>
                        {(event.userEarned !== 0) && (
                          <div className={`text-right font-black oswald text-xl min-w-[60px] z-10 ${isUserPositive ? 'text-green-400' : 'text-red-400'}`}>
                            {isUserPositive ? '+' : ''}{event.userEarned}
                          </div>
                        )}
                      </div>
                    );
                  })
                )}
              </div>
            </div>

            <PerformanceSummary events={game.events} />

            <GameLog 
              events={game.events} 
              homeTeam={game.homeTeam} 
              awayTeam={game.awayTeam} 
            />
          </div>

          <div className="lg:w-80 order-1 lg:order-2">
            <div className="lg:sticky lg:top-24 space-y-6">
              <Leaderboard 
                players={leaderboardData} 
                userPoints={game.totalPoints} 
                userRank={game.rank} 
              />

              <div className="bg-slate-900 border border-slate-800 p-5 rounded-2xl">
                <h3 className="text-xs font-black text-slate-200 uppercase tracking-widest mb-4 flex items-center gap-2">
                  <i className="fa-solid fa-scale-balanced text-amber-500"></i>
                  Scoring Key
                </h3>
                <div className="space-y-2">
                  <div className="flex justify-between text-[10px] font-bold">
                    <span className="text-slate-500">GOAL</span>
                    <span className="text-green-400">+5000</span>
                  </div>
                  <div className="flex justify-between text-[10px] font-bold">
                    <span className="text-slate-500">ASSIST</span>
                    <span className="text-blue-400">+1000</span>
                  </div>
                  <div className="flex justify-between text-[10px] font-bold">
                    <span className="text-slate-500">SAVE</span>
                    <span className="text-green-400">+250</span>
                  </div>
                  <div className="flex justify-between text-[10px] font-bold">
                    <span className="text-slate-500">HIT/SHOT</span>
                    <span className="text-slate-300">+200</span>
                  </div>
                  <div className="flex justify-between text-[10px] font-bold">
                    <span className="text-slate-500">GIVEAWAY</span>
                    <span className="text-red-400">-200</span>
                  </div>
                </div>
              </div>
            </div>
          </div>

        </div>
      </main>

      <footer className="fixed bottom-0 left-0 right-0 bg-slate-900 border-t border-slate-800 p-4 sm:p-6 shadow-2xl z-40 backdrop-blur-md">
        <div className="max-w-6xl mx-auto flex items-center justify-between gap-4">
          <div className="flex items-center gap-6">
            <div>
              <div className="text-[10px] font-bold text-slate-500 uppercase mb-1">Total Score</div>
              <div className="text-3xl font-black oswald text-amber-500 leading-none">{game.totalPoints.toLocaleString()}</div>
            </div>
            <div className="h-8 w-[1px] bg-slate-800"></div>
            <div>
              <div className="text-[10px] font-bold text-slate-500 uppercase mb-1">Rank</div>
              <div className="text-2xl font-black oswald text-white leading-none">#{game.rank}</div>
            </div>
          </div>

          <button 
            onClick={openPicks}
            disabled={game.waitingForPicks}
            className={`px-8 py-3 rounded-xl font-black oswald text-lg uppercase tracking-widest transition-all active:scale-95 ${
              game.waitingForPicks 
                ? 'bg-slate-800 text-slate-600 border border-slate-700 cursor-not-allowed'
                : 'bg-gradient-to-r from-blue-600 to-blue-700 hover:from-blue-500 hover:to-blue-600 text-white shadow-lg shadow-blue-900/30'
            }`}
          >
            {game.waitingForPicks ? 'Locking Lineup...' : 'Change Picks'}
          </button>
        </div>
      </footer>

      <style>{`
        @keyframes screen-flash {
          0% { opacity: 0; }
          10% { opacity: 1; }
          100% { opacity: 0; }
        }
        @keyframes goal-text {
          0% { transform: scale(0.5); opacity: 0; filter: blur(10px); }
          20% { transform: scale(1.2); opacity: 1; filter: blur(0); }
          80% { transform: scale(1.1); opacity: 1; }
          100% { transform: scale(1.5); opacity: 0; filter: blur(20px); }
        }
        @keyframes goal-explosion {
          0% { transform: scale(0); opacity: 0.8; }
          100% { transform: scale(4); opacity: 0; }
        }
        @keyframes goal-card-glow {
          0% { border-color: rgba(239, 68, 68, 0.4); box-shadow: 0 0 0px rgba(239, 68, 68, 0); }
          50% { border-color: rgba(239, 68, 68, 1); box-shadow: 0 0 20px rgba(239, 68, 68, 0.4); }
          100% { border-color: rgba(239, 68, 68, 0.4); box-shadow: 0 0 0px rgba(239, 68, 68, 0); }
        }
        .animate-screen-flash { animation: screen-flash 1.5s ease-out forwards; }
        .animate-goal-text { animation: goal-text 2s cubic-bezier(0.17, 0.67, 0.83, 0.67) forwards; }
        .animate-goal-explosion { animation: goal-explosion 1s ease-out forwards; }
        .animate-goal-card-glow { animation: goal-card-glow 2s ease-in-out infinite; }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { Position, TeamInfo, FloatingPoint, GameEvent } from '../types';
import { POSITIONS } from '../constants';

interface PickStatusProps {
  homeTeam: TeamInfo;
  awayTeam: TeamInfo;
  userPicks: { home: Position | null; away: Position | null; homeNumber: number | null; awayNumber: number | null };
  floatingPoints: FloatingPoint[];
  events: GameEvent[];
  isSelecting: boolean;
  onConfirmPicks: (picks: { home: Position; away: Position; homeNumber: number; awayNumber: number }) => void;
}

const PickStatus: React.FC<PickStatusProps> = ({ 
  homeTeam, 
  awayTeam, 
  userPicks, 
  floatingPoints, 
  events, 
  isSelecting,
  onConfirmPicks 
}) => {
  const [draftAway, setDraftAway] = useState<Position | null>(userPicks.away);
  const [draftHome, setDraftHome] = useState<Position | null>(userPicks.home);

  const getPointsForPick = (team: 'home' | 'away', pos: Position | null) => {
    if (!pos) return 0;
    return events
      .filter(e => e.team === team && e.position === pos)
      .reduce((sum, e) => sum + (e.userEarned || 0), 0);
  };

  // Generate stable random jersey numbers for this session's drafts
  const numbers = useMemo(() => {
    const res: Record<string, number> = {};
    POSITIONS.forEach(p => {
      res[`away-${p.value}`] = Math.floor(Math.random() * 98) + 1;
      res[`home-${p.value}`] = Math.floor(Math.random() * 98) + 1;
    });
    return res;
  }, []);

  const handleConfirm = () => {
    if (draftAway && draftHome) {
      onConfirmPicks({
        away: draftAway,
        home: draftHome,
        awayNumber: numbers[`away-${draftAway}`],
        homeNumber: numbers[`home-${draftHome}`]
      });
    }
  };

  const getPosCoords = (pos: Position, isHome: boolean) => {
    const baseCoords: Record<Position, { top: string; left: string }> = {
      'G': { top: '50%', left: isHome ? '92%' : '8%' },
      'LD': { top: '30%', left: isHome ? '75%' : '25%' },
      'RD': { top: '70%', left: isHome ? '75%' : '25%' },
      'LW': { top: '25%', left: isHome ? '58%' : '42%' },
      'RW': { top: '75%', left: isHome ? '58%' : '42%' },
      'C': { top: '50%', left: isHome ? '62%' : '38%' },
    };
    return baseCoords[pos];
  };

  if (isSelecting) {
    return (
      <div className="flex flex-col gap-6 animate-in zoom-in-95 duration-500">
        <div className="relative w-full aspect-[2.2/1] bg-slate-950 rounded-3xl border-2 border-slate-800 overflow-hidden shadow-inner p-2">
          {/* Rink Markings */}
          <div className="absolute inset-y-0 left-1/2 w-0.5 bg-red-600/30 -translate-x-1/2"></div>
          <div className="absolute top-1/2 left-1/2 w-24 h-24 border border-red-600/20 rounded-full -translate-x-1/2 -translate-y-1/2"></div>
          <div className="absolute inset-y-0 left-[28%] w-1 bg-blue-600/20"></div>
          <div className="absolute inset-y-0 right-[28%] w-1 bg-blue-600/20"></div>

          {/* Labels */}
          <div className="absolute top-3 left-6 oswald font-black text-slate-800 text-lg uppercase tracking-widest">{awayTeam.name}</div>
          <div className="absolute top-3 right-6 oswald font-black text-slate-800 text-lg uppercase tracking-widest text-right">{homeTeam.name}</div>

          {/* Selectors */}
          {POSITIONS.map(p => {
            const coordsA = getPosCoords(p.value, false);
            const isSelA = draftAway === p.value;
            return (
              <button
                key={`sel-away-${p.value}`}
                onClick={() => setDraftAway(p.value)}
                style={{ top: coordsA.top, left: coordsA.left }}
                className={`absolute -translate-x-1/2 -translate-y-1/2 w-10 h-10 sm:w-14 sm:h-14 rounded-full flex flex-col items-center justify-center transition-all border-2 ${
                  isSelA ? 'bg-amber-500 text-slate-950 border-white scale-110 shadow-[0_0_15px_rgba(245,158,11,0.5)] z-20' : 'bg-slate-900/80 text-slate-500 border-slate-700 hover:border-amber-500/50 z-10'
                }`}
              >
                <span className="text-xs sm:text-sm font-black oswald">{p.value}</span>
                {isSelA && <span className="text-[7px] font-bold">#{numbers[`away-${p.value}`]}</span>}
              </button>
            );
          })}

          {POSITIONS.map(p => {
            const coordsH = getPosCoords(p.value, true);
            const isSelH = draftHome === p.value;
            return (
              <button
                key={`sel-home-${p.value}`}
                onClick={() => setDraftHome(p.value)}
                style={{ top: coordsH.top, left: coordsH.left }}
                className={`absolute -translate-x-1/2 -translate-y-1/2 w-10 h-10 sm:w-14 sm:h-14 rounded-full flex flex-col items-center justify-center transition-all border-2 ${
                  isSelH ? 'bg-blue-600 text-white border-white scale-110 shadow-[0_0_15px_rgba(37,99,235,0.5)] z-20' : 'bg-slate-900/80 text-slate-500 border-slate-700 hover:border-blue-500/50 z-10'
                }`}
              >
                <span className="text-xs sm:text-sm font-black oswald">{p.value}</span>
                {isSelH && <span className="text-[7px] font-bold">#{numbers[`home-${p.value}`]}</span>}
              </button>
            );
          })}
        </div>

        <div className="flex items-center justify-between">
          <div className="flex gap-4">
            <div className="flex items-center gap-2">
              <span className="text-[9px] font-bold text-slate-500 uppercase">Away Pick:</span>
              <span className="text-xs font-black oswald text-amber-500">{draftAway || '---'}</span>
            </div>
            <div className="flex items-center gap-2">
              <span className="text-[9px] font-bold text-slate-500 uppercase">Home Pick:</span>
              <span className="text-xs font-black oswald text-blue-500">{draftHome || '---'}</span>
            </div>
          </div>
          <button
            disabled={!draftAway || !draftHome}
            onClick={handleConfirm}
            className={`px-8 py-2 rounded-xl font-black oswald text-lg uppercase tracking-widest transition-all ${
              draftAway && draftHome ? 'bg-green-600 text-white shadow-xl shadow-green-900/20 active:scale-95' : 'bg-slate-800 text-slate-600'
            }`}
          >
            Confirm Lines
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="grid grid-cols-1 md:grid-cols-2 gap-8 animate-in fade-in duration-500">
      {/* Away Performance Box */}
      <div className="flex flex-col gap-4">
        <div className="flex items-center gap-3">
          <div className="w-8 h-8 rounded-full bg-amber-500/20 flex items-center justify-center text-xl">{awayTeam.logo}</div>
          <span className="text-sm font-black oswald uppercase text-white tracking-widest">{awayTeam.name}</span>
        </div>

        <div className="bg-slate-950/50 border border-slate-800/50 rounded-2xl overflow-hidden p-3 shadow-inner">
          {/* Header Row */}
          <div className="grid grid-cols-6 border-b border-slate-800 pb-2 mb-2">
            {POSITIONS.map(p => (
              <div key={`away-h-${p.value}`} className="text-center text-[9px] font-black text-slate-600 uppercase tracking-tighter">
                {p.value}
              </div>
            ))}
          </div>

          {/* Data Row */}
          <div className="grid grid-cols-6 items-center">
            {POSITIONS.map(p => {
              const isPicked = userPicks.away === p.value;
              const pickPoints = isPicked ? getPointsForPick('away', p.value) : 0;
              return (
                <div key={`away-d-${p.value}`} className={`flex flex-col items-center gap-1 py-1 transition-all ${isPicked ? 'bg-amber-500/5 rounded-lg border border-amber-500/20' : ''}`}>
                  <span className={`text-[11px] font-black oswald ${isPicked ? 'text-white' : 'text-slate-700'}`}>
                    {isPicked ? `#${userPicks.awayNumber}` : '--'}
                  </span>
                  <span className={`text-[9px] font-bold oswald ${isPicked ? 'text-amber-500' : 'text-slate-800'}`}>
                    {isPicked ? `${pickPoints >= 0 ? '+' : ''}${pickPoints}` : '0'}
                  </span>
                </div>
              );
            })}
          </div>
        </div>
      </div>

      {/* Home Performance Box */}
      <div className="flex flex-col gap-4">
        <div className="flex items-center gap-3">
          <div className="w-8 h-8 rounded-full bg-blue-600/20 flex items-center justify-center text-xl">{homeTeam.logo}</div>
          <span className="text-sm font-black oswald uppercase text-white tracking-widest">{homeTeam.name}</span>
        </div>

        <div className="bg-slate-950/50 border border-slate-800/50 rounded-2xl overflow-hidden p-3 shadow-inner">
          {/* Header Row */}
          <div className="grid grid-cols-6 border-b border-slate-800 pb-2 mb-2">
            {POSITIONS.map(p => (
              <div key={`home-h-${p.value}`} className="text-center text-[9px] font-black text-slate-600 uppercase tracking-tighter">
                {p.value}
              </div>
            ))}
          </div>

          {/* Data Row */}
          <div className="grid grid-cols-6 items-center">
            {POSITIONS.map(p => {
              const isPicked = userPicks.home === p.value;
              const pickPoints = isPicked ? getPointsForPick('home', p.value) : 0;
              return (
                <div key={`home-d-${p.value}`} className={`flex flex-col items-center gap-1 py-1 transition-all ${isPicked ? 'bg-blue-600/5 rounded-lg border border-blue-500/20' : ''}`}>
                  <span className={`text-[11px] font-black oswald ${isPicked ? 'text-white' : 'text-slate-700'}`}>
                    {isPicked ? `#${userPicks.homeNumber}` : '--'}
                  </span>
                  <span className={`text-[9px] font-bold oswald ${isPicked ? 'text-blue-400' : 'text-slate-800'}`}>
                    {isPicked ? `${pickPoints >= 0 ? '+' : ''}${pickPoints}` : '0'}
                  </span>
                </div>
              );
            })}
          </div>
        </div>
      </div>

      {/* Floating points overlay for the component */}
      <div className="absolute inset-0 pointer-events-none overflow-hidden rounded-3xl">
        {floatingPoints.map(fp => (
          <div 
            key={fp.id}
            style={{ 
              left: `${50 + fp.xOffset}%`,
              top: '20%',
              animation: `float-up 2s ease-out forwards`
            }}
            className={`absolute font-black oswald text-2xl z-50 ${fp.points >= 5000 ? 'text-yellow-400 scale-150' : fp.points < 0 ? 'text-red-500' : 'text-green-400'}`}
          >
            {fp.points > 0 ? '+' : ''}{fp.points}
          </div>
        ))}
      </div>

      <style>{`
        @keyframes float-up {
          0% { transform: translateY(0); opacity: 0; }
          20% { transform: translateY(-20px); opacity: 1; }
          100% { transform: translateY(-120px); opacity: 0; }
        }
      `}</style>
    </div>
  );
};

export default PickStatus;

import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { GameState, Position, GameEvent, FloatingPoint, GoalExplosion, LeaderboardPlayer } from './types';
import { INITIAL_TEAMS } from './constants';
import ScoreBoard from './components/ScoreBoard';
import GameLog from './components/GameLog';
import PickStatus from './components/PickStatus';
import PerformanceSummary from './components/PerformanceSummary';
import Leaderboard from './components/Leaderboard';
import { fetchSimulatedEvents } from './services/geminiService';
import { requestNotificationPermission, sendGameNotification, getNotificationStatus } from './services/notificationService';

const App: React.FC = () => {
  const [game, setGame] = useState<GameState>({
    period: 1,
    timeRemaining: '20:00',
    isPaused: false,
    waitingForPicks: true,
    homeTeam: INITIAL_TEAMS.home,
    awayTeam: INITIAL_TEAMS.away,
    userPicks: { home: null, away: null, homeNumber: null, awayNumber: null },
    totalPoints: 0,
    rank: 124,
    totalPlayers: 1542,
    events: [],
  });

  const [competitors, setCompetitors] = useState<LeaderboardPlayer[]>(() => {
    return Array.from({ length: 49 }, (_, i) => ({
      id: `comp-${i}`,
      name: `User_${Math.floor(Math.random() * 9000) + 1000}`,
      points: Math.max(0, 15000 - (i * 300) + (Math.random() * 500)),
    }));
  });

  const [floatingPoints, setFloatingPoints] = useState<FloatingPoint[]>([]);
  const [explosions, setExplosions] = useState<GoalExplosion[]>([]);
  const [loadingEvents, setLoadingEvents] = useState(false);
  const [notifPermission, setNotifPermission] = useState<NotificationPermission>(getNotificationStatus());
  const tickerRef = useRef<any>(null);

  const leaderboardData = useMemo(() => {
    const userPlayer: LeaderboardPlayer = {
      id: 'user-main',
      name: 'PuckMaster99',
      points: game.totalPoints,
      isUser: true
    };
    return [...competitors, userPlayer];
  }, [competitors, game.totalPoints]);

  useEffect(() => {
    const sorted = [...leaderboardData].sort((a, b) => b.points - a.points);
    const userIndex = sorted.findIndex(p => p.isUser);
    setGame(prev => ({ ...prev, rank: userIndex + 1 }));
  }, [leaderboardData]);

  const updateCompetitors = useCallback(() => {
    setCompetitors(prev => prev.map(comp => {
      const gain = Math.random() > 0.7 ? Math.floor(Math.random() * 1000) : 0;
      return { ...comp, points: comp.points + gain };
    }));
  }, []);

  const triggerGoalExplosion = (team: 'home' | 'away') => {
    const id = Math.random().toString(36).substr(2, 9);
    const color = team === 'home' ? game.homeTeam.color : game.awayTeam.color;
    setExplosions(prev => [...prev, { id, team, color }]);
    setTimeout(() => {
      setExplosions(prev => prev.filter(e => e.id !== id));
    }, 3000);
  };

  const triggerPointsAnimation = (points: number, team: 'home' | 'away', isUser: boolean) => {
    const id = Math.random().toString(36).substr(2, 9);
    const newFloatingPoint: FloatingPoint = {
      id,
      points,
      team,
      isUser,
      xOffset: (Math.random() - 0.5) * 50,
      variant: Math.floor(Math.random() * 3),
    };
    setFloatingPoints(prev => [...prev, newFloatingPoint]);
    setTimeout(() => {
      setFloatingPoints(prev => prev.filter(fp => fp.id !== id));
    }, 2000);
  };

  const processEvents = useCallback(async () => {
    if (loadingEvents || game.waitingForPicks) return;

    setLoadingEvents(true);
    const result = await fetchSimulatedEvents(
      game.period,
      game.timeRemaining,
      game.homeTeam.name,
      game.awayTeam.name
    );

    let newPoints = 0;
    let currentHomeScore = game.homeTeam.score;
    let currentAwayScore = game.awayTeam.score;
    let goalScored = false;
    let scoringTeamName = "";
    let scoringTeamType: 'home' | 'away' | null = null;

    const processedEvents = result.events.map(event => {
      if (event.type === 'GOAL') {
        goalScored = true;
        scoringTeamType = event.team as 'home' | 'away';
        scoringTeamName = event.team === 'home' ? game.homeTeam.name : game.awayTeam.name;
        if (event.team === 'home') currentHomeScore++;
        else currentAwayScore++;
      }

      if (event.type === 'PENALTY') {
        const teamName = event.team === 'home' ? game.homeTeam.name : game.awayTeam.name;
        sendGameNotification(
          `Whistle! Penalty for ${teamName}`,
          `${event.description}`
        );
      }

      const userPickForTeam = event.team === 'home' ? game.userPicks.home : game.userPicks.away;
      const isUserPick = event.position === userPickForTeam;
      const earned = isUserPick ? (event.points || 0) : 0;

      if (earned !== 0) {
        newPoints += earned;
        triggerPointsAnimation(earned, event.team!, true);
      } else if (event.points !== 0) {
        triggerPointsAnimation(event.points!, event.team!, false);
      }

      return { 
        ...event, 
        userEarned: earned, 
        homeScoreAtEvent: currentHomeScore, 
        awayScoreAtEvent: currentAwayScore,
        period: game.period 
      } as GameEvent;
    });

    if (goalScored && scoringTeamType) {
      triggerGoalExplosion(scoringTeamType);
      sendGameNotification(
        `GOAL! ${scoringTeamName} Scores!`,
        `Current Score: ${game.awayTeam.name} ${currentAwayScore} - ${game.homeTeam.name} ${currentHomeScore}`
      );
    }

    if (result.nextFaceoffTrigger) {
      sendGameNotification(
        "Next Face-Off!",
        "Picks reset soon. Get back in the game to choose your positions!"
      );
    }

    setGame(prev => ({
      ...prev,
      totalPoints: prev.totalPoints + newPoints,
      events: [...processedEvents, ...prev.events].slice(0, 100),
      homeTeam: { ...prev.homeTeam, score: currentHomeScore },
      awayTeam: { ...prev.awayTeam, score: currentAwayScore },
      waitingForPicks: result.nextFaceoffTrigger,
    }));

    updateCompetitors();
    setLoadingEvents(false);
  }, [game.period, game.timeRemaining, game.homeTeam.name, game.awayTeam.name, game.userPicks, game.waitingForPicks, loadingEvents, game.homeTeam.score, game.awayTeam.score, updateCompetitors]);

  useEffect(() => {
    if (game.waitingForPicks || game.isPaused) return;

    tickerRef.current = setInterval(() => {
      setGame(prev => {
        const [mins, secs] = prev.timeRemaining.split(':').map(Number);
        let totalSecs = mins * 60 + secs - 12;

        if (totalSecs <= 0) {
          if (prev.period < 3) {
            return { ...prev, period: prev.period + 1, timeRemaining: '20:00', waitingForPicks: true };
          } else {
            return { ...prev, isPaused: true, timeRemaining: '00:00' };
          }
        }

        const newMins = Math.floor(totalSecs / 60);
        const newSecs = totalSecs % 60;
        return {
          ...prev,
          timeRemaining: `${newMins.toString().padStart(2, '0')}:${newSecs.toString().padStart(2, '0')}`
        };
      });
    }, 1000);

    return () => {
      if (tickerRef.current) clearInterval(tickerRef.current);
    };
  }, [game.waitingForPicks, game.isPaused]);

  useEffect(() => {
    if (game.waitingForPicks || game.isPaused) return;

    const eventInterval = setInterval(() => {
      processEvents();
    }, 8000);

    return () => clearInterval(eventInterval);
  }, [game.waitingForPicks, game.isPaused, processEvents]);

  const handlePicks = async (picks: { home: Position; away: Position; homeNumber: number; awayNumber: number }) => {
    if (notifPermission === 'default') {
      const granted = await requestNotificationPermission();
      setNotifPermission(granted ? 'granted' : 'denied');
    }

    setGame(prev => ({
      ...prev,
      userPicks: picks,
      waitingForPicks: false
    }));
  };

