              draftAway && draftHome ? 'bg-green-600 text-white shadow-xl shadow-green-900/30 active:scale-95' : 'bg-slate-800 text-slate-600 border border-slate-700'
            }`}
          >
            {draftAway && draftHome ? 'DROP THE PUCK' : 'SET LINEUPS'}
          </button>
        </div>
      </div>
