import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { GameState, Position, GameEvent, FloatingPoint, GoalExplosion, LeaderboardPlayer } from './types';
import { INITIAL_TEAMS } from './constants';
import ScoreBoard from './components/ScoreBoard';
import GameLog from './components/GameLog';
import PickStatus from './components/PickStatus';
import PerformanceSummary from './components/PerformanceSummary';
import Leaderboard from './components/Leaderboard';
import { fetchSimulatedEvents } from './services/geminiService';
import { requestNotificationPermission, sendGameNotification, getNotificationStatus } from './services/notificationService';

const App: React.FC = () => {
  const [game, setGame] = useState<GameState>({
    period: 1,
    timeRemaining: '20:00',
    isPaused: false,
    waitingForPicks: true,
    homeTeam: INITIAL_TEAMS.home,
    awayTeam: INITIAL_TEAMS.away,
    userPicks: { home: null, away: null, homeNumber: null, awayNumber: null },
    totalPoints: 0,
    rank: 124,
    totalPlayers: 1542,
    events: [],
  });

  const [competitors, setCompetitors] = useState<LeaderboardPlayer[]>(() => {
    return Array.from({ length: 49 }, (_, i) => ({
      id: `comp-${i}`,
      name: `User_${Math.floor(Math.random() * 9000) + 1000}`,
      points: Math.max(0, 15000 - (i * 300) + (Math.random() * 500)),
    }));
  });

  const [floatingPoints, setFloatingPoints] = useState<FloatingPoint[]>([]);
  const [explosions, setExplosions] = useState<GoalExplosion[]>([]);
  const [loadingEvents, setLoadingEvents] = useState(false);
  const [notifPermission, setNotifPermission] = useState<NotificationPermission>(getNotificationStatus());
  const tickerRef = useRef<any>(null);

  const leaderboardData = useMemo(() => {
    const userPlayer: LeaderboardPlayer = {
      id: 'user-main',
      name: 'PuckMaster99',
      points: game.totalPoints,
      isUser: true
    };
    return [...competitors, userPlayer];
  }, [competitors, game.totalPoints]);

  useEffect(() => {
    const sorted = [...leaderboardData].sort((a, b) => b.points - a.points);
    const userIndex = sorted.findIndex(p => p.isUser);
    setGame(prev => ({ ...prev, rank: userIndex + 1 }));
  }, [leaderboardData]);

  const updateCompetitors = useCallback(() => {
    setCompetitors(prev => prev.map(comp => {
      const gain = Math.random() > 0.7 ? Math.floor(Math.random() * 1000) : 0;
      return { ...comp, points: comp.points + gain };
    }));
  }, []);

  const triggerGoalExplosion = (team: 'home' | 'away') => {
    const id = Math.random().toString(36).substr(2, 9);
    const color = team === 'home' ? game.homeTeam.color : game.awayTeam.color;
    setExplosions(prev => [...prev, { id, team, color }]);
    setTimeout(() => {
      setExplosions(prev => prev.filter(e => e.id !== id));
    }, 3000);
  };

  const triggerPointsAnimation = (points: number, team: 'home' | 'away', isUser: boolean) => {
    const id = Math.random().toString(36).substr(2, 9);
    const newFloatingPoint: FloatingPoint = {
      id,
      points,
      team,
      isUser,
      xOffset: (Math.random() - 0.5) * 40,
      variant: Math.floor(Math.random() * 3),
    };
    setFloatingPoints(prev => [...prev, newFloatingPoint]);
    setTimeout(() => {
      setFloatingPoints(prev => prev.filter(fp => fp.id !== id));
    }, 2000);
  };

  const processEvents = useCallback(async () => {
    if (loadingEvents || game.waitingForPicks) return;

    setLoadingEvents(true);
    const result = await fetchSimulatedEvents(
      game.period,
      game.timeRemaining,
      game.homeTeam.name,
      game.awayTeam.name
    );

    let newPoints = 0;
    let currentHomeScore = game.homeTeam.score;
    let currentAwayScore = game.awayTeam.score;
    let goalScored = false;
    let scoringTeamType: 'home' | 'away' | null = null;

    const processedEvents = result.events.map(event => {
      if (event.type === 'GOAL') {
        goalScored = true;
        scoringTeamType = event.team as 'home' | 'away';
        if (event.team === 'home') currentHomeScore++;
        else currentAwayScore++;
      }

      const userPickForTeam = event.team === 'home' ? game.userPicks.home : game.userPicks.away;
      const isUserPick = event.position === userPickForTeam;
      const earned = isUserPick ? (event.points || 0) : 0;

      if (earned !== 0) {
        newPoints += earned;
        triggerPointsAnimation(earned, event.team!, true);
      } else if (event.points !== 0) {
        triggerPointsAnimation(event.points!, event.team!, false);
      }

      return { 
        ...event, 
        userEarned: earned, 
        homeScoreAtEvent: currentHomeScore, 
        awayScoreAtEvent: currentAwayScore,
        period: game.period 
      } as GameEvent;
    });

    if (goalScored && scoringTeamType) {
      triggerGoalExplosion(scoringTeamType);
    }

    if (result.nextFaceoffTrigger) {
      sendGameNotification("Face-Off!", "Play stopped. Update your picks now!");
    }

    setGame(prev => ({
      ...prev,
      totalPoints: prev.totalPoints + newPoints,
      events: [...processedEvents, ...prev.events].slice(0, 100),
      homeTeam: { ...prev.homeTeam, score: currentHomeScore },
      awayTeam: { ...prev.awayTeam, score: currentAwayScore },
      waitingForPicks: result.nextFaceoffTrigger,
    }));

    updateCompetitors();
    setLoadingEvents(false);
  }, [game.period, game.timeRemaining, game.homeTeam.name, game.awayTeam.name, game.userPicks, game.waitingForPicks, loadingEvents, game.homeTeam.score, game.awayTeam.score, updateCompetitors]);

  useEffect(() => {
    if (game.waitingForPicks || game.isPaused) return;
    tickerRef.current = setInterval(() => {
      setGame(prev => {
        const [mins, secs] = prev.timeRemaining.split(':').map(Number);
        let totalSecs = mins * 60 + secs - 12;
        if (totalSecs <= 0) {
          if (prev.period < 3) return { ...prev, period: prev.period + 1, timeRemaining: '20:00', waitingForPicks: true };
          return { ...prev, isPaused: true, timeRemaining: '00:00' };
        }
        const newMins = Math.floor(totalSecs / 60);
        const newSecs = totalSecs % 60;
        return { ...prev, timeRemaining: `${newMins.toString().padStart(2, '0')}:${newSecs.toString().padStart(2, '0')}` };
      });
    }, 1000);
    return () => { if (tickerRef.current) clearInterval(tickerRef.current); };
  }, [game.waitingForPicks, game.isPaused]);

  useEffect(() => {
    if (game.waitingForPicks || game.isPaused) return;
    const eventInterval = setInterval(() => { processEvents(); }, 8000);
    return () => clearInterval(eventInterval);
  }, [game.waitingForPicks, game.isPaused, processEvents]);

  const handlePicks = async (picks: { home: Position; away: Position; homeNumber: number; awayNumber: number }) => {
    if (notifPermission === 'default') {
      const granted = await requestNotificationPermission();
      setNotifPermission(granted ? 'granted' : 'denied');
    }
    setGame(prev => ({ ...prev, userPicks: picks, waitingForPicks: false }));
  };

  const openPicks = () => {
    // Only allow manual opening if game is "paused" by simulation logic
    if (game.waitingForPicks) return;
    setGame(prev => ({ ...prev, waitingForPicks: true }));
  };

  return (
    <div className="min-h-screen bg-slate-950 text-slate-100 flex flex-col pb-24 relative overflow-hidden">
      {explosions.map(exp => (
        <div key={exp.id} className="fixed inset-0 z-[100] pointer-events-none flex items-center justify-center">
          <div className="absolute inset-0 animate-screen-flash" style={{ backgroundColor: `${exp.color}22` }} />
          <div className="relative">
            <div className="text-8xl font-black oswald uppercase text-white animate-goal-text drop-shadow-[0_0_20px_rgba(255,255,255,0.8)]">GOAL!</div>
            <div className="absolute inset-0 animate-goal-explosion" style={{ background: `radial-gradient(circle, ${exp.color} 0%, transparent 70%)` }} />
          </div>
        </div>
      ))}

      <ScoreBoard home={game.homeTeam} away={game.awayTeam} period={game.period} time={game.timeRemaining} />

      <main className="flex-1 max-w-6xl mx-auto w-full p-4">
        <div className="flex flex-col lg:flex-row gap-8">

          <div className="flex-1 space-y-8 order-2 lg:order-1">
            <div className="grid grid-cols-2 sm:grid-cols-4 gap-4">
              <div className="bg-slate-900 border border-slate-800 p-4 rounded-xl shadow-lg relative overflow-hidden">
                <div className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-1">Score</div>
                <div className="text-3xl font-black text-amber-500 oswald">{game.totalPoints.toLocaleString()}</div>
              </div>
              <div className="bg-slate-900 border border-slate-800 p-4 rounded-xl shadow-lg relative overflow-hidden">
                <div className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-1">Rank</div>
                <div className="text-3xl font-black text-blue-400 oswald">#{game.rank}</div>
              </div>
              <div className="bg-slate-900 border border-slate-800 p-4 rounded-xl shadow-lg hidden sm:block">
                <div className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-1">Status</div>
                <div className="text-xs font-black text-white uppercase">{game.waitingForPicks ? 'Drafting Lines' : 'Puck in Play'}</div>
              </div>
              <div className="bg-slate-900 border border-slate-800 p-4 rounded-xl shadow-lg hidden sm:block">
                <div className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-1">Active Players</div>
                <div className="text-3xl font-black text-slate-300 oswald">{game.totalPlayers.toLocaleString()}</div>
              </div>
            </div>

            <div className="bg-slate-900/50 border border-slate-800 rounded-2xl overflow-hidden flex flex-col">
              <div className="bg-slate-800 px-6 py-4 border-b border-slate-700 flex justify-between items-center">
                <h2 className="text-sm font-black uppercase tracking-widest text-slate-200 flex items-center gap-2">
                  <i className="fa-solid fa-satellite-dish text-red-500 animate-pulse"></i> Live Rink Action
                </h2>
                {loadingEvents && <div className="text-[10px] font-bold text-slate-500 uppercase animate-pulse"><i className="fa-solid fa-spinner fa-spin mr-1"></i>Simulating...</div>}
              </div>
              <div className="overflow-y-auto p-4 space-y-4 max-h-[450px] scroll-smooth">
                {game.events.length === 0 ? (
                  <div className="h-40 flex flex-col items-center justify-center text-slate-600">
                    <i className="fa-solid fa-hockey-puck text-4xl mb-4 opacity-20"></i>
                    <p className="font-bold uppercase tracking-wider text-[10px]">Puck is currently in the air...</p>
                  </div>
                ) : (
                  game.events.slice(0, 15).map((event) => {
                    const isUserPositive = (event.userEarned || 0) > 0;
                    const isUserNegative = (event.userEarned || 0) < 0;
                    return (
                      <div key={`live-${event.id}`} className={`flex items-start gap-4 p-4 rounded-xl border transition-all animate-in slide-in-from-right duration-500 relative overflow-hidden ${isUserPositive ? 'bg-green-900/10 border-green-500/40' : isUserNegative ? 'bg-red-900/10 border-red-500/40' : 'bg-slate-800/40 border-slate-700'}`}>
                        <div className={`w-10 h-10 rounded-full flex-shrink-0 flex items-center justify-center font-black text-xs border-2 shadow-lg z-10 ${event.team === 'home' ? 'bg-blue-600 border-blue-400 text-white' : 'bg-amber-500 border-amber-300 text-slate-950'}`}>{event.position}</div>
                        <div className="flex-1 z-10">
                          <div className="text-[9px] font-bold text-slate-500 uppercase mb-1">{event.gameTime} • {event.type.replace('_', ' ')}</div>
                          <p className="text-sm text-slate-100 font-medium">{event.description}</p>
                        </div>
                        {event.userEarned !== 0 && <div className={`text-right font-black oswald text-xl min-w-[60px] z-10 ${isUserPositive ? 'text-green-400' : 'text-red-400'}`}>{isUserPositive ? '+' : ''}{event.userEarned}</div>}
                      </div>
                    );
                  })
                )}
              </div>
            </div>
            <PerformanceSummary events={game.events} />
            <GameLog events={game.events} homeTeam={game.homeTeam} awayTeam={game.awayTeam} />
          </div>

          <div className="lg:w-80 order-1 lg:order-2">
            <div className="lg:sticky lg:top-24 space-y-6 flex flex-col min-h-screen">
              {/* Tactical Hub Always Top */}
              <div className={`bg-slate-900 border border-slate-800 rounded-3xl p-4 shadow-2xl transition-all duration-500 ${game.waitingForPicks ? 'ring-2 ring-amber-500/30' : ''}`}>
                <div className="flex justify-between items-center mb-4">
                   <div className="text-[9px] font-black text-slate-500 uppercase tracking-widest flex items-center gap-2">
                      Tactical Command
                      <span className={`w-1.5 h-1.5 rounded-full ${game.waitingForPicks ? 'bg-amber-500 animate-pulse' : 'bg-green-500'}`}></span>
                   </div>
                   <div className={`text-[8px] font-black px-2 py-0.5 rounded uppercase ${game.waitingForPicks ? 'bg-amber-500/20 text-amber-500' : 'bg-slate-800 text-slate-500'}`}>
                    {game.waitingForPicks ? 'Open for Draft' : 'Locked During Play'}
                   </div>
                </div>

                <PickStatus 
                  homeTeam={game.homeTeam} 
                  awayTeam={game.awayTeam} 
                  userPicks={game.userPicks} 
                  floatingPoints={floatingPoints}
                  isSelecting={game.waitingForPicks}
                  onConfirmPicks={handlePicks}
                />
              </div>

              {/* Leaderboard Middle Section */}
              <div className="flex-1">
                <Leaderboard players={leaderboardData} userPoints={game.totalPoints} userRank={game.rank} />
              </div>

              {/* Scoring Key Bottom Section */}
              <div className="bg-slate-900 border border-slate-800 p-5 rounded-2xl mb-8">
                <h3 className="text-xs font-black text-slate-200 uppercase tracking-widest mb-4">Scoring Key</h3>
                <div className="space-y-2">
                  <div className="flex justify-between text-[10px] font-bold text-slate-500 uppercase"><span>Goal</span><span className="text-green-400">+5000</span></div>
                  <div className="flex justify-between text-[10px] font-bold text-slate-500 uppercase"><span>Assist</span><span className="text-blue-400">+1000</span></div>
                  <div className="flex justify-between text-[10px] font-bold text-slate-500 uppercase"><span>Save</span><span className="text-green-400">+250</span></div>
                  <div className="flex justify-between text-[10px] font-bold text-slate-500 uppercase"><span>Hit/Shot</span><span className="text-slate-300">+200</span></div>
                  <div className="flex justify-between text-[10px] font-bold text-slate-500 uppercase"><span>Giveaway</span><span className="text-red-400">-200</span></div>
                </div>
              </div>
            </div>
          </div>
        </div>
      </main>

      <footer className="fixed bottom-0 left-0 right-0 bg-slate-900/90 border-t border-slate-800 p-4 sm:p-6 shadow-2xl z-40 backdrop-blur-md">
        <div className="max-w-6xl mx-auto flex items-center justify-between gap-4">
          <div className="flex items-center gap-6">
            <div>
              <div className="text-[10px] font-bold text-slate-500 uppercase mb-1">Current Points</div>
              <div className="text-3xl font-black oswald text-amber-500 leading-none">{game.totalPoints.toLocaleString()}</div>
            </div>
            <div className="h-8 w-[1px] bg-slate-800"></div>
            <div>
              <div className="text-[10px] font-bold text-slate-500 uppercase mb-1">Current Rank</div>
              <div className="text-2xl font-black oswald text-white leading-none">#{game.rank}</div>
            </div>
          </div>

          <div className="flex items-center gap-4">
            {!game.waitingForPicks && (
              <div className="hidden md:flex flex-col items-end">
                <span className="text-[9px] font-black text-slate-500 uppercase tracking-widest">Picks Locked</span>
                <span className="text-[10px] font-bold text-slate-400 italic">Wait for stoppage to edit</span>
              </div>
            )}
            <button 
              onClick={openPicks} 
              disabled={!game.waitingForPicks} 
              className={`px-8 py-3 rounded-xl font-black oswald text-lg uppercase tracking-widest transition-all active:scale-95 ${
                game.waitingForPicks 
                ? 'bg-blue-600 hover:bg-blue-500 text-white shadow-lg shadow-blue-900/30 ring-2 ring-blue-400/50' 
                : 'bg-slate-800 text-slate-600 border border-slate-700 cursor-not-allowed'
              }`}
            >
              {game.waitingForPicks ? 'Drafting Open' : 'Picks Locked'}
            </button>
          </div>
        </div>
      </footer>

      <style>{`
        @keyframes screen-flash { 0% { opacity: 0; } 10% { opacity: 1; } 100% { opacity: 0; } }
        @keyframes goal-text { 0% { transform: scale(0.5); opacity: 0; filter: blur(10px); } 20% { transform: scale(1.2); opacity: 1; filter: blur(0); } 80% { transform: scale(1.1); opacity: 1; } 100% { transform: scale(1.5); opacity: 0; filter: blur(20px); } }
        @keyframes goal-explosion { 0% { transform: scale(0); opacity: 0.8; } 100% { transform: scale(4); opacity: 0; } }
        .animate-screen-flash { animation: screen-flash 1.5s ease-out forwards; }
        .animate-goal-text { animation: goal-text 2s cubic-bezier(0.17, 0.67, 0.83, 0.67) forwards; }
        .animate-goal-explosion { animation: goal-explosion 1s ease-out forwards; }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { Position, TeamInfo } from '../types';
import { POSITIONS } from '../constants';

interface SelectionOverlayProps {
  homeTeam: TeamInfo;
  awayTeam: TeamInfo;
  onConfirm: (picks: { home: Position; away: Position; homeNumber: number; awayNumber: number }) => void;
}

interface ScoutReport {
  name: string;
  goals: number;
  assists: number;
  sog: number;
  number: number;
}

const HOCKEY_NAMES = [
  'Connor McSoren', 'Sidney Crosby', 'Nathan Mack', 'Auston Matte', 'Leon Drai',
  'Cale Mak', 'Adam Fox', 'Victor Hed', 'Igor Shesky', 'Andrei Vasi',
  'Artemi Pan', 'Mitch Marner', 'Jack Hugh', 'Tage Thomp', 'Jason Robert'
];

const SelectionOverlay: React.FC<SelectionOverlayProps> = ({ homeTeam, awayTeam, onConfirm }) => {
  const [awayPick, setAwayPick] = useState<Position | null>(null);
  const [homePick, setHomePick] = useState<Position | null>(null);
  const [hovered, setHovered] = useState<{ side: 'home' | 'away'; pos: Position; x: string; y: string } | null>(null);

  // Generate stable scout reports for this selection session
  const scoutReports = useMemo(() => {
    const generateReports = (side: 'home' | 'away') => {
      return POSITIONS.reduce((acc, pos) => {
        acc[pos.value] = {
          name: `${HOCKEY_NAMES[Math.floor(Math.random() * HOCKEY_NAMES.length)]}${side === 'home' ? ' Jr.' : ''}`,
          goals: Math.floor(Math.random() * 3),
          assists: Math.floor(Math.random() * 4),
          sog: Math.floor(Math.random() * 8) + 1,
          number: Math.floor(Math.random() * 98) + 1,
        };
        return acc;
      }, {} as Record<Position, ScoutReport>);
    };

    return {
      away: generateReports('away'),
      home: generateReports('home')
    };
  }, []);

  const handleConfirm = () => {
    if (awayPick && homePick) {
      onConfirm({ 
        home: homePick, 
        away: awayPick, 
        homeNumber: scoutReports.home[homePick].number, 
        awayNumber: scoutReports.away[awayPick].number 
      });
    }
  };

  const getPosCoords = (pos: Position, isHome: boolean) => {
    const baseCoords: Record<Position, { top: string; left: string }> = {
      'G': { top: '50%', left: isHome ? '92%' : '8%' },
      'LD': { top: '30%', left: isHome ? '75%' : '25%' },
      'RD': { top: '70%', left: isHome ? '75%' : '25%' },
      'LW': { top: '22%', left: isHome ? '55%' : '45%' },
      'RW': { top: '78%', left: isHome ? '55%' : '45%' },
      'C': { top: '50%', left: isHome ? '60%' : '40%' },
    };
    return baseCoords[pos];
  };

  const isAwayHovered = hovered?.side === 'away';
  const isHomeHovered = hovered?.side === 'home';

  return (
    <div className="fixed inset-0 z-[100] bg-slate-950/95 backdrop-blur-xl flex items-center justify-center p-4 overflow-y-auto">
      <div className="bg-slate-900 border border-slate-700 w-full max-w-5xl rounded-3xl shadow-[0_0_50px_rgba(0,0,0,0.5)] overflow-hidden animate-in fade-in zoom-in duration-500 my-auto">

        {/* Header */}
        <div className="bg-slate-800/50 p-6 border-b border-slate-700 flex flex-col items-center text-center relative overflow-hidden">
          <div className={`absolute inset-0 opacity-10 transition-colors duration-500 pointer-events-none ${isAwayHovered ? 'bg-amber-500' : isHomeHovered ? 'bg-blue-500' : 'transparent'}`}></div>

          <div className="flex items-center gap-4 mb-2 relative z-10">
            <span className={`text-4xl transition-all duration-300 ${isAwayHovered ? 'scale-150 drop-shadow-[0_0_15px_rgba(245,158,11,0.8)]' : 'opacity-60'}`}>
              {awayTeam.logo}
            </span>
            <div className="h-px w-12 bg-slate-700"></div>
            <h2 className="text-3xl font-black oswald uppercase tracking-tighter text-white">Lineup Selection</h2>
            <div className="h-px w-12 bg-slate-700"></div>
            <span className={`text-4xl transition-all duration-300 ${isHomeHovered ? 'scale-150 drop-shadow-[0_0_15px_rgba(37,99,235,0.8)]' : 'opacity-60'}`}>
              {homeTeam.logo}
            </span>
          </div>
          <p className="text-slate-400 text-[10px] font-black uppercase tracking-[0.3em] relative z-10">Hover to scout • Click to lock</p>
        </div>

        {/* Rink Container */}
        <div className="relative p-4 sm:p-8 bg-slate-950">
          <div className="relative w-full aspect-[2/1] bg-slate-900 rounded-[120px] border-[6px] border-slate-800 overflow-hidden shadow-2xl">
            {/* Rink Layout Graphics */}
            <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,rgba(51,65,85,0.3)_0%,transparent_100%)]"></div>
            <div className="absolute inset-y-0 left-[6%] w-0.5 bg-red-600/40"></div>
            <div className="absolute inset-y-0 right-[6%] w-0.5 bg-red-600/40"></div>
            <div className="absolute inset-y-0 left-1/2 w-1 bg-red-600/50 -translate-x-1/2"></div>
            <div className="absolute top-1/2 left-1/2 w-4 h-4 bg-red-600/60 rounded-full -translate-x-1/2 -translate-y-1/2"></div>
            <div className="absolute top-1/2 left-1/2 w-40 h-40 border-2 border-red-600/20 rounded-full -translate-x-1/2 -translate-y-1/2"></div>
            <div className="absolute inset-y-0 left-[35%] w-2 bg-blue-600/40"></div>
            <div className="absolute inset-y-0 right-[35%] w-2 bg-blue-600/40"></div>

            {/* Position Buttons */}
            {POSITIONS.map((pos) => {
              const coords = getPosCoords(pos.value, false);
              const isSelected = awayPick === pos.value;
              const isThisHovered = hovered?.side === 'away' && hovered?.pos === pos.value;
              const report = scoutReports.away[pos.value];

              return (
                <button
                  key={`tactical-away-${pos.value}`}
                  onMouseEnter={(e) => setHovered({ side: 'away', pos: pos.value, x: coords.left, y: coords.top })}
                  onMouseLeave={() => setHovered(null)}
                  onClick={() => setAwayPick(pos.value)}
                  style={{ top: coords.top, left: coords.left }}
                  className={`absolute -translate-x-1/2 -translate-y-1/2 w-14 h-14 sm:w-16 sm:h-16 rounded-full flex flex-col items-center justify-center transition-all z-20 ${
                    isSelected
                      ? 'bg-amber-500 text-slate-950 border-4 border-amber-300 scale-110 shadow-[0_0_30px_rgba(245,158,11,0.6)]'
                      : isThisHovered 
                        ? 'bg-amber-500/20 text-amber-500 border-2 border-amber-500 scale-125 shadow-[0_0_20px_rgba(245,158,11,0.4)]'
                        : 'bg-slate-800/90 text-slate-400 border-2 border-slate-700 hover:border-amber-500/50 backdrop-blur-sm'
                  }`}
                >
                  <div className={`absolute -top-1 -right-1 bg-slate-950 text-[9px] font-black px-1.5 py-0.5 rounded-full border transition-all ${
                    isSelected || isThisHovered ? 'text-amber-500 border-amber-500 scale-125' : 'text-amber-500/50 border-amber-500/30'
                  }`}>
                    #{report.number}
                  </div>
                  <span className="text-base sm:text-lg font-black oswald leading-none">{pos.value}</span>
                  <span className="text-[8px] sm:text-[9px] font-bold uppercase opacity-60 leading-none">{pos.label.split(' ')[0]}</span>
                </button>
              );
            })}

            {POSITIONS.map((pos) => {
              const coords = getPosCoords(pos.value, true);
              const isSelected = homePick === pos.value;
              const isThisHovered = hovered?.side === 'home' && hovered?.pos === pos.value;
              const report = scoutReports.home[pos.value];

              return (
                <button
                  key={`tactical-home-${pos.value}`}
                  onMouseEnter={(e) => setHovered({ side: 'home', pos: pos.value, x: coords.left, y: coords.top })}
                  onMouseLeave={() => setHovered(null)}
                  onClick={() => setHomePick(pos.value)}
                  style={{ top: coords.top, left: coords.left }}
                  className={`absolute -translate-x-1/2 -translate-y-1/2 w-14 h-14 sm:w-16 sm:h-16 rounded-full flex flex-col items-center justify-center transition-all z-20 ${
                    isSelected
                      ? 'bg-blue-600 text-white border-4 border-blue-400 scale-110 shadow-[0_0_30px_rgba(37,99,235,0.6)]'
                      : isThisHovered
                        ? 'bg-blue-600/20 text-blue-400 border-2 border-blue-400 scale-125 shadow-[0_0_20px_rgba(37,99,235,0.4)]'
                        : 'bg-slate-800/90 text-slate-400 border-2 border-slate-700 hover:border-blue-400/50 backdrop-blur-sm'
                  }`}
                >
                  <div className={`absolute -top-1 -right-1 bg-slate-950 text-[9px] font-black px-1.5 py-0.5 rounded-full border transition-all ${
                    isSelected || isThisHovered ? 'text-blue-400 border-blue-400 scale-125' : 'text-blue-400/50 border-blue-400/30'
                  }`}>
                    #{report.number}
                  </div>
                  <span className="text-base sm:text-lg font-black oswald leading-none">{pos.value}</span>
                  <span className="text-[8px] sm:text-[9px] font-bold uppercase opacity-60 leading-none">{pos.label.split(' ')[0]}</span>
                </button>
              );
            })}

            {/* Hover Tooltip - Scout Report Card */}
            {hovered && (
              <div 
                style={{ 
                  top: `calc(${hovered.y} + (parseFloat(${hovered.y}) > 50 ? -120px : 60px))`,
                  left: `calc(${hovered.x} + (parseFloat(${hovered.x}) > 50 ? -160px : 40px))`
                }}
                className="absolute w-56 bg-slate-900/95 border-2 border-slate-700 p-4 rounded-2xl shadow-2xl z-[60] animate-in fade-in zoom-in duration-200 backdrop-blur-md pointer-events-none"
              >
                <div className="flex items-start justify-between mb-3">
                  <div className="flex flex-col">
                    <div className="text-[9px] font-black text-slate-500 uppercase tracking-widest">Scout Report</div>
                    <div className={`text-sm font-black oswald uppercase ${hovered.side === 'home' ? 'text-blue-400' : 'text-amber-500'}`}>
                      {scoutReports[hovered.side][hovered.pos].name}
                    </div>
                  </div>
                  <div className={`text-2xl font-black oswald opacity-20 ${hovered.side === 'home' ? 'text-blue-400' : 'text-amber-500'}`}>
                    #{scoutReports[hovered.side][hovered.pos].number}
                  </div>
                </div>

                <div className="grid grid-cols-3 gap-2 border-t border-slate-800 pt-3">
                  <div className="text-center">
                    <div className="text-[10px] font-black text-slate-100 oswald">{scoutReports[hovered.side][hovered.pos].goals}</div>
                    <div className="text-[8px] font-bold text-slate-600 uppercase">Goals</div>
                  </div>
                  <div className="text-center">
                    <div className="text-[10px] font-black text-slate-100 oswald">{scoutReports[hovered.side][hovered.pos].assists}</div>
                    <div className="text-[8px] font-bold text-slate-600 uppercase">Ast</div>
                  </div>
                  <div className="text-center">
                    <div className="text-[10px] font-black text-slate-100 oswald">{scoutReports[hovered.side][hovered.pos].sog}</div>
                    <div className="text-[8px] font-bold text-slate-600 uppercase">SOG</div>
                  </div>
                </div>

                <div className={`mt-3 py-1 rounded bg-slate-950/50 text-center border ${hovered.side === 'home' ? 'border-blue-500/20' : 'border-amber-500/20'}`}>
                  <span className={`text-[9px] font-black uppercase tracking-tighter ${hovered.side === 'home' ? 'text-blue-400' : 'text-amber-500'}`}>
                    {hovered.pos === 'G' ? 'Wall Mode Active' : 'Elite Playmaker'}
                  </span>
                </div>
              </div>
            )}
          </div>
        </div>

        {/* Footer Actions */}
        <div className="p-8 bg-slate-800/30 border-t border-slate-700 flex flex-col sm:flex-row items-center justify-between gap-6">
          <div className="flex gap-8">
            <div className={`flex items-center gap-3 transition-all ${isAwayHovered ? 'scale-110' : ''}`}>
              <div className={`w-4 h-4 rounded-full ${awayPick ? 'bg-amber-500 shadow-[0_0_10px_rgba(245,158,11,0.5)] animate-pulse' : 'bg-slate-700'}`}></div>
              <div className="flex flex-col">
                <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Away Select</span>
                <span className="text-sm font-black oswald text-white uppercase">
                  {awayPick ? `${awayPick} (#${scoutReports.away[awayPick].number})` : 'PICK PLAYER'}
                </span>
              </div>
            </div>
            <div className={`flex items-center gap-3 transition-all ${isHomeHovered ? 'scale-110' : ''}`}>
              <div className={`w-4 h-4 rounded-full ${homePick ? 'bg-blue-500 shadow-[0_0_10px_rgba(37,99,235,0.5)] animate-pulse' : 'bg-slate-700'}`}></div>
              <div className="flex flex-col">
                <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Home Select</span>
                <span className="text-sm font-black oswald text-white uppercase">
                  {homePick ? `${homePick} (#${scoutReports.home[homePick].number})` : 'PICK PLAYER'}
                </span>
              </div>
            </div>
          </div>

          <button
            disabled={!awayPick || !homePick}
            onClick={handleConfirm}
            className={`w-full sm:w-72 py-4 rounded-2xl font-black oswald text-2xl uppercase tracking-[0.1em] transition-all ${
              awayPick && homePick
                ? 'bg-gradient-to-r from-blue-600 to-indigo-600 hover:from-blue-500 hover:to-indigo-500 text-white shadow-[0_15px_35px_rgba(37,99,235,0.4)] active:scale-95'
                : 'bg-slate-800 text-slate-600 cursor-not-allowed border border-slate-700'
            }`}
          >
            {awayPick && homePick ? 'LOCK LINEUPS' : 'SELECT PLAYERS'}
          </button>
        </div>
      </div>
    </div>
  );
};

export default SelectionOverlay;

import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { GameState, Position, GameEvent, FloatingPoint, GoalExplosion, LeaderboardPlayer } from './types';
import { INITIAL_TEAMS } from './constants';
import ScoreBoard from './components/ScoreBoard';
import GameLog from './components/GameLog';
import PickStatus from './components/PickStatus';
import PerformanceSummary from './components/PerformanceSummary';
import Leaderboard from './components/Leaderboard';
import SelectionOverlay from './components/SelectionOverlay';
import { fetchSimulatedEvents } from './services/geminiService';
import { requestNotificationPermission, sendGameNotification, getNotificationStatus } from './services/notificationService';

const App: React.FC = () => {
  const [game, setGame] = useState<GameState>({
    period: 1,
    timeRemaining: '20:00',
    isPaused: false,
    waitingForPicks: true,
    homeTeam: INITIAL_TEAMS.home,
    awayTeam: INITIAL_TEAMS.away,
    userPicks: { home: null, away: null, homeNumber: null, awayNumber: null },
    totalPoints: 0,
    rank: 124,
    totalPlayers: 1542,
    events: [],
  });

  const [competitors, setCompetitors] = useState<LeaderboardPlayer[]>(() => {
    return Array.from({ length: 49 }, (_, i) => ({
      id: `comp-${i}`,
      name: `User_${Math.floor(Math.random() * 9000) + 1000}`,
      points: Math.max(0, 15000 - (i * 300) + (Math.random() * 500)),
    }));
  });

  const [floatingPoints, setFloatingPoints] = useState<FloatingPoint[]>([]);
  const [explosions, setExplosions] = useState<GoalExplosion[]>([]);
  const [loadingEvents, setLoadingEvents] = useState(false);
  const [notifPermission, setNotifPermission] = useState<NotificationPermission>(getNotificationStatus());
  const tickerRef = useRef<any>(null);

  const leaderboardData = useMemo(() => {
    const userPlayer: LeaderboardPlayer = {
      id: 'user-main',
      name: 'PuckMaster99',
      points: game.totalPoints,
      isUser: true
    };
    return [...competitors, userPlayer];
  }, [competitors, game.totalPoints]);

  useEffect(() => {
    const sorted = [...leaderboardData].sort((a, b) => b.points - a.points);
    const userIndex = sorted.findIndex(p => p.isUser);
    setGame(prev => ({ ...prev, rank: userIndex + 1 }));
  }, [leaderboardData]);

  const updateCompetitors = useCallback(() => {
    setCompetitors(prev => prev.map(comp => {
      const gain = Math.random() > 0.7 ? Math.floor(Math.random() * 1000) : 0;
      return { ...comp, points: comp.points + gain };
    }));
  }, []);

  const triggerGoalExplosion = (team: 'home' | 'away') => {
    const id = Math.random().toString(36).substr(2, 9);
    const color = team === 'home' ? game.homeTeam.color : game.awayTeam.color;
    setExplosions(prev => [...prev, { id, team, color }]);
    setTimeout(() => {
      setExplosions(prev => prev.filter(e => e.id !== id));
    }, 3000);
  };

  const triggerPointsAnimation = (points: number, team: 'home' | 'away', isUser: boolean) => {
    const id = Math.random().toString(36).substr(2, 9);
    const newFloatingPoint: FloatingPoint = {
      id,
      points,
      team,
      isUser,
      xOffset: (Math.random() - 0.5) * 40,
      variant: Math.floor(Math.random() * 3),
    };
    setFloatingPoints(prev => [...prev, newFloatingPoint]);
    setTimeout(() => {
      setFloatingPoints(prev => prev.filter(fp => fp.id !== id));
    }, 2000);
  };

  const processEvents = useCallback(async () => {
    if (loadingEvents || game.waitingForPicks) return;

    setLoadingEvents(true);
    const result = await fetchSimulatedEvents(
      game.period,
      game.timeRemaining,
      game.homeTeam.name,
      game.awayTeam.name
    );

    let newPoints = 0;
    let currentHomeScore = game.homeTeam.score;
    let currentAwayScore = game.awayTeam.score;
    let goalScored = false;
    let scoringTeamType: 'home' | 'away' | null = null;

    const processedEvents = result.events.map(event => {
      if (event.type === 'GOAL') {
        goalScored = true;
        scoringTeamType = event.team as 'home' | 'away';
        if (event.team === 'home') currentHomeScore++;
        else currentAwayScore++;
      }

      const userPickForTeam = event.team === 'home' ? game.userPicks.home : game.userPicks.away;
      const isUserPick = event.position === userPickForTeam;
      const earned = isUserPick ? (event.points || 0) : 0;

      if (earned !== 0) {
        newPoints += earned;
        triggerPointsAnimation(earned, event.team!, true);
      } else if (event.points !== 0) {
        triggerPointsAnimation(event.points!, event.team!, false);
      }

      return { 
        ...event, 
        userEarned: earned, 
        homeScoreAtEvent: currentHomeScore, 
        awayScoreAtEvent: currentAwayScore,
        period: game.period 
      } as GameEvent;
    });

    if (goalScored && scoringTeamType) {
      triggerGoalExplosion(scoringTeamType);
    }

    if (result.nextFaceoffTrigger) {
      sendGameNotification("Face-Off!", "Play stopped. Update your picks now!");
    }

    setGame(prev => ({
      ...prev,
      totalPoints: prev.totalPoints + newPoints,
      events: [...processedEvents, ...prev.events].slice(0, 100),
      homeTeam: { ...prev.homeTeam, score: currentHomeScore },
      awayTeam: { ...prev.awayTeam, score: currentAwayScore },
      waitingForPicks: result.nextFaceoffTrigger,
    }));

    updateCompetitors();
    setLoadingEvents(false);
  }, [game.period, game.timeRemaining, game.homeTeam.name, game.awayTeam.name, game.userPicks, game.waitingForPicks, loadingEvents, game.homeTeam.score, game.awayTeam.score, updateCompetitors]);

  useEffect(() => {
    if (game.waitingForPicks || game.isPaused) return;
    tickerRef.current = setInterval(() => {
      setGame(prev => {
        const [mins, secs] = prev.timeRemaining.split(':').map(Number);
        let totalSecs = mins * 60 + secs - 12;
        if (totalSecs <= 0) {
          if (prev.period < 3) return { ...prev, period: prev.period + 1, timeRemaining: '20:00', waitingForPicks: true };
          return { ...prev, isPaused: true, timeRemaining: '00:00' };
        }
        const newMins = Math.floor(totalSecs / 60);
        const newSecs = totalSecs % 60;
        return { ...prev, timeRemaining: `${newMins.toString().padStart(2, '0')}:${newSecs.toString().padStart(2, '0')}` };
      });
    }, 1000);
    return () => { if (tickerRef.current) clearInterval(tickerRef.current); };
  }, [game.waitingForPicks, game.isPaused]);

  useEffect(() => {
    if (game.waitingForPicks || game.isPaused) return;
    const eventInterval = setInterval(() => { processEvents(); }, 8000);
    return () => clearInterval(eventInterval);
  }, [game.waitingForPicks, game.isPaused, processEvents]);

  const handlePicks = async (picks: { home: Position; away: Position; homeNumber: number; awayNumber: number }) => {
    if (notifPermission === 'default') {
      const granted = await requestNotificationPermission();
      setNotifPermission(granted ? 'granted' : 'denied');
    }
    setGame(prev => ({ ...prev, userPicks: picks, waitingForPicks: false }));
  };

  const openPicks = () => {
    if (game.waitingForPicks) return;
    setGame(prev => ({ ...prev, waitingForPicks: true }));
  };

  return (
    <div className="min-h-screen bg-slate-950 text-slate-100 flex flex-col pb-24 relative overflow-hidden">
      {explosions.map(exp => (
        <div key={exp.id} className="fixed inset-0 z-[100] pointer-events-none flex items-center justify-center">
          <div className="absolute inset-0 animate-screen-flash" style={{ backgroundColor: `${exp.color}22` }} />
          <div className="relative">
            <div className="text-8xl font-black oswald uppercase text-white animate-goal-text drop-shadow-[0_0_20px_rgba(255,255,255,0.8)]">GOAL!</div>
            <div className="absolute inset-0 animate-goal-explosion" style={{ background: `radial-gradient(circle, ${exp.color} 0%, transparent 70%)` }} />
          </div>
        </div>
      ))}

      {game.waitingForPicks && (
        <SelectionOverlay 
          homeTeam={game.homeTeam} 
          awayTeam={game.awayTeam} 
          onConfirm={handlePicks} 
        />
      )}

      <ScoreBoard home={game.homeTeam} away={game.awayTeam} period={game.period} time={game.timeRemaining} />

      <main className="flex-1 max-w-6xl mx-auto w-full p-4">
        <div className="flex flex-col lg:flex-row gap-8">

          <div className="flex-1 space-y-8 order-2 lg:order-1">
            <div className="grid grid-cols-2 sm:grid-cols-4 gap-4">
              <div className="bg-slate-900 border border-slate-800 p-4 rounded-xl shadow-lg relative overflow-hidden">
                <div className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-1">Score</div>
                <div className="text-3xl font-black text-amber-500 oswald">{game.totalPoints.toLocaleString()}</div>
              </div>
              <div className="bg-slate-900 border border-slate-800 p-4 rounded-xl shadow-lg relative overflow-hidden">
                <div className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-1">Rank</div>
                <div className="text-3xl font-black text-blue-400 oswald">#{game.rank}</div>
              </div>
              <div className="bg-slate-900 border border-slate-800 p-4 rounded-xl shadow-lg hidden sm:block">
                <div className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-1">Status</div>
                <div className="text-xs font-black text-white uppercase">{game.waitingForPicks ? 'Drafting Lines' : 'Puck in Play'}</div>
              </div>
              <div className="bg-slate-900 border border-slate-800 p-4 rounded-xl shadow-lg hidden sm:block">
                <div className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-1">Active Players</div>
                <div className="text-3xl font-black text-slate-300 oswald">{game.totalPlayers.toLocaleString()}</div>
              </div>
            </div>

            <div className="bg-slate-900/50 border border-slate-800 rounded-2xl overflow-hidden flex flex-col">
              <div className="bg-slate-800 px-6 py-4 border-b border-slate-700 flex justify-between items-center">
                <h2 className="text-sm font-black uppercase tracking-widest text-slate-200 flex items-center gap-2">
                  <i className="fa-solid fa-satellite-dish text-red-500 animate-pulse"></i> Live Rink Action
                </h2>
                {loadingEvents && <div className="text-[10px] font-bold text-slate-500 uppercase animate-pulse"><i className="fa-solid fa-spinner fa-spin mr-1"></i>Simulating...</div>}
              </div>
              <div className="overflow-y-auto p-4 space-y-4 max-h-[450px] scroll-smooth">
                {game.events.length === 0 ? (
                  <div className="h-40 flex flex-col items-center justify-center text-slate-600">
                    <i className="fa-solid fa-hockey-puck text-4xl mb-4 opacity-20"></i>
                    <p className="font-bold uppercase tracking-wider text-[10px]">Puck is currently in the air...</p>
                  </div>
                ) : (
                  game.events.slice(0, 15).map((event) => {
                    const isUserPositive = (event.userEarned || 0) > 0;
                    const isUserNegative = (event.userEarned || 0) < 0;
                    return (
                      <div key={`live-${event.id}`} className={`flex items-start gap-4 p-4 rounded-xl border transition-all animate-in slide-in-from-right duration-500 relative overflow-hidden ${isUserPositive ? 'bg-green-900/10 border-green-500/40' : isUserNegative ? 'bg-red-900/10 border-red-500/40' : 'bg-slate-800/40 border-slate-700'}`}>
                        <div className={`w-10 h-10 rounded-full flex-shrink-0 flex items-center justify-center font-black text-xs border-2 shadow-lg z-10 ${event.team === 'home' ? 'bg-blue-600 border-blue-400 text-white' : 'bg-amber-500 border-amber-300 text-slate-950'}`}>{event.position}</div>
                        <div className="flex-1 z-10">
                          <div className="text-[9px] font-bold text-slate-500 uppercase mb-1">{event.gameTime} • {event.type.replace('_', ' ')}</div>
                          <p className="text-sm text-slate-100 font-medium">{event.description}</p>
                        </div>
                        {event.userEarned !== 0 && <div className={`text-right font-black oswald text-xl min-w-[60px] z-10 ${isUserPositive ? 'text-green-400' : 'text-red-400'}`}>{isUserPositive ? '+' : ''}{event.userEarned}</div>}
                      </div>
                    );
                  })
                )}
              </div>
            </div>
            <PerformanceSummary events={game.events} />
            <GameLog events={game.events} homeTeam={game.homeTeam} awayTeam={game.awayTeam} />
          </div>

          <div className="lg:w-80 order-1 lg:order-2">
            <div className="lg:sticky lg:top-24 space-y-6 flex flex-col min-h-screen">
              {/* Tactical Hub Always Top */}
              <div className={`bg-slate-900 border border-slate-800 rounded-3xl p-4 shadow-2xl transition-all duration-500 ${game.waitingForPicks ? 'ring-2 ring-amber-500/30' : ''}`}>
                <div className="flex justify-between items-center mb-4">
                   <div className="text-[9px] font-black text-slate-500 uppercase tracking-widest flex items-center gap-2">
                      Tactical Command
                      <span className={`w-1.5 h-1.5 rounded-full ${game.waitingForPicks ? 'bg-amber-500 animate-pulse' : 'bg-green-500'}`}></span>
                   </div>
                   <div className={`text-[8px] font-black px-2 py-0.5 rounded uppercase ${game.waitingForPicks ? 'bg-amber-500/20 text-amber-500' : 'bg-slate-800 text-slate-500'}`}>
                    {game.waitingForPicks ? 'Open for Draft' : 'Locked During Play'}
                   </div>
                </div>

                <PickStatus 
                  homeTeam={game.homeTeam} 
                  awayTeam={game.awayTeam} 
                  userPicks={game.userPicks} 
                  floatingPoints={floatingPoints}
                  isSelecting={game.waitingForPicks}
                  onConfirmPicks={handlePicks}
                />
              </div>

              {/* Leaderboard Middle Section */}
              <div className="flex-1">
                <Leaderboard players={leaderboardData} userPoints={game.totalPoints} userRank={game.rank} />
              </div>

              {/* Scoring Key Bottom Section */}
              <div className="bg-slate-900 border border-slate-800 p-5 rounded-2xl mb-8">
                <h3 className="text-xs font-black text-slate-200 uppercase tracking-widest mb-4">Scoring Key</h3>
                <div className="space-y-2">
                  <div className="flex justify-between text-[10px] font-bold text-slate-500 uppercase"><span>Goal</span><span className="text-green-400">+5000</span></div>
                  <div className="flex justify-between text-[10px] font-bold text-slate-500 uppercase"><span>Assist</span><span className="text-blue-400">+1000</span></div>
                  <div className="flex justify-between text-[10px] font-bold text-slate-500 uppercase"><span>Save</span><span className="text-green-400">+250</span></div>
                  <div className="flex justify-between text-[10px] font-bold text-slate-500 uppercase"><span>Hit/Shot</span><span className="text-slate-300">+200</span></div>
                  <div className="flex justify-between text-[10px] font-bold text-slate-500 uppercase"><span>Giveaway</span><span className="text-red-400">-200</span></div>
                </div>
              </div>
            </div>
          </div>
        </div>
      </main>

      <footer className="fixed bottom-0 left-0 right-0 bg-slate-900/90 border-t border-slate-800 p-4 sm:p-6 shadow-2xl z-40 backdrop-blur-md">
        <div className="max-w-6xl mx-auto flex items-center justify-between gap-4">
          <div className="flex items-center gap-6">
            <div>
              <div className="text-[10px] font-bold text-slate-500 uppercase mb-1">Current Points</div>
              <div className="text-3xl font-black oswald text-amber-500 leading-none">{game.totalPoints.toLocaleString()}</div>
            </div>
            <div className="h-8 w-[1px] bg-slate-800"></div>
            <div>
              <div className="text-[10px] font-bold text-slate-500 uppercase mb-1">Current Rank</div>
              <div className="text-2xl font-black oswald text-white leading-none">#{game.rank}</div>
            </div>
          </div>

          <div className="flex items-center gap-4">
            {!game.waitingForPicks && (
              <div className="hidden md:flex flex-col items-end">
                <span className="text-[9px] font-black text-slate-500 uppercase tracking-widest">Picks Locked</span>
                <span className="text-[10px] font-bold text-slate-400 italic">Wait for stoppage to edit</span>
              </div>
            )}
            <button 
              onClick={openPicks} 
              disabled={game.waitingForPicks} 
              className={`px-8 py-3 rounded-xl font-black oswald text-lg uppercase tracking-widest transition-all active:scale-95 ${
                !game.waitingForPicks 
                ? 'bg-blue-600 hover:bg-blue-500 text-white shadow-lg shadow-blue-900/30 ring-2 ring-blue-400/50' 
                : 'bg-slate-800 text-slate-600 border border-slate-700 cursor-not-allowed'
              }`}
            >
              {game.waitingForPicks ? 'Drafting Open' : 'Change Lineup'}
            </button>
          </div>
        </div>
      </footer>

      <style>{`
        @keyframes screen-flash { 0% { opacity: 0; } 10% { opacity: 1; } 100% { opacity: 0; } }
        @keyframes goal-text { 0% { transform: scale(0.5); opacity: 0; filter: blur(10px); } 20% { transform: scale(1.2); opacity: 1; filter: blur(0); } 80% { transform: scale(1.1); opacity: 1; } 100% { transform: scale(1.5); opacity: 0; filter: blur(20px); } }
        @keyframes goal-explosion { 0% { transform: scale(0); opacity: 0.8; } 100% { transform: scale(4); opacity: 0; } }
        .animate-screen-flash { animation: screen-flash 1.5s ease-out forwards; }
        .animate-goal-text { animation: goal-text 2s cubic-bezier(0.17, 0.67, 0.83, 0.67) forwards; }
        .animate-goal-explosion { animation: goal-explosion 1s ease-out forwards; }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { Position, TeamInfo } from '../types';
import { POSITIONS } from '../constants';

interface SelectionOverlayProps {
  homeTeam: TeamInfo;
  awayTeam: TeamInfo;
  onConfirm: (picks: { home: Position; away: Position; homeNumber: number; awayNumber: number }) => void;
}

interface ScoutReport {
  name: string;
  goals: number;
  assists: number;
  sog: number;
  number: number;
}

const HOCKEY_NAMES = [
  'Connor McSoren', 'Sidney Crosby', 'Nathan Mack', 'Auston Matte', 'Leon Drai',
  'Cale Mak', 'Adam Fox', 'Victor Hed', 'Igor Shesky', 'Andrei Vasi',
  'Artemi Pan', 'Mitch Marner', 'Jack Hugh', 'Tage Thomp', 'Jason Robert'
];

const SelectionOverlay: React.FC<SelectionOverlayProps> = ({ homeTeam, awayTeam, onConfirm }) => {
  const [awayPick, setAwayPick] = useState<Position | null>(null);
  const [homePick, setHomePick] = useState<Position | null>(null);
  const [hovered, setHovered] = useState<{ side: 'home' | 'away'; pos: Position; x: string; y: string } | null>(null);

  // Generate stable scout reports for this selection session
  const scoutReports = useMemo(() => {
    const generateReports = (side: 'home' | 'away') => {
      return POSITIONS.reduce((acc, pos) => {
        acc[pos.value] = {
          name: `${HOCKEY_NAMES[Math.floor(Math.random() * HOCKEY_NAMES.length)]}${side === 'home' ? ' Jr.' : ''}`,
          goals: Math.floor(Math.random() * 3),
          assists: Math.floor(Math.random() * 4),
          sog: Math.floor(Math.random() * 8) + 1,
          number: Math.floor(Math.random() * 98) + 1,
        };
        return acc;
      }, {} as Record<Position, ScoutReport>);
    };

    return {
      away: generateReports('away'),
      home: generateReports('home')
    };
  }, []);

  const handleConfirm = () => {
    if (awayPick && homePick) {
      onConfirm({ 
        home: homePick, 
        away: awayPick, 
        homeNumber: scoutReports.home[homePick].number, 
        awayNumber: scoutReports.away[awayPick].number 
      });
    }
  };

  const getPosCoords = (pos: Position, isHome: boolean) => {
    // Standardizing the "Lines" for a professional tactical view
    // Forward line is aligned on X-axis, Wings equidistant from Center (Y-axis)
    const baseCoords: Record<Position, { top: string; left: string }> = {
      'G': { top: '50%', left: isHome ? '92%' : '8%' },
      'LD': { top: '33%', left: isHome ? '75%' : '25%' },
      'RD': { top: '67%', left: isHome ? '75%' : '25%' },
      'LW': { top: '20%', left: isHome ? '58%' : '42%' },
      'RW': { top: '80%', left: isHome ? '58%' : '42%' },
      'C': { top: '50%', left: isHome ? '58%' : '42%' },
    };
    return baseCoords[pos];
  };

  const isAwayHovered = hovered?.side === 'away';
  const isHomeHovered = hovered?.side === 'home';

  return (
    <div className="fixed inset-0 z-[100] bg-slate-950/95 backdrop-blur-xl flex items-center justify-center p-4 overflow-y-auto">
      <div className="bg-slate-900 border border-slate-700 w-full max-w-5xl rounded-3xl shadow-[0_0_50px_rgba(0,0,0,0.5)] overflow-hidden animate-in fade-in zoom-in duration-500 my-auto">

        {/* Header */}
        <div className="bg-slate-800/50 p-6 border-b border-slate-700 flex flex-col items-center text-center relative overflow-hidden">
          <div className={`absolute inset-0 opacity-10 transition-colors duration-500 pointer-events-none ${isAwayHovered ? 'bg-amber-500' : isHomeHovered ? 'bg-blue-500' : 'transparent'}`}></div>

          <div className="flex items-center gap-4 mb-2 relative z-10">
            <span className={`text-4xl transition-all duration-300 ${isAwayHovered ? 'scale-150 drop-shadow-[0_0_15px_rgba(245,158,11,0.8)]' : 'opacity-60'}`}>
              {awayTeam.logo}
            </span>
            <div className="h-px w-12 bg-slate-700"></div>
            <h2 className="text-3xl font-black oswald uppercase tracking-tighter text-white">Lineup Selection</h2>
            <div className="h-px w-12 bg-slate-700"></div>
            <span className={`text-4xl transition-all duration-300 ${isHomeHovered ? 'scale-150 drop-shadow-[0_0_15px_rgba(37,99,235,0.8)]' : 'opacity-60'}`}>
              {homeTeam.logo}
            </span>
          </div>
          <p className="text-slate-400 text-[10px] font-black uppercase tracking-[0.3em] relative z-10">Hover to scout • Click to lock</p>
        </div>

        {/* Rink Container */}
        <div className="relative p-4 sm:p-8 bg-slate-950">
          <div className="relative w-full aspect-[2/1] bg-slate-900 rounded-[120px] border-[6px] border-slate-800 overflow-hidden shadow-2xl">
            {/* Rink Layout Graphics */}
            <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,rgba(51,65,85,0.3)_0%,transparent_100%)]"></div>
            <div className="absolute inset-y-0 left-[6%] w-0.5 bg-red-600/40"></div>
            <div className="absolute inset-y-0 right-[6%] w-0.5 bg-red-600/40"></div>
            <div className="absolute inset-y-0 left-1/2 w-1 bg-red-600/50 -translate-x-1/2"></div>
            <div className="absolute top-1/2 left-1/2 w-4 h-4 bg-red-600/60 rounded-full -translate-x-1/2 -translate-y-1/2"></div>
            <div className="absolute top-1/2 left-1/2 w-40 h-40 border-2 border-red-600/20 rounded-full -translate-x-1/2 -translate-y-1/2"></div>
            <div className="absolute inset-y-0 left-[35%] w-2 bg-blue-600/40"></div>
            <div className="absolute inset-y-0 right-[35%] w-2 bg-blue-600/40"></div>

            {/* Position Buttons */}
            {POSITIONS.map((pos) => {
              const coords = getPosCoords(pos.value, false);
              const isSelected = awayPick === pos.value;
              const isThisHovered = hovered?.side === 'away' && hovered?.pos === pos.value;
              const report = scoutReports.away[pos.value];

              return (
                <button
                  key={`tactical-away-${pos.value}`}
                  onMouseEnter={(e) => setHovered({ side: 'away', pos: pos.value, x: coords.left, y: coords.top })}
                  onMouseLeave={() => setHovered(null)}
                  onClick={() => setAwayPick(pos.value)}
                  style={{ top: coords.top, left: coords.left }}
                  className={`absolute -translate-x-1/2 -translate-y-1/2 w-14 h-14 sm:w-16 sm:h-16 rounded-full flex flex-col items-center justify-center transition-all z-20 ${
                    isSelected
                      ? 'bg-amber-500 text-slate-950 border-4 border-amber-300 scale-110 shadow-[0_0_30px_rgba(245,158,11,0.6)]'
                      : isThisHovered 
                        ? 'bg-amber-500/20 text-amber-500 border-2 border-amber-500 scale-125 shadow-[0_0_20px_rgba(245,158,11,0.4)]'
                        : 'bg-slate-800/90 text-slate-400 border-2 border-slate-700 hover:border-amber-500/50 backdrop-blur-sm'
                  }`}
                >
                  <div className={`absolute -top-1 -right-1 bg-slate-950 text-[9px] font-black px-1.5 py-0.5 rounded-full border transition-all ${
                    isSelected || isThisHovered ? 'text-amber-500 border-amber-500 scale-125' : 'text-amber-500/50 border-amber-500/30'
                  }`}>
                    #{report.number}
                  </div>
                  <span className="text-base sm:text-lg font-black oswald leading-none">{pos.value}</span>
                  <span className="text-[8px] sm:text-[9px] font-bold uppercase opacity-60 leading-none">{pos.label.split(' ')[0]}</span>
                </button>
              );
            })}

            {POSITIONS.map((pos) => {
              const coords = getPosCoords(pos.value, true);
              const isSelected = homePick === pos.value;
              const isThisHovered = hovered?.side === 'home' && hovered?.pos === pos.value;
              const report = scoutReports.home[pos.value];

              return (
                <button
                  key={`tactical-home-${pos.value}`}
                  onMouseEnter={(e) => setHovered({ side: 'home', pos: pos.value, x: coords.left, y: coords.top })}
                  onMouseLeave={() => setHovered(null)}
                  onClick={() => setHomePick(pos.value)}
                  style={{ top: coords.top, left: coords.left }}
                  className={`absolute -translate-x-1/2 -translate-y-1/2 w-14 h-14 sm:w-16 sm:h-16 rounded-full flex flex-col items-center justify-center transition-all z-20 ${
                    isSelected
                      ? 'bg-blue-600 text-white border-4 border-blue-400 scale-110 shadow-[0_0_30px_rgba(37,99,235,0.6)]'
                      : isThisHovered
                        ? 'bg-blue-600/20 text-blue-400 border-2 border-blue-400 scale-125 shadow-[0_0_20px_rgba(37,99,235,0.4)]'
                        : 'bg-slate-800/90 text-slate-400 border-2 border-slate-700 hover:border-blue-400/50 backdrop-blur-sm'
                  }`}
                >
                  <div className={`absolute -top-1 -right-1 bg-slate-950 text-[9px] font-black px-1.5 py-0.5 rounded-full border transition-all ${
                    isSelected || isThisHovered ? 'text-blue-400 border-blue-400 scale-125' : 'text-blue-400/50 border-blue-400/30'
                  }`}>
                    #{report.number}
                  </div>
                  <span className="text-base sm:text-lg font-black oswald leading-none">{pos.value}</span>
                  <span className="text-[8px] sm:text-[9px] font-bold uppercase opacity-60 leading-none">{pos.label.split(' ')[0]}</span>
                </button>
              );
            })}

            {/* Hover Tooltip - Scout Report Card */}
            {hovered && (
              <div 
                style={{ 
                  top: `calc(${hovered.y} + (parseFloat(${hovered.y}) > 50 ? -120px : 60px))`,
                  left: `calc(${hovered.x} + (parseFloat(${hovered.x}) > 50 ? -160px : 40px))`
                }}
                className="absolute w-56 bg-slate-900/95 border-2 border-slate-700 p-4 rounded-2xl shadow-2xl z-[60] animate-in fade-in zoom-in duration-200 backdrop-blur-md pointer-events-none"
              >
                <div className="flex items-start justify-between mb-3">
                  <div className="flex flex-col">
                    <div className="text-[9px] font-black text-slate-500 uppercase tracking-widest">Scout Report</div>
                    <div className={`text-sm font-black oswald uppercase ${hovered.side === 'home' ? 'text-blue-400' : 'text-amber-500'}`}>
                      {scoutReports[hovered.side][hovered.pos].name}
                    </div>
                  </div>
                  <div className={`text-2xl font-black oswald opacity-20 ${hovered.side === 'home' ? 'text-blue-400' : 'text-amber-500'}`}>
                    #{scoutReports[hovered.side][hovered.pos].number}
                  </div>
                </div>

                <div className="grid grid-cols-3 gap-2 border-t border-slate-800 pt-3">
                  <div className="text-center">
                    <div className="text-[10px] font-black text-slate-100 oswald">{scoutReports[hovered.side][hovered.pos].goals}</div>
                    <div className="text-[8px] font-bold text-slate-600 uppercase">Goals</div>
                  </div>
                  <div className="text-center">
                    <div className="text-[10px] font-black text-slate-100 oswald">{scoutReports[hovered.side][hovered.pos].assists}</div>
                    <div className="text-[8px] font-bold text-slate-600 uppercase">Ast</div>
                  </div>
                  <div className="text-center">
                    <div className="text-[10px] font-black text-slate-100 oswald">{scoutReports[hovered.side][hovered.pos].sog}</div>
                    <div className="text-[8px] font-bold text-slate-600 uppercase">SOG</div>
                  </div>
                </div>

                <div className={`mt-3 py-1 rounded bg-slate-950/50 text-center border ${hovered.side === 'home' ? 'border-blue-500/20' : 'border-amber-500/20'}`}>
                  <span className={`text-[9px] font-black uppercase tracking-tighter ${hovered.side === 'home' ? 'text-blue-400' : 'text-amber-500'}`}>
                    {hovered.pos === 'G' ? 'Wall Mode Active' : 'Elite Playmaker'}
                  </span>
                </div>
              </div>
            )}
          </div>
        </div>

        {/* Footer Actions */}
        <div className="p-8 bg-slate-800/30 border-t border-slate-700 flex flex-col sm:flex-row items-center justify-between gap-6">
          <div className="flex gap-8">
            <div className={`flex items-center gap-3 transition-all ${isAwayHovered ? 'scale-110' : ''}`}>
              <div className={`w-4 h-4 rounded-full ${awayPick ? 'bg-amber-500 shadow-[0_0_10px_rgba(245,158,11,0.5)] animate-pulse' : 'bg-slate-700'}`}></div>
              <div className="flex flex-col">
                <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Away Select</span>
                <span className="text-sm font-black oswald text-white uppercase">
                  {awayPick ? `${awayPick} (#${scoutReports.away[awayPick].number})` : 'PICK PLAYER'}
                </span>
              </div>
            </div>
            <div className={`flex items-center gap-3 transition-all ${isHomeHovered ? 'scale-110' : ''}`}>
              <div className={`w-4 h-4 rounded-full ${homePick ? 'bg-blue-500 shadow-[0_0_10px_rgba(37,99,235,0.5)] animate-pulse' : 'bg-slate-700'}`}></div>
              <div className="flex flex-col">
                <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Home Select</span>
                <span className="text-sm font-black oswald text-white uppercase">
                  {homePick ? `${homePick} (#${scoutReports.home[homePick].number})` : 'PICK PLAYER'}
                </span>
              </div>
            </div>
          </div>

          <button
            disabled={!awayPick || !homePick}
            onClick={handleConfirm}
            className={`w-full sm:w-72 py-4 rounded-2xl font-black oswald text-2xl uppercase tracking-[0.1em] transition-all ${
              awayPick && homePick
                ? 'bg-gradient-to-r from-blue-600 to-indigo-600 hover:from-blue-500 hover:to-indigo-500 text-white shadow-[0_15px_35px_rgba(37,99,235,0.4)] active:scale-95'
                : 'bg-slate-800 text-slate-600 cursor-not-allowed border border-slate-700'
            }`}
          >
            {awayPick && homePick ? 'LOCK LINEUPS' : 'SELECT PLAYERS'}
          </button>
        </div>
      </div>
    </div>
  );
};

export default SelectionOverlay;

import React, { useState, useMemo } from 'react';
import { Position, TeamInfo, FloatingPoint } from '../types';
import { POSITIONS } from '../constants';

interface PickStatusProps {
  homeTeam: TeamInfo;
  awayTeam: TeamInfo;
  userPicks: { home: Position | null; away: Position | null; homeNumber: number | null; awayNumber: number | null };
  floatingPoints: FloatingPoint[];
  isSelecting: boolean;
  onConfirmPicks: (picks: { home: Position; away: Position; homeNumber: number; awayNumber: number }) => void;
}

const PickStatus: React.FC<PickStatusProps> = ({ 
  homeTeam, 
  awayTeam, 
  userPicks, 
  floatingPoints, 
  isSelecting,
  onConfirmPicks 
}) => {
  const [draftAway, setDraftAway] = useState<Position | null>(userPicks.away);
  const [draftHome, setDraftHome] = useState<Position | null>(userPicks.home);

  const numbers = useMemo(() => {
    const res: Record<string, number> = {};
    POSITIONS.forEach(p => {
      res[`away-${p.value}`] = Math.floor(Math.random() * 98) + 1;
      res[`home-${p.value}`] = Math.floor(Math.random() * 98) + 1;
    });
    return res;
  }, []);

  const handleConfirm = () => {
    if (draftAway && draftHome) {
      onConfirmPicks({
        away: draftAway,
        home: draftHome,
        awayNumber: numbers[`away-${draftAway}`],
        homeNumber: numbers[`home-${draftHome}`]
      });
    }
  };

  const getPosCoords = (pos: Position, isHome: boolean) => {
    const baseCoords: Record<Position, { top: string; left: string }> = {
      'G': { top: '50%', left: isHome ? '92%' : '8%' },
      'LD': { top: '33%', left: isHome ? '75%' : '25%' },
      'RD': { top: '67%', left: isHome ? '75%' : '25%' },
      'LW': { top: '20%', left: isHome ? '58%' : '42%' },
      'RW': { top: '80%', left: isHome ? '58%' : '42%' },
      'C': { top: '50%', left: isHome ? '58%' : '42%' },
    };
    return baseCoords[pos];
  };

  return (
    <div className="flex flex-col gap-4">
      {/* Enhanced Tactical Rink - Always Visible */}
      <div className={`relative w-full aspect-[1.5/1] bg-slate-900 rounded-[40px] border-[4px] overflow-hidden shadow-2xl transition-colors duration-500 ${isSelecting ? 'border-blue-500/50' : 'border-slate-800'}`}>
        {/* Ice Surface Glow */}
        <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,rgba(51,65,85,0.2)_0%,transparent_100%)]"></div>

        {/* Goal Lines */}
        <div className="absolute inset-y-0 left-[6%] w-px bg-red-600/30"></div>
        <div className="absolute inset-y-0 right-[6%] w-px bg-red-600/30"></div>

        {/* Center Line & Center Face-Off Dot */}
        <div className="absolute inset-y-0 left-1/2 w-0.5 bg-red-600/40 -translate-x-1/2"></div>
        <div className="absolute top-1/2 left-1/2 w-1.5 h-1.5 bg-red-600/60 rounded-full -translate-x-1/2 -translate-y-1/2"></div>
        <div className="absolute top-1/2 left-1/2 w-16 h-16 border border-red-600/20 rounded-full -translate-x-1/2 -translate-y-1/2"></div>

        {/* Blue Lines */}
        <div className="absolute inset-y-0 left-[35%] w-1.5 bg-blue-600/30"></div>
        <div className="absolute inset-y-0 right-[35%] w-1.5 bg-blue-600/30"></div>

        {/* Goal Creases */}
        <div className="absolute top-1/2 left-[6%] w-4 h-10 border border-blue-500/20 rounded-r-full -translate-y-1/2 bg-blue-500/5"></div>
        <div className="absolute top-1/2 right-[6%] w-4 h-10 border border-blue-500/20 rounded-l-full -translate-y-1/2 bg-blue-500/5"></div>

        <div className="absolute top-2 left-4 oswald font-black text-slate-800 text-[10px] uppercase pointer-events-none">{awayTeam.name}</div>
        <div className="absolute top-2 right-4 oswald font-black text-slate-800 text-[10px] uppercase text-right pointer-events-none">{homeTeam.name}</div>

        {/* Position Markers */}
        {POSITIONS.map(p => {
          const coordsA = getPosCoords(p.value, false);
          const isDrafted = draftAway === p.value;
          const isConfirmed = userPicks.away === p.value;
          const isSelected = isSelecting ? isDrafted : isConfirmed;

          return (
            <button
              key={`rink-away-${p.value}`}
              disabled={!isSelecting}
              onClick={() => isSelecting && setDraftAway(p.value)}
              style={{ top: coordsA.top, left: coordsA.left }}
              className={`absolute -translate-x-1/2 -translate-y-1/2 w-7 h-7 sm:w-8 sm:h-8 rounded-full flex flex-col items-center justify-center transition-all border-2 shadow-lg ${
                isSelected ? 'bg-amber-500 text-slate-950 border-white scale-110 z-20 shadow-amber-500/40' : 'bg-slate-800/90 text-slate-500 border-slate-700 z-10'
              } ${isSelecting ? 'hover:scale-110 cursor-pointer active:scale-90 animate-pulse-subtle' : 'cursor-default opacity-80'}`}
            >
              <span className="text-[9px] font-black oswald leading-none">{p.value}</span>
              {isSelected && <span className="text-[6px] font-bold">#{isSelecting ? (numbers[`away-${p.value}`] || '??') : userPicks.awayNumber}</span>}

              {/* Point Explosion from Position */}
              {!isSelecting && isConfirmed && floatingPoints.filter(fp => fp.team === 'away').map(fp => (
                <div key={fp.id} style={{ left: `${fp.xOffset}px`, animation: 'float-up-rink 2s ease-out forwards' }} className={`absolute bottom-full mb-2 font-black oswald text-lg whitespace-nowrap z-50 drop-shadow-lg ${fp.points > 0 ? 'text-green-400' : 'text-red-500'}`}>
                  {fp.points > 0 ? '+' : ''}{fp.points}
                </div>
              ))}
            </button>
          );
        })}

        {POSITIONS.map(p => {
          const coordsH = getPosCoords(p.value, true);
          const isDrafted = draftHome === p.value;
          const isConfirmed = userPicks.home === p.value;
          const isSelected = isSelecting ? isDrafted : isConfirmed;

          return (
            <button
              key={`rink-home-${p.value}`}
              disabled={!isSelecting}
              onClick={() => isSelecting && setDraftHome(p.value)}
              style={{ top: coordsH.top, left: coordsH.left }}
              className={`absolute -translate-x-1/2 -translate-y-1/2 w-7 h-7 sm:w-8 sm:h-8 rounded-full flex flex-col items-center justify-center transition-all border-2 shadow-lg ${
                isSelected ? 'bg-blue-600 text-white border-white scale-110 z-20 shadow-blue-500/40' : 'bg-slate-800/90 text-slate-500 border-slate-700 z-10'
              } ${isSelecting ? 'hover:scale-110 cursor-pointer active:scale-90 animate-pulse-subtle' : 'cursor-default opacity-80'}`}
            >
              <span className="text-[9px] font-black oswald leading-none">{p.value}</span>
              {isSelected && <span className="text-[6px] font-bold">#{isSelecting ? (numbers[`home-${p.value}`] || '??') : userPicks.homeNumber}</span>}

              {/* Point Explosion from Position */}
              {!isSelecting && isConfirmed && floatingPoints.filter(fp => fp.team === 'home').map(fp => (
                <div key={fp.id} style={{ left: `${fp.xOffset}px`, animation: 'float-up-rink 2s ease-out forwards' }} className={`absolute bottom-full mb-2 font-black oswald text-lg whitespace-nowrap z-50 drop-shadow-lg ${fp.points > 0 ? 'text-green-400' : 'text-red-500'}`}>
                  {fp.points > 0 ? '+' : ''}{fp.points}
                </div>
              ))}
            </button>
          );
        })}
      </div>

      {/* Control Area */}
      <div className="space-y-3">
        {isSelecting ? (
          <div className="space-y-3 animate-in fade-in duration-300">
            <div className="grid grid-cols-2 gap-2">
              <div className="bg-slate-950 border border-slate-800 rounded-lg p-2">
                <span className="text-[8px] font-bold text-slate-500 uppercase block">Away Drafting</span>
                <span className="text-sm font-black oswald text-amber-500">{draftAway || 'PENDING'}</span>
              </div>
              <div className="bg-slate-950 border border-slate-800 rounded-lg p-2">
                <span className="text-[8px] font-bold text-slate-500 uppercase block">Home Drafting</span>
                <span className="text-sm font-black oswald text-blue-400">{draftHome || 'PENDING'}</span>
              </div>
            </div>
            <button 
              onClick={handleConfirm} 
              disabled={!draftAway || !draftHome}
              className={`w-full py-3.5 rounded-xl font-black oswald text-lg uppercase tracking-widest transition-all ${draftAway && draftHome ? 'bg-blue-600 text-white shadow-xl shadow-blue-900/40 active:scale-95' : 'bg-slate-800 text-slate-600 border border-slate-700'}`}
            >
              Lock In Lineup
            </button>
          </div>
        ) : (
          <div className="grid grid-cols-2 gap-3 animate-in fade-in duration-300">
            <div className="bg-amber-500/5 border border-amber-500/20 rounded-xl p-3 flex flex-col items-center">
              <span className="text-[8px] font-black text-amber-500/60 uppercase mb-1">Away Tracked</span>
              <span className="text-xl font-black oswald text-white leading-none">{userPicks.away}</span>
              <span className="text-[10px] font-bold text-amber-500">#{userPicks.awayNumber}</span>
            </div>
            <div className="bg-blue-600/5 border border-blue-600/20 rounded-xl p-3 flex flex-col items-center">
              <span className="text-[8px] font-black text-blue-400/60 uppercase mb-1">Home Tracked</span>
              <span className="text-xl font-black oswald text-white leading-none">{userPicks.home}</span>
              <span className="text-[10px] font-bold text-blue-400">#{userPicks.homeNumber}</span>
            </div>
          </div>
        )}
      </div>

      <style>{`
        @keyframes float-up-rink {
          0% { transform: translateY(0); opacity: 0; }
          15% { transform: translateY(-12px); opacity: 1; }
          100% { transform: translateY(-90px); opacity: 0; }
        }
        @keyframes pulse-subtle {
          0% { transform: translate(-50%, -50%) scale(1); }
          50% { transform: translate(-50%, -50%) scale(1.05); }
          100% { transform: translate(-50%, -50%) scale(1); }
        }
        .animate-pulse-subtle { animation: pulse-subtle 2s infinite ease-in-out; }
      `}</style>
    </div>
  );
};

export default PickStatus;

import React, { useState, useMemo } from 'react';
import { Position, TeamInfo } from '../types';
import { POSITIONS } from '../constants';

interface SelectionOverlayProps {
  homeTeam: TeamInfo;
  awayTeam: TeamInfo;
  onConfirm: (picks: { home: Position; away: Position; homeNumber: number; awayNumber: number }) => void;
}

interface ScoutReport {
  name: string;
  goals: number;
  assists: number;
  sog: number;
  number: number;
}

const HOCKEY_NAMES = [
  'Connor McSoren', 'Sidney Crosby', 'Nathan Mack', 'Auston Matte', 'Leon Drai',
  'Cale Mak', 'Adam Fox', 'Victor Hed', 'Igor Shesky', 'Andrei Vasi',
  'Artemi Pan', 'Mitch Marner', 'Jack Hugh', 'Tage Thomp', 'Jason Robert'
];

const SelectionOverlay: React.FC<SelectionOverlayProps> = ({ homeTeam, awayTeam, onConfirm }) => {
  const [awayPick, setAwayPick] = useState<Position | null>(null);
  const [homePick, setHomePick] = useState<Position | null>(null);
  const [hovered, setHovered] = useState<{ side: 'home' | 'away'; pos: Position; x: string; y: string } | null>(null);

  // Generate stable scout reports for this selection session
  const scoutReports = useMemo(() => {
    const generateReports = (side: 'home' | 'away') => {
      return POSITIONS.reduce((acc, pos) => {
        acc[pos.value] = {
          name: `${HOCKEY_NAMES[Math.floor(Math.random() * HOCKEY_NAMES.length)]}${side === 'home' ? ' Jr.' : ''}`,
          goals: Math.floor(Math.random() * 3),
          assists: Math.floor(Math.random() * 4),
          sog: Math.floor(Math.random() * 8) + 1,
          number: Math.floor(Math.random() * 98) + 1,
        };
        return acc;
      }, {} as Record<Position, ScoutReport>);
    };

    return {
      away: generateReports('away'),
      home: generateReports('home')
    };
  }, []);

  const handleConfirm = () => {
    if (awayPick && homePick) {
      onConfirm({ 
        home: homePick, 
        away: awayPick, 
        homeNumber: scoutReports.home[homePick].number, 
        awayNumber: scoutReports.away[awayPick].number 
      });
    }
  };

  const getPosCoords = (pos: Position, isHome: boolean) => {
    const baseCoords: Record<Position, { top: string; left: string }> = {
      'G': { top: '50%', left: isHome ? '92%' : '8%' },
      'LD': { top: '33%', left: isHome ? '75%' : '25%' },
      'RD': { top: '67%', left: isHome ? '75%' : '25%' },
      'LW': { top: '20%', left: isHome ? '58%' : '42%' },
      'RW': { top: '80%', left: isHome ? '58%' : '42%' },
      'C': { top: '50%', left: isHome ? '58%' : '42%' },
    };
    return baseCoords[pos];
  };

  const isAwayHovered = hovered?.side === 'away';
  const isHomeHovered = hovered?.side === 'home';

  return (
    <div className="fixed inset-0 z-[100] bg-slate-950/95 backdrop-blur-xl flex items-center justify-center p-4 overflow-y-auto">
      <div className="bg-slate-900 border border-slate-700 w-full max-w-5xl rounded-3xl shadow-[0_0_50px_rgba(0,0,0,0.5)] overflow-hidden animate-in fade-in zoom-in duration-500 my-auto">

        {/* Header */}
        <div className="bg-slate-800/50 p-6 border-b border-slate-700 flex flex-col items-center text-center relative overflow-hidden">
          <div className={`absolute inset-0 opacity-10 transition-colors duration-500 pointer-events-none ${isAwayHovered ? 'bg-amber-500' : isHomeHovered ? 'bg-blue-500' : 'transparent'}`}></div>

          <div className="flex items-center gap-4 mb-2 relative z-10">
