            <div className="absolute top-[22%] left-[18%] w-3 h-3 bg-red-600/30 rounded-full -translate-x-1/2 -translate-y-1/2"></div>

            <div className="absolute bottom-[22%] left-[18%] w-40 h-40 border-2 border-red-600/15 rounded-full -translate-x-1/2 -translate-y-1/2"></div>
            <div className="absolute bottom-[22%] left-[18%] w-3 h-3 bg-red-600/30 rounded-full -translate-x-1/2 -translate-y-1/2"></div>

