          <div className="flex items-center gap-4 mb-2 relative z-10">
            <span className={`text-4xl transition-all duration-300 ${isAwayHovered ? 'scale-150 drop-shadow-[0_0_15px_rgba(245,158,11,0.8)]' : 'opacity-60'}`}>
              {awayTeam.logo}
            </span>
            <div className="h-px w-12 bg-slate-700"></div>
            <h2 className="text-3xl font-black oswald uppercase tracking-tighter text-white">POWERPLAY Selection</h2>
            <div className="h-px w-12 bg-slate-700"></div>
            <span className={`text-4xl transition-all duration-300 ${isHomeHovered ? 'scale-150 drop-shadow-[0_0_15px_rgba(37,99,235,0.8)]' : 'opacity-60'}`}>
              {homeTeam.logo}
            </span>
          </div>
          <p className="text-slate-400 text-[10px] font-black uppercase tracking-[0.3em] relative z-10">Deploy your key players for the next shift</p>
        </div>

        {/* Rink Container */}
        <div className="relative p-4 sm:p-8 bg-slate-950">
          <div className="relative w-full aspect-[2/1] bg-slate-900 rounded-[120px] border-[6px] border-slate-800 overflow-hidden shadow-2xl">
            <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,rgba(51,65,85,0.3)_0%,transparent_100%)]"></div>
            <div className="absolute inset-y-0 left-[6%] w-0.5 bg-red-600/40"></div>
            <div className="absolute inset-y-0 right-[6%] w-0.5 bg-red-600/40"></div>
            <div className="absolute inset-y-0 left-1/2 w-1 bg-red-600/50 -translate-x-1/2"></div>
            <div className="absolute top-1/2 left-1/2 w-4 h-4 bg-red-600/60 rounded-full -translate-x-1/2 -translate-y-1/2 shadow-[0_0_10px_rgba(220,38,38,0.5)]"></div>
            <div className="absolute top-1/2 left-1/2 w-40 h-40 border-2 border-red-600/20 rounded-full -translate-x-1/2 -translate-y-1/2"></div>
            <div className="absolute inset-y-0 left-[35%] w-2 bg-blue-600/40"></div>
            <div className="absolute inset-y-0 right-[35%] w-2 bg-blue-600/40"></div>

            {/* End Zone Face-Off Circles & Dots */}
            <div className="absolute top-[20%] left-[18%] w-32 h-32 border-2 border-red-600/20 rounded-full -translate-x-1/2 -translate-y-1/2"></div>
            <div className="absolute top-[20%] right-[18%] w-32 h-32 border-2 border-red-600/20 rounded-full translate-x-1/2 -translate-y-1/2"></div>
            <div className="absolute bottom-[20%] left-[18%] w-32 h-32 border-2 border-red-600/20 rounded-full -translate-x-1/2 -translate-y-1/2"></div>
            <div className="absolute bottom-[20%] right-[18%] w-32 h-32 border-2 border-red-600/20 rounded-full translate-x-1/2 -translate-y-1/2"></div>

            {/* Labels */}
            <div className={`absolute top-6 left-16 oswald font-black uppercase tracking-widest text-2xl pointer-events-none transition-all duration-300 ${isAwayHovered ? 'text-amber-500 opacity-100' : 'text-slate-800'}`}>{awayTeam.name}</div>
            <div className={`absolute top-6 right-16 oswald font-black uppercase tracking-widest text-2xl pointer-events-none text-right transition-all duration-300 ${isHomeHovered ? 'text-blue-500 opacity-100' : 'text-slate-800'}`}>{homeTeam.name}</div>

            {/* Away Positions */}
            {POSITIONS.map((pos) => {
              const coords = getPosCoords(pos.value, false);
              const isSelected = awayPick === pos.value;
              const isThisHovered = hovered?.side === 'away' && hovered?.pos === pos.value;
              return (
                <button
                  key={`tactical-away-${pos.value}`}
                  onMouseEnter={() => setHovered({ side: 'away', pos: pos.value })}
                  onMouseLeave={() => setHovered(null)}
                  onClick={() => setAwayPick(pos.value)}
                  style={{ top: coords.top, left: coords.left }}
                  className={`absolute -translate-x-1/2 -translate-y-1/2 w-14 h-14 sm:w-16 sm:h-16 rounded-full flex flex-col items-center justify-center transition-all z-10 ${
                    isSelected
                      ? 'bg-amber-500 text-slate-950 border-4 border-amber-300 scale-110 shadow-[0_0_30px_rgba(245,158,11,0.6)]'
                      : isThisHovered 
                        ? 'bg-amber-500/20 text-amber-500 border-2 border-amber-500 scale-125'
                        : 'bg-slate-800/90 text-slate-400 border-2 border-slate-700 hover:border-amber-500/50'
                  }`}
                >
                  <div className={`absolute -top-1 -right-1 bg-slate-950 text-[9px] font-black px-1.5 py-0.5 rounded-full border transition-all ${isSelected || isThisHovered ? 'text-amber-500 border-amber-500' : 'text-amber-500/50 border-amber-500/30'}`}>#{awayNumbers[pos.value]}</div>
                  <span className="text-base sm:text-lg font-black oswald leading-none">{pos.value}</span>
                </button>
              );
            })}

            {/* Home Positions */}
            {POSITIONS.map((pos) => {
              const coords = getPosCoords(pos.value, true);
              const isSelected = homePick === pos.value;
              const isThisHovered = hovered?.side === 'home' && hovered?.pos === pos.value;
              return (
                <button
                  key={`tactical-home-${pos.value}`}
                  onMouseEnter={() => setHovered({ side: 'home', pos: pos.value })}
                  onMouseLeave={() => setHovered(null)}
                  onClick={() => setHomePick(pos.value)}
                  style={{ top: coords.top, left: coords.left }}
                  className={`absolute -translate-x-1/2 -translate-y-1/2 w-14 h-14 sm:w-16 sm:h-16 rounded-full flex flex-col items-center justify-center transition-all z-10 ${
                    isSelected
                      ? 'bg-blue-600 text-white border-4 border-blue-400 scale-110 shadow-[0_0_30px_rgba(37,99,235,0.6)]'
                      : isThisHovered
                        ? 'bg-blue-600/20 text-blue-400 border-2 border-blue-400 scale-125'
                        : 'bg-slate-800/90 text-slate-400 border-2 border-slate-700 hover:border-blue-400/50'
                  }`}
                >
                  <div className={`absolute -top-1 -right-1 bg-slate-950 text-[9px] font-black px-1.5 py-0.5 rounded-full border transition-all ${isSelected || isThisHovered ? 'text-blue-400 border-blue-400' : 'text-blue-400/50 border-blue-400/30'}`}>#{homeNumbers[pos.value]}</div>
                  <span className="text-base sm:text-lg font-black oswald leading-none">{pos.value}</span>
                </button>
              );
            })}
          </div>
        </div>

        <div className="p-8 bg-slate-800/30 border-t border-slate-700 flex flex-col sm:flex-row items-center justify-between gap-6">
          <div className="flex gap-8">
            <div className="flex flex-col">
              <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-1">Away Draft</span>
              <span className="text-sm font-black oswald text-amber-500">{awayPick ? `${awayPick} (#${awayNumbers[awayPick]})` : 'PENDING'}</span>
            </div>
            <div className="flex flex-col">
              <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-1">Home Draft</span>
              <span className="text-sm font-black oswald text-blue-400">{homePick ? `${homePick} (#${homeNumbers[homePick]})` : 'PENDING'}</span>
            </div>
          </div>

          <button
            disabled={!awayPick || !homePick}
            onClick={handleConfirm}
            className={`w-full sm:w-72 py-4 rounded-2xl font-black oswald text-2xl uppercase tracking-[0.1em] transition-all ${
              awayPick && homePick
                ? 'bg-blue-600 hover:bg-blue-500 text-white shadow-xl active:scale-95'
                : 'bg-slate-800 text-slate-600 cursor-not-allowed'
            }`}
          >
            {awayPick && homePick ? 'LOCK ROSTER' : 'SELECT PLAYERS'}
          </button>
        </div>
      </div>
    </div>
  );
};

export default SelectionOverlay;

import React, { useState, useMemo } from 'react';
import { Position, TeamInfo, FloatingPoint } from '../types';
import { POSITIONS } from '../constants';

interface PickStatusProps {
  homeTeam: TeamInfo;
  awayTeam: TeamInfo;
  userPicks: { home: Position | null; away: Position | null; homeNumber: number | null; awayNumber: number | null };
  floatingPoints: FloatingPoint[];
  isSelecting: boolean;
  onConfirmPicks: (picks: { home: Position; away: Position; homeNumber: number; awayNumber: number }) => void;
}

const PickStatus: React.FC<PickStatusProps> = ({ 
  homeTeam, 
  awayTeam, 
  userPicks, 
  floatingPoints, 
  isSelecting,
  onConfirmPicks 
}) => {
  const [draftAway, setDraftAway] = useState<Position | null>(userPicks.away);
  const [draftHome, setDraftHome] = useState<Position | null>(userPicks.home);

  const numbers = useMemo(() => {
    const res: Record<string, number> = {};
    POSITIONS.forEach(p => {
      res[`away-${p.value}`] = Math.floor(Math.random() * 98) + 1;
      res[`home-${p.value}`] = Math.floor(Math.random() * 98) + 1;
    });
    return res;
  }, []);

  const handleConfirm = () => {
    if (draftAway && draftHome) {
      onConfirmPicks({
        away: draftAway,
        home: draftHome,
        awayNumber: numbers[`away-${draftAway}`],
        homeNumber: numbers[`home-${draftHome}`]
      });
    }
  };

  const getPosCoords = (pos: Position, isHome: boolean) => {
    const baseCoords: Record<Position, { top: string; left: string }> = {
      'G': { top: '50%', left: isHome ? '92%' : '8%' },
      'LD': { top: '30%', left: isHome ? '75%' : '25%' },
      'RD': { top: '70%', left: isHome ? '75%' : '25%' },
      // Move LW and RW dots to same horizontal distance as Center (Home: 58%, Away: 42%)
      'LW': { top: '22%', left: isHome ? '58%' : '42%' },
      'RW': { top: '78%', left: isHome ? '58%' : '42%' },
      'C': { top: '50%', left: isHome ? '58%' : '42%' },
    };
    return baseCoords[pos];
  };

  return (
    <div className="flex flex-col gap-4">
      {/* Enhanced Tactical Rink - Always Visible */}
      <div className={`relative w-full aspect-[1.5/1] bg-slate-900 rounded-[40px] border-[4px] overflow-hidden shadow-2xl transition-colors duration-500 ${isSelecting ? 'border-blue-500/50' : 'border-slate-800'}`}>
        {/* Ice Surface Glow */}
        <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,rgba(51,65,85,0.2)_0%,transparent_100%)]"></div>

        {/* Goal Lines */}
        <div className="absolute inset-y-0 left-[6%] w-px bg-red-600/30"></div>
        <div className="absolute inset-y-0 right-[6%] w-px bg-red-600/30"></div>

        {/* Center Line & Center Face-Off Dot */}
        <div className="absolute inset-y-0 left-1/2 w-0.5 bg-red-600/40 -translate-x-1/2"></div>
        <div className="absolute top-1/2 left-1/2 w-1.5 h-1.5 bg-red-600/60 rounded-full -translate-x-1/2 -translate-y-1/2"></div>
        <div className="absolute top-1/2 left-1/2 w-16 h-16 border border-red-600/20 rounded-full -translate-x-1/2 -translate-y-1/2"></div>

        {/* Blue Lines */}
        <div className="absolute inset-y-0 left-[35%] w-1.5 bg-blue-600/30"></div>
        <div className="absolute inset-y-0 right-[35%] w-1.5 bg-blue-600/30"></div>

        {/* Goal Creases */}
        <div className="absolute top-1/2 left-[6%] w-4 h-10 border border-blue-500/20 rounded-r-full -translate-y-1/2 bg-blue-500/5"></div>
        <div className="absolute top-1/2 right-[6%] w-4 h-10 border border-blue-500/20 rounded-l-full -translate-y-1/2 bg-blue-500/5"></div>

        <div className="absolute top-2 left-4 oswald font-black text-slate-800 text-[10px] uppercase pointer-events-none">{awayTeam.name}</div>
        <div className="absolute top-2 right-4 oswald font-black text-slate-800 text-[10px] uppercase text-right pointer-events-none">{homeTeam.name}</div>

        {/* Position Markers */}
        {POSITIONS.map(p => {
          const coordsA = getPosCoords(p.value, false);
          const isDrafted = draftAway === p.value;
          const isConfirmed = userPicks.away === p.value;
          const isSelected = isSelecting ? isDrafted : isConfirmed;

          const activePoint = floatingPoints.find(fp => fp.team === 'away' && fp.position === p.value);
          const flashClass = activePoint 
            ? (activePoint.points > 0 ? 'animate-flash-green' : 'animate-flash-red') 
            : '';

          return (
            <div 
              key={`rink-away-${p.value}`}
              style={{ top: coordsA.top, left: coordsA.left }}
              className="absolute -translate-x-1/2 -translate-y-1/2 z-10"
            >
              <button
                disabled={!isSelecting}
                onClick={() => isSelecting && setDraftAway(p.value)}
                className={`w-7 h-7 sm:w-8 sm:h-8 rounded-full flex flex-col items-center justify-center transition-all border-2 shadow-lg ${
                  isSelected ? 'bg-amber-500 text-slate-950 border-white scale-110 z-20 shadow-amber-500/40' : 'bg-slate-800/90 text-slate-500 border-slate-700 z-10'
                } ${isSelecting ? 'hover:scale-110 cursor-pointer active:scale-90' : 'cursor-default opacity-80'} ${flashClass}`}
              >
                <span className="text-[9px] font-black oswald leading-none">{p.value}</span>
                {isSelected && <span className="text-[6px] font-bold">#{isSelecting ? (numbers[`away-${p.value}`] || '??') : userPicks.awayNumber}</span>}
              </button>

              {floatingPoints.filter(fp => fp.team === 'away' && fp.position === p.value).map(fp => (
                <div key={fp.id} style={{ left: `${fp.xOffset}px`, animation: 'float-up-rink 2s ease-out forwards' }} className={`absolute bottom-full mb-2 font-black oswald text-lg whitespace-nowrap z-50 drop-shadow-lg ${fp.points > 0 ? 'text-green-400' : 'text-red-500'}`}>
                  {fp.points > 0 ? '+' : ''}{fp.points}
                </div>
              ))}
            </div>
          );
        })}

        {POSITIONS.map(p => {
          const coordsH = getPosCoords(p.value, true);
          const isDrafted = draftHome === p.value;
          const isConfirmed = userPicks.home === p.value;
          const isSelected = isSelecting ? isDrafted : isConfirmed;

          const activePoint = floatingPoints.find(fp => fp.team === 'home' && fp.position === p.value);
          const flashClass = activePoint 
            ? (activePoint.points > 0 ? 'animate-flash-green' : 'animate-flash-red') 
            : '';

          return (
            <div 
              key={`rink-home-${p.value}`}
              style={{ top: coordsH.top, left: coordsH.left }}
              className="absolute -translate-x-1/2 -translate-y-1/2 z-10"
            >
              <button
                disabled={!isSelecting}
                onClick={() => isSelecting && setDraftHome(p.value)}
                className={`w-7 h-7 sm:w-8 sm:h-8 rounded-full flex flex-col items-center justify-center transition-all border-2 shadow-lg ${
                  isSelected ? 'bg-blue-600 text-white border-white scale-110 z-20 shadow-blue-500/40' : 'bg-slate-800/90 text-slate-500 border-slate-700 z-10'
                } ${isSelecting ? 'hover:scale-110 cursor-pointer active:scale-90' : 'cursor-default opacity-80'} ${flashClass}`}
              >
                <span className="text-[9px] font-black oswald leading-none">{p.value}</span>
                {isSelected && <span className="text-[6px] font-bold">#{isSelecting ? (numbers[`home-${p.value}`] || '??') : userPicks.homeNumber}</span>}
              </button>

              {floatingPoints.filter(fp => fp.team === 'home' && fp.position === p.value).map(fp => (
                <div key={fp.id} style={{ left: `${fp.xOffset}px`, animation: 'float-up-rink 2s ease-out forwards' }} className={`absolute bottom-full mb-2 font-black oswald text-lg whitespace-nowrap z-50 drop-shadow-lg ${fp.points > 0 ? 'text-green-400' : 'text-red-500'}`}>
                  {fp.points > 0 ? '+' : ''}{fp.points}
                </div>
              ))}
            </div>
          );
        })}
      </div>

      {/* Control Area */}
      <div className="space-y-3">
        {isSelecting ? (
          <div className="space-y-3 animate-in fade-in duration-300">
            <div className="grid grid-cols-2 gap-2">
              <div className="bg-slate-950 border border-slate-800 rounded-lg p-2">
                <span className="text-[8px] font-bold text-slate-500 uppercase block">Away Drafting</span>
                <span className="text-sm font-black oswald text-amber-500">{draftAway || 'PENDING'}</span>
              </div>
              <div className="bg-slate-950 border border-slate-800 rounded-lg p-2">
                <span className="text-[8px] font-bold text-slate-500 uppercase block">Home Drafting</span>
                <span className="text-sm font-black oswald text-blue-400">{draftHome || 'PENDING'}</span>
              </div>
            </div>
            <button 
              onClick={handleConfirm} 
              disabled={!draftAway || !draftHome}
              className={`w-full py-3.5 rounded-xl font-black oswald text-lg uppercase tracking-widest transition-all ${draftAway && draftHome ? 'bg-blue-600 text-white shadow-xl shadow-blue-900/40 active:scale-95' : 'bg-slate-800 text-slate-600 border border-slate-700'}`}
            >
              Lock POWERPLAY
            </button>
          </div>
        ) : (
          <div className="grid grid-cols-2 gap-3 animate-in fade-in duration-300">
            <div className="bg-amber-500/5 border border-amber-500/20 rounded-xl p-3 flex flex-col items-center">
              <span className="text-[8px] font-black text-amber-500/60 uppercase mb-1">Away Tracked</span>
              <span className="text-xl font-black oswald text-white leading-none">{userPicks.away}</span>
              <span className="text-[10px] font-bold text-amber-500">#{userPicks.awayNumber}</span>
            </div>
            <div className="bg-blue-600/5 border border-blue-600/20 rounded-xl p-3 flex flex-col items-center">
              <span className="text-[8px] font-black text-blue-400/60 uppercase mb-1">Home Tracked</span>
              <span className="text-xl font-black oswald text-white leading-none">{userPicks.home}</span>
              <span className="text-[10px] font-bold text-blue-400">#{userPicks.homeNumber}</span>
            </div>
          </div>
        )}
      </div>

      <style>{`
        @keyframes float-up-rink {
          0% { transform: translateY(0); opacity: 0; }
          15% { transform: translateY(-12px); opacity: 1; }
          100% { transform: translateY(-90px); opacity: 0; }
        }
      `}</style>
    </div>
  );
};

export default PickStatus;

import React, { useState, useMemo } from 'react';
import { Position, TeamInfo } from '../types';
import { POSITIONS } from '../constants';

interface SelectionOverlayProps {
  homeTeam: TeamInfo;
  awayTeam: TeamInfo;
  onConfirm: (picks: { home: Position; away: Position; homeNumber: number; awayNumber: number }) => void;
}

const SelectionOverlay: React.FC<SelectionOverlayProps> = ({ homeTeam, awayTeam, onConfirm }) => {
  const [awayPick, setAwayPick] = useState<Position | null>(null);
  const [homePick, setHomePick] = useState<Position | null>(null);
  const [hovered, setHovered] = useState<{ side: 'home' | 'away'; pos: Position } | null>(null);

  // Generate stable random jersey numbers for this session
  const awayNumbers = useMemo(() => {
    return POSITIONS.reduce((acc, pos) => {
      acc[pos.value] = Math.floor(Math.random() * 98) + 1;
      return acc;
    }, {} as Record<Position, number>);
  }, []);

  const homeNumbers = useMemo(() => {
    return POSITIONS.reduce((acc, pos) => {
      acc[pos.value] = Math.floor(Math.random() * 98) + 1;
      return acc;
    }, {} as Record<Position, number>);
  }, []);

  const handleConfirm = () => {
    if (awayPick && homePick) {
      onConfirm({ 
        home: homePick, 
        away: awayPick, 
        homeNumber: homeNumbers[homePick], 
        awayNumber: awayNumbers[awayPick] 
      });
    }
  };

  // Helper to get positioning on the tactical rink
  const getPosCoords = (pos: Position, isHome: boolean) => {
    const baseCoords: Record<Position, { top: string; left: string }> = {
      'G': { top: '50%', left: isHome ? '92%' : '8%' },
      'LD': { top: '30%', left: isHome ? '75%' : '25%' },
      'RD': { top: '70%', left: isHome ? '75%' : '25%' },
      'LW': { top: '22%', left: isHome ? '60%' : '40%' },
      'RW': { top: '78%', left: isHome ? '60%' : '40%' },
      'C': { top: '50%', left: isHome ? '60%' : '40%' },
    };
    return baseCoords[pos];
  };

  const isAwayHovered = hovered?.side === 'away';
  const isHomeHovered = hovered?.side === 'home';

  return (
    <div className="fixed inset-0 z-[100] bg-slate-950/95 backdrop-blur-xl flex items-center justify-center p-4 overflow-y-auto">
      <div className="bg-slate-900 border border-slate-700 w-full max-w-5xl rounded-3xl shadow-[0_0_50px_rgba(0,0,0,0.5)] overflow-hidden animate-in fade-in zoom-in duration-500 my-auto">

        {/* Header */}
        <div className="bg-slate-800/50 p-6 border-b border-slate-700 flex flex-col items-center text-center relative overflow-hidden">
          <div className={`absolute inset-0 opacity-10 transition-colors duration-500 pointer-events-none ${isAwayHovered ? 'bg-amber-500' : isHomeHovered ? 'bg-blue-500' : 'transparent'}`}></div>

          <div className="flex items-center gap-4 mb-2 relative z-10">
            <span className={`text-4xl transition-all duration-300 ${isAwayHovered ? 'scale-150 drop-shadow-[0_0_15px_rgba(245,158,11,0.8)]' : 'opacity-60'}`}>
              {awayTeam.logo}
            </span>
            <div className="h-px w-12 bg-slate-700"></div>
            <h2 className="text-3xl font-black oswald uppercase tracking-tighter text-white">POWERPLAY Selection</h2>
            <div className="h-px w-12 bg-slate-700"></div>
            <span className={`text-4xl transition-all duration-300 ${isHomeHovered ? 'scale-150 drop-shadow-[0_0_15px_rgba(37,99,235,0.8)]' : 'opacity-60'}`}>
              {homeTeam.logo}
            </span>
          </div>
          <p className="text-slate-400 text-[10px] font-black uppercase tracking-[0.3em] relative z-10">Deploy your key players for the next shift</p>
        </div>

        {/* WHITE ICE Rink Container */}
        <div className="relative p-4 sm:p-8 bg-slate-100">
          <div className="relative w-full aspect-[2/1] bg-white rounded-[120px] border-[6px] border-slate-300 overflow-hidden shadow-2xl">
            {/* Ice Scratches and Gloss Texture */}
            <div className="absolute inset-0 bg-[linear-gradient(45deg,rgba(255,255,255,0.8)_25%,transparent_25%,transparent_50%,rgba(255,255,255,0.8)_50%,rgba(255,255,255,0.8)_75%,transparent_75%,transparent)] bg-[size:100px_100px] opacity-10"></div>
            <div className="absolute inset-0 bg-[radial-gradient(ellipse_at_top,rgba(255,255,255,0.9)_0%,transparent_70%)] opacity-50"></div>

            {/* Rink Markings with high contrast on white */}
            <div className="absolute inset-y-0 left-[6%] w-1 bg-red-600/60"></div>
