import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { GameState, Position, GameEvent, FloatingPoint, GoalExplosion, LeaderboardPlayer } from './types';
import { INITIAL_TEAMS } from './constants';
import ScoreBoard from './components/ScoreBoard';
import GameLog from './components/GameLog';
import PickStatus from './components/PickStatus';
import PerformanceSummary from './components/PerformanceSummary';
import Leaderboard from './components/Leaderboard';
import SelectionOverlay from './components/SelectionOverlay';
import { fetchSimulatedEvents } from './services/geminiService';
import { requestNotificationPermission, sendGameNotification, getNotificationStatus } from './services/notificationService';

const App: React.FC = () => {
  const [game, setGame] = useState<GameState>({
    period: 1,
    timeRemaining: '20:00',
    isPaused: false,
    waitingForPicks: true,
    homeTeam: INITIAL_TEAMS.home,
    awayTeam: INITIAL_TEAMS.away,
    userPicks: { home: null, away: null, homeNumber: null, awayNumber: null },
    totalPoints: 0,
    rank: 124,
    totalPlayers: 1542,
    events: [],
    puckPossession: null,
  });

  const [competitors, setCompetitors] = useState<LeaderboardPlayer[]>(() => {
    return Array.from({ length: 49 }, (_, i) => ({
      id: `comp-${i}`,
      name: `User_${Math.floor(Math.random() * 9000) + 1000}`,
      points: Math.max(0, 15000 - (i * 300) + (Math.random() * 500)),
    }));
  });

  const [floatingPoints, setFloatingPoints] = useState<FloatingPoint[]>([]);
  const [explosions, setExplosions] = useState<GoalExplosion[]>([]);
  const [loadingEvents, setLoadingEvents] = useState(false);
  const [notifPermission, setNotifPermission] = useState<NotificationPermission>(getNotificationStatus());
  const tickerRef = useRef<any>(null);

  const leaderboardData = useMemo(() => {
    const userPlayer: LeaderboardPlayer = {
      id: 'user-main',
      name: 'PuckMaster99',
      points: game.totalPoints,
      isUser: true
    };
    return [...competitors, userPlayer];
  }, [competitors, game.totalPoints]);

  useEffect(() => {
    const sorted = [...leaderboardData].sort((a, b) => b.points - a.points);
    const userIndex = sorted.findIndex(p => p.isUser);
    setGame(prev => ({ ...prev, rank: userIndex + 1 }));
  }, [leaderboardData]);

  const updateCompetitors = useCallback(() => {
    setCompetitors(prev => prev.map(comp => {
      const gain = Math.random() > 0.7 ? Math.floor(Math.random() * 1000) : 0;
      return { ...comp, points: comp.points + gain };
    }));
  }, []);

  const triggerGoalExplosion = (team: 'home' | 'away') => {
    const id = Math.random().toString(36).substr(2, 9);
    const color = team === 'home' ? game.homeTeam.color : game.awayTeam.color;
    setExplosions(prev => [...prev, { id, team, color }]);
    setTimeout(() => {
      setExplosions(prev => prev.filter(e => e.id !== id));
    }, 3000);
  };

  const triggerPointsAnimation = (points: number, team: 'home' | 'away', position: Position, isUser: boolean) => {
    const id = Math.random().toString(36).substr(2, 9);
    const newFloatingPoint: FloatingPoint = {
      id,
      points,
      team,
      position,
      isUser,
      xOffset: (Math.random() - 0.5) * 40,
      variant: Math.floor(Math.random() * 3),
    };
    setFloatingPoints(prev => [...prev, newFloatingPoint]);
    setTimeout(() => {
      setFloatingPoints(prev => prev.filter(fp => fp.id !== id));
    }, 2000);
  };

  const processEvents = useCallback(async () => {
    if (loadingEvents || game.waitingForPicks) return;

    setLoadingEvents(true);
    const result = await fetchSimulatedEvents(
      game.period,
      game.timeRemaining,
      game.homeTeam.name,
      game.awayTeam.name
    );

    let newPoints = 0;
    let currentHomeScore = game.homeTeam.score;
    let currentAwayScore = game.awayTeam.score;
    let goalScored = false;
    let scoringTeamType: 'home' | 'away' | null = null;

    const processedEvents = result.events.map(event => {
      if (event.type === 'GOAL') {
        goalScored = true;
        scoringTeamType = event.team as 'home' | 'away';
        if (event.team === 'home') currentHomeScore++;
        else currentAwayScore++;
      }

      const userPickForTeam = event.team === 'home' ? game.userPicks.home : game.userPicks.away;
      const isUserPick = event.position === userPickForTeam;
      const earned = isUserPick ? (event.points || 0) : 0;

      if (earned !== 0) {
        newPoints += earned;
        triggerPointsAnimation(earned, event.team!, event.position!, true);
      } else if (event.points && event.points !== 0) {
        triggerPointsAnimation(event.points!, event.team!, event.position!, false);
      }

      return { 
        ...event, 
        userEarned: earned, 
        homeScoreAtEvent: currentHomeScore, 
        awayScoreAtEvent: currentAwayScore,
        period: game.period 
      } as GameEvent;
    });

    if (goalScored && scoringTeamType) {
      triggerGoalExplosion(scoringTeamType);
    }

    if (result.nextFaceoffTrigger) {
      sendGameNotification("Face-Off!", "Play stopped. Update your picks now!");
    }

    setGame(prev => ({
      ...prev,
      totalPoints: prev.totalPoints + newPoints,
      events: [...processedEvents, ...prev.events].slice(0, 100),
      homeTeam: { ...prev.homeTeam, score: currentHomeScore },
      awayTeam: { ...prev.awayTeam, score: currentAwayScore },
      waitingForPicks: result.nextFaceoffTrigger,
      puckPossession: result.currentPossession,
    }));

    updateCompetitors();
    setLoadingEvents(false);
  }, [game.period, game.timeRemaining, game.homeTeam.name, game.awayTeam.name, game.userPicks, game.waitingForPicks, loadingEvents, game.homeTeam.score, game.awayTeam.score, updateCompetitors]);

  useEffect(() => {
    if (game.waitingForPicks || game.isPaused) return;
    tickerRef.current = setInterval(() => {
      setGame(prev => {
        const [mins, secs] = prev.timeRemaining.split(':').map(Number);
        let totalSecs = mins * 60 + secs - 12;
        if (totalSecs <= 0) {
          if (prev.period < 3) return { ...prev, period: prev.period + 1, timeRemaining: '20:00', waitingForPicks: true, puckPossession: null };
          return { ...prev, isPaused: true, timeRemaining: '00:00', puckPossession: null };
        }
        const newMins = Math.floor(totalSecs / 60);
        const newSecs = totalSecs % 60;
        return { ...prev, timeRemaining: `${newMins.toString().padStart(2, '0')}:${newSecs.toString().padStart(2, '0')}` };
      });
    }, 1000);
    return () => { if (tickerRef.current) clearInterval(tickerRef.current); };
  }, [game.waitingForPicks, game.isPaused]);

  useEffect(() => {
    if (game.waitingForPicks || game.isPaused) return;
    const eventInterval = setInterval(() => { processEvents(); }, 8000);
    return () => clearInterval(eventInterval);
  }, [game.waitingForPicks, game.isPaused, processEvents]);

  const handlePicks = async (picks: { home: Position; away: Position; homeNumber: number; awayNumber: number }) => {
    if (notifPermission === 'default') {
      const granted = await requestNotificationPermission();
      setNotifPermission(granted ? 'granted' : 'denied');
    }
    setGame(prev => ({ ...prev, userPicks: picks, waitingForPicks: false }));
  };

  const openPicks = () => {
    if (game.waitingForPicks) return;
    setGame(prev => ({ ...prev, waitingForPicks: true, puckPossession: null }));
  };

  return (
    <div className="min-h-screen bg-slate-950 text-slate-100 flex flex-col pb-24 relative overflow-hidden">
      {explosions.map(exp => (
        <div key={exp.id} className="fixed inset-0 z-[100] pointer-events-none flex items-center justify-center">
          <div className="absolute inset-0 animate-screen-flash" style={{ backgroundColor: `${exp.color}22` }} />
          <div className="relative">
            <div className="text-8xl font-black oswald uppercase text-white animate-goal-text drop-shadow-[0_0_20px_rgba(255,255,255,0.8)]">GOAL!</div>
            <div className="absolute inset-0 animate-goal-explosion" style={{ background: `radial-gradient(circle, ${exp.color} 0%, transparent 70%)` }} />
          </div>
        </div>
      ))}

      {game.waitingForPicks && (
        <SelectionOverlay 
          homeTeam={game.homeTeam} 
          awayTeam={game.awayTeam} 
          onConfirm={handlePicks} 
          events={game.events}
          puckPossession={game.puckPossession}
        />
      )}

      <ScoreBoard home={game.homeTeam} away={game.awayTeam} period={game.period} time={game.timeRemaining} />

      <main className="flex-1 max-w-6xl mx-auto w-full p-4">
        <div className="flex flex-col lg:flex-row gap-8">

          <div className="flex-1 space-y-8 order-2 lg:order-1">
            <div className="grid grid-cols-2 sm:grid-cols-4 gap-4">
              <div className="bg-slate-900 border border-slate-800 p-4 rounded-xl shadow-lg relative overflow-hidden">
                <div className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-1">Score</div>
                <div className="text-3xl font-black text-amber-500 oswald">{game.totalPoints.toLocaleString()}</div>
              </div>
              <div className="bg-slate-900 border border-slate-800 p-4 rounded-xl shadow-lg relative overflow-hidden">
                <div className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-1">Rank</div>
                <div className="text-3xl font-black text-blue-400 oswald">#{game.rank}</div>
              </div>
              <div className="bg-slate-900 border border-slate-800 p-4 rounded-xl shadow-lg hidden sm:block">
                <div className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-1">Status</div>
                <div className="text-xs font-black text-white uppercase">{game.waitingForPicks ? 'Drafting Lines' : 'POWERPLAY Active'}</div>
              </div>
              <div className="bg-slate-900 border border-slate-800 p-4 rounded-xl shadow-lg hidden sm:block">
                <div className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-1">Active Players</div>
                <div className="text-3xl font-black text-slate-300 oswald">{game.totalPlayers.toLocaleString()}</div>
              </div>
            </div>

            <div className="bg-slate-900/50 border border-slate-800 rounded-2xl overflow-hidden flex flex-col">
              <div className="bg-slate-800 px-6 py-4 border-b border-slate-700 flex justify-between items-center">
                <h2 className="text-sm font-black uppercase tracking-widest text-slate-200 flex items-center gap-2">
                  <i className="fa-solid fa-satellite-dish text-red-500 animate-pulse"></i> POWERPLAY Live Feed
                </h2>
                {loadingEvents && <div className="text-[10px] font-bold text-slate-500 uppercase animate-pulse"><i className="fa-solid fa-spinner fa-spin mr-1"></i>Simulating...</div>}
              </div>
              <div className="overflow-y-auto p-4 space-y-4 max-h-[450px] scroll-smooth">
                {game.events.length === 0 ? (
                  <div className="h-40 flex flex-col items-center justify-center text-slate-600">
                    <i className="fa-solid fa-hockey-puck text-4xl mb-4 opacity-20"></i>
                    <p className="font-bold uppercase tracking-wider text-[10px]">Puck is currently in the air...</p>
                  </div>
                ) : (
                  game.events.slice(0, 15).map((event) => {
                    const isUserPositive = (event.userEarned || 0) > 0;
                    const isUserNegative = (event.userEarned || 0) < 0;
                    return (
                      <div key={`live-${event.id}`} className={`flex items-start gap-4 p-4 rounded-xl border transition-all animate-in slide-in-from-right duration-500 relative overflow-hidden ${isUserPositive ? 'bg-green-900/10 border-green-500/40' : isUserNegative ? 'bg-red-900/10 border-red-500/40' : 'bg-slate-800/40 border-slate-700'}`}>
                        <div className={`w-10 h-10 rounded-full flex-shrink-0 flex items-center justify-center font-black text-xs border-2 shadow-lg z-10 ${event.team === 'home' ? 'bg-blue-600 border-blue-400 text-white' : 'bg-amber-500 border-amber-300 text-slate-950'}`}>{event.position}</div>
                        <div className="flex-1 z-10">
                          <div className="text-[9px] font-bold text-slate-500 uppercase mb-1">{event.gameTime} • {event.type.replace('_', ' ')}</div>
                          <p className="text-sm text-slate-100 font-medium">{event.description}</p>
                        </div>
                        {event.userEarned !== 0 && <div className={`text-right font-black oswald text-xl min-w-[60px] z-10 ${isUserPositive ? 'text-green-400' : 'text-red-400'}`}>{isUserPositive ? '+' : ''}{event.userEarned}</div>}
                      </div>
                    );
                  })
                )}
              </div>
            </div>
            <PerformanceSummary events={game.events} />
            <GameLog events={game.events} homeTeam={game.homeTeam} awayTeam={game.awayTeam} />
          </div>

          <div className="lg:w-80 order-1 lg:order-2">
            <div className="lg:sticky lg:top-24 space-y-6 flex flex-col min-h-screen">
              <div className={`bg-slate-900 border border-slate-800 rounded-3xl p-4 shadow-2xl transition-all duration-500 ${game.waitingForPicks ? 'ring-2 ring-amber-500/30' : ''}`}>
                <div className="flex justify-between items-center mb-4">
                   <div className="text-[9px] font-black text-slate-500 uppercase tracking-widest flex items-center gap-2">
                      Tactical Command
                      <span className={`w-1.5 h-1.5 rounded-full ${game.waitingForPicks ? 'bg-amber-500 animate-pulse' : 'bg-green-500'}`}></span>
                   </div>
                   <div className={`text-[8px] font-black px-2 py-0.5 rounded uppercase ${game.waitingForPicks ? 'bg-amber-500/20 text-amber-500' : 'bg-slate-800 text-slate-500'}`}>
                    {game.waitingForPicks ? 'Update Lineup' : 'Picks Locked'}
                   </div>
                </div>

                <PickStatus 
                  homeTeam={game.homeTeam} 
                  awayTeam={game.awayTeam} 
                  userPicks={game.userPicks} 
                  floatingPoints={floatingPoints}
                  isSelecting={game.waitingForPicks}
                  onConfirmPicks={handlePicks}
                  puckPossession={game.puckPossession}
                />
              </div>

              <div className="bg-slate-900 border border-slate-800 p-5 rounded-2xl">
                <h3 className="text-xs font-black text-slate-200 uppercase tracking-widest mb-4">Scoring Key</h3>
                <div className="space-y-2">
                  <div className="flex justify-between text-[10px] font-bold text-slate-500 uppercase"><span>Goal</span><span className="text-green-400">+5000</span></div>
                  <div className="flex justify-between text-[10px] font-bold text-slate-500 uppercase"><span>Assist</span><span className="text-blue-400">+1000</span></div>
                  <div className="flex justify-between text-[10px] font-bold text-slate-500 uppercase"><span>Save</span><span className="text-green-400">+250</span></div>
                  <div className="flex justify-between text-[10px] font-bold text-slate-500 uppercase"><span>Hit/Shot</span><span className="text-slate-300">+200</span></div>
                  <div className="flex justify-between text-[10px] font-bold text-slate-500 uppercase"><span>Giveaway</span><span className="text-red-400">-200</span></div>
                </div>
              </div>

              <div className="flex-1">
                <Leaderboard players={leaderboardData} userPoints={game.totalPoints} userRank={game.rank} />
              </div>
            </div>
          </div>
        </div>
      </main>

      <footer className="fixed bottom-0 left-0 right-0 bg-slate-900/90 border-t border-slate-800 p-4 sm:p-6 shadow-2xl z-40 backdrop-blur-md">
        <div className="max-w-6xl mx-auto flex items-center justify-between gap-4">
          <div className="flex items-center gap-6">
            <div>
              <div className="text-[10px] font-bold text-slate-500 uppercase mb-1">POWERPLAY Points</div>
              <div className="text-3xl font-black oswald text-amber-500 leading-none">{game.totalPoints.toLocaleString()}</div>
            </div>
            <div className="h-8 w-[1px] bg-slate-800"></div>
            <div>
              <div className="text-[10px] font-bold text-slate-500 uppercase mb-1">Current Rank</div>
              <div className="text-2xl font-black oswald text-white leading-none">#{game.rank}</div>
            </div>
          </div>

          <div className="flex items-center gap-4">
            {!game.waitingForPicks && (
              <div className="hidden md:flex flex-col items-end">
                <span className="text-[9px] font-black text-slate-500 uppercase tracking-widest">Picks Locked</span>
                <span className="text-[10px] font-bold text-slate-400 italic">Wait for stoppage to edit</span>
              </div>
            )}
            <button 
              onClick={openPicks} 
              disabled={game.waitingForPicks} 
              className={`px-8 py-3 rounded-xl font-black oswald text-lg uppercase tracking-widest transition-all active:scale-95 ${
                !game.waitingForPicks 
                ? 'bg-blue-600 hover:bg-blue-500 text-white shadow-lg shadow-blue-900/30 ring-2 ring-blue-400/50' 
                : 'bg-slate-800 text-slate-600 border border-slate-700 cursor-not-allowed'
              }`}
            >
              {game.waitingForPicks ? 'Drafting Open' : 'Change Lineup'}
            </button>
          </div>
        </div>
      </footer>

      <style>{`
        @keyframes screen-flash { 0% { opacity: 0; } 10% { opacity: 1; } 100% { opacity: 0; } }
        @keyframes goal-text { 0% { transform: scale(0.5); opacity: 0; filter: blur(10px); } 20% { transform: scale(1.2); opacity: 1; filter: blur(0); } 80% { transform: scale(1.1); opacity: 1; } 100% { transform: scale(1.5); opacity: 0; filter: blur(20px); } }
        @keyframes goal-explosion { 0% { transform: scale(0); opacity: 0.8; } 100% { transform: scale(4); opacity: 0; } }
        .animate-screen-flash { animation: screen-flash 1.5s ease-out forwards; }
        .animate-goal-text { animation: goal-text 2s cubic-bezier(0.17, 0.67, 0.83, 0.67) forwards; }
        .animate-goal-explosion { animation: goal-explosion 1s ease-out forwards; }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { Position, TeamInfo, GameEvent } from '../types';
import { POSITIONS } from '../constants';

interface SelectionOverlayProps {
  homeTeam: TeamInfo;
  awayTeam: TeamInfo;
  onConfirm: (picks: { home: Position; away: Position; homeNumber: number; awayNumber: number }) => void;
  events: GameEvent[];
  puckPossession?: { team: 'home' | 'away'; position: Position } | null;
}

const PLAYER_NAMES: Record<string, Record<Position, string>> = {
  'Rangers': { 'C': 'M. Zibanejad', 'LW': 'A. Panarin', 'RW': 'A. Lafreniere', 'LD': 'R. Lindgren', 'RD': 'A. Fox', 'G': 'I. Shesterkin' },
  'Bruins': { 'C': 'C. Coyle', 'LW': 'B. Marchand', 'RW': 'D. Pastrnak', 'LD': 'H. Lindholm', 'RD': 'C. McAvoy', 'G': 'J. Swayman' }
};

const SelectionOverlay: React.FC<SelectionOverlayProps> = ({ homeTeam, awayTeam, onConfirm, events, puckPossession }) => {
  const [awayPick, setAwayPick] = useState<Position | null>(null);
  const [homePick, setHomePick] = useState<Position | null>(null);
  const [hovered, setHovered] = useState<{ side: 'home' | 'away'; pos: Position } | null>(null);
  const [flash, setFlash] = useState<{ side: 'home' | 'away'; pos: Position; type: 'green' | 'red' } | null>(null);
  const prevPossessionRef = useRef<{ team: 'home' | 'away'; position: Position } | null>(null);

  // Generate stable random jersey numbers for this session
  const awayNumbers = useMemo(() => {
    return POSITIONS.reduce((acc, pos) => {
      acc[pos.value] = Math.floor(Math.random() * 98) + 1;
      return acc;
    }, {} as Record<Position, number>);
  }, []);

  const homeNumbers = useMemo(() => {
    return POSITIONS.reduce((acc, pos) => {
      acc[pos.value] = Math.floor(Math.random() * 98) + 1;
      return acc;
    }, {} as Record<Position, number>);
  }, []);

  const triggerFlash = (side: 'home' | 'away', pos: Position, type: 'green' | 'red') => {
    setFlash({ side, pos, type });
    setTimeout(() => setFlash(null), 1500); // Changed to 1.5s as requested
  };

  // Trigger flash when puck possession changes
  useEffect(() => {
    if (puckPossession && (
      puckPossession.team !== prevPossessionRef.current?.team || 
      puckPossession.position !== prevPossessionRef.current?.position
    )) {
      triggerFlash(puckPossession.team, puckPossession.position, 'green');
    }
    prevPossessionRef.current = puckPossession || null;
  }, [puckPossession]);

  const handleConfirm = () => {
    if (awayPick && homePick) {
      onConfirm({ 
        home: homePick, 
        away: awayPick, 
        homeNumber: homeNumbers[homePick], 
        awayNumber: awayNumbers[awayPick] 
      });
    }
  };

  const handlePick = (side: 'home' | 'away', pos: Position) => {
    const current = side === 'home' ? homePick : awayPick;
    if (current === pos) {
      triggerFlash(side, pos, 'red');
    } else {
      triggerFlash(side, pos, 'green');
      if (side === 'home') setHomePick(pos);
      else setAwayPick(pos);
    }
  };

  const getPlayerStats = (side: 'home' | 'away', pos: Position) => {
    const playerEvents = events.filter(e => e.team === side && e.position === pos);
    return {
      goals: playerEvents.filter(e => e.type === 'GOAL').length,
      assists: playerEvents.filter(e => e.type === 'ASSIST').length,
      hits: playerEvents.filter(e => e.type === 'HIT').length,
      shots: playerEvents.filter(e => e.type === 'SHOT').length,
      saves: playerEvents.filter(e => e.type === 'SAVE').length,
    };
  };

  const getPlayerName = (teamName: string, pos: Position) => {
    return PLAYER_NAMES[teamName]?.[pos] || `${pos} Star Player`;
  };

  // Helper to get positioning on the tactical rink
  const getPosCoords = (pos: Position, isHome: boolean) => {
    const baseCoords: Record<Position, { top: string; left: string }> = {
      'G': { top: '50%', left: isHome ? '92%' : '8%' },
      'LD': { top: '30%', left: isHome ? '75%' : '25%' },
      'RD': { top: '70%', left: isHome ? '75%' : '25%' },
      'LW': { top: '22%', left: isHome ? '60%' : '40%' },
      'RW': { top: '78%', left: isHome ? '60%' : '40%' },
      'C': { top: '50%', left: isHome ? '60%' : '40%' },
    };
    return baseCoords[pos];
  };

  // Calculate smart position for tooltip
  const getTooltipStyle = () => {
    if (!hovered) return {};
    const coords = getPosCoords(hovered.pos, hovered.side === 'home');
    const topVal = parseInt(coords.top);

    // Vertical Logic: If in the top 40% of the rink, display tooltip BELOW the dot. Otherwise ABOVE.
    const verticalOffset = topVal < 40 ? '40px' : '-160px';

    // Horizontal Logic: If on the home side (right), display to the LEFT. Otherwise to the RIGHT.
    const horizontalOffset = hovered.side === 'home' ? '-210px' : '30px';

    return {
      top: `calc(${coords.top} + ${verticalOffset})`,
      left: `calc(${coords.left} + ${horizontalOffset})`
    };
  };

  const isAwayHovered = hovered?.side === 'away';
  const isHomeHovered = hovered?.side === 'home';

  return (
    <div className="fixed inset-0 z-[100] bg-slate-950/95 backdrop-blur-xl flex items-center justify-center p-4 overflow-y-auto">
      <div className="bg-slate-900 border border-slate-700 w-full max-w-5xl rounded-3xl shadow-[0_0_50px_rgba(0,0,0,0.5)] overflow-hidden animate-in fade-in zoom-in duration-500 my-auto">

        {/* Header */}
        <div className="bg-slate-800/50 p-6 border-b border-slate-700 flex flex-col items-center text-center relative overflow-hidden">
          <div className={`absolute inset-0 opacity-10 transition-colors duration-500 pointer-events-none ${isAwayHovered ? 'bg-amber-500' : isHomeHovered ? 'bg-blue-500' : 'transparent'}`}></div>

          <div className="flex items-center gap-4 mb-2 relative z-10">
            <span className={`text-4xl transition-all duration-300 ${isAwayHovered ? 'scale-150 drop-shadow-[0_0_15px_rgba(245,158,11,0.8)]' : 'opacity-60'}`}>
              {awayTeam.logo}
            </span>
            <div className="h-px w-12 bg-slate-700"></div>
            <h2 className="text-3xl font-black oswald uppercase tracking-tighter text-white">POWERPLAY Selection</h2>
            <div className="h-px w-12 bg-slate-700"></div>
            <span className={`text-4xl transition-all duration-300 ${isHomeHovered ? 'scale-150 drop-shadow-[0_0_15px_rgba(37,99,235,0.8)]' : 'opacity-60'}`}>
              {homeTeam.logo}
            </span>
          </div>
          <p className="text-slate-400 text-[10px] font-black uppercase tracking-[0.3em] relative z-10">Deploy your key players for the next shift</p>
        </div>

        {/* WHITE ICE Rink Container */}
        <div className="relative p-4 sm:p-8 bg-slate-200">
          <div className="relative w-full aspect-[2/1] bg-white rounded-[120px] border-[6px] border-slate-300 overflow-hidden shadow-inner">
            <div className="absolute inset-0 bg-[radial-gradient(ellipse_at_center,rgba(224,242,254,0.4)_0%,transparent_80%)]"></div>
            <div className="absolute inset-0 opacity-[0.03] pointer-events-none bg-[url('https://www.transparenttextures.com/patterns/scratched-metal.png')]"></div>

            <div className="absolute inset-y-0 left-[6%] w-1 bg-red-600/60"></div>
            <div className="absolute inset-y-0 right-[6%] w-1 bg-red-600/60"></div>
            <div className="absolute inset-y-0 left-1/2 w-2 bg-red-600/80 -translate-x-1/2"></div>
            <div className="absolute top-1/2 left-1/2 w-4 h-4 bg-red-600 rounded-full -translate-x-1/2 -translate-y-1/2 shadow-sm"></div>

            <div className="absolute inset-y-0 left-[35%] w-3 bg-blue-600/70"></div>
            <div className="absolute inset-y-0 right-[35%] w-3 bg-blue-600/70"></div>

            {[
              { top: '22%', left: '18%' },
              { top: '22%', left: '82%' },
              { top: '78%', left: '18%' },
              { top: '78%', left: '82%' }
            ].map((coords, i) => (
              <div key={i} style={{ top: coords.top, left: coords.left }} className="absolute w-2 h-2 bg-red-600/40 rounded-full -translate-x-1/2 -translate-y-1/2"></div>
            ))}

            <div className="absolute top-1/2 left-[6%] w-6 h-12 border-2 border-blue-500/30 bg-blue-100/30 rounded-r-full -translate-y-1/2"></div>
            <div className="absolute top-1/2 right-[6%] w-6 h-12 border-2 border-blue-500/30 bg-blue-100/30 rounded-l-full -translate-y-1/2"></div>

            <div className={`absolute top-6 left-16 oswald font-black uppercase tracking-widest text-3xl pointer-events-none transition-all duration-300 ${isAwayHovered ? 'text-amber-500 opacity-100' : 'text-slate-200'}`}>{awayTeam.name}</div>
            <div className={`absolute top-6 right-16 oswald font-black uppercase tracking-widest text-3xl pointer-events-none text-right transition-all duration-300 ${isHomeHovered ? 'text-blue-500 opacity-100' : 'text-slate-200'}`}>{homeTeam.name}</div>

            {/* Tactical Tooltip with Smart Positioning */}
            {hovered && (
              <div 
                className={`absolute z-[200] w-48 bg-slate-900/95 backdrop-blur-md border border-slate-700 rounded-2xl p-4 shadow-2xl pointer-events-none animate-in zoom-in-95 fade-in duration-200`}
                style={getTooltipStyle()}
              >
                <div className="flex items-center justify-between mb-2">
                  <span className="text-xs font-black oswald uppercase tracking-wider text-white">
                    {getPlayerName(hovered.side === 'home' ? homeTeam.name : awayTeam.name, hovered.pos)}
                  </span>
                  <span className={`text-[10px] font-bold px-1.5 py-0.5 rounded ${hovered.side === 'home' ? 'bg-blue-600 text-white' : 'bg-amber-500 text-slate-950'}`}>
                    #{hovered.side === 'home' ? homeNumbers[hovered.pos] : awayNumbers[hovered.pos]}
                  </span>
                </div>

                <div className="grid grid-cols-2 gap-2 mt-2 pt-2 border-t border-slate-800">
                  {hovered.pos === 'G' ? (
                    <>
                      <div className="flex justify-between items-center">
                        <span className="text-[9px] font-bold text-slate-500 uppercase">Saves</span>
                        <span className="text-[10px] font-black text-green-400">{getPlayerStats(hovered.side, hovered.pos).saves}</span>
                      </div>
                      <div className="flex justify-between items-center">
                        <span className="text-[9px] font-bold text-slate-500 uppercase">G.A.</span>
                        <span className="text-[10px] font-black text-red-400">0</span>
                      </div>
                    </>
                  ) : (
                    <>
                      <div className="flex justify-between items-center">
                        <span className="text-[9px] font-bold text-slate-500 uppercase">Goals</span>
                        <span className="text-[10px] font-black text-white">{getPlayerStats(hovered.side, hovered.pos).goals}</span>
                      </div>
                      <div className="flex justify-between items-center">
                        <span className="text-[9px] font-bold text-slate-500 uppercase">Assts</span>
                        <span className="text-[10px] font-black text-white">{getPlayerStats(hovered.side, hovered.pos).assists}</span>
                      </div>
                      <div className="flex justify-between items-center">
                        <span className="text-[9px] font-bold text-slate-500 uppercase">Hits</span>
                        <span className="text-[10px] font-black text-slate-300">{getPlayerStats(hovered.side, hovered.pos).hits}</span>
                      </div>
                      <div className="flex justify-between items-center">
                        <span className="text-[9px] font-bold text-slate-500 uppercase">Shots</span>
                        <span className="text-[10px] font-black text-slate-300">{getPlayerStats(hovered.side, hovered.pos).shots}</span>
                      </div>
                    </>
                  )}
                </div>
              </div>
            )}

            {/* Away Positions */}
            {POSITIONS.map((pos) => {
              const coords = getPosCoords(pos.value, false);
              const isSelected = awayPick === pos.value;
              const isThisHovered = hovered?.side === 'away' && hovered?.pos === pos.value;
              const isFlashing = flash?.side === 'away' && flash?.pos === pos.value;
              const flashClass = isFlashing ? (flash?.type === 'green' ? 'animate-flash-green' : 'animate-flash-red') : '';

              return (
                <button
                  key={`tactical-away-${pos.value}`}
                  onMouseEnter={() => setHovered({ side: 'away', pos: pos.value })}
                  onMouseLeave={() => setHovered(null)}
                  onClick={() => handlePick('away', pos.value)}
                  style={{ top: coords.top, left: coords.left }}
                  className={`absolute -translate-x-1/2 -translate-y-1/2 w-8 h-8 sm:w-9 sm:h-9 rounded-full flex flex-col items-center justify-center transition-all z-10 shadow-md ${
                    isSelected
                      ? 'bg-amber-500 text-slate-950 border-2 border-white scale-110 ring-4 ring-amber-500/30'
                      : isThisHovered 
                        ? 'bg-amber-500/20 text-amber-600 border-2 border-amber-500 scale-125'
                        : 'bg-slate-800 text-white border-2 border-slate-600 hover:border-amber-500/50'
                  } ${flashClass}`}
                >
                  <div className={`absolute -top-1 -right-1 bg-white text-[7px] font-black px-1 py-0.5 rounded-full border shadow-sm transition-all ${isSelected || isThisHovered ? 'text-amber-600 border-amber-500' : 'text-slate-400 border-slate-300'}`}>#{awayNumbers[pos.value]}</div>
                  <span className="text-[10px] sm:text-xs font-black oswald leading-none">{pos.value}</span>
                </button>
              );
            })}

            {/* Home Positions */}
            {POSITIONS.map((pos) => {
              const coords = getPosCoords(pos.value, true);
              const isSelected = homePick === pos.value;
              const isThisHovered = hovered?.side === 'home' && hovered?.pos === pos.value;
              const isFlashing = flash?.side === 'home' && flash?.pos === pos.value;
              const flashClass = isFlashing ? (flash?.type === 'green' ? 'animate-flash-green' : 'animate-flash-red') : '';

              return (
                <button
                  key={`tactical-home-${pos.value}`}
                  onMouseEnter={() => setHovered({ side: 'home', pos: pos.value })}
                  onMouseLeave={() => setHovered(null)}
                  onClick={() => handlePick('home', pos.value)}
                  style={{ top: coords.top, left: coords.left }}
                  className={`absolute -translate-x-1/2 -translate-y-1/2 w-8 h-8 sm:w-9 sm:h-9 rounded-full flex flex-col items-center justify-center transition-all z-10 shadow-md ${
                    isSelected
                      ? 'bg-blue-600 text-white border-2 border-white scale-110 ring-4 ring-blue-600/30'
                      : isThisHovered
                        ? 'bg-blue-600/20 text-blue-600 border-2 border-blue-400 scale-125'
                        : 'bg-slate-800 text-white border-2 border-slate-600 hover:border-blue-400/50'
                  } ${flashClass}`}
                >
                  <div className={`absolute -top-1 -right-1 bg-white text-[7px] font-black px-1 py-0.5 rounded-full border shadow-sm transition-all ${isSelected || isThisHovered ? 'text-blue-600 border-blue-500' : 'text-slate-400 border-slate-300'}`}>#{homeNumbers[pos.value]}</div>
                  <span className="text-[10px] sm:text-xs font-black oswald leading-none">{pos.value}</span>
                </button>
              );
            })}
          </div>
        </div>

        <div className="p-8 bg-slate-900 border-t border-slate-700 flex flex-col sm:flex-row items-center justify-between gap-6">
          <div className="flex gap-8">
            <div className="flex flex-col">
              <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-1">Away Draft</span>
              <span className="text-sm font-black oswald text-amber-500">{awayPick ? `${awayPick} (#${awayNumbers[awayPick]})` : 'PENDING'}</span>
            </div>
            <div className="flex flex-col">
              <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-1">Home Draft</span>
              <span className="text-sm font-black oswald text-blue-400">{homePick ? `${homePick} (#${homeNumbers[homePick]})` : 'PENDING'}</span>
            </div>
          </div>

          <button
            disabled={!awayPick || !homePick}
            onClick={handleConfirm}
            className={`w-full sm:w-72 py-4 rounded-2xl font-black oswald text-2xl uppercase tracking-[0.1em] transition-all ${
              awayPick && homePick
                ? 'bg-blue-600 hover:bg-blue-500 text-white shadow-xl active:scale-95'
                : 'bg-slate-800 text-slate-600 cursor-not-allowed'
            }`}
          >
            {awayPick && homePick ? 'LOCK ROSTER' : 'SELECT PLAYERS'}
          </button>
        </div>
      </div>
    </div>
  );
};

export default SelectionOverlay;

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { Position, TeamInfo, FloatingPoint } from '../types';
import { POSITIONS } from '../constants';

interface PickStatusProps {
  homeTeam: TeamInfo;
  awayTeam: TeamInfo;
  userPicks: { home: Position | null; away: Position | null; homeNumber: number | null; awayNumber: number | null };
  floatingPoints: FloatingPoint[];
  isSelecting: boolean;
  onConfirmPicks: (picks: { home: Position; away: Position; homeNumber: number; awayNumber: number }) => void;
  puckPossession?: { team: 'home' | 'away'; position: Position } | null;
}

const PickStatus: React.FC<PickStatusProps> = ({ 
  homeTeam, 
  awayTeam, 
  userPicks, 
  floatingPoints, 
  isSelecting,
  onConfirmPicks,
  puckPossession
}) => {
  const [draftAway, setDraftAway] = useState<Position | null>(userPicks.away);
  const [draftHome, setDraftHome] = useState<Position | null>(userPicks.home);
  const [possessionFlash, setPossessionFlash] = useState<{ team: 'home' | 'away'; position: Position } | null>(null);
  const prevPossessionRef = useRef<{ team: 'home' | 'away'; position: Position } | null>(null);

  const numbers = useMemo(() => {
    const res: Record<string, number> = {};
    POSITIONS.forEach(p => {
      res[`away-${p.value}`] = Math.floor(Math.random() * 98) + 1;
      res[`home-${p.value}`] = Math.floor(Math.random() * 98) + 1;
    });
    return res;
  }, []);

  // Detect possession changes for 1.5s flash
  useEffect(() => {
    if (puckPossession && (
      puckPossession.team !== prevPossessionRef.current?.team || 
      puckPossession.position !== prevPossessionRef.current?.position
    )) {
      setPossessionFlash({ team: puckPossession.team, position: puckPossession.position });
      setTimeout(() => setPossessionFlash(null), 1500);
    }
    prevPossessionRef.current = puckPossession || null;
  }, [puckPossession]);

  const handleConfirm = () => {
    if (draftAway && draftHome) {
      onConfirmPicks({
        away: draftAway,
        home: draftHome,
        awayNumber: numbers[`away-${draftAway}`],
        homeNumber: numbers[`home-${draftHome}`]
      });
    }
  };

  const getPosCoords = (pos: Position, isHome: boolean) => {
    const baseCoords: Record<Position, { top: string; left: string }> = {
      'G': { top: '50%', left: isHome ? '92%' : '8%' },
      'LD': { top: '30%', left: isHome ? '75%' : '25%' },
      'RD': { top: '70%', left: isHome ? '75%' : '25%' },
      'LW': { top: '22%', left: isHome ? '60%' : '40%' },
      'RW': { top: '78%', left: isHome ? '60%' : '40%' },
      'C': { top: '50%', left: isHome ? '60%' : '40%' },
    };
    return baseCoords[pos];
  };

  return (
    <div className="flex flex-col gap-4">
      {/* Premium WHITE ICE Tactical Rink */}
      <div className={`relative w-full aspect-[1.5/1] bg-white rounded-[40px] border-[4px] overflow-hidden shadow-2xl transition-all duration-500 ${isSelecting ? 'border-blue-500/50' : 'border-slate-300'}`}>
        <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,rgba(224,242,254,0.3)_0%,transparent_100%)]"></div>
        <div className="absolute inset-0 bg-[linear-gradient(rgba(100,116,139,0.05)_1px,transparent_1px),linear-gradient(90deg,rgba(100,116,139,0.05)_1px,transparent_1px)] bg-[size:10px_10px]"></div>

        <div className="absolute inset-y-0 left-[6%] w-0.5 bg-red-600/40"></div>
        <div className="absolute inset-y-0 right-[6%] w-0.5 bg-red-600/40"></div>
        <div className="absolute inset-y-0 left-1/2 w-1 bg-red-600/60 -translate-x-1/2"></div>
        <div className="absolute top-1/2 left-1/2 w-1.5 h-1.5 bg-red-600 rounded-full -translate-x-1/2 -translate-y-1/2"></div>

        <div className="absolute inset-y-0 left-[35%] w-1.5 bg-blue-600/50"></div>
        <div className="absolute inset-y-0 right-[35%] w-1.5 bg-blue-600/50"></div>

        <div className="absolute top-2 left-4 oswald font-black text-slate-300 text-[10px] uppercase pointer-events-none">{awayTeam.name}</div>
        <div className="absolute top-2 right-4 oswald font-black text-slate-300 text-[10px] uppercase text-right pointer-events-none">{homeTeam.name}</div>

        {['away', 'home'].map((side) => 
          POSITIONS.map((p) => {
            const isHomeSide = side === 'home';
            const coords = getPosCoords(p.value, isHomeSide);
            const isDrafted = isHomeSide ? draftHome === p.value : draftAway === p.value;
            const isConfirmed = isHomeSide ? userPicks.home === p.value : userPicks.away === p.value;
            const isSelected = isSelecting ? isDrafted : isConfirmed;

            const hasPuck = puckPossession?.team === side && puckPossession?.position === p.value;
            const isFlashing = possessionFlash?.team === side && possessionFlash?.position === p.value;
            const activePoint = floatingPoints.find(fp => fp.team === side && fp.position === p.value);

            // Combine flash classes
            const flashClass = [
              activePoint ? (activePoint.points > 0 ? 'animate-flash-green' : 'animate-flash-red') : '',
              isFlashing ? 'animate-flash-green' : ''
            ].filter(Boolean).join(' ');

            return (
              <div
                key={`sidebar-rink-${side}-${p.value}`}
                style={{ top: coords.top, left: coords.left }}
                className="absolute -translate-x-1/2 -translate-y-1/2 z-20"
              >
                <button
                  disabled={!isSelecting}
                  onClick={() => isSelecting && (isHomeSide ? setDraftHome(p.value) : setDraftAway(p.value))}
                  className={`relative w-6 h-6 sm:w-7 sm:h-7 rounded-full flex flex-col items-center justify-center transition-all border-2 shadow-sm ${
                    hasPuck 
                      ? 'bg-green-500 border-white scale-125 ring-4 ring-green-400/50 z-30'
                      : isSelected 
                        ? (isHomeSide ? 'bg-blue-600 border-white scale-110' : 'bg-amber-500 border-white scale-110 text-slate-950') 
                        : 'bg-slate-800 text-slate-400 border-slate-600'
                  } ${isSelecting ? 'cursor-pointer hover:scale-110 active:scale-95' : 'cursor-default'} ${flashClass}`}
                >
                  <span className="text-[8px] font-black oswald leading-none">{p.value}</span>
                  {isSelected && (
                    <span className="text-[5px] font-bold opacity-80 leading-tight">
                      #{isSelecting ? (numbers[`${side}-${p.value}`] || '??') : (isHomeSide ? userPicks.homeNumber : userPicks.awayNumber)}
                    </span>
                  )}
                  {hasPuck && <div className="absolute -bottom-1 -right-1 w-2.5 h-2.5 bg-black rounded-full border border-white flex items-center justify-center text-[5px]">P</div>}
                </button>

                {floatingPoints.filter(fp => fp.team === side && fp.position === p.value).map(fp => (
                  <div 
                    key={fp.id} 
                    style={{ left: `${fp.xOffset}px`, animation: 'float-up-rink 2s ease-out forwards' }} 
                    className={`absolute bottom-full mb-1 font-black oswald text-lg whitespace-nowrap z-50 drop-shadow-md flex flex-col items-center ${fp.isUser ? (fp.points > 0 ? 'text-green-500' : 'text-red-500') : 'text-slate-400 scale-75 opacity-50'}`}
                  >
                    <span>{fp.points > 0 ? '+' : ''}{fp.points}</span>
                  </div>
                ))}
              </div>
            );
          })
        )}
      </div>

      <div className="space-y-3">
        {isSelecting ? (
          <div className="space-y-3 animate-in fade-in duration-300">
            <div className="grid grid-cols-2 gap-2">
              <div className="bg-slate-900 border border-slate-800 rounded-lg p-2 flex flex-col items-center">
                <span className="text-[8px] font-bold text-slate-500 uppercase block">Away</span>
                <span className="text-sm font-black oswald text-amber-500">{draftAway || '---'}</span>
              </div>
              <div className="bg-slate-900 border border-slate-800 rounded-lg p-2 flex flex-col items-center">
                <span className="text-[8px] font-bold text-slate-500 uppercase block">Home</span>
                <span className="text-sm font-black oswald text-blue-400">{draftHome || '---'}</span>
              </div>
            </div>
            <button 
              onClick={handleConfirm} 
              disabled={!draftAway || !draftHome}
              className={`w-full py-3.5 rounded-xl font-black oswald text-lg uppercase tracking-widest transition-all ${draftAway && draftHome ? 'bg-blue-600 text-white shadow-xl shadow-blue-900/40 active:scale-95' : 'bg-slate-800 text-slate-600'}`}
            >
              Lock POWERPLAY
            </button>
          </div>
        ) : (
          <div className="grid grid-cols-2 gap-3 animate-in fade-in duration-300">
            <div className={`rounded-xl p-3 flex flex-col items-center shadow-sm border transition-all ${puckPossession?.team === 'away' ? 'bg-green-500/10 border-green-500 shadow-green-500/20' : 'bg-amber-500/5 border-amber-500/20'}`}>
              <span className="text-[8px] font-black uppercase tracking-widest mb-1">{puckPossession?.team === 'away' ? 'Puck Carrier' : 'Away Track'}</span>
              <span className="text-xl font-black oswald text-white leading-none">{userPicks.away}</span>
              <span className="text-[10px] font-bold text-amber-500">#{userPicks.awayNumber}</span>
            </div>
            <div className={`rounded-xl p-3 flex flex-col items-center shadow-sm border transition-all ${puckPossession?.team === 'home' ? 'bg-green-500/10 border-green-500 shadow-green-500/20' : 'bg-blue-600/5 border-blue-600/20'}`}>
              <span className="text-[8px] font-black uppercase tracking-widest mb-1">{puckPossession?.team === 'home' ? 'Puck Carrier' : 'Home Track'}</span>
              <span className="text-xl font-black oswald text-white leading-none">{userPicks.home}</span>
              <span className="text-[10px] font-bold text-blue-400">#{userPicks.homeNumber}</span>
            </div>
          </div>
        )}
      </div>

      <style>{`
        @keyframes float-up-rink {
          0% { transform: translateY(0) scale(0.8); opacity: 0; }
          15% { transform: translateY(-5px) scale(1.1); opacity: 1; }
          100% { transform: translateY(-60px) scale(1.2); opacity: 0; }
        }
      `}</style>
    </div>
  );
};

export default PickStatus;

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { Position, TeamInfo, GameEvent } from '../types';
import { POSITIONS } from '../constants';

interface SelectionOverlayProps {
  homeTeam: TeamInfo;
  awayTeam: TeamInfo;
  onConfirm: (picks: { home: Position; away: Position; homeNumber: number; awayNumber: number }) => void;
  events: GameEvent[];
  puckPossession?: { team: 'home' | 'away'; position: Position } | null;
}

const PLAYER_NAMES: Record<string, Record<Position, string>> = {
  'Rangers': { 'C': 'M. Zibanejad', 'LW': 'A. Panarin', 'RW': 'A. Lafreniere', 'LD': 'R. Lindgren', 'RD': 'A. Fox', 'G': 'I. Shesterkin' },
  'Bruins': { 'C': 'C. Coyle', 'LW': 'B. Marchand', 'RW': 'D. Pastrnak', 'LD': 'H. Lindholm', 'RD': 'C. McAvoy', 'G': 'J. Swayman' }
};

const SelectionOverlay: React.FC<SelectionOverlayProps> = ({ homeTeam, awayTeam, onConfirm, events, puckPossession }) => {
  const [awayPick, setAwayPick] = useState<Position | null>(null);
  const [homePick, setHomePick] = useState<Position | null>(null);
  const [hovered, setHovered] = useState<{ side: 'home' | 'away'; pos: Position } | null>(null);
  const [flash, setFlash] = useState<{ side: 'home' | 'away'; pos: Position; type: 'green' | 'red' } | null>(null);
  const prevPossessionRef = useRef<{ team: 'home' | 'away'; position: Position } | null>(null);

  // Generate stable random jersey numbers for this session
  const awayNumbers = useMemo(() => {
    return POSITIONS.reduce((acc, pos) => {
      acc[pos.value] = Math.floor(Math.random() * 98) + 1;
      return acc;
    }, {} as Record<Position, number>);
  }, []);

  const homeNumbers = useMemo(() => {
    return POSITIONS.reduce((acc, pos) => {
      acc[pos.value] = Math.floor(Math.random() * 98) + 1;
      return acc;
    }, {} as Record<Position, number>);
  }, []);

  const triggerFlash = (side: 'home' | 'away', pos: Position, type: 'green' | 'red') => {
    setFlash({ side, pos, type });
    setTimeout(() => setFlash(null), 1500);
  };

  // Trigger flash when puck possession changes
  useEffect(() => {
    if (puckPossession && (
      puckPossession.team !== prevPossessionRef.current?.team || 
      puckPossession.position !== prevPossessionRef.current?.position
    )) {
      triggerFlash(puckPossession.team, puckPossession.position, 'green');
    }
    prevPossessionRef.current = puckPossession || null;
  }, [puckPossession]);

  const handleConfirm = () => {
    if (awayPick && homePick) {
      onConfirm({ 
        home: homePick, 
        away: awayPick, 
        homeNumber: homeNumbers[homePick], 
        awayNumber: awayNumbers[awayPick] 
      });
    }
  };

  const handlePick = (side: 'home' | 'away', pos: Position) => {
    const current = side === 'home' ? homePick : awayPick;
    if (current === pos) {
      triggerFlash(side, pos, 'red');
    } else {
      triggerFlash(side, pos, 'green');
      if (side === 'home') setHomePick(pos);
      else setAwayPick(pos);
    }
  };

  const getPlayerStats = (side: 'home' | 'away', pos: Position) => {
    const playerEvents = events.filter(e => e.team === side && e.position === pos);
    return {
      goals: playerEvents.filter(e => e.type === 'GOAL').length,
      assists: playerEvents.filter(e => e.type === 'ASSIST').length,
      hits: playerEvents.filter(e => e.type === 'HIT').length,
      shots: playerEvents.filter(e => e.type === 'SHOT').length,
      saves: playerEvents.filter(e => e.type === 'SAVE').length,
    };
  };

  const getPlayerName = (teamName: string, pos: Position) => {
    return PLAYER_NAMES[teamName]?.[pos] || `${pos} Star Player`;
  };

  const getPosCoords = (pos: Position, isHome: boolean) => {
    const baseCoords: Record<Position, { top: string; left: string }> = {
      'G': { top: '50%', left: isHome ? '92%' : '8%' },
      'LD': { top: '30%', left: isHome ? '75%' : '25%' },
      'RD': { top: '70%', left: isHome ? '75%' : '25%' },
      'LW': { top: '22%', left: isHome ? '60%' : '40%' },
      'RW': { top: '78%', left: isHome ? '60%' : '40%' },
      'C': { top: '50%', left: isHome ? '60%' : '40%' },
    };
    return baseCoords[pos];
  };

  // Improved smarter and smaller tooltip positioning
  const getTooltipStyle = () => {
    if (!hovered) return {};
    const coords = getPosCoords(hovered.pos, hovered.side === 'home');
    const topVal = parseInt(coords.top);

    // Smaller tooltip dimensions: ~150px wide, ~120px tall
    // Vertical: If in top 35% of rink, show below (+30px). Otherwise above (-130px).
    const verticalOffset = topVal < 35 ? '30px' : '-130px';

    // Horizontal: Show on opposite side of dot
    const horizontalOffset = hovered.side === 'home' ? '-160px' : '25px';

    return {
      top: `calc(${coords.top} + ${verticalOffset})`,
      left: `calc(${coords.left} + ${horizontalOffset})`
    };
  };

  const isAwayHovered = hovered?.side === 'away';
  const isHomeHovered = hovered?.side === 'home';

  return (
