            <div className={`absolute top-4 right-6 oswald font-black uppercase tracking-widest text-2xl pointer-events-none text-right transition-all duration-300 ${isHomeHovered ? 'text-blue-500 opacity-100' : 'text-slate-200'}`}>{homeTeam.name}</div>

            {/* Tactical Tooltip - Smaller & Smarter */}
            {hovered && (
              <div 
                className={`absolute z-[200] w-40 bg-slate-900/98 backdrop-blur-xl border border-slate-700 rounded-xl p-3 shadow-2xl pointer-events-none animate-in zoom-in-95 fade-in duration-200`}
