                    <>
                      <div className="flex justify-between items-center">
                        <span className="text-[8px] font-bold text-slate-500 uppercase">G</span>
                        <span className="text-[9px] font-black text-white">{getPlayerStats(hovered.side, hovered.pos).goals}</span>
                      </div>
                      <div className="flex justify-between items-center">
                        <span className="text-[8px] font-bold text-slate-500 uppercase">A</span>
                        <span className="text-[9px] font-black text-white">{getPlayerStats(hovered.side, hovered.pos).assists}</span>
