import React, { useState, useMemo, useEffect, useRef } from 'react';
import { Position, TeamInfo, GameEvent, FloatingPoint } from '../types';
import { POSITIONS } from '../constants';

interface SelectionOverlayProps {
  homeTeam: TeamInfo;
  awayTeam: TeamInfo;
  onConfirm: (picks: { home: Position; away: Position; homeNumber: number; awayNumber: number }) => void;
  events: GameEvent[];
  puckPossession?: { team: 'home' | 'away'; position: Position } | null;
  floatingPoints?: FloatingPoint[];
}

const PLAYER_NAMES: Record<string, Record<Position, string>> = {
  'Rangers': { 'C': 'M. Zibanejad', 'LW': 'A. Panarin', 'RW': 'A. Lafreniere', 'LD': 'R. Lindgren', 'RD': 'A. Fox', 'G': 'I. Shesterkin' },
  'Bruins': { 'C': 'C. Coyle', 'LW': 'B. Marchand', 'RW': 'D. Pastrnak', 'LD': 'H. Lindholm', 'RD': 'C. McAvoy', 'G': 'J. Swayman' }
};

const SelectionOverlay: React.FC<SelectionOverlayProps> = ({ homeTeam, awayTeam, onConfirm, events, puckPossession, floatingPoints }) => {
  const [awayPick, setAwayPick] = useState<Position | null>(null);
  const [homePick, setHomePick] = useState<Position | null>(null);
  const [hovered, setHovered] = useState<{ side: 'home' | 'away'; pos: Position } | null>(null);
  const [flash, setFlash] = useState<{ side: 'home' | 'away'; pos: Position; type: 'green' | 'red' } | null>(null);
  const prevPossessionRef = useRef<{ team: 'home' | 'away'; position: Position } | null>(null);

  const awayNumbers = useMemo(() => {
    return POSITIONS.reduce((acc, pos) => {
      acc[pos.value] = Math.floor(Math.random() * 98) + 1;
      return acc;
    }, {} as Record<Position, number>);
  }, []);

  const homeNumbers = useMemo(() => {
    return POSITIONS.reduce((acc, pos) => {
      acc[pos.value] = Math.floor(Math.random() * 98) + 1;
      return acc;
    }, {} as Record<Position, number>);
  }, []);

  const triggerFlash = (side: 'home' | 'away', pos: Position, type: 'green' | 'red', duration = 1500) => {
    setFlash({ side, pos, type });
    setTimeout(() => setFlash(null), duration);
  };

  useEffect(() => {
    if (puckPossession && (
      puckPossession.team !== prevPossessionRef.current?.team || 
      puckPossession.position !== prevPossessionRef.current?.position
    )) {
      // Flash for 1.5 seconds on possession change
      triggerFlash(puckPossession.team, puckPossession.position, 'green', 1500);
    }
    prevPossessionRef.current = puckPossession || null;
  }, [puckPossession]);

  const handleConfirm = () => {
    if (awayPick && homePick) {
      onConfirm({ 
        home: homePick, 
        away: awayPick, 
        homeNumber: homeNumbers[homePick], 
        awayNumber: awayNumbers[awayPick] 
      });
    }
  };

  const handlePick = (side: 'home' | 'away', pos: Position) => {
    const current = side === 'home' ? homePick : awayPick;
    if (current === pos) {
      triggerFlash(side, pos, 'red', 1000);
    } else {
      triggerFlash(side, pos, 'green', 1000);
      if (side === 'home') setHomePick(pos);
      else setAwayPick(pos);
    }
  };

  const getPlayerStats = (side: 'home' | 'away', pos: Position) => {
    const playerEvents = events.filter(e => e.team === side && e.position === pos);
    return {
      goals: playerEvents.filter(e => e.type === 'GOAL').length,
      assists: playerEvents.filter(e => e.type === 'ASSIST').length,
      hits: playerEvents.filter(e => e.type === 'HIT').length,
      shots: playerEvents.filter(e => e.type === 'SHOT').length,
      saves: playerEvents.filter(e => e.type === 'SAVE').length,
    };
  };

  const getPlayerName = (teamName: string, pos: Position) => {
    return PLAYER_NAMES[teamName]?.[pos] || `${pos} Star Player`;
  };

  const getPosCoords = (pos: Position, isHome: boolean) => {
    const baseCoords: Record<Position, { top: string; left: string }> = {
      'G': { top: '50%', left: isHome ? '92%' : '8%' },
      'LD': { top: '30%', left: isHome ? '75%' : '25%' },
      'RD': { top: '70%', left: isHome ? '75%' : '25%' },
      'LW': { top: '22%', left: isHome ? '60%' : '40%' },
      'RW': { top: '78%', left: isHome ? '60%' : '40%' },
      'C': { top: '50%', left: isHome ? '60%' : '40%' },
    };
    return baseCoords[pos];
  };

  const getTooltipStyle = () => {
    if (!hovered) return {};
    const coords = getPosCoords(hovered.pos, hovered.side === 'home');
    const topVal = parseInt(coords.top);
    const showBelow = topVal <= 55;
    const verticalOffset = showBelow ? '32px' : '-115px';
    const horizontalOffset = hovered.side === 'home' ? '-145px' : '22px';

    return {
      top: `calc(${coords.top} + ${verticalOffset})`,
      left: `calc(${coords.left} + ${horizontalOffset})`
    };
  };

  const isAwayHovered = hovered?.side === 'away';
  const isHomeHovered = hovered?.side === 'home';

  return (
    <div className="fixed inset-0 z-[100] bg-slate-950/95 backdrop-blur-xl flex items-center justify-center p-4 overflow-y-auto">
      <div className="bg-slate-900 border border-slate-700 w-full max-w-5xl rounded-3xl shadow-[0_0_60px_rgba(0,0,0,0.6)] overflow-hidden animate-in fade-in zoom-in duration-500 my-auto">

        {/* Header */}
        <div className="bg-slate-800/80 p-6 border-b border-slate-700 flex flex-col items-center text-center relative overflow-hidden">
          <div className={`absolute inset-0 opacity-15 transition-colors duration-500 pointer-events-none ${isAwayHovered ? 'bg-amber-500' : isHomeHovered ? 'bg-blue-500' : 'transparent'}`}></div>

          <div className="flex items-center gap-6 mb-2 relative z-10 w-full justify-between max-w-2xl">
            <div className="flex flex-col items-center gap-1 group">
               <span className={`text-5xl transition-all duration-300 ${isAwayHovered ? 'scale-125 drop-shadow-[0_0_15px_rgba(245,158,11,0.8)]' : 'opacity-60'}`}>
                {awayTeam.logo}
              </span>
              <span className="text-[10px] font-black oswald text-slate-400 group-hover:text-amber-500 transition-colors uppercase">{awayTeam.abbreviation}</span>
            </div>

            <div className="flex flex-col items-center">
              <h2 className="text-3xl font-black oswald uppercase tracking-tighter text-white">POWERPLAY Selection</h2>
              <p className="text-slate-400 text-[9px] font-black uppercase tracking-[0.4em]">Tactical Shift Deployment</p>
            </div>

            <div className="flex flex-col items-center gap-1 group">
              <span className={`text-5xl transition-all duration-300 ${isHomeHovered ? 'scale-125 drop-shadow-[0_0_15px_rgba(37,99,235,0.8)]' : 'opacity-60'}`}>
                {homeTeam.logo}
              </span>
              <span className="text-[10px] font-black oswald text-slate-400 group-hover:text-blue-500 transition-colors uppercase">{homeTeam.abbreviation}</span>
            </div>
          </div>
        </div>

        {/* FULL ICE Rink Container */}
        <div className="relative bg-white border-b border-slate-400">
          <div className="relative w-full aspect-[2.4/1] bg-white shadow-inner">
            <div className="absolute inset-0 bg-[radial-gradient(ellipse_at_center,rgba(224,242,254,0.3)_0%,transparent_90%)]"></div>
            <div className="absolute inset-0 opacity-[0.04] pointer-events-none bg-[url('https://www.transparenttextures.com/patterns/white-diamond.png')]"></div>

            <div className="absolute inset-y-0 left-[6%] w-1.5 bg-red-600/50"></div>
            <div className="absolute inset-y-0 right-[6%] w-1.5 bg-red-600/50"></div>
            <div className="absolute inset-y-0 left-1/2 w-2 bg-red-600/70 -translate-x-1/2"></div>
            <div className="absolute top-1/2 left-1/2 w-5 h-5 bg-red-600 rounded-full -translate-x-1/2 -translate-y-1/2 shadow-sm border-2 border-white"></div>

            <div className="absolute inset-y-0 left-[35%] w-4 bg-blue-600/60"></div>
            <div className="absolute inset-y-0 right-[35%] w-4 bg-blue-600/60"></div>

            {[
              { top: '22%', left: '18%' }, { top: '22%', left: '82%' },
              { top: '78%', left: '18%' }, { top: '78%', left: '82%' }
            ].map((coords, i) => (
              <div key={i} style={{ top: coords.top, left: coords.left }} className="absolute w-2.5 h-2.5 bg-red-600/40 rounded-full -translate-x-1/2 -translate-y-1/2 border border-white"></div>
            ))}

            <div className="absolute top-1/2 left-[6%] w-8 h-16 border-4 border-blue-500/20 bg-blue-100/20 rounded-r-full -translate-y-1/2"></div>
            <div className="absolute top-1/2 right-[6%] w-8 h-16 border-4 border-blue-500/20 bg-blue-100/20 rounded-l-full -translate-y-1/2"></div>

            <div className={`absolute top-6 left-10 oswald font-black uppercase tracking-widest text-3xl pointer-events-none transition-all duration-300 ${isAwayHovered ? 'text-amber-500/20 opacity-100' : 'text-slate-100'}`}>
              {awayTeam.name} <span className="text-[0.6em] opacity-40">[{awayTeam.abbreviation}]</span>
            </div>
            <div className={`absolute top-6 right-10 oswald font-black uppercase tracking-widest text-3xl pointer-events-none text-right transition-all duration-300 ${isHomeHovered ? 'text-blue-500/20 opacity-100' : 'text-slate-100'}`}>
              <span className="text-[0.6em] opacity-40">[{homeTeam.abbreviation}]</span> {homeTeam.name}
            </div>

            {/* Tactical Tooltip */}
            {hovered && (
              <div 
                className={`absolute z-[200] w-36 bg-slate-900/95 backdrop-blur-2xl border border-slate-700 rounded-lg p-2.5 shadow-[0_10px_30px_rgba(0,0,0,0.5)] pointer-events-none animate-in zoom-in-95 fade-in duration-200`}
                style={getTooltipStyle()}
              >
                <div className="flex items-center justify-between mb-1">
                  <span className="text-[9px] font-black oswald uppercase tracking-wider text-white truncate max-w-[80%]">
                    {getPlayerName(hovered.side === 'home' ? homeTeam.name : awayTeam.name, hovered.pos)}
                  </span>
                  <span className={`text-[8px] font-black px-1 py-0.5 rounded leading-none ${hovered.side === 'home' ? 'bg-blue-600 text-white' : 'bg-amber-500 text-slate-950'}`}>
                    #{hovered.side === 'home' ? homeNumbers[hovered.pos] : awayNumbers[hovered.pos]}
                  </span>
                </div>

                <div className="grid grid-cols-2 gap-x-1.5 gap-y-0.5 mt-1 pt-1 border-t border-slate-800">
                  {hovered.pos === 'G' ? (
                    <>
                      <div className="flex justify-between items-center">
                        <span className="text-[7px] font-bold text-slate-500 uppercase">Saves</span>
                        <span className="text-[8px] font-black text-green-400">{getPlayerStats(hovered.side, hovered.pos).saves}</span>
                      </div>
                      <div className="flex justify-between items-center">
                        <span className="text-[7px] font-bold text-slate-500 uppercase">GA</span>
                        <span className="text-[8px] font-black text-red-400">0</span>
                      </div>
                    </>
                  ) : (
                    <>
                      <div className="flex justify-between items-center">
                        <span className="text-[7px] font-bold text-slate-500 uppercase">G</span>
                        <span className="text-[8px] font-black text-white">{getPlayerStats(hovered.side, hovered.pos).goals}</span>
                      </div>
                      <div className="flex justify-between items-center">
                        <span className="text-[7px] font-bold text-slate-500 uppercase">A</span>
                        <span className="text-[8px] font-black text-white">{getPlayerStats(hovered.side, hovered.pos).assists}</span>
                      </div>
                      <div className="flex justify-between items-center">
                        <span className="text-[7px] font-bold text-slate-500 uppercase">Hit</span>
                        <span className="text-[8px] font-black text-slate-400">{getPlayerStats(hovered.side, hovered.pos).hits}</span>
                      </div>
                      <div className="flex justify-between items-center">
                        <span className="text-[7px] font-bold text-slate-500 uppercase">Shot</span>
                        <span className="text-[8px] font-black text-slate-400">{getPlayerStats(hovered.side, hovered.pos).shots}</span>
                      </div>
                    </>
                  )}
                </div>
              </div>
            )}

            {/* Positions */}
            {['away', 'home'].map((side) => 
              POSITIONS.map((pos) => {
                const isHomeSide = side === 'home';
                const coords = getPosCoords(pos.value, isHomeSide);
                const isSelected = isHomeSide ? homePick === pos.value : awayPick === pos.value;
                const isThisHovered = hovered?.side === side && hovered?.pos === pos.value;

                // Real-time point confirmation flash & possession change flash
                const activePoint = floatingPoints?.find(fp => fp.team === side && fp.position === pos.value);
                const isManualFlashing = flash?.side === side && flash?.pos === pos.value;

                const flashClass = [
                  activePoint ? (activePoint.points > 0 ? 'animate-flash-green' : 'animate-flash-red') : '',
                  isManualFlashing ? (flash?.type === 'green' ? 'animate-flash-green' : 'animate-flash-red') : ''
                ].filter(Boolean).join(' ');

                return (
                  <React.Fragment key={`tactical-container-${side}-${pos.value}`}>
                    <button
                      onMouseEnter={() => setHovered({ side: side as 'home' | 'away', pos: pos.value })}
                      onMouseLeave={() => setHovered(null)}
                      onClick={() => handlePick(side as 'home' | 'away', pos.value)}
                      style={{ top: coords.top, left: coords.left }}
                      className={`absolute -translate-x-1/2 -translate-y-1/2 w-8 h-8 sm:w-10 sm:h-10 rounded-full flex flex-col items-center justify-center transition-all z-10 shadow-lg ${
                        isSelected
                          ? (isHomeSide ? 'bg-blue-600 text-white border-2 border-white scale-110 ring-4 ring-blue-600/30' : 'bg-amber-500 text-slate-950 border-2 border-white scale-110 ring-4 ring-amber-500/30')
                          : isThisHovered 
                            ? (isHomeSide ? 'bg-blue-600/30 text-blue-600 border-2 border-blue-400 scale-125' : 'bg-amber-500/30 text-amber-600 border-2 border-amber-500 scale-125')
                            : 'bg-slate-800 text-white border-2 border-slate-600 hover:border-slate-500/50'
                      } ${flashClass}`}
                    >
                      <div className={`absolute -top-1.5 -right-1.5 bg-white text-[7px] font-black px-1.5 py-0.5 rounded-full border shadow-sm transition-all ${isSelected || isThisHovered ? (isHomeSide ? 'text-blue-600 border-blue-500' : 'text-amber-600 border-amber-500') : 'text-slate-400 border-slate-300'}`}>
                        #{isHomeSide ? homeNumbers[pos.value] : awayNumbers[pos.value]}
                      </div>
                      <span className="text-[10px] sm:text-sm font-black oswald leading-none">{pos.value}</span>
                    </button>

                    {/* Point Indicator Indicators */}
                    {floatingPoints?.filter(fp => fp.team === side && fp.position === pos.value).map(fp => (
                      <div 
                        key={`overlay-point-${fp.id}`} 
                        style={{ 
                          left: `calc(${coords.left} + ${fp.xOffset}px)`, 
                          top: `calc(${coords.top} - 30px)`,
                          animation: 'float-up-overlay 2s ease-out forwards' 
                        }} 
                        className={`absolute pointer-events-none font-black oswald text-2xl z-[250] drop-shadow-[0_2px_4px_rgba(0,0,0,0.5)] flex flex-col items-center ${fp.isUser ? (fp.points > 0 ? 'text-green-500' : 'text-red-500') : 'text-slate-400 scale-75 opacity-50'}`}
                      >
                        <span className="bg-slate-950/80 px-2 py-0.5 rounded-lg border border-slate-700/50 backdrop-blur-sm">
                          {fp.points > 0 ? '+' : ''}{fp.points}
                        </span>
                      </div>
                    ))}
                  </React.Fragment>
                );
              })
            )}
          </div>
        </div>

        {/* Footer Actions */}
        <div className="p-8 bg-slate-900 border-t border-slate-700 flex flex-col sm:flex-row items-center justify-between gap-8">
          <div className="flex gap-12">
            <div className="flex flex-col">
              <span className="text-[11px] font-black text-slate-500 uppercase tracking-[0.2em] mb-1.5">{awayTeam.abbreviation} Pick</span>
              <div className="flex items-center gap-3">
                <span className={`w-3 h-3 rounded-full ${awayPick ? 'bg-amber-500 animate-pulse' : 'bg-slate-700'}`}></span>
                <span className="text-xl font-black oswald text-white">{awayPick ? `${getPlayerName(awayTeam.name, awayPick)} (#${awayNumbers[awayPick]})` : 'PICK PLAYER'}</span>
              </div>
            </div>
            <div className="flex flex-col">
              <span className="text-[11px] font-black text-slate-500 uppercase tracking-[0.2em] mb-1.5">{homeTeam.abbreviation} Pick</span>
              <div className="flex items-center gap-3">
                <span className={`w-3 h-3 rounded-full ${homePick ? 'bg-blue-500 animate-pulse' : 'bg-slate-700'}`}></span>
                <span className="text-xl font-black oswald text-white">{homePick ? `${getPlayerName(homeTeam.name, homePick)} (#${homeNumbers[homePick]})` : 'PICK PLAYER'}</span>
              </div>
            </div>
          </div>

          <button
            disabled={!awayPick || !homePick}
            onClick={handleConfirm}
            className={`w-full sm:w-80 py-4.5 rounded-2xl font-black oswald text-2xl uppercase tracking-[0.15em] transition-all relative overflow-hidden group ${
              awayPick && homePick
                ? 'bg-blue-600 hover:bg-blue-500 text-white shadow-[0_0_20px_rgba(37,99,235,0.4)] active:scale-95'
                : 'bg-slate-800 text-slate-600 cursor-not-allowed'
            }`}
          >
            <span className="relative z-10">{awayPick && homePick ? 'LOCK STARTERS' : 'SELECT LINEUP'}</span>
            {awayPick && homePick && (
              <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/10 to-transparent -translate-x-full group-hover:animate-shimmer" />
            )}
          </button>
        </div>
      </div>
      <style>{`
        @keyframes shimmer { 100% { transform: translateX(100%); } }
        @keyframes float-up-overlay {
          0% { transform: translateY(0) scale(0.8); opacity: 0; }
          15% { transform: translateY(-10px) scale(1.1); opacity: 1; }
          100% { transform: translateY(-80px) scale(1.3); opacity: 0; }
        }
        .group-hover\\:animate-shimmer { animation: shimmer 1.5s infinite; }
      `}</style>
    </div>
  );
};

export default SelectionOverlay;

export type Position = 'C' | 'LW' | 'RW' | 'LD' | 'RD' | 'G';

export interface GameEvent {
  id: string;
  timestamp: number;
  gameTime: string;
  team: 'home' | 'away';
  position: Position;
  type: 'GOAL' | 'ASSIST' | 'HIT' | 'SHOT' | 'BLOCKED_SHOT' | 'TAKEAWAY' | 'PASS' | 'GIVEAWAY' | 'SAVE' | 'GOAL_AGAINST' | 'PENALTY';
  description: string;
  points: number;
  homeScoreAtEvent?: number;
  awayScoreAtEvent?: number;
  userEarned?: number;
  period: number;
}

export interface FloatingPoint {
  id: string;
  points: number;
  team: 'home' | 'away';
  position: Position;
  isUser: boolean;
  xOffset: number;
  variant: number; // For varied animation paths
}

export interface GoalExplosion {
  id: string;
  team: 'home' | 'away';
