      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            games: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  id: { type: Type.STRING },
                  homeTeam: {
                    type: Type.OBJECT,
                    properties: {
                      name: { type: Type.STRING },
                      city: { type: Type.STRING },
                      abbreviation: { type: Type.STRING },
                      color: { type: Type.STRING, description: "hex color code" },
                      logo: { type: Type.STRING }
                    },
                    required: ['name', 'city', 'abbreviation', 'color', 'logo']
                  },
                  awayTeam: {
                    type: Type.OBJECT,
                    properties: {
                      name: { type: Type.STRING },
                      city: { type: Type.STRING },
                      abbreviation: { type: Type.STRING },
                      color: { type: Type.STRING, description: "hex color code" },
                      logo: { type: Type.STRING }
                    },
                    required: ['name', 'city', 'abbreviation', 'color', 'logo']
                  },
                  startTime: { type: Type.STRING },
                  venue: { type: Type.STRING }
                },
                required: ['id', 'homeTeam', 'awayTeam', 'startTime', 'venue']
              }
            }
          },
          required: ['games']
        }
      }
    });

    const data = JSON.parse(response.text || '{"games": []}');
    return data.games;
  } catch (error) {
    console.error("Error fetching today's games:", error);
    // Return mock data as fallback if search fails
    return [
      {
