};

export const fetchSimulatedEvents = async (
  period: number, 
  timeRemaining: string, 
  homeTeamName: string, 
  awayTeamName: string
): Promise<{ 
  events: Partial<GameEvent>[], 
  nextFaceoffTrigger: boolean,
  currentPossession: { team: 'home' | 'away', position: Position } | null
}> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Simulate 2-4 play-by-play events for an NHL game between ${homeTeamName} and ${awayTeamName}. 
      Current Time: Period ${period}, ${timeRemaining} remaining.
      Include the position responsible for each event (C, LW, RW, LD, RD, G).
      Event types allowed: GOAL, ASSIST, HIT, SHOT, BLOCKED_SHOT, TAKEAWAY, PASS, GIVEAWAY, SAVE, GOAL_AGAINST, PENALTY.
      Decide if a new face-off should happen after these events (usually after a goal, penalty whistle, goalie freeze, or period end).
      Also specify which player (team and position) currently has the puck possession after these events.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            events: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  team: { type: Type.STRING, enum: ['home', 'away'] },
                  position: { type: Type.STRING, enum: ['C', 'LW', 'RW', 'LD', 'RD', 'G'] },
                  type: { type: Type.STRING, enum: ['GOAL', 'ASSIST', 'HIT', 'SHOT', 'BLOCKED_SHOT', 'TAKEAWAY', 'PASS', 'GIVEAWAY', 'SAVE', 'GOAL_AGAINST', 'PENALTY'] },
                  description: { type: Type.STRING },
                  gameTime: { type: Type.STRING }
                },
                required: ['team', 'position', 'type', 'description', 'gameTime']
              }
            },
            nextFaceoffTrigger: { type: Type.BOOLEAN },
            currentPossession: {
              type: Type.OBJECT,
              properties: {
                team: { type: Type.STRING, enum: ['home', 'away'] },
                position: { type: Type.STRING, enum: ['C', 'LW', 'RW', 'LD', 'RD', 'G'] }
              },
              required: ['team', 'position']
            }
          },
          required: ['events', 'nextFaceoffTrigger', 'currentPossession']
        }
      }
    });

    const data = JSON.parse(response.text || '{"events":[], "nextFaceoffTrigger": false, "currentPossession": null}');

    const eventsWithPoints = data.events.map((e: any) => {
      let points = 0;
      if (e.position === 'G') {
        points = e.type === 'SAVE' ? SCORING_RULES.GOALIE.SAVE : SCORING_RULES.GOALIE.GOAL_AGAINST;
      } else {
        points = (SCORING_RULES.SKATER as any)[e.type] || 0;
      }
      return { ...e, points, id: Math.random().toString(36).substr(2, 9), timestamp: Date.now() };
    });

    return { 
      events: eventsWithPoints, 
      nextFaceoffTrigger: data.nextFaceoffTrigger,
      currentPossession: data.currentPossession
    };
  } catch (error) {
    console.error("Error fetching simulated events:", error);
    return { events: [], nextFaceoffTrigger: false, currentPossession: null };
  }
};

