            <p className="text-[10px] font-black uppercase tracking-widest">Waiting for the puck to drop...</p>
          </div>
        ) : (
          lastFive.map((event) => (
            <div key={`pbp-${event.id}`} className="p-3 flex items-center gap-4 hover:bg-slate-800/20 transition-colors group">
              <div className={`w-8 h-8 rounded-full flex-shrink-0 flex items-center justify-center text-[10px] font-black border-2 shadow-sm transition-transform group-hover:scale-110 ${event.team === 'home' ? 'bg-blue-600 border-blue-400 text-white' : 'bg-amber-500 border-amber-300 text-slate-950'}`}>
                {event.position}
              </div>
              <div className="flex-1 min-w-0">
                <div className="flex items-center gap-2 mb-0.5">
                  <span className="text-[9px] font-black oswald text-slate-500">{event.gameTime}</span>
                  <span className={`text-[8px] font-black uppercase px-1.5 py-0.5 rounded ${event.type === 'GOAL' ? 'bg-red-500/20 text-red-500' : 'bg-slate-800 text-slate-400'}`}>
                    {event.type.replace('_', ' ')} {event.strength && event.strength !== '5v5' ? `(${event.strength})` : ''}
                  </span>
                </div>
                <p className="text-xs text-slate-300 font-medium truncate group-hover:text-white transition-colors">
                  {event.description}
                </p>
              </div>
              {event.userEarned !== 0 && (
                <div className={`text-right font-black oswald text-lg ${event.userEarned! > 0 ? 'text-green-400' : 'text-red-400'}`}>
                  {event.userEarned! > 0 ? '+' : ''}{event.userEarned}
                </div>
              )}
            </div>
          ))
        )}
      </div>
    </div>
  );
};

const App: React.FC = () => {
  const [scheduledGames, setScheduledGames] = useState<ScheduledGame[]>([]);
  const [isLoadingSchedule, setIsLoadingSchedule] = useState(false);
  const [hasSelectedGame, setHasSelectedGame] = useState(false);
  const [isRealTimeSync, setIsRealTimeSync] = useState(false);

  const [game, setGame] = useState<GameState>({
    period: 1,
    timeRemaining: '20:00',
    isPaused: false,
    waitingForPicks: true,
    homeTeam: INITIAL_TEAMS.home,
    awayTeam: INITIAL_TEAMS.away,
    strength: '5v5',
    penaltyClocks: { home: null, away: null },
    userPicks: { home: null, away: null, homeNumber: null, awayNumber: null },
    totalPoints: 0,
    rank: 124,
    totalPlayers: 1542,
    events: [],
    puckPossession: null,
  });

  const [competitors, setCompetitors] = useState<LeaderboardPlayer[]>(() => {
    return Array.from({ length: 49 }, (_, i) => ({
      id: `comp-${i}`,
      name: `User_${Math.floor(Math.random() * 9000) + 1000}`,
      points: Math.max(0, 15000 - (i * 300) + (Math.random() * 500)),
    }));
  });

  const [floatingPoints, setFloatingPoints] = useState<FloatingPoint[]>([]);
  const [explosions, setExplosions] = useState<GoalExplosion[]>([]);
  const [loadingEvents, setLoadingEvents] = useState(false);
  const [notifPermission, setNotifPermission] = useState<NotificationPermission>(getNotificationStatus());
  const tickerRef = useRef<any>(null);

  useEffect(() => {
    const loadGames = async () => {
      setIsLoadingSchedule(true);
      const games = await fetchTodayGames();
      setScheduledGames(games);
      setIsLoadingSchedule(false);
    };
    loadGames();
  }, []);

  const handleSelectGame = (selected: ScheduledGame) => {
    setGame(prev => ({
      ...prev,
      homeTeam: { ...selected.homeTeam, score: 0 },
      awayTeam: { ...selected.awayTeam, score: 0 },
      events: [],
      totalPoints: 0,
      waitingForPicks: true,
      period: 1,
      timeRemaining: '20:00',
      strength: '5v5',
    }));
    setHasSelectedGame(true);
  };

  const leaderboardData = useMemo(() => {
    const userPlayer: LeaderboardPlayer = {
      id: 'user-main',
      name: 'PuckMaster99',
      points: game.totalPoints,
      isUser: true
    };
    return [...competitors, userPlayer];
  }, [competitors, game.totalPoints]);

  useEffect(() => {
    const sorted = [...leaderboardData].sort((a, b) => b.points - a.points);
    const userIndex = sorted.findIndex(p => p.isUser);
    setGame(prev => ({ ...prev, rank: userIndex + 1 }));
  }, [leaderboardData]);

  const updateCompetitors = useCallback(() => {
    setCompetitors(prev => prev.map(comp => {
      const gain = Math.random() > 0.7 ? Math.floor(Math.random() * 1000) : 0;
      return { ...comp, points: comp.points + gain };
    }));
  }, []);

  const triggerGoalExplosion = (team: 'home' | 'away') => {
    const id = Math.random().toString(36).substr(2, 9);
    const color = team === 'home' ? game.homeTeam.color : game.awayTeam.color;
    setExplosions(prev => [...prev, { id, team, color }]);
    setTimeout(() => {
      setExplosions(prev => prev.filter(e => e.id !== id));
    }, 3000);
  };

  const triggerPointsAnimation = (points: number, team: 'home' | 'away', position: Position, isUser: boolean) => {
    const id = Math.random().toString(36).substr(2, 9);
    const newFloatingPoint: FloatingPoint = {
      id,
      points,
      team,
      position,
      isUser,
      xOffset: (Math.random() - 0.5) * 40,
      variant: Math.floor(Math.random() * 3),
    };
    setFloatingPoints(prev => [...prev, newFloatingPoint]);
    setTimeout(() => {
      setFloatingPoints(prev => prev.filter(fp => fp.id !== id));
    }, 2000);
  };

  const processEvents = useCallback(async () => {
    if (loadingEvents || game.waitingForPicks || !hasSelectedGame) return;

    setLoadingEvents(true);
    const result = await fetchSimulatedEvents(
      game.period,
      game.timeRemaining,
      game.homeTeam,
      game.awayTeam
    );

    setIsRealTimeSync(result.realTimeSync);

    let newPoints = 0;
    let currentHomeScore = game.homeTeam.score;
    let currentAwayScore = game.awayTeam.score;
    let goalScored = false;
    let scoringTeamType: 'home' | 'away' | null = null;

    const processedEvents = result.events.map(event => {
      if (event.type === 'GOAL') {
        goalScored = true;
        scoringTeamType = event.team as 'home' | 'away';
        if (event.team === 'home') currentHomeScore++;
        else currentAwayScore++;
      }

      const userPickForTeam = event.team === 'home' ? game.userPicks.home : game.userPicks.away;
      const isUserPick = event.position === userPickForTeam;
      const earned = isUserPick ? (event.points || 0) : 0;

      if (earned !== 0) {
        newPoints += earned;
        triggerPointsAnimation(earned, event.team!, event.position!, true);
      } else if (event.points && event.points !== 0) {
        triggerPointsAnimation(event.points!, event.team!, event.position!, false);
      }

      return { 
        ...event, 
        userEarned: earned, 
        homeScoreAtEvent: currentHomeScore, 
        awayScoreAtEvent: currentAwayScore,
        period: game.period 
      } as GameEvent;
    });

    if (goalScored && scoringTeamType) {
      triggerGoalExplosion(scoringTeamType);
    }

    const strengthChanged = result.strength !== game.strength;
    const faceoffTriggered = result.nextFaceoffTrigger || strengthChanged;

    if (faceoffTriggered) {
      const msg = strengthChanged ? `Special Teams Alert: ${result.strength}` : "Play stopped. Update your lineup!";
      sendGameNotification("Tactical Alert!", msg);
    }

    setGame(prev => ({
      ...prev,
      totalPoints: prev.totalPoints + newPoints,
      events: [...processedEvents, ...prev.events].slice(0, 100),
      homeTeam: { ...prev.homeTeam, score: currentHomeScore },
      awayTeam: { ...prev.awayTeam, score: currentAwayScore },
      waitingForPicks: faceoffTriggered,
      puckPossession: result.currentPossession,
      strength: result.strength,
      penaltyClocks: result.penaltyClocks,
    }));

    updateCompetitors();
    setLoadingEvents(false);
  }, [game.period, game.timeRemaining, game.homeTeam, game.awayTeam, game.userPicks, game.waitingForPicks, loadingEvents, game.homeTeam.score, game.awayTeam.score, updateCompetitors, hasSelectedGame, game.strength]);

  useEffect(() => {
    if (game.waitingForPicks || game.isPaused || !hasSelectedGame) return;
    tickerRef.current = setInterval(() => {
      setGame(prev => {
        const [mins, secs] = prev.timeRemaining.split(':').map(Number);
        let totalSecs = mins * 60 + secs - 12;
        if (totalSecs <= 0) {
          if (prev.period < 3) return { ...prev, period: prev.period + 1, timeRemaining: '20:00', waitingForPicks: true, puckPossession: null };
          // Logic for OT
          if (prev.period === 3 && prev.homeTeam.score === prev.awayTeam.score) {
             return { ...prev, period: 4, timeRemaining: '05:00', waitingForPicks: true, puckPossession: null, strength: '3v3' };
          }
          return { ...prev, isPaused: true, timeRemaining: '00:00', puckPossession: null };
        }
        const newMins = Math.floor(totalSecs / 60);
        const newSecs = totalSecs % 60;
        return { ...prev, timeRemaining: `${newMins.toString().padStart(2, '0')}:${newSecs.toString().padStart(2, '0')}` };
      });
    }, 1000);
    return () => { if (tickerRef.current) clearInterval(tickerRef.current); };
  }, [game.waitingForPicks, game.isPaused, hasSelectedGame]);

  useEffect(() => {
    if (game.waitingForPicks || game.isPaused || !hasSelectedGame) return;
    const eventInterval = setInterval(() => { processEvents(); }, 8000);
    return () => clearInterval(eventInterval);
  }, [game.waitingForPicks, game.isPaused, processEvents, hasSelectedGame]);

  const handlePicks = async (picks: { home: Position; away: Position; homeNumber: number; awayNumber: number }) => {
    if (notifPermission === 'default') {
      const granted = await requestNotificationPermission();
      setNotifPermission(granted ? 'granted' : 'denied');
    }
    setGame(prev => ({ ...prev, userPicks: picks, waitingForPicks: false }));
  };

  const openPicks = () => {
    if (game.waitingForPicks) return;
    setGame(prev => ({ ...prev, waitingForPicks: true, puckPossession: null }));
  };

  const goBackToSelection = () => {
    setHasSelectedGame(false);
  };

  if (!hasSelectedGame) {
    return <GameSelectionScreen games={scheduledGames} onSelectGame={handleSelectGame} isLoading={isLoadingSchedule} />;
  }

  return (
    <div className="min-h-screen bg-slate-950 text-slate-100 flex flex-col pb-24 relative overflow-hidden">
      {explosions.map(exp => (
        <div key={exp.id} className="fixed inset-0 z-[100] pointer-events-none flex items-center justify-center">
          <div className="absolute inset-0 animate-screen-flash" style={{ backgroundColor: `${exp.color}22` }} />
          <div className="relative">
            <div className="text-8xl font-black oswald uppercase text-white animate-goal-text drop-shadow-[0_0_20px_rgba(255,255,255,0.8)]">GOAL!</div>
            <div className="absolute inset-0 animate-goal-explosion" style={{ background: `radial-gradient(circle, ${exp.color} 0%, transparent 70%)` }} />
          </div>
        </div>
      ))}

      {game.waitingForPicks && (
        <SelectionOverlay 
          homeTeam={game.homeTeam} 
          awayTeam={game.awayTeam} 
          onConfirm={handlePicks} 
          events={game.events}
          puckPossession={game.puckPossession}
          floatingPoints={floatingPoints}
          strength={game.strength}
        />
      )}

      <ScoreBoard 
        home={game.homeTeam} 
        away={game.awayTeam} 
        period={game.period} 
        time={game.timeRemaining}
        strength={game.strength}
        penaltyClocks={game.penaltyClocks}
      />

      <main className="flex-1 max-w-6xl mx-auto w-full p-4">
        <div className="mb-6 flex justify-between items-center">
          <button 
            onClick={goBackToSelection}
            className="text-[10px] font-black uppercase tracking-widest text-slate-500 hover:text-white transition-colors flex items-center gap-2 group"
          >
            <i className="fa-solid fa-chevron-left group-hover:-translate-x-1 transition-transform"></i>
            Change Game
          </button>

          <div className="flex gap-4">
            {isRealTimeSync && (
              <div className="bg-green-600/20 text-green-400 text-[9px] font-black uppercase tracking-widest px-3 py-1 rounded-full border border-green-500/30 flex items-center gap-2 animate-pulse">
                 <span className="w-1.5 h-1.5 bg-green-500 rounded-full"></span>
                 Live Match Grounding
              </div>
            )}
            {game.strength !== '5v5' && (
              <div className="bg-amber-600/20 text-amber-500 text-[9px] font-black uppercase tracking-widest px-3 py-1 rounded-full border border-amber-500/30 flex items-center gap-2 animate-bounce">
                 <i className="fa-solid fa-bolt"></i>
                 Special Teams active
              </div>
            )}
          </div>
        </div>

        <div className="flex flex-col lg:flex-row gap-8">

          <div className="flex-1 space-y-8 order-2 lg:order-1">
            <div className="grid grid-cols-2 sm:grid-cols-4 gap-4">
              <div className="bg-slate-900 border border-slate-800 p-4 rounded-xl shadow-lg relative overflow-hidden">
                <div className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-1">Score</div>
                <div className="text-3xl font-black text-amber-500 oswald">{game.totalPoints.toLocaleString()}</div>
              </div>
              <div className="bg-slate-900 border border-slate-800 p-4 rounded-xl shadow-lg relative overflow-hidden">
                <div className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-1">Rank</div>
                <div className="text-3xl font-black text-blue-400 oswald">#{game.rank}</div>
              </div>
              <div className="bg-slate-900 border border-slate-800 p-4 rounded-xl shadow-lg hidden sm:block">
                <div className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-1">On-Ice Strength</div>
                <div className={`text-xl font-black oswald uppercase ${game.strength === '5v5' ? 'text-white' : 'text-amber-500'}`}>{game.strength}</div>
              </div>
              <div className="bg-slate-900 border border-slate-800 p-4 rounded-xl shadow-lg hidden sm:block">
                <div className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-1">Active Players</div>
                <div className="text-3xl font-black text-slate-300 oswald">{game.totalPlayers.toLocaleString()}</div>
              </div>
            </div>

            <div className="space-y-6">
              <div className="bg-slate-900/50 border border-slate-800 rounded-2xl overflow-hidden flex flex-col">
                <div className="bg-slate-800 px-6 py-4 border-b border-slate-700 flex justify-between items-center">
                  <h2 className="text-sm font-black uppercase tracking-widest text-slate-200 flex items-center gap-2">
                    <i className="fa-solid fa-satellite-dish text-red-500 animate-pulse"></i> POWERPLAY Live Feed
                  </h2>
                  {loadingEvents && <div className="text-[10px] font-bold text-slate-500 uppercase animate-pulse"><i className="fa-solid fa-spinner fa-spin mr-1"></i>Scanning Grounding...</div>}
                </div>
                <div className="overflow-y-auto p-4 space-y-4 max-h-[450px] scroll-smooth">
                  {game.events.length === 0 ? (
                    <div className="h-40 flex flex-col items-center justify-center text-slate-600">
                      <i className="fa-solid fa-hockey-puck text-4xl mb-4 opacity-20"></i>
                      <p className="font-bold uppercase tracking-wider text-[10px]">Puck is currently in the air...</p>
                    </div>
                  ) : (
                    game.events.slice(0, 15).map((event) => {
                      const isUserPositive = (event.userEarned || 0) > 0;
                      const isUserNegative = (event.userEarned || 0) < 0;
                      return (
                        <div key={`live-${event.id}`} className={`flex items-start gap-4 p-4 rounded-xl border transition-all animate-in slide-in-from-right duration-500 relative overflow-hidden ${isUserPositive ? 'bg-green-900/10 border-green-500/40' : isUserNegative ? 'bg-red-900/10 border-red-500/40' : 'bg-slate-800/40 border-slate-700'}`}>
                          <div className={`w-10 h-10 rounded-full flex-shrink-0 flex items-center justify-center font-black text-xs border-2 shadow-lg z-10 ${event.team === 'home' ? 'bg-blue-600 border-blue-400 text-white' : 'bg-amber-500 border-amber-300 text-slate-950'}`}>{event.position}</div>
                          <div className="flex-1 z-10">
                            <div className="text-[9px] font-bold text-slate-500 uppercase mb-1">
                                {event.gameTime} • {event.type.replace('_', ' ')} 
                                {event.strength && event.strength !== '5v5' && <span className="ml-2 text-amber-500">[{event.strength}]</span>}
                            </div>
                            <p className="text-sm text-slate-100 font-medium">{event.description}</p>
                          </div>
                          {event.userEarned !== 0 && <div className={`text-right font-black oswald text-xl min-w-[60px] z-10 ${isUserPositive ? 'text-green-400' : 'text-red-400'}`}>{isUserPositive ? '+' : ''}{event.userEarned}</div>}
                        </div>
                      );
                    })
                  )}
                </div>
              </div>

              <PlayByPlayFeed events={game.events} />
            </div>

            <PerformanceSummary events={game.events} />
            <GameLog events={game.events} homeTeam={game.homeTeam} awayTeam={game.awayTeam} />
          </div>

          <div className="lg:w-80 order-1 lg:order-2">
            <div className="lg:sticky lg:top-24 space-y-6 flex flex-col min-h-screen">
              <div className={`bg-slate-900 border border-slate-800 rounded-3xl p-4 shadow-2xl transition-all duration-500 ${game.waitingForPicks ? 'ring-2 ring-amber-500/30' : ''}`}>
                <div className="flex justify-between items-center mb-4">
                   <div className="text-[9px] font-black text-slate-500 uppercase tracking-widest flex items-center gap-2">
                      Tactical Command
                      <span className={`w-1.5 h-1.5 rounded-full ${game.waitingForPicks ? 'bg-amber-500 animate-pulse' : 'bg-green-500'}`}></span>
                   </div>
                   <div className={`text-[8px] font-black px-2 py-0.5 rounded uppercase ${game.waitingForPicks ? 'bg-amber-500/20 text-amber-500' : 'bg-slate-800 text-slate-500'}`}>
                    {game.waitingForPicks ? 'Update Lineup' : 'Picks Locked'}
                   </div>
                </div>

                <PickStatus 
                  homeTeam={game.homeTeam} 
                  awayTeam={game.awayTeam} 
                  userPicks={game.userPicks} 
                  floatingPoints={floatingPoints}
                  isSelecting={game.waitingForPicks}
                  onConfirmPicks={handlePicks}
                  puckPossession={game.puckPossession}
                  strength={game.strength}
                />
              </div>

              <div className="bg-slate-900 border border-slate-800 p-5 rounded-2xl">
                <h3 className="text-xs font-black text-slate-200 uppercase tracking-widest mb-4">Special Teams Key</h3>
                <div className="space-y-2">
                  <div className="flex justify-between text-[10px] font-bold text-amber-500 uppercase"><span>PP Goal</span><span>+6250</span></div>
                  <div className="flex justify-between text-[10px] font-bold text-slate-500 uppercase"><span>5v5 Goal</span><span>+5000</span></div>
                  <div className="flex justify-between text-[10px] font-bold text-slate-500 uppercase"><span>3v3 Goal</span><span>+6250</span></div>
                </div>
              </div>

              <div className="flex-1">
                <Leaderboard players={leaderboardData} userPoints={game.totalPoints} userRank={game.rank} />
              </div>
            </div>
          </div>
        </div>
      </main>

      <footer className="fixed bottom-0 left-0 right-0 bg-slate-900/90 border-t border-slate-800 p-4 sm:p-6 shadow-2xl z-40 backdrop-blur-md">
        <div className="max-w-6xl mx-auto flex items-center justify-between gap-4">
          <div className="flex items-center gap-6">
            <div>
              <div className="text-[10px] font-bold text-slate-500 uppercase mb-1">POWERPLAY Points</div>
              <div className="text-3xl font-black oswald text-amber-500 leading-none">{game.totalPoints.toLocaleString()}</div>
            </div>
            <div className="h-8 w-[1px] bg-slate-800"></div>
            <div>
              <div className="text-[10px] font-bold text-slate-500 uppercase mb-1">On-Ice</div>
              <div className="text-2xl font-black oswald text-white leading-none">{game.strength}</div>
            </div>
          </div>

          <div className="flex items-center gap-4">
            <button 
              onClick={openPicks} 
              disabled={game.waitingForPicks} 
              className={`px-8 py-3 rounded-xl font-black oswald text-lg uppercase tracking-widest transition-all active:scale-95 ${
                !game.waitingForPicks 
                ? 'bg-blue-600 hover:bg-blue-500 text-white shadow-lg shadow-blue-900/30 ring-2 ring-blue-400/50' 
                : 'bg-slate-800 text-slate-600 border border-slate-700 cursor-not-allowed'
              }`}
            >
              {game.waitingForPicks ? 'Drafting Open' : 'Tactical Change'}
            </button>
          </div>
        </div>
      </footer>
    </div>
  );
};

export default App;

import React from 'react';
import { TeamInfo, OnIceStrength } from '../types';

interface ScoreBoardProps {
  home: TeamInfo;
  away: TeamInfo;
  period: number;
  time: string;
  strength?: OnIceStrength;
  penaltyClocks?: { home: string | null; away: string | null };
}

const ScoreBoard: React.FC<ScoreBoardProps> = ({ home, away, period, time, strength, penaltyClocks }) => {
  return (
    <div className="bg-slate-900 border-b border-slate-700 p-4 sticky top-0 z-50 shadow-2xl">
      <div className="max-w-4xl mx-auto flex items-center justify-between">
        {/* Away Team */}
        <div className="flex items-center gap-4 flex-1">
          <div className="text-right hidden sm:block">
            <div className="text-xs text-slate-400 font-bold uppercase tracking-wider">{away.city}</div>
            <div className="text-xl font-black oswald uppercase">{away.name}</div>
            {penaltyClocks?.away && (
               <div className="text-[10px] font-black text-amber-500 animate-pulse uppercase tracking-widest bg-amber-500/10 px-2 rounded-md border border-amber-500/20 mt-1 inline-block">
                PK {penaltyClocks.away}
               </div>
            )}
          </div>
          <div className="relative">
            <div 
              className={`w-12 h-12 rounded-full flex items-center justify-center text-3xl shadow-lg border-2 transition-all duration-500 ${strength?.startsWith('5v4') && strength.includes('away') ? 'ring-4 ring-amber-400/50 scale-110' : 'border-slate-700'}`}
              style={{ backgroundColor: away.color }}
            >
              {away.logo}
            </div>
            <div className="absolute -bottom-1 -right-1 bg-slate-800 text-[8px] font-black oswald px-1 rounded border border-slate-700 text-white">
              {away.abbreviation}
            </div>
          </div>
          <div className="text-4xl font-black oswald min-w-[3rem] text-center">{away.score}</div>
        </div>

        {/* Center Clock */}
        <div className="flex flex-col items-center px-8 border-x border-slate-800">
          <div className={`text-xs font-bold uppercase animate-pulse ${strength !== '5v5' ? 'text-amber-500' : 'text-red-500'}`}>
            {strength !== '5v5' ? strength : 'Live'}
          </div>
          <div className="text-3xl font-mono font-bold tracking-tighter text-white">{time}</div>
          <div className="text-xs font-black text-slate-400 uppercase tracking-widest">
            {period === 1 ? '1st' : period === 2 ? '2nd' : period === 3 ? '3rd' : period === 4 ? 'OT' : 'FINAL'}
          </div>
        </div>

        {/* Home Team */}
        <div className="flex items-center gap-4 flex-1 justify-end">
          <div className="text-4xl font-black oswald min-w-[3rem] text-center">{home.score}</div>
          <div className="relative">
            <div 
              className={`w-12 h-12 rounded-full flex items-center justify-center text-3xl shadow-lg border-2 transition-all duration-500 ${strength?.startsWith('5v4') && strength.includes('home') ? 'ring-4 ring-blue-400/50 scale-110' : 'border-slate-700'}`}
              style={{ backgroundColor: home.color }}
            >
              {home.logo}
            </div>
            <div className="absolute -bottom-1 -left-1 bg-slate-800 text-[8px] font-black oswald px-1 rounded border border-slate-700 text-white">
              {home.abbreviation}
            </div>
          </div>
          <div className="text-left hidden sm:block">
            <div className="text-xs text-slate-400 font-bold uppercase tracking-wider">{home.city}</div>
            <div className="text-xl font-black oswald uppercase">{home.name}</div>
            {penaltyClocks?.home && (
               <div className="text-[10px] font-black text-amber-500 animate-pulse uppercase tracking-widest bg-amber-500/10 px-2 rounded-md border border-amber-500/20 mt-1 inline-block">
                PK {penaltyClocks.home}
               </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default ScoreBoard;

import React, { useState, useEffect, useRef } from 'react';
import { Position, TeamInfo, GameEvent, FloatingPoint, OnIceStrength } from '../types';
import { POSITIONS } from '../constants';

interface SelectionOverlayProps {
  homeTeam: TeamInfo;
  awayTeam: TeamInfo;
  onConfirm: (picks: { home: Position; away: Position; homeNumber: number; awayNumber: number }) => void;
  events: GameEvent[];
  puckPossession?: { team: 'home' | 'away'; position: Position } | null;
  floatingPoints?: FloatingPoint[];
  strength: OnIceStrength;
}

const PLAYER_NAMES: Record<string, Record<Position, string>> = {
  'Rangers': { 'C': 'M. Zibanejad', 'LW': 'A. Panarin', 'RW': 'A. Lafreniere', 'LD': 'R. Lindgren', 'RD': 'A. Fox', 'G': 'I. Shesterkin' },
  'Bruins': { 'C': 'C. Coyle', 'LW': 'B. Marchand', 'RW': 'D. Pastrnak', 'LD': 'H. Lindholm', 'RD': 'C. McAvoy', 'G': 'J. Swayman' }
};

const SelectionOverlay: React.FC<SelectionOverlayProps> = ({ homeTeam, awayTeam, onConfirm, events, puckPossession, floatingPoints, strength }) => {
  const [awayPick, setAwayPick] = useState<Position | null>(null);
  const [homePick, setHomePick] = useState<Position | null>(null);
  const [awayNum, setAwayNum] = useState<string>('');
  const [homeNum, setHomeNum] = useState<string>('');

  const [hovered, setHovered] = useState<{ side: 'home' | 'away'; pos: Position } | null>(null);
  const [flash, setFlash] = useState<{ side: 'home' | 'away'; pos: Position; type: 'green' | 'red' } | null>(null);
  const prevPossessionRef = useRef<{ team: 'home' | 'away'; position: Position } | null>(null);

  const triggerFlash = (side: 'home' | 'away', pos: Position, type: 'green' | 'red', duration = 1500) => {
    setFlash({ side, pos, type });
    setTimeout(() => setFlash(null), duration);
  };

  useEffect(() => {
    if (puckPossession && (
      puckPossession.team !== prevPossessionRef.current?.team || 
      puckPossession.position !== prevPossessionRef.current?.position
    )) {
      triggerFlash(puckPossession.team, puckPossession.position, 'green', 1500);
    }
    prevPossessionRef.current = puckPossession || null;
  }, [puckPossession]);

  const handleConfirm = () => {
    const aNum = parseInt(awayNum);
    const hNum = parseInt(homeNum);
    if (awayPick && homePick && !isNaN(aNum) && !isNaN(hNum)) {
      onConfirm({ 
        home: homePick, 
        away: awayPick, 
        homeNumber: hNum, 
        awayNumber: aNum 
      });
    }
  };

  const handlePick = (side: 'home' | 'away', pos: Position) => {
    const current = side === 'home' ? homePick : awayPick;
    if (current === pos) {
      triggerFlash(side, pos, 'red', 1000);
    } else {
      triggerFlash(side, pos, 'green', 1000);
      if (side === 'home') setHomePick(pos);
      else setAwayPick(pos);
    }
  };

  const getPlayerStats = (side: 'home' | 'away', pos: Position) => {
    const playerEvents = events.filter(e => e.team === side && e.position === pos);
    return {
      goals: playerEvents.filter(e => e.type === 'GOAL').length,
      assists: playerEvents.filter(e => e.type === 'ASSIST').length,
      hits: playerEvents.filter(e => e.type === 'HIT').length,
      shots: playerEvents.filter(e => e.type === 'SHOT').length,
      saves: playerEvents.filter(e => e.type === 'SAVE').length,
    };
  };

  const getPlayerName = (teamName: string, pos: Position) => {
    return PLAYER_NAMES[teamName]?.[pos] || `${pos} Star Player`;
  };

  const getPosCoords = (pos: Position, isHome: boolean) => {
    const baseCoords: Record<Position, { top: string; left: string }> = {
      'G': { top: '50%', left: isHome ? '92%' : '8%' },
      'LD': { top: '30%', left: isHome ? '75%' : '25%' },
      'RD': { top: '70%', left: isHome ? '75%' : '25%' },
      'LW': { top: '22%', left: isHome ? '60%' : '40%' },
      'RW': { top: '78%', left: isHome ? '60%' : '40%' },
      'C': { top: '50%', left: isHome ? '60%' : '40%' },
    };
    return baseCoords[pos];
  };

  const isFormValid = awayPick && homePick && awayNum !== '' && homeNum !== '' && parseInt(awayNum) > 0 && parseInt(homeNum) > 0;

  return (
    <div className="fixed inset-0 z-[100] bg-slate-950/95 backdrop-blur-xl flex items-center justify-center p-4 overflow-y-auto">
      <div className="bg-slate-900 border border-slate-700 w-full max-w-5xl rounded-3xl shadow-[0_0_60px_rgba(0,0,0,0.6)] overflow-hidden animate-in fade-in zoom-in duration-500 my-auto">

        {/* Header */}
        <div className="bg-slate-800/80 p-6 border-b border-slate-700 flex flex-col items-center text-center relative overflow-hidden">
          <div className="flex items-center gap-6 mb-2 relative z-10 w-full justify-between max-w-2xl">
            <div className="flex flex-col items-center gap-1 group">
               <span className="text-5xl transition-all duration-300">
                {awayTeam.logo}
              </span>
              <span className="text-[10px] font-black oswald text-slate-400 uppercase">{awayTeam.abbreviation}</span>
            </div>

            <div className="flex flex-col items-center">
              <h2 className={`text-3xl font-black oswald uppercase tracking-tighter italic ${strength !== '5v5' ? 'text-amber-500' : 'text-white'}`}>
                {strength !== '5v5' ? `SPECIAL TEAMS: ${strength}` : 'LINEUP BUILDER'}
              </h2>
              <p className="text-slate-400 text-[9px] font-black uppercase tracking-[0.4em]">Tactical Deployments for current strength</p>
            </div>

            <div className="flex flex-col items-center gap-1 group">
              <span className="text-5xl transition-all duration-300">
                {homeTeam.logo}
              </span>
              <span className="text-[10px] font-black oswald text-slate-400 uppercase">{homeTeam.abbreviation}</span>
            </div>
          </div>
        </div>

        {/* FULL ICE Rink Container */}
        <div className="relative bg-white border-b border-slate-400">
          <div className="relative w-full aspect-[2.4/1] bg-white shadow-inner">
            {/* Rink Overlays for Special Teams */}
            {strength !== '5v5' && (
               <div className="absolute inset-0 bg-amber-500/5 animate-pulse pointer-events-none"></div>
            )}

            <div className="absolute inset-y-0 left-[6%] w-1.5 bg-red-600/50"></div>
            <div className="absolute inset-y-0 right-[6%] w-1.5 bg-red-600/50"></div>
            <div className="absolute inset-y-0 left-1/2 w-2 bg-red-600/70 -translate-x-1/2"></div>
            <div className="absolute top-1/2 left-1/2 w-5 h-5 bg-red-600 rounded-full -translate-x-1/2 -translate-y-1/2 shadow-sm border-2 border-white"></div>

            <div className="absolute inset-y-0 left-[35%] w-4 bg-blue-600/60"></div>
            <div className="absolute inset-y-0 right-[35%] w-4 bg-blue-600/60"></div>

            <div className="absolute top-6 left-10 oswald font-black uppercase tracking-widest text-3xl pointer-events-none text-slate-100">
              {awayTeam.name}
            </div>
            <div className="absolute top-6 right-10 oswald font-black uppercase tracking-widest text-3xl pointer-events-none text-right text-slate-100">
              {homeTeam.name}
            </div>

            {/* Positions */}
            {['away', 'home'].map((side) => 
              POSITIONS.map((pos) => {
                const isHomeSide = side === 'home';
                const coords = getPosCoords(pos.value, isHomeSide);
                const isSelected = isHomeSide ? homePick === pos.value : awayPick === pos.value;
                const isThisHovered = hovered?.side === side && hovered?.pos === pos.value;

                const activePoint = floatingPoints?.find(fp => fp.team === side && fp.position === pos.value);
                const isManualFlashing = flash?.side === side && flash?.pos === pos.value;

                const flashClass = [
                  activePoint ? (activePoint.points > 0 ? 'animate-flash-green' : 'animate-flash-red') : '',
                  isManualFlashing ? (flash?.type === 'green' ? 'animate-flash-green' : 'animate-flash-red') : ''
                ].filter(Boolean).join(' ');

                // Tactical recommendation for Special Teams
                const isKeySpecialTeamsPos = strength !== '5v5' && (pos.value === 'C' || pos.value === 'RD' || pos.value === 'RW');

                return (
                  <React.Fragment key={`tactical-container-${side}-${pos.value}`}>
                    <button
                      onMouseEnter={() => setHovered({ side: side as 'home' | 'away', pos: pos.value })}
                      onMouseLeave={() => setHovered(null)}
                      onClick={() => handlePick(side as 'home' | 'away', pos.value)}
                      style={{ top: coords.top, left: coords.left }}
                      className={`absolute -translate-x-1/2 -translate-y-1/2 w-8 h-8 sm:w-10 sm:h-10 rounded-full flex flex-col items-center justify-center transition-all z-10 shadow-lg ${
                        isSelected
                          ? (isHomeSide ? 'bg-blue-600 text-white border-2 border-white scale-110 ring-4 ring-blue-600/30' : 'bg-amber-500 text-slate-950 border-2 border-white scale-110 ring-4 ring-amber-500/30')
                          : isThisHovered 
                            ? (isHomeSide ? 'bg-blue-600/30 text-blue-600 border-2 border-blue-400 scale-125' : 'bg-amber-500/30 text-amber-600 border-2 border-amber-500 scale-125')
                            : isKeySpecialTeamsPos 
                               ? 'bg-amber-100 text-amber-900 border-2 border-amber-400 animate-pulse'
                               : 'bg-slate-800 text-white border-2 border-slate-600'
                      } ${flashClass}`}
                    >
                      <span className="text-[10px] sm:text-sm font-black oswald leading-none">{pos.value}</span>
                      {isSelected && (
                         <div className={`absolute -top-1.5 -right-1.5 bg-white text-[7px] font-black px-1.5 py-0.5 rounded-full border shadow-sm transition-all ${isHomeSide ? 'text-blue-600 border-blue-500' : 'text-amber-600 border-amber-500'}`}>
                          #{isHomeSide ? homeNum : awayNum}
                        </div>
                      )}
                    </button>
                  </React.Fragment>
                );
              })
            )}
          </div>
        </div>

        {/* Footer Actions */}
        <div className="p-8 bg-slate-900 border-t border-slate-700 flex flex-col lg:flex-row items-center justify-between gap-8">
          <div className="flex flex-col sm:flex-row gap-8 lg:gap-12 w-full lg:w-auto">
            {/* Away Selection */}
            <div className={`flex flex-col p-4 rounded-2xl border transition-all ${awayPick ? 'bg-slate-800 border-amber-500/30' : 'bg-slate-900/50 border-slate-800'}`}>
              <span className="text-[11px] font-black text-slate-500 uppercase tracking-[0.2em] mb-3">{awayTeam.abbreviation} Selection</span>
              <div className="flex items-center gap-4">
                <div className={`w-12 h-12 rounded-full flex items-center justify-center font-black oswald text-xl border-2 ${awayPick ? 'bg-amber-500 border-white text-slate-950 animate-pulse' : 'bg-slate-800 border-slate-700 text-slate-600'}`}>
                  {awayPick || '?'}
                </div>
                <div className="flex flex-col gap-1">
                  <span className="text-sm font-black text-white">{awayPick ? getPlayerName(awayTeam.name, awayPick) : 'Select Position'}</span>
                  <div className="flex items-center gap-2">
                    <span className="text-[9px] font-bold text-slate-500 uppercase">Jersey #</span>
                    <input 
                      type="number" 
                      min="1" 
                      max="99" 
                      value={awayNum}
                      disabled={!awayPick}
                      onChange={(e) => setAwayNum(e.target.value.slice(0, 2))}
                      placeholder="--"
                      className="bg-slate-950 border border-slate-700 rounded-md w-12 py-1 text-center font-black oswald text-amber-500 focus:border-amber-500 outline-none transition-all disabled:opacity-20"
                    />
                  </div>
                </div>
              </div>
            </div>

            {/* Home Selection */}
            <div className={`flex flex-col p-4 rounded-2xl border transition-all ${homePick ? 'bg-slate-800 border-blue-500/30' : 'bg-slate-900/50 border-slate-800'}`}>
              <span className="text-[11px] font-black text-slate-500 uppercase tracking-[0.2em] mb-3">{homeTeam.abbreviation} Selection</span>
              <div className="flex items-center gap-4">
                <div className={`w-12 h-12 rounded-full flex items-center justify-center font-black oswald text-xl border-2 ${homePick ? 'bg-blue-600 border-white text-white animate-pulse' : 'bg-slate-800 border-slate-700 text-slate-600'}`}>
                  {homePick || '?'}
                </div>
                <div className="flex flex-col gap-1">
                  <span className="text-sm font-black text-white">{homePick ? getPlayerName(homeTeam.name, homePick) : 'Select Position'}</span>
                  <div className="flex items-center gap-2">
                    <span className="text-[9px] font-bold text-slate-500 uppercase">Jersey #</span>
                    <input 
                      type="number" 
                      min="1" 
                      max="99" 
                      value={homeNum}
                      disabled={!homePick}
                      onChange={(e) => setHomeNum(e.target.value.slice(0, 2))}
                      placeholder="--"
                      className="bg-slate-950 border border-slate-700 rounded-md w-12 py-1 text-center font-black oswald text-blue-400 focus:border-blue-500 outline-none transition-all disabled:opacity-20"
                    />
                  </div>
                </div>
              </div>
            </div>
          </div>

          <button
            disabled={!isFormValid}
            onClick={handleConfirm}
            className={`w-full lg:w-80 py-6 rounded-2xl font-black oswald text-2xl uppercase tracking-[0.15em] transition-all relative overflow-hidden group ${
              isFormValid
                ? 'bg-blue-600 hover:bg-blue-500 text-white shadow-[0_0_30px_rgba(37,99,235,0.4)] active:scale-95'
                : 'bg-slate-800 text-slate-600 cursor-not-allowed opacity-50'
            }`}
          >
            <span className="relative z-10">{isFormValid ? 'LOCK LINEUP' : 'COMPLETE PICKS'}</span>
            {isFormValid && (
              <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/10 to-transparent -translate-x-full group-hover:animate-shimmer" />
            )}
          </button>
        </div>
      </div>
    </div>
  );
};

export default SelectionOverlay;

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { Position, TeamInfo, FloatingPoint, OnIceStrength } from '../types';
import { POSITIONS } from '../constants';

interface PickStatusProps {
  homeTeam: TeamInfo;
  awayTeam: TeamInfo;
  userPicks: { home: Position | null; away: Position | null; homeNumber: number | null; awayNumber: number | null };
  floatingPoints: FloatingPoint[];
  isSelecting: boolean;
  onConfirmPicks: (picks: { home: Position; away: Position; homeNumber: number; awayNumber: number }) => void;
  puckPossession?: { team: 'home' | 'away'; position: Position } | null;
  strength: OnIceStrength;
}

const PickStatus: React.FC<PickStatusProps> = ({ 
  homeTeam, 
  awayTeam, 
  userPicks, 
  floatingPoints, 
  isSelecting,
  onConfirmPicks,
  puckPossession,
  strength
}) => {
  const [draftAway, setDraftAway] = useState<Position | null>(userPicks.away);
  const [draftHome, setDraftHome] = useState<Position | null>(userPicks.home);
  const [possessionFlash, setPossessionFlash] = useState<{ team: 'home' | 'away'; position: Position } | null>(null);
  const prevPossessionRef = useRef<{ team: 'home' | 'away'; position: Position } | null>(null);

  const numbers = useMemo(() => {
    const res: Record<string, number> = {};
    POSITIONS.forEach(p => {
      res[`away-${p.value}`] = Math.floor(Math.random() * 98) + 1;
      res[`home-${p.value}`] = Math.floor(Math.random() * 98) + 1;
    });
    return res;
  }, []);

  useEffect(() => {
    if (puckPossession && (
      puckPossession.team !== prevPossessionRef.current?.team || 
      puckPossession.position !== prevPossessionRef.current?.position
    )) {
      setPossessionFlash({ team: puckPossession.team, position: puckPossession.position });
      setTimeout(() => setPossessionFlash(null), 1500);
    }
    prevPossessionRef.current = puckPossession || null;
  }, [puckPossession]);

  const handleConfirm = () => {
    if (draftAway && draftHome) {
      onConfirmPicks({
        away: draftAway,
        home: draftHome,
        awayNumber: numbers[`away-${draftAway}`],
        homeNumber: numbers[`home-${draftHome}`]
      });
    }
  };

  const getPosCoords = (pos: Position, isHome: boolean) => {
    const baseCoords: Record<Position, { top: string; left: string }> = {
      'G': { top: '50%', left: isHome ? '92%' : '8%' },
      'LD': { top: '30%', left: isHome ? '75%' : '25%' },
      'RD': { top: '70%', left: isHome ? '75%' : '25%' },
      'LW': { top: '22%', left: isHome ? '60%' : '40%' },
      'RW': { top: '78%', left: isHome ? '60%' : '40%' },
      'C': { top: '50%', left: isHome ? '60%' : '40%' },
    };
    return baseCoords[pos];
  };

  return (
    <div className="flex flex-col gap-4">
      {/* Premium Tactical Rink */}
      <div className={`relative w-full aspect-[1.5/1] bg-white rounded-[40px] border-[4px] overflow-hidden shadow-2xl transition-all duration-500 ${strength !== '5v5' ? 'border-amber-500' : isSelecting ? 'border-blue-500/50' : 'border-slate-300'}`}>
        <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,rgba(224,242,254,0.3)_0%,transparent_100%)]"></div>

        <div className="absolute inset-y-0 left-[6%] w-0.5 bg-red-600/40"></div>
        <div className="absolute inset-y-0 right-[6%] w-0.5 bg-red-600/40"></div>
        <div className="absolute inset-y-0 left-1/2 w-1 bg-red-600/60 -translate-x-1/2"></div>

        {strength !== '5v5' && (
           <div className="absolute inset-0 bg-amber-500/5 animate-pulse"></div>
        )}

        {['away', 'home'].map((side) => 
          POSITIONS.map((p) => {
            const isHomeSide = side === 'home';
            const coords = getPosCoords(p.value, isHomeSide);
            const isSelected = isSelecting ? (isHomeSide ? draftHome === p.value : draftAway === p.value) : (isHomeSide ? userPicks.home === p.value : userPicks.away === p.value);

            const hasPuck = puckPossession?.team === side && puckPossession?.position === p.value;
            const isFlashing = possessionFlash?.team === side && possessionFlash?.position === p.value;
            const activePoint = floatingPoints.find(fp => fp.team === side && fp.position === p.value);

            const flashClass = [
              activePoint ? (activePoint.points > 0 ? 'animate-flash-green' : 'animate-flash-red') : '',
              isFlashing ? 'animate-flash-green' : ''
            ].filter(Boolean).join(' ');

            return (
              <div
                key={`sidebar-rink-${side}-${p.value}`}
                style={{ top: coords.top, left: coords.left }}
                className="absolute -translate-x-1/2 -translate-y-1/2 z-20"
              >
                <button
                  disabled={!isSelecting}
                  onClick={() => isSelecting && (isHomeSide ? setDraftHome(p.value) : setDraftAway(p.value))}
                  className={`relative w-6 h-6 sm:w-7 sm:h-7 rounded-full flex flex-col items-center justify-center transition-all border-2 shadow-sm ${
                    hasPuck 
                      ? 'bg-green-500 border-white scale-125 z-30'
                      : isSelected 
                        ? (isHomeSide ? 'bg-blue-600 border-white text-white' : 'bg-amber-500 border-white text-slate-950') 
                        : 'bg-slate-800 text-slate-400 border-slate-600'
                  } ${isSelecting ? 'cursor-pointer hover:scale-110 active:scale-95' : 'cursor-default'} ${flashClass}`}
                >
                  <span className="text-[8px] font-black oswald leading-none">{p.value}</span>
                  {isSelected && (
                    <span className="text-[5px] font-bold opacity-80 leading-tight">
                      #{isSelecting ? (numbers[`${side}-${p.value}`] || '??') : (isHomeSide ? userPicks.homeNumber : userPicks.awayNumber)}
                    </span>
                  )}
                  {hasPuck && <div className="absolute -bottom-1 -right-1 w-2.5 h-2.5 bg-black rounded-full border border-white flex items-center justify-center text-[5px]">P</div>}
                </button>
              </div>
            );
          })
        )}
      </div>

      <div className="space-y-3">
        {isSelecting ? (
          <div className="space-y-3">
            <div className="grid grid-cols-2 gap-2">
              <div className="bg-slate-900 border border-slate-800 rounded-lg p-2 flex flex-col items-center">
                <span className="text-[8px] font-bold text-slate-500 uppercase block">Away</span>
                <span className="text-sm font-black oswald text-amber-500">{draftAway || '---'}</span>
              </div>
              <div className="bg-slate-900 border border-slate-800 rounded-lg p-2 flex flex-col items-center">
                <span className="text-[8px] font-bold text-slate-500 uppercase block">Home</span>
                <span className="text-sm font-black oswald text-blue-400">{draftHome || '---'}</span>
              </div>
            </div>
            <button 
              onClick={handleConfirm} 
              disabled={!draftAway || !draftHome}
              className={`w-full py-3.5 rounded-xl font-black oswald text-lg uppercase tracking-widest transition-all ${draftAway && draftHome ? 'bg-blue-600 text-white shadow-xl shadow-blue-900/40 active:scale-95' : 'bg-slate-800 text-slate-600'}`}
            >
              Update Tactical Line
            </button>
          </div>
        ) : (
          <div className="grid grid-cols-2 gap-3">
            <div className={`rounded-xl p-3 flex flex-col items-center shadow-sm border transition-all ${puckPossession?.team === 'away' ? 'bg-green-500/10 border-green-500 shadow-green-500/20' : 'bg-amber-500/5 border-amber-500/20'}`}>
              <span className="text-[8px] font-black uppercase tracking-widest mb-1">{strength !== '5v5' && strength.includes('away') ? 'Powerplay' : 'Away'}</span>
              <span className="text-xl font-black oswald text-white leading-none">{userPicks.away}</span>
              <span className="text-[10px] font-bold text-amber-500">#{userPicks.awayNumber}</span>
            </div>
            <div className={`rounded-xl p-3 flex flex-col items-center shadow-sm border transition-all ${puckPossession?.team === 'home' ? 'bg-green-500/10 border-green-500 shadow-green-500/20' : 'bg-blue-600/5 border-blue-600/20'}`}>
              <span className="text-[8px] font-black uppercase tracking-widest mb-1">{strength !== '5v5' && strength.includes('home') ? 'Powerplay' : 'Home'}</span>
              <span className="text-xl font-black oswald text-white leading-none">{userPicks.home}</span>
              <span className="text-[10px] font-bold text-blue-400">#{userPicks.homeNumber}</span>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default PickStatus;

export type Position = 'C' | 'LW' | 'RW' | 'LD' | 'RD' | 'G';
export type OnIceStrength = '5v5' | '5v4' | '5v3' | '4v4' | '4v3' | '3v3';

export interface ShootoutState {
  isActive: boolean;
  round: number;
  homeAttempts: boolean[]; // true = score, false = miss
  awayAttempts: boolean[];
  currentTurn: 'home' | 'away';
  shooterName: string;
  goalieName: string;
}

export interface GameEvent {
  id: string;
  timestamp: number;
  gameTime: string;
  team: 'home' | 'away';
  position: Position;
  type: 'GOAL' | 'ASSIST' | 'HIT' | 'SHOT' | 'BLOCKED_SHOT' | 'TAKEAWAY' | 'PASS' | 'GIVEAWAY' | 'SAVE' | 'GOAL_AGAINST' | 'PENALTY' | 'SO_GOAL' | 'SO_MISS';
  description: string;
  points: number;
  homeScoreAtEvent?: number;
  awayScoreAtEvent?: number;
  userEarned?: number;
  period: number;
  strength?: OnIceStrength;
}

export interface FloatingPoint {
  id: string;
  points: number;
  team: 'home' | 'away';
  position: Position;
  isUser: boolean;
  xOffset: number;
  variant: number;
}

export interface GoalExplosion {
  id: string;
  team: 'home' | 'away';
  color: string;
}

export interface LeaderboardPlayer {
  id: string;
  name: string;
  points: number;
  isUser?: boolean;
}

export interface TeamInfo {
  name: string;
  city: string;
  abbreviation: string;
  score: number;
  color: string;
  logo: string;
}

export interface ScheduledGame {
  id: string;
  homeTeam: Omit<TeamInfo, 'score'>;
  awayTeam: Omit<TeamInfo, 'score'>;
  startTime: string;
  venue: string;
}

export interface GameState {
  period: number;
  timeRemaining: string;
  isPaused: boolean;
  waitingForPicks: boolean;
  homeTeam: TeamInfo;
  awayTeam: TeamInfo;
  strength: OnIceStrength;
  penaltyClocks: {
    home: string | null;
    away: string | null;
  };
  userPicks: {
    home: Position | null;
    away: Position | null;
    homeNumber: number | null;
    awayNumber: number | null;
  };
  totalPoints: number;
  rank: number;
  totalPlayers: number;
  events: GameEvent[];
  puckPossession?: {
    team: 'home' | 'away';
    position: Position;
  } | null;
  shootout: ShootoutState;
}

