                    <span className="text-[9px] font-bold text-slate-500 uppercase">Jersey #</span>
                    <input 
                      type="number" 
                      min="1" 
                      max="99" 
                      value={homeNum}
                      disabled={!homePick || showSuccess}
                      onChange={(e) => setHomeNum(e.target.value.slice(0, 2))}
                      placeholder="--"
                      className="bg-slate-950 border border-slate-700 rounded-md w-12 py-1 text-center font-black oswald text-blue-400 focus:border-blue-500 outline-none transition-all disabled:opacity-20"
                    />
                  </div>
                </div>
              </div>
            </div>
          </div>

          <button
            disabled={!isFormValid || showSuccess}
            onClick={handleConfirm}
            className={`w-full lg:w-80 py-6 rounded-2xl font-black oswald text-2xl uppercase tracking-[0.15em] transition-all relative overflow-hidden group ${
              isFormValid && !showSuccess
                ? 'bg-blue-600 hover:bg-blue-500 text-white shadow-[0_0_30px_rgba(37,99,235,0.4)] active:scale-95'
                : 'bg-slate-800 text-slate-600 cursor-not-allowed opacity-50'
            }`}
          >
            <span className="relative z-10">{showSuccess ? 'LOCKED' : (isFormValid ? 'LOCK LINEUP' : 'COMPLETE PICKS')}</span>
            {isFormValid && !showSuccess && (
              <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/10 to-transparent -translate-x-full group-hover:animate-shimmer" />
            )}
          </button>
        </div>
      </div>
      <style>{`
        @keyframes shimmer { 100% { transform: translateX(100%); } }
        @keyframes float-up-overlay {
          0% { transform: translateY(0) scale(0.8); opacity: 0; }
          15% { transform: translateY(-10px) scale(1.1); opacity: 1; }
          100% { transform: translateY(-80px) scale(1.3); opacity: 0; }
        }
        .group-hover\\:animate-shimmer { animation: shimmer 1.5s infinite; }
        input[type=number]::-webkit-inner-spin-button, 
        input[type=number]::-webkit-outer-spin-button { 
          -webkit-appearance: none; 
          margin: 0; 
        }
      `}</style>
    </div>
  );
};

export default SelectionOverlay;

export type Position = 'C' | 'LW' | 'RW' | 'LD' | 'RD' | 'G';
export type OnIceStrength = '5v5' | '5v4' | '5v3' | '4v4' | '4v3' | '3v3';

export interface ShotTrajectory {
  id: string;
  startX: string;
  startY: string;
  endX: string;
  endY: string;
  team: 'home' | 'away';
  color: string;
}

export interface ShootoutState {
  isActive: boolean;
  round: number;
  homeAttempts: boolean[]; // true = score, false = miss
  awayAttempts: boolean[];
  currentTurn: 'home' | 'away';
  shooterName: string;
  goalieName: string;
}

export interface GameEvent {
  id: string;
  timestamp: number;
  gameTime: string;
  team: 'home' | 'away';
  position: Position;
  type: 'GOAL' | 'ASSIST' | 'HIT' | 'SHOT' | 'BLOCKED_SHOT' | 'TAKEAWAY' | 'PASS' | 'GIVEAWAY' | 'SAVE' | 'GOAL_AGAINST' | 'PENALTY' | 'SO_GOAL' | 'SO_MISS';
  description: string;
  points: number;
  homeScoreAtEvent?: number;
  awayScoreAtEvent?: number;
  userEarned?: number;
  period: number;
  strength?: OnIceStrength;
}

export interface FloatingPoint {
  id: string;
  points: number;
  team: 'home' | 'away';
  position: Position;
  isUser: boolean;
  xOffset: number;
  variant: number;
}

export interface GoalExplosion {
  id: string;
  team: 'home' | 'away';
  color: string;
}

export interface LeaderboardPlayer {
  id: string;
  name: string;
  points: number;
  isUser?: boolean;
}

export interface TeamInfo {
  name: string;
  city: string;
  abbreviation: string;
  score: number;
  color: string;
  logo: string;
}

export interface ScheduledGame {
  id: string;
  homeTeam: Omit<TeamInfo, 'score'>;
  awayTeam: Omit<TeamInfo, 'score'>;
  startTime: string;
  venue: string;
}

export interface GameState {
  period: number;
  timeRemaining: string;
  isPaused: boolean;
  waitingForPicks: boolean;
  waitingReason?: string;
  homeTeam: TeamInfo;
  awayTeam: TeamInfo;
  strength: OnIceStrength;
  penaltyClocks: {
    home: string | null;
    away: string | null;
  };
  userPicks: {
    home: Position | null;
    away: Position | null;
    homeNumber: number | null;
    awayNumber: number | null;
  };
  totalPoints: number;
  rank: number;
  totalPlayers: number;
  events: GameEvent[];
  puckPossession?: {
    team: 'home' | 'away';
    position: Position;
  } | null;
  shootout: ShootoutState;
}

