                           >
                            #{isHomeSide ? homeNum : awayNum}
                          </div>
                        )}
                      </button>

                      {/* Tactical Tooltip with boundary logic */}
                      {isThisHovered && (
                        <div 
                          className={`absolute z-[300] w-48 bg-slate-900/95 backdrop-blur-md border rounded-xl p-3 shadow-2xl pointer-events-none animate-in zoom-in fade-in duration-200 ${horizontalClass} ${
                            showBelow ? 'top-full mt-4' : 'bottom-full mb-4'
                          }`}
                          style={{ borderColor: `${teamColor}40` }}
                        >
                          <div className="flex items-center justify-between mb-2">
                            <span className="text-[10px] font-black uppercase tracking-widest text-white/60">
                              {isHomeSide ? homeTeam.abbreviation : awayTeam.abbreviation} Tactical Info
                            </span>
                            <span className="oswald font-black text-xl italic" style={{ color: teamColor }}>
                              #{playerData.number}
                            </span>
                          </div>

                          <div className="text-sm font-black text-white oswald uppercase tracking-tight mb-2">
                            {playerData.name}
                          </div>

                          <div className="grid grid-cols-2 gap-2 border-t border-white/10 pt-2">
                            <div className="flex flex-col">
                              <span className="text-[8px] font-bold text-slate-500 uppercase">Goals</span>
                              <span className="text-sm font-black text-white">{posStats.goals}</span>
                            </div>
                            <div className="flex flex-col">
                              <span className="text-[8px] font-bold text-slate-500 uppercase">Assists</span>
                              <span className="text-sm font-black text-white">{posStats.assists}</span>
                            </div>
                          </div>

                          {isSelected && (
                            <div className="mt-2 pt-2 border-t border-white/10">
                               <div className="bg-green-500/10 text-green-400 text-[9px] font-black uppercase text-center py-1 rounded border border-green-500/20">
