                <div className="flex flex-col gap-1">
                  <span className="text-sm font-black text-white">{awayPick ? getPlayerData(awayTeam.name, awayPick).name : 'Select Position'}</span>
                  <div className="flex items-center gap-2">
                    <span className="text-[9px] font-bold text-slate-500 uppercase">Jersey #</span>
                    <input 
                      type="number" 
                      min="1" 
                      max="99" 
                      value={awayNum}
                      disabled={!awayPick || showSuccess}
                      onFocus={() => setFocusedSide('away')}
                      onBlur={() => setFocusedSide(null)}
                      onChange={(e) => setAwayNum(e.target.value.slice(0, 2))}
                      placeholder="--"
                      className="bg-slate-950 border border-slate-700 rounded-md w-12 py-1 text-center font-black oswald outline-none transition-all disabled:opacity-20"
                      style={{ 
                        color: awayTeam.color,
                        borderColor: focusedSide === 'away' ? awayTeam.color : undefined,
                        boxShadow: focusedSide === 'away' ? `0 0 10px ${awayTeam.color}33` : undefined
                      }}
                    />
                  </div>
                </div>
              </div>
            </div>

            {/* Home Selection */}
            <div className={`flex flex-col p-4 rounded-2xl border transition-all ${homePick ? 'bg-slate-800 border-opacity-50' : 'bg-slate-900/50 border-slate-800'}`}
                 style={homePick ? { borderColor: `${homeTeam.color}80` } : {}}>
              <span className="text-[11px] font-black text-slate-500 uppercase tracking-[0.2em] mb-3">{homeTeam.abbreviation} Selection</span>
              <div className="flex items-center gap-4">
                <div 
                  className={`w-12 h-12 rounded-full flex items-center justify-center font-black oswald text-xl border-2 ${homePick ? 'border-white text-white animate-pulse' : 'bg-slate-800 border-slate-700 text-slate-600'}`}
                  style={homePick ? { backgroundColor: homeTeam.color } : {}}
                >
                  {homePick || '?'}
                </div>
                <div className="flex flex-col gap-1">
                  <span className="text-sm font-black text-white">{homePick ? getPlayerData(homeTeam.name, homePick).name : 'Select Position'}</span>
                  <div className="flex items-center gap-2">
                    <span className="text-[9px] font-bold text-slate-500 uppercase">Jersey #</span>
                    <input 
                      type="number" 
                      min="1" 
                      max="99" 
                      value={homeNum}
                      disabled={!homePick || showSuccess}
                      onFocus={() => setFocusedSide('home')}
                      onBlur={() => setFocusedSide(null)}
                      onChange={(e) => setHomeNum(e.target.value.slice(0, 2))}
                      placeholder="--"
                      className="bg-slate-950 border border-slate-700 rounded-md w-12 py-1 text-center font-black oswald outline-none transition-all disabled:opacity-20"
                      style={{ 
                        color: homeTeam.color,
                        borderColor: focusedSide === 'home' ? homeTeam.color : undefined,
                        boxShadow: focusedSide === 'home' ? `0 0 10px ${homeTeam.color}33` : undefined
                      }}
                    />
                  </div>
                </div>
              </div>
            </div>
          </div>

          <button
            disabled={!isFormValid || showSuccess}
            onClick={handleConfirm}
            className={`w-full lg:w-80 py-6 rounded-2xl font-black oswald text-2xl uppercase tracking-[0.15em] transition-all relative overflow-hidden group ${
              isFormValid && !showSuccess
                ? 'bg-blue-600 hover:bg-blue-500 text-white shadow-[0_0_30px_rgba(37,99,235,0.4)] active:scale-95'
                : 'bg-slate-800 text-slate-600 cursor-not-allowed opacity-50'
            }`}
          >
            <span className="relative z-10">{showSuccess ? 'LOCKED' : (isFormValid ? 'LOCK LINEUP' : 'COMPLETE PICKS')}</span>
            {isFormValid && !showSuccess && (
              <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/10 to-transparent -translate-x-full group-hover:animate-shimmer" />
            )}
          </button>
        </div>
      </div>
      <style>{`
        @keyframes shimmer { 100% { transform: translateX(100%); } }
        @keyframes point-pop-overlay {
          0% { transform: translateY(0) scale(0.4); opacity: 0; }
          15% { transform: translateY(-15px) scale(1.1); opacity: 1; }
          70% { transform: translateY(-40px) scale(1); opacity: 1; }
          100% { transform: translateY(-55px) scale(0.85); opacity: 0; }
        }
        .group-hover\\:animate-shimmer { animation: shimmer 1.5s infinite; }
        input[type=number]::-webkit-inner-spin-button, 
        input[type=number]::-webkit-outer-spin-button { 
          -webkit-appearance: none; 
          margin: 0; 
        }
      `}</style>
    </div>
  );
};

export default SelectionOverlay;

import React, { useState, useEffect, useRef } from 'react';
import { Position, TeamInfo, GameEvent, FloatingPoint, OnIceStrength } from '../types';
import { POSITIONS } from '../constants';

interface SelectionOverlayProps {
  homeTeam: TeamInfo;
  awayTeam: TeamInfo;
  onConfirm: (picks: { home: Position; away: Position; homeNumber: number; awayNumber: number }) => void;
  events: GameEvent[];
  puckPossession?: { team: 'home' | 'away'; position: Position } | null;
  floatingPoints?: FloatingPoint[];
  strength: OnIceStrength;
  waitingReason?: string;
}

const PLAYER_DATA: Record<string, Record<Position, { name: string; number: number }>> = {
  'Rangers': { 
    'C': { name: 'M. Zibanejad', number: 93 }, 
    'LW': { name: 'A. Panarin', number: 10 }, 
    'RW': { name: 'A. Lafreniere', number: 13 }, 
    'LD': { name: 'R. Lindgren', number: 55 }, 
    'RD': { name: 'A. Fox', number: 23 }, 
    'G': { name: 'I. Shesterkin', number: 31 } 
  },
  'Bruins': { 
    'C': { name: 'C. Coyle', number: 13 }, 
    'LW': { name: 'B. Marchand', number: 63 }, 
    'RW': { name: 'D. Pastrnak', number: 88 }, 
    'LD': { name: 'H. Lindholm', number: 27 }, 
    'RD': { name: 'C. McAvoy', number: 73 }, 
    'G': { name: 'J. Swayman', number: 1 } 
  }
};

const SelectionOverlay: React.FC<SelectionOverlayProps> = ({ homeTeam, awayTeam, onConfirm, events, puckPossession, floatingPoints, strength, waitingReason }) => {
  const [awayPick, setAwayPick] = useState<Position | null>(null);
  const [homePick, setHomePick] = useState<Position | null>(null);
  const [awayNum, setAwayNum] = useState<string>('');
  const [homeNum, setHomeNum] = useState<string>('');
  const [showSuccess, setShowSuccess] = useState(false);
  const [focusedSide, setFocusedSide] = useState<'home' | 'away' | null>(null);

  const [hovered, setHovered] = useState<{ side: 'home' | 'away'; pos: Position } | null>(null);
  const [flash, setFlash] = useState<{ side: 'home' | 'away'; pos: Position; type: 'green' | 'red' | 'possession' } | null>(null);
  const prevPossessionRef = useRef<{ team: 'home' | 'away'; position: Position } | null>(null);

  const triggerFlash = (side: 'home' | 'away', pos: Position, type: 'green' | 'red' | 'possession', duration = 1500) => {
    setFlash({ side, pos, type });
    setTimeout(() => setFlash(null), duration);
  };

  useEffect(() => {
    if (puckPossession && (
      puckPossession.team !== prevPossessionRef.current?.team || 
      puckPossession.position !== prevPossessionRef.current?.position
    )) {
      triggerFlash(puckPossession.team, puckPossession.position, 'possession', 1500);
    }
    prevPossessionRef.current = puckPossession || null;
  }, [puckPossession]);

  const handleConfirm = () => {
    const aNum = parseInt(awayNum);
    const hNum = parseInt(homeNum);
    if (awayPick && homePick && !isNaN(aNum) && !isNaN(hNum)) {
      setShowSuccess(true);
      setTimeout(() => {
        onConfirm({ 
          home: homePick, 
          away: awayPick, 
          homeNumber: hNum, 
          awayNumber: aNum 
        });
      }, 1200);
    }
  };

  const handlePick = (side: 'home' | 'away', pos: Position) => {
    if (showSuccess) return; 
    const current = side === 'home' ? homePick : awayPick;
    if (current === pos) {
      triggerFlash(side, pos, 'red', 1000);
    } else {
      triggerFlash(side, pos, 'green', 1000);
      if (side === 'home') {
        setHomePick(pos);
        setHomeNum(PLAYER_DATA[homeTeam.name]?.[pos]?.number.toString() || '');
      } else {
        setAwayPick(pos);
        setAwayNum(PLAYER_DATA[awayTeam.name]?.[pos]?.number.toString() || '');
      }
    }
  };

  const getPlayerData = (teamName: string, pos: Position) => {
    return PLAYER_DATA[teamName]?.[pos] || { name: `${pos} Prospect`, number: 0 };
  };

  const getPosStats = (side: 'home' | 'away', pos: Position) => {
    const posEvents = events.filter(e => e.team === side && e.position === pos);
    const goals = posEvents.filter(e => e.type === 'GOAL' || e.type === 'SO_GOAL').length;
    const assists = posEvents.filter(e => e.type === 'ASSIST').length;
    return { goals, assists };
  };

  const getPosCoords = (pos: Position, isHome: boolean) => {
    const baseCoords: Record<Position, { top: string; left: string }> = {
      'G': { top: '50%', left: isHome ? '92%' : '8%' },
      'LD': { top: '30%', left: isHome ? '75%' : '25%' },
      'RD': { top: '70%', left: isHome ? '75%' : '25%' },
      'LW': { top: '22%', left: isHome ? '60%' : '40%' },
      'RW': { top: '78%', left: isHome ? '60%' : '40%' },
      'C': { top: '50%', left: isHome ? '60%' : '40%' },
    };
    return baseCoords[pos];
  };

  const isFormValid = awayPick && homePick && awayNum !== '' && homeNum !== '' && parseInt(awayNum) > 0 && parseInt(homeNum) > 0;

  return (
    <div className="fixed inset-0 z-[100] bg-slate-950/95 backdrop-blur-xl flex items-center justify-center p-4 overflow-y-auto">
      <div className="bg-slate-900 border border-slate-700 w-full max-w-5xl rounded-3xl shadow-[0_0_60px_rgba(0,0,0,0.6)] overflow-hidden animate-in fade-in zoom-in duration-500 my-auto relative">

        {showSuccess && (
          <div className="absolute inset-0 z-[200] bg-slate-950/60 backdrop-blur-md flex flex-col items-center justify-center animate-in fade-in duration-300">
            <div className="flex flex-col items-center gap-6 animate-in zoom-in slide-in-from-bottom-12 duration-500">
              <div className="w-24 h-24 bg-green-500 rounded-full flex items-center justify-center shadow-[0_0_50px_rgba(34,197,94,0.6)] border-4 border-green-400">
                <i className="fa-solid fa-check text-5xl text-white"></i>
              </div>
              <div className="text-center">
                <h3 className="text-5xl font-black oswald uppercase tracking-tighter text-white italic mb-2">Lineup Locked!</h3>
                <p className="text-green-400 text-sm font-black uppercase tracking-[0.4em]">Tactical Data Syncing...</p>
              </div>
            </div>
          </div>
        )}

        <div className="bg-slate-800/80 p-6 border-b border-slate-700 flex flex-col items-center text-center relative overflow-hidden">
          <div className="flex items-center gap-6 mb-2 relative z-10 w-full justify-between max-w-2xl">
            <div className="flex flex-col items-center gap-1 group">
               <span className="text-5xl transition-all duration-300">
                {awayTeam.logo}
              </span>
              <span className="text-[10px] font-black oswald text-slate-400 uppercase">{awayTeam.abbreviation}</span>
            </div>

            <div className="flex flex-col items-center">
              <div className="bg-amber-500/10 text-amber-500 text-[10px] font-black px-3 py-1 rounded-full border border-amber-500/20 uppercase tracking-[0.2em] mb-2 animate-pulse">
                {waitingReason || "Lineup Reset"}
              </div>
              <h2 className={`text-3xl font-black oswald uppercase tracking-tighter italic ${strength !== '5v5' ? 'text-amber-500' : 'text-white'}`}>
                {strength !== '5v5' ? `SPECIAL TEAMS: ${strength}` : 'LINEUP BUILDER'}
              </h2>
              <p className="text-slate-400 text-[9px] font-black uppercase tracking-[0.4em]">Tactical Deployments for current strength</p>
            </div>

            <div className="flex flex-col items-center gap-1 group">
              <span className="text-5xl transition-all duration-300">
                {homeTeam.logo}
              </span>
              <span className="text-[10px] font-black oswald text-slate-400 uppercase">{homeTeam.abbreviation}</span>
            </div>
          </div>
        </div>

        <div className="relative bg-white border-b border-slate-400">
          <div className="relative w-full aspect-[2.4/1] bg-white shadow-inner">
            {strength !== '5v5' && (
               <div className="absolute inset-0 bg-amber-500/5 animate-pulse pointer-events-none"></div>
            )}

            <div className="absolute inset-y-0 left-[6%] w-1.5 bg-red-600/50"></div>
            <div className="absolute inset-y-0 right-[6%] w-1.5 bg-red-600/50"></div>
            <div className="absolute inset-y-0 left-1/2 w-2 bg-red-600/70 -translate-x-1/2"></div>
            <div className="absolute top-1/2 left-1/2 w-5 h-5 bg-red-600 rounded-full -translate-x-1/2 -translate-y-1/2 shadow-sm border-2 border-white"></div>

            <div className="absolute inset-y-0 left-[35%] w-4 bg-blue-600/60"></div>
            <div className="absolute inset-y-0 right-[35%] w-4 bg-blue-600/60"></div>

            <div className="absolute top-6 left-10 oswald font-black uppercase tracking-widest text-3xl pointer-events-none text-slate-100 flex items-center gap-4">
              <span className="text-4xl filter drop-shadow-md">{awayTeam.logo}</span>
              {awayTeam.name}
            </div>
            <div className="absolute top-6 right-10 oswald font-black uppercase tracking-widest text-3xl pointer-events-none text-right text-slate-100 flex items-center gap-4">
              {homeTeam.name}
              <span className="text-4xl filter drop-shadow-md">{homeTeam.logo}</span>
            </div>

            {['away', 'home'].map((side) => 
              POSITIONS.map((pos) => {
                const isHomeSide = side === 'home';
                const coords = getPosCoords(pos.value, isHomeSide);
                const isSelected = isHomeSide ? homePick === pos.value : awayPick === pos.value;
                const isThisHovered = hovered?.side === side && hovered?.pos === pos.value;
                const activePoints = floatingPoints?.filter(fp => fp.team === side && fp.position === pos.value) || [];
                const isManualFlashing = flash?.side === side && flash?.pos === pos.value;

                let flashClass = '';
                let flashStyle: React.CSSProperties = {};
                if (isManualFlashing) {
                  if (flash.type === 'possession') {
                    flashClass = 'animate-possession-pulse';
                    flashStyle = { '--pulse-color': isHomeSide ? homeTeam.color : awayTeam.color } as React.CSSProperties;
                  } else {
                    flashClass = flash.type === 'green' ? 'animate-flash-green' : 'animate-flash-red';
                  }
                }

                const isKeySpecialTeamsPos = strength !== '5v5' && (pos.value === 'C' || pos.value === 'RD' || pos.value === 'RW');
                const teamColor = isHomeSide ? homeTeam.color : awayTeam.color;

                const playerData = getPlayerData(isHomeSide ? homeTeam.name : awayTeam.name, pos.value);
                const posStats = getPosStats(side as 'home' | 'away', pos.value);

                // Tooltip boundary logic
                const topVal = parseFloat(coords.top);
                const leftVal = parseFloat(coords.left);
                const showBelow = topVal < 40;
                const horizontalClass = leftVal < 15 ? 'left-0 translate-x-0' : leftVal > 85 ? 'right-0 translate-x-0' : 'left-1/2 -translate-x-1/2';

                return (
                  <React.Fragment key={`tactical-container-${side}-${pos.value}`}>
                    <div
                      style={{ top: coords.top, left: coords.left }}
                      className="absolute -translate-x-1/2 -translate-y-1/2 z-20"
                    >
                      <button
                        onMouseEnter={() => setHovered({ side: side as 'home' | 'away', pos: pos.value })}
                        onMouseLeave={() => setHovered(null)}
                        onClick={() => handlePick(side as 'home' | 'away', pos.value)}
                        className={`relative w-8 h-8 sm:w-10 sm:h-10 rounded-full flex flex-col items-center justify-center transition-all z-10 shadow-lg ${
                          isSelected
                            ? ('scale-110 ring-4 border-2 border-white text-white')
                            : isThisHovered 
                              ? ('scale-125 border-2 border-slate-400')
                              : isKeySpecialTeamsPos 
                                ? 'bg-amber-100 text-amber-900 border-2 border-amber-400 animate-pulse'
                                : 'bg-slate-800 text-white border-2 border-slate-600'
                        } ${flashClass}`}
                        style={{
                          ...(isSelected ? { backgroundColor: teamColor, boxShadow: `0 0 0 4px ${teamColor}4D` } : {}),
                          ...flashStyle
                        }}
                      >
                        <span className="text-[10px] sm:text-sm font-black oswald leading-none">{pos.value}</span>
                        {isSelected && (
                           <div 
                             className="absolute -top-1.5 -right-1.5 bg-white text-[7px] font-black px-1.5 py-0.5 rounded-full border shadow-sm transition-all"
                             style={{ color: teamColor, borderColor: teamColor }}
                           >
                            #{isHomeSide ? homeNum : awayNum}
                          </div>
                        )}
                      </button>

                      {/* Tactical Tooltip with boundary logic */}
                      {isThisHovered && (
                        <div 
                          className={`absolute z-[300] w-48 bg-slate-900/95 backdrop-blur-md border rounded-xl p-3 shadow-2xl pointer-events-none animate-in zoom-in fade-in duration-200 ${horizontalClass} ${
                            showBelow ? 'top-full mt-4' : 'bottom-full mb-4'
                          }`}
                          style={{ borderColor: `${teamColor}40` }}
                        >
                          <div className="flex items-center justify-between mb-2">
                            <span className="text-[10px] font-black uppercase tracking-widest text-white/60">
                              {isHomeSide ? homeTeam.abbreviation : awayTeam.abbreviation} Tactical Info
                            </span>
                            <span className="oswald font-black text-xl italic" style={{ color: teamColor }}>
                              #{playerData.number}
                            </span>
                          </div>

                          <div className="text-sm font-black text-white oswald uppercase tracking-tight mb-2">
                            {playerData.name}
                          </div>

                          <div className="grid grid-cols-2 gap-2 border-t border-white/10 pt-2">
                            <div className="flex flex-col">
                              <span className="text-[8px] font-bold text-slate-500 uppercase">Goals</span>
                              <span className="text-sm font-black text-white">{posStats.goals}</span>
                            </div>
                            <div className="flex flex-col">
                              <span className="text-[8px] font-bold text-slate-500 uppercase">Assists</span>
                              <span className="text-sm font-black text-white">{posStats.assists}</span>
                            </div>
                          </div>

                          {isSelected && (
                            <div className="mt-2 pt-2 border-t border-white/10">
                               <div className="bg-green-500/10 text-green-400 text-[9px] font-black uppercase text-center py-1 rounded border border-green-500/20">
                                Active In Lineup
                               </div>
                            </div>
                          )}
                        </div>
                      )}
                    </div>

                    {activePoints.map(fp => (
                      <div 
                        key={`overlay-point-pop-${fp.id}`} 
                        style={{ 
                          left: `calc(${coords.left} + ${fp.xOffset}px)`, 
                          top: `calc(${coords.top} - 32px)`,
                          animation: 'point-pop-overlay 1.8s cubic-bezier(0.175, 0.885, 0.32, 1.275) forwards' 
                        }} 
                        className="absolute pointer-events-none z-[250] flex flex-col items-center"
                      >
                        <div className={`px-2 py-0.5 rounded-full font-black oswald text-sm shadow-xl border border-white/40 backdrop-blur-md flex items-center gap-1.5 ${fp.isUser ? (fp.points > 0 ? 'bg-green-600 text-white' : 'bg-red-600 text-white') : 'bg-slate-800/90 text-slate-400'}`}>
                          {fp.points > 0 ? '+' : ''}{fp.points}
                          {fp.isUser && fp.points > 0 && <i className="fa-solid fa-star text-[8px] animate-spin"></i>}
                        </div>
                      </div>
                    ))}
                  </React.Fragment>
                );
              })
            )}
          </div>
        </div>

        <div className="p-8 bg-slate-900 border-t border-slate-700 flex flex-col lg:flex-row items-center justify-between gap-8">
          <div className="flex flex-col sm:flex-row gap-8 lg:gap-12 w-full lg:w-auto">
            {/* Away Selection */}
            <div className={`flex flex-col p-4 rounded-2xl border transition-all ${awayPick ? 'bg-slate-800 border-opacity-50' : 'bg-slate-900/50 border-slate-800'}`}
                 style={awayPick ? { borderColor: `${awayTeam.color}80` } : {}}>
              <span className="text-[11px] font-black text-slate-500 uppercase tracking-[0.2em] mb-3">{awayTeam.abbreviation} Selection</span>
              <div className="flex items-center gap-4">
                <div 
                  className={`w-12 h-12 rounded-full flex items-center justify-center font-black oswald text-xl border-2 ${awayPick ? 'border-white text-slate-950 animate-pulse' : 'bg-slate-800 border-slate-700 text-slate-600'}`}
                  style={awayPick ? { backgroundColor: awayTeam.color } : {}}
                >
                  {awayPick || '?'}
                </div>
                <div className="flex flex-col gap-1">
                  <span className="text-sm font-black text-white">{awayPick ? getPlayerData(awayTeam.name, awayPick).name : 'Select Position'}</span>
                  <div className="flex items-center gap-2">
                    <span className="text-[9px] font-bold text-slate-500 uppercase">Jersey #</span>
                    <input 
                      type="number" 
                      min="1" 
                      max="99" 
                      value={awayNum}
                      disabled={!awayPick || showSuccess}
                      onFocus={() => setFocusedSide('away')}
                      onBlur={() => setFocusedSide(null)}
                      onChange={(e) => setAwayNum(e.target.value.slice(0, 2))}
                      placeholder="--"
                      className="bg-slate-950 border border-slate-700 rounded-md w-12 py-1 text-center font-black oswald outline-none transition-all disabled:opacity-20"
                      style={{ 
                        color: awayTeam.color,
                        borderColor: focusedSide === 'away' ? awayTeam.color : undefined,
                        boxShadow: focusedSide === 'away' ? `0 0 10px ${awayTeam.color}33` : undefined
                      }}
                    />
                  </div>
                </div>
              </div>
            </div>

            {/* Home Selection */}
            <div className={`flex flex-col p-4 rounded-2xl border transition-all ${homePick ? 'bg-slate-800 border-opacity-50' : 'bg-slate-900/50 border-slate-800'}`}
                 style={homePick ? { borderColor: `${homeTeam.color}80` } : {}}>
              <span className="text-[11px] font-black text-slate-500 uppercase tracking-[0.2em] mb-3">{homeTeam.abbreviation} Selection</span>
              <div className="flex items-center gap-4">
                <div 
                  className={`w-12 h-12 rounded-full flex items-center justify-center font-black oswald text-xl border-2 ${homePick ? 'border-white text-white animate-pulse' : 'bg-slate-800 border-slate-700 text-slate-600'}`}
                  style={homePick ? { backgroundColor: homeTeam.color } : {}}
                >
                  {homePick || '?'}
                </div>
                <div className="flex flex-col gap-1">
                  <span className="text-sm font-black text-white">{homePick ? getPlayerData(homeTeam.name, homePick).name : 'Select Position'}</span>
                  <div className="flex items-center gap-2">
                    <span className="text-[9px] font-bold text-slate-500 uppercase">Jersey #</span>
                    <input 
                      type="number" 
                      min="1" 
                      max="99" 
                      value={homeNum}
                      disabled={!homePick || showSuccess}
                      onFocus={() => setFocusedSide('home')}
                      onBlur={() => setFocusedSide(null)}
                      onChange={(e) => setHomeNum(e.target.value.slice(0, 2))}
                      placeholder="--"
                      className="bg-slate-950 border border-slate-700 rounded-md w-12 py-1 text-center font-black oswald outline-none transition-all disabled:opacity-20"
                      style={{ 
                        color: homeTeam.color,
                        borderColor: focusedSide === 'home' ? homeTeam.color : undefined,
                        boxShadow: focusedSide === 'home' ? `0 0 10px ${homeTeam.color}33` : undefined
                      }}
                    />
                  </div>
                </div>
              </div>
            </div>
          </div>

          <button
            disabled={!isFormValid || showSuccess}
            onClick={handleConfirm}
            className={`w-full lg:w-80 py-6 rounded-2xl font-black oswald text-2xl uppercase tracking-[0.15em] transition-all relative overflow-hidden group ${
              isFormValid && !showSuccess
                ? 'bg-blue-600 hover:bg-blue-500 text-white shadow-[0_0_30px_rgba(37,99,235,0.4)] active:scale-95'
                : 'bg-slate-800 text-slate-600 cursor-not-allowed opacity-50'
            }`}
          >
            <span className="relative z-10">{showSuccess ? 'LOCKED' : (isFormValid ? 'LOCK LINEUP' : 'COMPLETE PICKS')}</span>
            {isFormValid && !showSuccess && (
              <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/10 to-transparent -translate-x-full group-hover:animate-shimmer" />
            )}
          </button>
        </div>
      </div>
      <style>{`
        @keyframes shimmer { 100% { transform: translateX(100%); } }
        @keyframes point-pop-overlay {
          0% { transform: translateY(0) scale(0.4); opacity: 0; }
          15% { transform: translateY(-15px) scale(1.1); opacity: 1; }
          70% { transform: translateY(-40px) scale(1); opacity: 1; }
          100% { transform: translateY(-55px) scale(0.85); opacity: 0; }
        }
        @keyframes possession-pulse {
          0% { box-shadow: 0 0 0 0 var(--pulse-color); filter: brightness(1); transform: scale(1); }
          50% { box-shadow: 0 0 30px 15px var(--pulse-color); filter: brightness(1.6); transform: scale(1.25); }
          100% { box-shadow: 0 0 0 0 var(--pulse-color); filter: brightness(1); transform: scale(1); }
        }
        .animate-possession-pulse { animation: possession-pulse 1.5s ease-in-out; }
        .group-hover\\:animate-shimmer { animation: shimmer 1.5s infinite; }
        input[type=number]::-webkit-inner-spin-button, 
        input[type=number]::-webkit-outer-spin-button { 
          -webkit-appearance: none; 
          margin: 0; 
        }
      `}</style>
    </div>
  );
};

export default SelectionOverlay;

import React, { useState, useEffect, useRef } from 'react';
import { Position, TeamInfo, GameEvent, FloatingPoint, OnIceStrength } from '../types';
import { POSITIONS } from '../constants';

interface SelectionOverlayProps {
  homeTeam: TeamInfo;
  awayTeam: TeamInfo;
  onConfirm: (picks: { home: Position; away: Position; homeNumber: number; awayNumber: number }) => void;
  events: GameEvent[];
  puckPossession?: { team: 'home' | 'away'; position: Position } | null;
  floatingPoints?: FloatingPoint[];
  strength: OnIceStrength;
  waitingReason?: string;
}

const PLAYER_DATA: Record<string, Record<Position, { name: string; number: number }>> = {
  'Rangers': { 
    'C': { name: 'M. Zibanejad', number: 93 }, 
    'LW': { name: 'A. Panarin', number: 10 }, 
    'RW': { name: 'A. Lafreniere', number: 13 }, 
    'LD': { name: 'R. Lindgren', number: 55 }, 
    'RD': { name: 'A. Fox', number: 23 }, 
    'G': { name: 'I. Shesterkin', number: 31 } 
  },
  'Bruins': { 
    'C': { name: 'C. Coyle', number: 13 }, 
    'LW': { name: 'B. Marchand', number: 63 }, 
    'RW': { name: 'D. Pastrnak', number: 88 }, 
    'LD': { name: 'H. Lindholm', number: 27 }, 
    'RD': { name: 'C. McAvoy', number: 73 }, 
    'G': { name: 'J. Swayman', number: 1 } 
  }
};

const SelectionOverlay: React.FC<SelectionOverlayProps> = ({ homeTeam, awayTeam, onConfirm, events, puckPossession, floatingPoints, strength, waitingReason }) => {
  const [awayPick, setAwayPick] = useState<Position | null>(null);
  const [homePick, setHomePick] = useState<Position | null>(null);
  const [awayNum, setAwayNum] = useState<string>('');
  const [homeNum, setHomeNum] = useState<string>('');
  const [showSuccess, setShowSuccess] = useState(false);
  const [focusedSide, setFocusedSide] = useState<'home' | 'away' | null>(null);

  const [hovered, setHovered] = useState<{ side: 'home' | 'away'; pos: Position } | null>(null);
  const [flash, setFlash] = useState<{ side: 'home' | 'away'; pos: Position; type: 'green' | 'red' | 'possession' } | null>(null);
  const prevPossessionRef = useRef<{ team: 'home' | 'away'; position: Position } | null>(null);

  const triggerFlash = (side: 'home' | 'away', pos: Position, type: 'green' | 'red' | 'possession', duration = 1500) => {
    setFlash({ side, pos, type });
    setTimeout(() => setFlash(null), duration);
  };

  useEffect(() => {
    if (puckPossession && (
      puckPossession.team !== prevPossessionRef.current?.team || 
      puckPossession.position !== prevPossessionRef.current?.position
    )) {
      triggerFlash(puckPossession.team, puckPossession.position, 'possession', 1500);
    }
    prevPossessionRef.current = puckPossession || null;
  }, [puckPossession]);

  const handleConfirm = () => {
    const aNum = parseInt(awayNum);
    const hNum = parseInt(homeNum);
    if (awayPick && homePick && !isNaN(aNum) && !isNaN(hNum)) {
      setShowSuccess(true);
      setTimeout(() => {
        onConfirm({ 
          home: homePick, 
          away: awayPick, 
          homeNumber: hNum, 
          awayNumber: aNum 
        });
      }, 1200);
    }
  };

  const handlePick = (side: 'home' | 'away', pos: Position) => {
    if (showSuccess) return; 
    const current = side === 'home' ? homePick : awayPick;
    if (current === pos) {
      triggerFlash(side, pos, 'red', 1000);
    } else {
      triggerFlash(side, pos, 'green', 1000);
      if (side === 'home') {
        setHomePick(pos);
        setHomeNum(PLAYER_DATA[homeTeam.name]?.[pos]?.number.toString() || '');
      } else {
        setAwayPick(pos);
        setAwayNum(PLAYER_DATA[awayTeam.name]?.[pos]?.number.toString() || '');
      }
    }
  };

  const getPlayerData = (teamName: string, pos: Position) => {
    return PLAYER_DATA[teamName]?.[pos] || { name: `${pos} Prospect`, number: 0 };
  };

  const getPosStats = (side: 'home' | 'away', pos: Position) => {
    const posEvents = events.filter(e => e.team === side && e.position === pos);
    const goals = posEvents.filter(e => e.type === 'GOAL' || e.type === 'SO_GOAL').length;
    const assists = posEvents.filter(e => e.type === 'ASSIST').length;
    return { goals, assists };
  };

  const getPosCoords = (pos: Position, isHome: boolean) => {
    const baseCoords: Record<Position, { top: string; left: string }> = {
      'G': { top: '50%', left: isHome ? '92%' : '8%' },
      'LD': { top: '30%', left: isHome ? '75%' : '25%' },
      'RD': { top: '70%', left: isHome ? '75%' : '25%' },
      'LW': { top: '22%', left: isHome ? '60%' : '40%' },
      'RW': { top: '78%', left: isHome ? '60%' : '40%' },
      'C': { top: '50%', left: isHome ? '60%' : '40%' },
    };
    return baseCoords[pos];
  };

  const isFormValid = awayPick && homePick && awayNum !== '' && homeNum !== '' && parseInt(awayNum) > 0 && parseInt(homeNum) > 0;

  return (
    <div className="fixed inset-0 z-[100] bg-slate-950/95 backdrop-blur-xl flex items-center justify-center p-4 overflow-y-auto">
      <div className="bg-slate-900 border border-slate-700 w-full max-w-5xl rounded-3xl shadow-[0_0_60px_rgba(0,0,0,0.6)] overflow-hidden animate-in fade-in zoom-in duration-500 my-auto relative">

        {showSuccess && (
          <div className="absolute inset-0 z-[200] bg-slate-950/60 backdrop-blur-md flex flex-col items-center justify-center animate-in fade-in duration-300">
            <div className="flex flex-col items-center gap-6 animate-in zoom-in slide-in-from-bottom-12 duration-500">
              <div className="w-24 h-24 bg-green-500 rounded-full flex items-center justify-center shadow-[0_0_50px_rgba(34,197,94,0.6)] border-4 border-green-400">
                <i className="fa-solid fa-check text-5xl text-white"></i>
              </div>
              <div className="text-center">
                <h3 className="text-5xl font-black oswald uppercase tracking-tighter text-white italic mb-2">Lineup Locked!</h3>
                <p className="text-green-400 text-sm font-black uppercase tracking-[0.4em]">Tactical Data Syncing...</p>
              </div>
            </div>
          </div>
        )}

        <div className="bg-slate-800/80 p-6 border-b border-slate-700 flex flex-col items-center text-center relative overflow-hidden">
          <div className="flex items-center gap-6 mb-2 relative z-10 w-full justify-between max-w-2xl">
            <div className="flex flex-col items-center gap-1 group">
               <span className="text-5xl transition-all duration-300">
                {awayTeam.logo}
              </span>
              <span className="text-[10px] font-black oswald text-slate-400 uppercase">{awayTeam.abbreviation}</span>
            </div>

            <div className="flex flex-col items-center">
              <div className="bg-amber-500/10 text-amber-500 text-[10px] font-black px-3 py-1 rounded-full border border-amber-500/20 uppercase tracking-[0.2em] mb-2 animate-pulse">
                {waitingReason || "Lineup Reset"}
              </div>
              <h2 className={`text-3xl font-black oswald uppercase tracking-tighter italic ${strength !== '5v5' ? 'text-amber-500' : 'text-white'}`}>
                {strength !== '5v5' ? `SPECIAL TEAMS: ${strength}` : 'LINEUP BUILDER'}
              </h2>
              <p className="text-slate-400 text-[9px] font-black uppercase tracking-[0.4em]">Tactical Deployments for current strength</p>
            </div>

            <div className="flex flex-col items-center gap-1 group">
              <span className="text-5xl transition-all duration-300">
                {homeTeam.logo}
              </span>
              <span className="text-[10px] font-black oswald text-slate-400 uppercase">{homeTeam.abbreviation}</span>
            </div>
          </div>
        </div>

        <div className="relative bg-white border-b border-slate-400">
          <div className="relative w-full aspect-[2.4/1] bg-white shadow-inner">
            {strength !== '5v5' && (
               <div className="absolute inset-0 bg-amber-500/5 animate-pulse pointer-events-none"></div>
            )}

            <div className="absolute inset-y-0 left-[6%] w-1.5 bg-red-600/50"></div>
            <div className="absolute inset-y-0 right-[6%] w-1.5 bg-red-600/50"></div>
            <div className="absolute inset-y-0 left-1/2 w-2 bg-red-600/70 -translate-x-1/2"></div>
            <div className="absolute top-1/2 left-1/2 w-5 h-5 bg-red-600 rounded-full -translate-x-1/2 -translate-y-1/2 shadow-sm border-2 border-white"></div>

            <div className="absolute inset-y-0 left-[35%] w-4 bg-blue-600/60"></div>
            <div className="absolute inset-y-0 right-[35%] w-4 bg-blue-600/60"></div>

            <div className="absolute top-6 left-10 oswald font-black uppercase tracking-widest text-3xl pointer-events-none text-slate-100 flex items-center gap-4">
              <span className="text-4xl filter drop-shadow-md">{awayTeam.logo}</span>
              {awayTeam.name}
            </div>
            <div className="absolute top-6 right-10 oswald font-black uppercase tracking-widest text-3xl pointer-events-none text-right text-slate-100 flex items-center gap-4">
              {homeTeam.name}
              <span className="text-4xl filter drop-shadow-md">{homeTeam.logo}</span>
            </div>

            {['away', 'home'].map((side) => 
              POSITIONS.map((pos) => {
                const isHomeSide = side === 'home';
                const coords = getPosCoords(pos.value, isHomeSide);
                const isSelected = isHomeSide ? homePick === pos.value : awayPick === pos.value;
                const isThisHovered = hovered?.side === side && hovered?.pos === pos.value;
                const activePoints = floatingPoints?.filter(fp => fp.team === side && fp.position === pos.value) || [];
                const isManualFlashing = flash?.side === side && flash?.pos === pos.value;

                let flashClass = '';
                let flashStyle: React.CSSProperties = {};
                if (isManualFlashing) {
                  if (flash.type === 'possession') {
                    flashClass = 'animate-possession-pulse';
                    flashStyle = { '--pulse-color': isHomeSide ? homeTeam.color : awayTeam.color } as React.CSSProperties;
                  } else {
                    flashClass = flash.type === 'green' ? 'animate-flash-green' : 'animate-flash-red';
                  }
                }

                const isKeySpecialTeamsPos = strength !== '5v5' && (pos.value === 'C' || pos.value === 'RD' || pos.value === 'RW');
                const teamColor = isHomeSide ? homeTeam.color : awayTeam.color;

                const playerData = getPlayerData(isHomeSide ? homeTeam.name : awayTeam.name, pos.value);
                const posStats = getPosStats(side as 'home' | 'away', pos.value);

                // Advanced Tooltip Boundary Logic
                const topVal = parseFloat(coords.top);
                const leftVal = parseFloat(coords.left);
                // Flip vertically if in the bottom half of the rink
                const showBelow = topVal < 50; 
                // Determine horizontal alignment based on quadrant to avoid side-clipping
                let horizontalClass = 'left-1/2 -translate-x-1/2'; // default center
                if (leftVal < 20) {
                    horizontalClass = 'left-0 translate-x-0';
                } else if (leftVal > 80) {
                    horizontalClass = 'right-0 translate-x-0';
                }

                return (
                  <React.Fragment key={`tactical-container-${side}-${pos.value}`}>
                    <div
                      style={{ top: coords.top, left: coords.left }}
                      className="absolute -translate-x-1/2 -translate-y-1/2 z-20"
                    >
                      <button
                        onMouseEnter={() => setHovered({ side: side as 'home' | 'away', pos: pos.value })}
                        onMouseLeave={() => setHovered(null)}
                        onClick={() => handlePick(side as 'home' | 'away', pos.value)}
                        className={`relative w-8 h-8 sm:w-10 sm:h-10 rounded-full flex flex-col items-center justify-center transition-all z-10 shadow-lg ${
                          isSelected
                            ? ('scale-110 ring-4 border-2 border-white text-white')
                            : isThisHovered 
                              ? ('scale-125 border-2 border-slate-400')
                              : isKeySpecialTeamsPos 
                                ? 'bg-amber-100 text-amber-900 border-2 border-amber-400 animate-pulse'
                                : 'bg-slate-800 text-white border-2 border-slate-600'
                        } ${flashClass}`}
                        style={{
                          ...(isSelected ? { backgroundColor: teamColor, boxShadow: `0 0 0 4px ${teamColor}4D` } : {}),
                          ...flashStyle
                        }}
                      >
                        <span className="text-[10px] sm:text-sm font-black oswald leading-none">{pos.value}</span>
                        {isSelected && (
                           <div 
                             className="absolute -top-1.5 -right-1.5 bg-white text-[7px] font-black px-1.5 py-0.5 rounded-full border shadow-sm transition-all"
                             style={{ color: teamColor, borderColor: teamColor }}
                           >
                            #{isHomeSide ? homeNum : awayNum}
                          </div>
                        )}
                      </button>

                      {/* Intelligent Tactical Tooltip */}
                      {isThisHovered && (
                        <div 
                          className={`absolute z-[300] w-52 bg-slate-900/98 backdrop-blur-xl border-2 rounded-2xl p-4 shadow-[0_20px_50px_rgba(0,0,0,0.5)] pointer-events-none animate-in zoom-in slide-in-from-top-2 duration-300 ${horizontalClass} ${
                            showBelow ? 'top-full mt-4' : 'bottom-full mb-4'
                          }`}
                          style={{ borderColor: `${teamColor}80`, boxShadow: `0 10px 30px -10px ${teamColor}40` }}
                        >
                          <div className="flex items-center justify-between mb-3">
                            <div className="flex items-center gap-2">
                                <span className="text-xl">{isHomeSide ? homeTeam.logo : awayTeam.logo}</span>
                                <span className="text-[10px] font-black uppercase tracking-widest text-white/50">
                                    {isHomeSide ? homeTeam.abbreviation : awayTeam.abbreviation} DATA
                                </span>
                            </div>
                            <span className="oswald font-black text-2xl italic leading-none" style={{ color: teamColor }}>
                              #{playerData.number}
                            </span>
                          </div>

                          <div className="text-base font-black text-white oswald uppercase tracking-tight mb-3 border-b border-white/10 pb-2">
                            {playerData.name}
                          </div>

                          <div className="grid grid-cols-2 gap-3">
                            <div className="bg-slate-950/50 p-2 rounded-lg border border-white/5">
                              <span className="text-[8px] font-bold text-slate-500 uppercase block mb-1">Goals</span>
                              <span className="text-lg font-black text-white oswald">{posStats.goals}</span>
                            </div>
                            <div className="bg-slate-950/50 p-2 rounded-lg border border-white/5">
                              <span className="text-[8px] font-bold text-slate-500 uppercase block mb-1">Assists</span>
                              <span className="text-lg font-black text-white oswald">{posStats.assists}</span>
                            </div>
                          </div>

                          {isSelected && (
                            <div className="mt-3">
                               <div className="bg-blue-500/10 text-blue-400 text-[10px] font-black uppercase text-center py-1.5 rounded-lg border border-blue-500/20 flex items-center justify-center gap-2">
                                <i className="fa-solid fa-check-double text-[8px]"></i>
                                Current Pick
                               </div>
                            </div>
                          )}
                        </div>
                      )}
                    </div>

                    {activePoints.map(fp => (
                      <div 
                        key={`overlay-point-pop-${fp.id}`} 
                        style={{ 
                          left: `calc(${coords.left} + ${fp.xOffset}px)`, 
                          top: `calc(${coords.top} - 32px)`,
                          animation: 'point-pop-overlay 1.8s cubic-bezier(0.175, 0.885, 0.32, 1.275) forwards' 
                        }} 
                        className="absolute pointer-events-none z-[250] flex flex-col items-center"
                      >
                        <div className={`px-2 py-0.5 rounded-full font-black oswald text-sm shadow-xl border border-white/40 backdrop-blur-md flex items-center gap-1.5 ${fp.isUser ? (fp.points > 0 ? 'bg-green-600 text-white' : 'bg-red-600 text-white') : 'bg-slate-800/90 text-slate-400'}`}>
                          {fp.points > 0 ? '+' : ''}{fp.points}
                          {fp.isUser && fp.points > 0 && <i className="fa-solid fa-star text-[8px] animate-spin"></i>}
                        </div>
                      </div>
                    ))}
                  </React.Fragment>
                );
              })
            )}
          </div>
        </div>

        <div className="p-8 bg-slate-900 border-t border-slate-700 flex flex-col lg:flex-row items-center justify-between gap-8">
          <div className="flex flex-col sm:flex-row gap-8 lg:gap-12 w-full lg:w-auto">
            {/* Away Selection */}
            <div className={`flex flex-col p-4 rounded-2xl border transition-all ${awayPick ? 'bg-slate-800 border-opacity-50' : 'bg-slate-900/50 border-slate-800'}`}
                 style={awayPick ? { borderColor: `${awayTeam.color}80` } : {}}>
              <span className="text-[11px] font-black text-slate-500 uppercase tracking-[0.2em] mb-3">{awayTeam.abbreviation} Selection</span>
              <div className="flex items-center gap-4">
                <div 
                  className={`w-12 h-12 rounded-full flex items-center justify-center font-black oswald text-xl border-2 ${awayPick ? 'border-white text-slate-950 animate-pulse' : 'bg-slate-800 border-slate-700 text-slate-600'}`}
                  style={awayPick ? { backgroundColor: awayTeam.color } : {}}
                >
                  {awayPick || '?'}
                </div>
                <div className="flex flex-col gap-1">
                  <span className="text-sm font-black text-white">{awayPick ? getPlayerData(awayTeam.name, awayPick).name : 'Select Position'}</span>
                  <div className="flex items-center gap-2">
                    <span className="text-[9px] font-bold text-slate-500 uppercase">Jersey #</span>
                    <input 
                      type="number" 
                      min="1" 
                      max="99" 
                      value={awayNum}
                      disabled={!awayPick || showSuccess}
                      onFocus={() => setFocusedSide('away')}
                      onBlur={() => setFocusedSide(null)}
                      onChange={(e) => setAwayNum(e.target.value.slice(0, 2))}
                      placeholder="--"
                      className="bg-slate-950 border border-slate-700 rounded-md w-12 py-1 text-center font-black oswald outline-none transition-all disabled:opacity-20"
                      style={{ 
                        color: awayTeam.color,
                        borderColor: focusedSide === 'away' ? awayTeam.color : undefined,
                        boxShadow: focusedSide === 'away' ? `0 0 10px ${awayTeam.color}33` : undefined
                      }}
                    />
                  </div>
                </div>
              </div>
            </div>

            {/* Home Selection */}
            <div className={`flex flex-col p-4 rounded-2xl border transition-all ${homePick ? 'bg-slate-800 border-opacity-50' : 'bg-slate-900/50 border-slate-800'}`}
                 style={homePick ? { borderColor: `${homeTeam.color}80` } : {}}>
              <span className="text-[11px] font-black text-slate-500 uppercase tracking-[0.2em] mb-3">{homeTeam.abbreviation} Selection</span>
              <div className="flex items-center gap-4">
                <div 
                  className={`w-12 h-12 rounded-full flex items-center justify-center font-black oswald text-xl border-2 ${homePick ? 'border-white text-white animate-pulse' : 'bg-slate-800 border-slate-700 text-slate-600'}`}
                  style={homePick ? { backgroundColor: homeTeam.color } : {}}
                >
                  {homePick || '?'}
                </div>
                <div className="flex flex-col gap-1">
                  <span className="text-sm font-black text-white">{homePick ? getPlayerData(homeTeam.name, homePick).name : 'Select Position'}</span>
                  <div className="flex items-center gap-2">
                    <span className="text-[9px] font-bold text-slate-500 uppercase">Jersey #</span>
                    <input 
                      type="number" 
                      min="1" 
                      max="99" 
                      value={homeNum}
                      disabled={!homePick || showSuccess}
                      onFocus={() => setFocusedSide('home')}
                      onBlur={() => setFocusedSide(null)}
                      onChange={(e) => setHomeNum(e.target.value.slice(0, 2))}
                      placeholder="--"
                      className="bg-slate-950 border border-slate-700 rounded-md w-12 py-1 text-center font-black oswald outline-none transition-all disabled:opacity-20"
                      style={{ 
                        color: homeTeam.color,
                        borderColor: focusedSide === 'home' ? homeTeam.color : undefined,
                        boxShadow: focusedSide === 'home' ? `0 0 10px ${homeTeam.color}33` : undefined
                      }}
                    />
                  </div>
                </div>
              </div>
            </div>
          </div>

          <button
            disabled={!isFormValid || showSuccess}
            onClick={handleConfirm}
            className={`w-full lg:w-80 py-6 rounded-2xl font-black oswald text-2xl uppercase tracking-[0.15em] transition-all relative overflow-hidden group ${
              isFormValid && !showSuccess
                ? 'bg-blue-600 hover:bg-blue-500 text-white shadow-[0_0_30px_rgba(37,99,235,0.4)] active:scale-95'
                : 'bg-slate-800 text-slate-600 cursor-not-allowed opacity-50'
            }`}
          >
            <span className="relative z-10">{showSuccess ? 'LOCKED' : (isFormValid ? 'LOCK LINEUP' : 'COMPLETE PICKS')}</span>
            {isFormValid && !showSuccess && (
              <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/10 to-transparent -translate-x-full group-hover:animate-shimmer" />
            )}
          </button>
        </div>
      </div>
      <style>{`
        @keyframes shimmer { 100% { transform: translateX(100%); } }
        @keyframes point-pop-overlay {
          0% { transform: translateY(0) scale(0.4); opacity: 0; }
          15% { transform: translateY(-15px) scale(1.1); opacity: 1; }
          70% { transform: translateY(-40px) scale(1); opacity: 1; }
          100% { transform: translateY(-55px) scale(0.85); opacity: 0; }
        }
        @keyframes possession-pulse {
          0% { box-shadow: 0 0 0 0 var(--pulse-color); filter: brightness(1); transform: scale(1); }
          50% { box-shadow: 0 0 40px 20px var(--pulse-color); filter: brightness(1.8); transform: scale(1.3); }
          100% { box-shadow: 0 0 0 0 var(--pulse-color); filter: brightness(1); transform: scale(1); }
        }
        .animate-possession-pulse { animation: possession-pulse 1.5s ease-in-out; }
        .group-hover\\:animate-shimmer { animation: shimmer 1.5s infinite; }
        input[type=number]::-webkit-inner-spin-button, 
        input[type=number]::-webkit-outer-spin-button { 
          -webkit-appearance: none; 
          margin: 0; 
        }
      `}</style>
    </div>
  );
};

export default SelectionOverlay;

import React, { useState, useEffect, useRef } from 'react';
import { Position, TeamInfo, GameEvent, FloatingPoint, OnIceStrength } from '../types';
import { POSITIONS } from '../constants';

interface SelectionOverlayProps {
  homeTeam: TeamInfo;
  awayTeam: TeamInfo;
  onConfirm: (picks: { home: Position; away: Position; homeNumber: number; awayNumber: number }) => void;
  events: GameEvent[];
  puckPossession?: { team: 'home' | 'away'; position: Position } | null;
  floatingPoints?: FloatingPoint[];
  strength: OnIceStrength;
  waitingReason?: string;
}

const PLAYER_DATA: Record<string, Record<Position, { name: string; number: number }>> = {
  'Rangers': { 
    'C': { name: 'M. Zibanejad', number: 93 }, 
    'LW': { name: 'A. Panarin', number: 10 }, 
    'RW': { name: 'A. Lafreniere', number: 13 }, 
    'LD': { name: 'R. Lindgren', number: 55 }, 
    'RD': { name: 'A. Fox', number: 23 }, 
    'G': { name: 'I. Shesterkin', number: 31 } 
  },
  'Bruins': { 
    'C': { name: 'C. Coyle', number: 13 }, 
    'LW': { name: 'B. Marchand', number: 63 }, 
    'RW': { name: 'D. Pastrnak', number: 88 }, 
    'LD': { name: 'H. Lindholm', number: 27 }, 
    'RD': { name: 'C. McAvoy', number: 73 }, 
    'G': { name: 'J. Swayman', number: 1 } 
  }
};

const SelectionOverlay: React.FC<SelectionOverlayProps> = ({ homeTeam, awayTeam, onConfirm, events, puckPossession, floatingPoints, strength, waitingReason }) => {
  const [awayPick, setAwayPick] = useState<Position | null>(null);
  const [homePick, setHomePick] = useState<Position | null>(null);
  const [awayNum, setAwayNum] = useState<string>('');
  const [homeNum, setHomeNum] = useState<string>('');
  const [showSuccess, setShowSuccess] = useState(false);
  const [focusedSide, setFocusedSide] = useState<'home' | 'away' | null>(null);

  const [hovered, setHovered] = useState<{ side: 'home' | 'away'; pos: Position } | null>(null);
  const [flash, setFlash] = useState<{ side: 'home' | 'away'; pos: Position; type: 'green' | 'red' | 'possession' } | null>(null);
  const prevPossessionRef = useRef<{ team: 'home' | 'away'; position: Position } | null>(null);

  const triggerFlash = (side: 'home' | 'away', pos: Position, type: 'green' | 'red' | 'possession', duration = 1500) => {
    setFlash({ side, pos, type });
    setTimeout(() => setFlash(null), duration);
  };

  useEffect(() => {
    if (puckPossession && (
      puckPossession.team !== prevPossessionRef.current?.team || 
      puckPossession.position !== prevPossessionRef.current?.position
    )) {
      triggerFlash(puckPossession.team, puckPossession.position, 'possession', 1500);
    }
    prevPossessionRef.current = puckPossession || null;
  }, [puckPossession]);

  const handleConfirm = () => {
    const aNum = parseInt(awayNum);
    const hNum = parseInt(homeNum);
    if (awayPick && homePick && !isNaN(aNum) && !isNaN(hNum)) {
      setShowSuccess(true);
      setTimeout(() => {
        onConfirm({ 
          home: homePick, 
          away: awayPick, 
          homeNumber: hNum, 
          awayNumber: aNum 
        });
      }, 1200);
    }
  };

  const handlePick = (side: 'home' | 'away', pos: Position) => {
    if (showSuccess) return; 
    const current = side === 'home' ? homePick : awayPick;
    if (current === pos) {
      triggerFlash(side, pos, 'red', 1000);
    } else {
      triggerFlash(side, pos, 'green', 1000);
      if (side === 'home') {
        setHomePick(pos);
        setHomeNum(PLAYER_DATA[homeTeam.name]?.[pos]?.number.toString() || '');
      } else {
        setAwayPick(pos);
        setAwayNum(PLAYER_DATA[awayTeam.name]?.[pos]?.number.toString() || '');
      }
    }
  };

  const getPlayerData = (teamName: string, pos: Position) => {
    return PLAYER_DATA[teamName]?.[pos] || { name: `${pos} Prospect`, number: 0 };
  };

  const getPosStats = (side: 'home' | 'away', pos: Position) => {
    const posEvents = events.filter(e => e.team === side && e.position === pos);
    const goals = posEvents.filter(e => e.type === 'GOAL' || e.type === 'SO_GOAL').length;
    const assists = posEvents.filter(e => e.type === 'ASSIST').length;
    return { goals, assists };
  };

  const getPosCoords = (pos: Position, isHome: boolean) => {
    const baseCoords: Record<Position, { top: string; left: string }> = {
      'G': { top: '50%', left: isHome ? '92%' : '8%' },
      'LD': { top: '30%', left: isHome ? '75%' : '25%' },
      'RD': { top: '70%', left: isHome ? '75%' : '25%' },
      'LW': { top: '22%', left: isHome ? '60%' : '40%' },
      'RW': { top: '78%', left: isHome ? '60%' : '40%' },
      'C': { top: '50%', left: isHome ? '60%' : '40%' },
    };
    return baseCoords[pos];
  };

  const isFormValid = awayPick && homePick && awayNum !== '' && homeNum !== '' && parseInt(awayNum) > 0 && parseInt(homeNum) > 0;

  return (
    <div className="fixed inset-0 z-[100] bg-slate-950/95 backdrop-blur-xl flex items-center justify-center p-4 overflow-y-auto">
      <div className="bg-slate-900 border border-slate-700 w-full max-w-5xl rounded-3xl shadow-[0_0_60px_rgba(0,0,0,0.6)] overflow-hidden animate-in fade-in zoom-in duration-500 my-auto relative">

        {showSuccess && (
          <div className="absolute inset-0 z-[200] bg-slate-950/60 backdrop-blur-md flex flex-col items-center justify-center animate-in fade-in duration-300">
            <div className="flex flex-col items-center gap-6 animate-in zoom-in slide-in-from-bottom-12 duration-500">
              <div className="w-24 h-24 bg-green-500 rounded-full flex items-center justify-center shadow-[0_0_50px_rgba(34,197,94,0.6)] border-4 border-green-400">
                <i className="fa-solid fa-check text-5xl text-white"></i>
              </div>
              <div className="text-center">
                <h3 className="text-5xl font-black oswald uppercase tracking-tighter text-white italic mb-2">Lineup Locked!</h3>
                <p className="text-green-400 text-sm font-black uppercase tracking-[0.4em]">Tactical Data Syncing...</p>
              </div>
            </div>
          </div>
        )}

        <div className="bg-slate-800/80 p-6 border-b border-slate-700 flex flex-col items-center text-center relative overflow-hidden">
          <div className="flex items-center gap-6 mb-2 relative z-10 w-full justify-between max-w-2xl">
            <div className="flex flex-col items-center gap-1 group">
               <span className="text-5xl transition-all duration-300">
                {awayTeam.logo}
              </span>
              <span className="text-[10px] font-black oswald text-slate-400 uppercase">{awayTeam.abbreviation}</span>
            </div>

            <div className="flex flex-col items-center">
              <div className="bg-amber-500/10 text-amber-500 text-[10px] font-black px-3 py-1 rounded-full border border-amber-500/20 uppercase tracking-[0.2em] mb-2 animate-pulse">
                {waitingReason || "Lineup Reset"}
              </div>
              <h2 className={`text-3xl font-black oswald uppercase tracking-tighter italic ${strength !== '5v5' ? 'text-amber-500' : 'text-white'}`}>
                {strength !== '5v5' ? `SPECIAL TEAMS: ${strength}` : 'LINEUP BUILDER'}
              </h2>
              <p className="text-slate-400 text-[9px] font-black uppercase tracking-[0.4em]">Tactical Deployments for current strength</p>
            </div>

            <div className="flex flex-col items-center gap-1 group">
              <span className="text-5xl transition-all duration-300">
                {homeTeam.logo}
              </span>
              <span className="text-[10px] font-black oswald text-slate-400 uppercase">{homeTeam.abbreviation}</span>
            </div>
          </div>
        </div>

        <div className="relative bg-slate-100 border-b border-slate-400 p-1">
          <div className="relative w-full aspect-[2.4/1] bg-white shadow-inner rounded-sm overflow-hidden border border-slate-300">
            {/* Ice Texture Overlay */}
            <div className="absolute inset-0 opacity-[0.03] pointer-events-none bg-[url('https://www.transparenttextures.com/patterns/pinstriped-suit.png')]"></div>

            {/* Rink Lines and Markings */}
            <svg className="absolute inset-0 w-full h-full pointer-events-none" viewBox="0 0 240 100" preserveAspectRatio="none">
              {/* Goal Creases */}
              <path d="M 14.4 42 A 8 8 0 0 1 14.4 58" fill="rgba(37, 99, 235, 0.1)" stroke="rgba(239, 68, 68, 0.4)" strokeWidth="0.5" />
              <path d="M 225.6 42 A 8 8 0 0 0 225.6 58" fill="rgba(37, 99, 235, 0.1)" stroke="rgba(239, 68, 68, 0.4)" strokeWidth="0.5" />

              {/* Goal Lines */}
              <line x1="14.4" y1="0" x2="14.4" y2="100" stroke="rgba(239, 68, 68, 0.6)" strokeWidth="0.8" />
              <line x1="225.6" y1="0" x2="225.6" y2="100" stroke="rgba(239, 68, 68, 0.6)" strokeWidth="0.8" />

              {/* Blue Lines */}
              <rect x="84" y="0" width="1.5" height="100" fill="rgba(37, 99, 235, 0.8)" />
              <rect x="154.5" y="0" width="1.5" height="100" fill="rgba(37, 99, 235, 0.8)" />

              {/* Center Line */}
              <rect x="119.5" y="0" width="1" height="100" fill="rgba(239, 68, 68, 0.8)" />

              {/* Center Circle */}
              <circle cx="120" cy="50" r="15" fill="none" stroke="rgba(37, 99, 235, 0.4)" strokeWidth="0.5" />
              <circle cx="120" cy="50" r="1.5" fill="rgba(37, 99, 235, 0.8)" />

              {/* End Zone Faceoff Circles */}
              <circle cx="48" cy="25" r="15" fill="none" stroke="rgba(239, 68, 68, 0.3)" strokeWidth="0.5" />
              <circle cx="48" cy="75" r="15" fill="none" stroke="rgba(239, 68, 68, 0.3)" strokeWidth="0.5" />
              <circle cx="192" cy="25" r="15" fill="none" stroke="rgba(239, 68, 68, 0.3)" strokeWidth="0.5" />
              <circle cx="192" cy="75" r="15" fill="none" stroke="rgba(239, 68, 68, 0.3)" strokeWidth="0.5" />

              {/* Faceoff Dots */}
              <circle cx="48" cy="25" r="1" fill="rgba(239, 68, 68, 0.6)" />
              <circle cx="48" cy="75" r="1" fill="rgba(239, 68, 68, 0.6)" />
              <circle cx="192" cy="25" r="1" fill="rgba(239, 68, 68, 0.6)" />
              <circle cx="192" cy="75" r="1" fill="rgba(239, 68, 68, 0.6)" />

              {/* Neutral Zone Dots */}
              <circle cx="84.75" cy="25" r="1" fill="rgba(239, 68, 68, 0.6)" />
              <circle cx="84.75" cy="75" r="1" fill="rgba(239, 68, 68, 0.6)" />
              <circle cx="155.25" cy="25" r="1" fill="rgba(239, 68, 68, 0.6)" />
              <circle cx="155.25" cy="75" r="1" fill="rgba(239, 68, 68, 0.6)" />
            </svg>

            {strength !== '5v5' && (
               <div className="absolute inset-0 bg-amber-500/5 animate-pulse pointer-events-none"></div>
            )}

            <div className="absolute top-6 left-10 oswald font-black uppercase tracking-widest text-3xl pointer-events-none text-slate-100 flex items-center gap-4">
              <span className="text-4xl filter drop-shadow-md">{awayTeam.logo}</span>
              {awayTeam.name}
            </div>
            <div className="absolute top-6 right-10 oswald font-black uppercase tracking-widest text-3xl pointer-events-none text-right text-slate-100 flex items-center gap-4">
              {homeTeam.name}
              <span className="text-4xl filter drop-shadow-md">{homeTeam.logo}</span>
            </div>

            {['away', 'home'].map((side) => 
              POSITIONS.map((pos) => {
                const isHomeSide = side === 'home';
                const coords = getPosCoords(pos.value, isHomeSide);
                const isSelected = isHomeSide ? homePick === pos.value : awayPick === pos.value;
                const isThisHovered = hovered?.side === side && hovered?.pos === pos.value;
                const activePoints = floatingPoints?.filter(fp => fp.team === side && fp.position === pos.value) || [];
                const isManualFlashing = flash?.side === side && flash?.pos === pos.value;

                let flashClass = '';
                let flashStyle: React.CSSProperties = {};
                if (isManualFlashing) {
                  if (flash.type === 'possession') {
                    flashClass = 'animate-possession-pulse';
                    flashStyle = { '--pulse-color': isHomeSide ? homeTeam.color : awayTeam.color } as React.CSSProperties;
                  } else {
                    flashClass = flash.type === 'green' ? 'animate-flash-green' : 'animate-flash-red';
                  }
                }

                const isKeySpecialTeamsPos = strength !== '5v5' && (pos.value === 'C' || pos.value === 'RD' || pos.value === 'RW');
                const teamColor = isHomeSide ? homeTeam.color : awayTeam.color;

                const playerData = getPlayerData(isHomeSide ? homeTeam.name : awayTeam.name, pos.value);
                const posStats = getPosStats(side as 'home' | 'away', pos.value);

                // Advanced Tooltip Boundary Logic
                const topVal = parseFloat(coords.top);
                const leftVal = parseFloat(coords.left);
                // Flip vertically if in the bottom half of the rink
                const showBelow = topVal < 50; 
                // Determine horizontal alignment based on quadrant to avoid side-clipping
                let horizontalClass = 'left-1/2 -translate-x-1/2'; // default center
                if (leftVal < 20) {
                    horizontalClass = 'left-0 translate-x-0';
                } else if (leftVal > 80) {
                    horizontalClass = 'right-0 translate-x-0';
                }

                return (
                  <React.Fragment key={`tactical-container-${side}-${pos.value}`}>
                    <div
                      style={{ top: coords.top, left: coords.left }}
                      className="absolute -translate-x-1/2 -translate-y-1/2 z-20"
                    >
                      <button
                        onMouseEnter={() => setHovered({ side: side as 'home' | 'away', pos: pos.value })}
                        onMouseLeave={() => setHovered(null)}
                        onClick={() => handlePick(side as 'home' | 'away', pos.value)}
                        className={`relative w-8 h-8 sm:w-10 sm:h-10 rounded-full flex flex-col items-center justify-center transition-all z-10 shadow-lg ${
                          isSelected
                            ? ('scale-110 ring-4 border-2 border-white text-white')
                            : isThisHovered 
                              ? ('scale-125 border-2 border-slate-400')
                              : isKeySpecialTeamsPos 
                                ? 'bg-amber-100 text-amber-900 border-2 border-amber-400 animate-pulse'
                                : 'bg-slate-800 text-white border-2 border-slate-600'
                        } ${flashClass}`}
                        style={{
