                                <i className="fa-solid fa-check-double text-[8px]"></i>
                                Current Pick
                               </div>
                            </div>
                          )}
                        </div>
                      )}
                    </div>

                    {activePoints.map(fp => (
                      <div 
                        key={`overlay-point-pop-${fp.id}`} 
                        style={{ 
