import { GoogleGenAI, Type } from "@google/genai";
import { GameEvent, Position, ScheduledGame, OnIceStrength, GroundingSource } from "../types";
import { SCORING_RULES } from "../constants";

export const fetchTodayGames = async (): Promise<{ games: ScheduledGame[]; sources: GroundingSource[] }> => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: "Find today's NHL schedule (current date is " + new Date().toLocaleDateString() + "). Return a list of games including home team, away team, start time, and venue. Include city names, full team names, and short abbreviations like NYR or BOS. Use representative emojis for team logos.",
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            games: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  id: { type: Type.STRING },
                  homeTeam: {
                    type: Type.OBJECT,
                    properties: {
                      name: { type: Type.STRING },
                      city: { type: Type.STRING },
                      abbreviation: { type: Type.STRING },
                      color: { type: Type.STRING, description: "hex color code" },
                      logo: { type: Type.STRING }
                    },
                    required: ['name', 'city', 'abbreviation', 'color', 'logo']
                  },
                  awayTeam: {
                    type: Type.OBJECT,
                    properties: {
                      name: { type: Type.STRING },
                      city: { type: Type.STRING },
                      abbreviation: { type: Type.STRING },
                      color: { type: Type.STRING, description: "hex color code" },
                      logo: { type: Type.STRING }
                    },
                    required: ['name', 'city', 'abbreviation', 'color', 'logo']
                  },
                  startTime: { type: Type.STRING },
                  venue: { type: Type.STRING }
                },
                required: ['id', 'homeTeam', 'awayTeam', 'startTime', 'venue']
              }
            }
          },
          required: ['games']
        }
      }
    });

    const data = JSON.parse(response.text || '{"games": []}');
    const sources: GroundingSource[] = response.candidates?.[0]?.groundingMetadata?.groundingChunks
      ?.filter((chunk: any) => chunk.web)
      ?.map((chunk: any) => ({
        title: chunk.web.title,
        uri: chunk.web.uri
      })) || [];

    return { games: data.games, sources };
  } catch (error) {
    console.error("Error fetching today's games:", error);
    return { games: [], sources: [] };
  }
};

export const fetchSimulatedEvents = async (
  period: number, 
  timeRemaining: string, 
  homeTeam: { name: string; city: string; abbreviation: string }, 
  awayTeam: { name: string; city: string; abbreviation: string }
): Promise<{ 
  events: Partial<GameEvent>[], 
  nextFaceoffTrigger: boolean,
  currentPossession: { team: 'home' | 'away', position: Position } | null,
  realTimeSync: boolean,
  strength: OnIceStrength,
  penaltyClocks: { home: string | null, away: string | null },
  sources: GroundingSource[]
}> => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const searchPrompt = `Search for live play-by-play and current score for the NHL game: ${awayTeam.city} ${awayTeam.name} vs ${homeTeam.city} ${homeTeam.name} today. 
    Detect if there is currently a penalty or overtime situation.
    Strengths possible: 5v5, 5v4, 5v3, 4v4, 4v3, 3v3.
    If the game is live, find the most recent events and strength.
    Return a list of events including the position responsible (C, LW, RW, LD, RD, G) AND THEIR JERSEY NUMBER.
    If a goal was just scored or a penalty just started/ended, set nextFaceoffTrigger to true.`;

    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: searchPrompt,
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            events: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  team: { type: Type.STRING, enum: ['home', 'away'] },
                  position: { type: Type.STRING, enum: ['C', 'LW', 'RW', 'LD', 'RD', 'G'] },
                  playerNumber: { type: Type.INTEGER },
                  type: { type: Type.STRING, enum: ['GOAL', 'ASSIST', 'HIT', 'SHOT', 'BLOCKED_SHOT', 'TAKEAWAY', 'PASS', 'GIVEAWAY', 'SAVE', 'GOAL_AGAINST', 'PENALTY'] },
                  description: { type: Type.STRING },
                  gameTime: { type: Type.STRING }
                },
                required: ['team', 'position', 'playerNumber', 'type', 'description', 'gameTime']
              }
            },
            nextFaceoffTrigger: { type: Type.BOOLEAN },
            currentPossession: {
              type: Type.OBJECT,
              properties: {
                team: { type: Type.STRING, enum: ['home', 'away'] },
                position: { type: Type.STRING, enum: ['C', 'LW', 'RW', 'LD', 'RD', 'G'] }
              },
              required: ['team', 'position']
            },
            strength: { type: Type.STRING, enum: ['5v5', '5v4', '5v3', '4v4', '4v3', '3v3'] },
            penaltyClocks: {
              type: Type.OBJECT,
              properties: {
                home: { type: Type.STRING, nullable: true },
                away: { type: Type.STRING, nullable: true }
              },
              required: ['home', 'away']
            },
            foundRealData: { type: Type.BOOLEAN }
          },
          required: ['events', 'nextFaceoffTrigger', 'currentPossession', 'strength', 'penaltyClocks', 'foundRealData']
        }
      }
    });

    const data = JSON.parse(response.text || '{"events":[], "nextFaceoffTrigger": false, "currentPossession": null, "strength": "5v5", "penaltyClocks": {"home":null, "away":null}, "foundRealData": false}');

    const sources: GroundingSource[] = response.candidates?.[0]?.groundingMetadata?.groundingChunks
      ?.filter((chunk: any) => chunk.web)
      ?.map((chunk: any) => ({
        title: chunk.web.title,
        uri: chunk.web.uri
      })) || [];

    const eventsWithPoints = data.events.map((e: any) => {
      let points = 0;
      if (e.position === 'G') {
        points = e.type === 'SAVE' ? SCORING_RULES.GOALIE.SAVE : SCORING_RULES.GOALIE.GOAL_AGAINST;
      } else {
        points = (SCORING_RULES.SKATER as any)[e.type] || 0;
      }
      if (data.strength !== '5v5' && (e.type === 'GOAL' || e.type === 'ASSIST')) {
        points = Math.floor(points * 1.25);
      }
      return { ...e, points, id: Math.random().toString(36).substr(2, 9), timestamp: Date.now(), strength: data.strength };
    });

    return { 
      events: eventsWithPoints, 
      nextFaceoffTrigger: data.nextFaceoffTrigger,
      currentPossession: data.currentPossession,
      realTimeSync: data.foundRealData,
      strength: data.strength,
      penaltyClocks: data.penaltyClocks,
      sources
    };
  } catch (error) {
    console.error("Error fetching events via search:", error);
    return { events: [], nextFaceoffTrigger: false, currentPossession: null, realTimeSync: false, strength: '5v5', penaltyClocks: { home: null, away: null }, sources: [] };
  }
};

