            {event.type.replace('_', ' ')}
          </span>
          <span className="text-[10px] font-black text-slate-500 oswald tracking-widest">{event.gameTime} • {event.period === 4 ? 'OT' : event.period === 5 ? 'SO' : `P${event.period}`}</span>
          {event.strength && event.strength !== '5v5' && (
            <span className="text-[9px] font-black text-amber-500 border border-amber-500/30 px-2 py-0.5 rounded-full bg-amber-500/5">
              {event.strength}
            </span>
          )}
        </div>
        <p className="text-sm font-bold text-slate-100 truncate flex items-center gap-2">
          <span className={`w-8 text-center text-[10px] font-black rounded ${event.team === 'home' ? 'bg-blue-600/20 text-blue-400' : 'bg-amber-500/20 text-amber-500'}`}>{event.position}</span>
          {event.playerNumber ? <span className="text-white/60 font-black">#{event.playerNumber}</span> : null}
          {event.description}
        </p>
      </div>

      {event.userEarned !== 0 && (
        <div className={`flex-shrink-0 px-5 py-2 rounded-2xl font-black oswald text-xl border transition-all duration-300 group-hover:scale-105 ${event.userEarned! > 0 ? 'bg-green-600/20 border-green-500/40 text-green-400 shadow-[0_0_15px_rgba(34,197,94,0.2)]' : 'bg-red-600/20 border-red-500/40 text-red-400'}`}>
          {event.userEarned! > 0 ? '+' : ''}{event.userEarned}
          <span className="text-[8px] block leading-none opacity-60">PTS</span>
        </div>
      )}
    </div>
  );
};

