                {event.position}
              </div>
              <div className="flex-1 min-w-0">
                <div className="flex items-center gap-2 mb-0.5">
                  <span className="text-[9px] font-black oswald text-slate-500">{event.gameTime}</span>
                  <span className={`text-[8px] font-black uppercase px-1.5 py-0.5 rounded ${event.type === 'GOAL' || event.type === 'SO_GOAL' ? 'bg-red-500/20 text-red-500' : 'bg-slate-800 text-slate-400'}`}>
