};

const App: React.FC = () => {
  const [scheduledGames, setScheduledGames] = useState<ScheduledGame[]>([]);
  const [scheduleSources, setScheduleSources] = useState<GroundingSource[]>([]);
  const [isLoadingSchedule, setIsLoadingSchedule] = useState(false);
  const [hasSelectedGame, setHasSelectedGame] = useState(false);
  const [isRealTimeSync, setIsRealTimeSync] = useState(false);

  const [game, setGame] = useState<GameState>({
    period: 1,
    timeRemaining: '20:00',
    isPaused: false,
    waitingForPicks: true,
    waitingReason: 'Initial Lineup',
    homeTeam: INITIAL_TEAMS.home,
    awayTeam: INITIAL_TEAMS.away,
    strength: '5v5',
    penaltyClocks: { home: null, away: null },
    userPicks: { home: null, away: null, homeNumber: null, awayNumber: null },
    totalPoints: 1000,
    rank: 124,
    totalPlayers: 1542,
    events: [],
    puckPossession: null,
    shootout: {
      isActive: false,
      round: 1,
      homeAttempts: [],
      awayAttempts: [],
      currentTurn: 'away',
      shooterName: '',
      goalieName: '',
    },
    groundingSources: [],
  });

  const [competitors, setCompetitors] = useState<LeaderboardPlayer[]>(() => {
    return Array.from({ length: 49 }, (_, i) => ({
      id: `comp-${i}`,
      name: `User_${Math.floor(Math.random() * 9000) + 1000}`,
      points: Math.max(0, 15000 - (i * 300) + (Math.random() * 500)),
    }));
  });

  const [floatingPoints, setFloatingPoints] = useState<FloatingPoint[]>([]);
  const [shotTrajectories, setShotTrajectories] = useState<ShotTrajectory[]>([]);
  const [explosions, setExplosions] = useState<GoalExplosion[]>([]);
  const [loadingEvents, setLoadingEvents] = useState(false);
  const [notifPermission, setNotifPermission] = useState<NotificationPermission>(getNotificationStatus());
  const tickerRef = useRef<any>(null);

  useEffect(() => {
    const loadGames = async () => {
      setIsLoadingSchedule(true);
      const result = await fetchTodayGames();
      setScheduledGames(result.games);
      setScheduleSources(result.sources);
      setIsLoadingSchedule(false);
    };
    loadGames();
  }, []);

  const handleSelectGame = (selected: ScheduledGame) => {
    setGame(prev => ({
      ...prev,
      homeTeam: { ...selected.homeTeam, score: 0 },
      awayTeam: { ...selected.awayTeam, score: 0 },
      events: [],
      totalPoints: 1000,
      waitingForPicks: true,
      waitingReason: 'Start of Game',
      period: 1,
      timeRemaining: '20:00',
      strength: '5v5',
      shootout: {
        isActive: false,
        round: 1,
        homeAttempts: [],
        awayAttempts: [],
        currentTurn: 'away',
        shooterName: '',
        goalieName: '',
      },
      groundingSources: [],
    }));
    setHasSelectedGame(true);
  };

  const leaderboardData = useMemo(() => {
    const userPlayer: LeaderboardPlayer = {
      id: 'user-main',
      name: 'PuckMaster99',
      points: game.totalPoints,
      isUser: true
    };
    return [...competitors, userPlayer];
  }, [competitors, game.totalPoints]);

  useEffect(() => {
    const sorted = [...leaderboardData].sort((a, b) => b.points - a.points);
    const userIndex = sorted.findIndex(p => p.isUser);
    setGame(prev => ({ ...prev, rank: userIndex + 1 }));
  }, [leaderboardData]);

  const updateCompetitors = useCallback(() => {
    setCompetitors(prev => prev.map(comp => {
      const gain = Math.random() > 0.7 ? Math.floor(Math.random() * 1000) : 0;
      return { ...comp, points: comp.points + gain };
    }));
  }, []);

  const triggerGoalExplosion = (team: 'home' | 'away') => {
    const id = Math.random().toString(36).substr(2, 9);
    const color = team === 'home' ? game.homeTeam.color : game.awayTeam.color;
    setExplosions(prev => [...prev, { id, team, color }]);
    setTimeout(() => {
      setExplosions(prev => prev.filter(e => e.id !== id));
    }, 3000);
  };

  const triggerPointsAnimation = (points: number, team: 'home' | 'away', position: Position, isUser: boolean) => {
    const id = Math.random().toString(36).substr(2, 9);
    const newFloatingPoint: FloatingPoint = {
      id,
      points,
      team,
      position,
      isUser,
      xOffset: (Math.random() - 0.5) * 40,
      variant: Math.floor(Math.random() * 3),
    };
    setFloatingPoints(prev => [...prev, newFloatingPoint]);
    setTimeout(() => {
      setFloatingPoints(prev => prev.filter(fp => fp.id !== id));
    }, 2000);
  };

  const triggerShotAnimation = (team: 'home' | 'away', pos: Position) => {
    const id = Math.random().toString(36).substr(2, 9);

    const baseCoords: Record<Position, { top: string; left: string }> = {
      'G': { top: '50%', left: team === 'home' ? '92%' : '8%' },
      'LD': { top: '30%', left: team === 'home' ? '75%' : '25%' },
      'RD': { top: '70%', left: team === 'home' ? '75%' : '25%' },
      'LW': { top: '22%', left: team === 'home' ? '60%' : '40%' },
      'RW': { top: '78%', left: team === 'home' ? '60%' : '40%' },
      'C': { top: '50%', left: team === 'home' ? '60%' : '40%' },
    };

    const start = baseCoords[pos];
    const end = { top: '50%', left: team === 'home' ? '8%' : '92%' }; 

    const newTrajectory: ShotTrajectory = {
      id,
      startX: start.left,
      startY: start.top,
      endX: end.left,
      endY: end.top,
      team,
      color: team === 'home' ? '#3b82f6' : '#f59e0b',
    };

    setShotTrajectories(prev => [...prev, newTrajectory]);
    setTimeout(() => {
      setShotTrajectories(prev => prev.filter(st => st.id !== id));
    }, 1500);
  };

  const processEvents = useCallback(async () => {
    if (loadingEvents || game.waitingForPicks || !hasSelectedGame || game.shootout.isActive) return;

    setLoadingEvents(true);
    const result = await fetchSimulatedEvents(
      game.period,
      game.timeRemaining,
      game.homeTeam,
      game.awayTeam
    );

    setIsRealTimeSync(result.realTimeSync);

    let newPoints = 0;
    let currentHomeScore = game.homeTeam.score;
    let currentAwayScore = game.awayTeam.score;
    let goalScored = false;
    let scoringTeamType: 'home' | 'away' | null = null;

    const processedEvents = result.events.map(event => {
      if (event.type === 'GOAL') {
        goalScored = true;
        scoringTeamType = event.team as 'home' | 'away';
        if (event.team === 'home') currentHomeScore++;
        else currentAwayScore++;
      }

      if (event.type === 'SHOT' || event.type === 'GOAL') {
        triggerShotAnimation(event.team as 'home' | 'away', event.position!);
      }

      const userPickPos = event.team === 'home' ? game.userPicks.home : game.userPicks.away;
      const userPickNum = event.team === 'home' ? game.userPicks.homeNumber : game.userPicks.awayNumber;

      // Points only earned if BOTH position and number match the live event
      const isUserPick = event.position === userPickPos && (event.playerNumber ? event.playerNumber === userPickNum : false);
      const earned = isUserPick ? (event.points || 0) : 0;

      if (earned !== 0) {
        newPoints += earned;
        triggerPointsAnimation(earned, event.team!, event.position!, true);
      } else if (event.points && event.points !== 0) {
        triggerPointsAnimation(event.points!, event.team!, event.position!, false);
      }

      return { 
        ...event, 
        userEarned: earned, 
        homeScoreAtEvent: currentHomeScore, 
        awayScoreAtEvent: currentAwayScore,
        period: game.period 
      } as GameEvent;
    });

    if (goalScored && scoringTeamType) {
      triggerGoalExplosion(scoringTeamType);
    }

    const strengthChanged = result.strength !== game.strength;
    const faceoffTriggered = result.nextFaceoffTrigger || strengthChanged;

    let reason = "Live Faceoff";
    if (strengthChanged) {
        reason = `Special Teams Shift: ${result.strength}`;
    } else if (goalScored) {
        reason = "Goal Scored - Reset Lines";
    }

    if (faceoffTriggered) {
      sendGameNotification("Tactical Alert!", reason);
    }

    setGame(prev => ({
      ...prev,
      totalPoints: prev.totalPoints + newPoints,
      events: [...processedEvents, ...prev.events].slice(0, 100),
      homeTeam: { ...prev.homeTeam, score: currentHomeScore },
      awayTeam: { ...prev.awayTeam, score: currentAwayScore },
      waitingForPicks: faceoffTriggered,
      waitingReason: reason,
      puckPossession: result.currentPossession,
      strength: result.strength,
      penaltyClocks: result.penaltyClocks,
      groundingSources: result.sources,
    }));

    updateCompetitors();
    setLoadingEvents(false);
  }, [game.period, game.timeRemaining, game.homeTeam, game.awayTeam, game.userPicks, game.waitingForPicks, loadingEvents, game.homeTeam.score, game.awayTeam.score, updateCompetitors, hasSelectedGame, game.strength, game.shootout.isActive]);

  useEffect(() => {
    if (game.waitingForPicks || game.isPaused || !hasSelectedGame || game.shootout.isActive) return;
    tickerRef.current = setInterval(() => {
      setGame(prev => {
        const [mins, secs] = prev.timeRemaining.split(':').map(Number);
        let totalSecs = mins * 60 + secs - 12;
        if (totalSecs <= 0) {
          if (prev.period < 3) return { ...prev, period: prev.period + 1, timeRemaining: '20:00', waitingForPicks: true, waitingReason: `End of ${prev.period === 1 ? '1st' : '2nd'} Period`, puckPossession: null };
          if (prev.period === 3 && prev.homeTeam.score === prev.awayTeam.score) {
             return { ...prev, period: 4, timeRemaining: '05:00', waitingForPicks: true, waitingReason: 'Overtime Sudden Death', puckPossession: null, strength: '3v3' };
          }
          if (prev.period === 4 && prev.homeTeam.score === prev.awayTeam.score) {
            return { 
              ...prev, 
              period: 5, 
              timeRemaining: 'SO', 
              waitingForPicks: true, 
              waitingReason: 'Shootout Mode',
              shootout: { 
                isActive: true, 
                round: 1, 
                homeAttempts: [], 
                awayAttempts: [], 
                currentTurn: 'away',
                shooterName: 'Top Prospect',
                goalieName: 'Elite Keeper'
              } 
            };
          }
          return { ...prev, isPaused: true, timeRemaining: '00:00', puckPossession: null };
        }
        const newMins = Math.floor(totalSecs / 60);
        const newSecs = totalSecs % 60;
        return { ...prev, timeRemaining: `${newMins.toString().padStart(2, '0')}:${newSecs.toString().padStart(2, '0')}` };
      });
    }, 1000);
    return () => { if (tickerRef.current) clearInterval(tickerRef.current); };
  }, [game.waitingForPicks, game.isPaused, hasSelectedGame, game.shootout.isActive]);

  useEffect(() => {
    if (game.waitingForPicks || game.isPaused || !hasSelectedGame || game.shootout.isActive) return;
    const eventInterval = setInterval(() => { processEvents(); }, 8000);
    return () => clearInterval(eventInterval);
  }, [game.waitingForPicks, game.isPaused, processEvents, hasSelectedGame, game.shootout.isActive]);

  const handlePicks = async (picks: { home: Position; away: Position; homeNumber: number; awayNumber: number }) => {
    if (notifPermission === 'default') {
      const granted = await requestNotificationPermission();
      setNotifPermission(granted ? 'granted' : 'denied');
    }
    setGame(prev => ({ ...prev, userPicks: picks, waitingForPicks: false }));
  };

  const handleShootoutBet = (prediction: 'SCORE' | 'SAVE', wager: number) => {
    const isSuccess = Math.random() > 0.5; 
    const pointsDelta = isSuccess ? wager : -wager;
    const turn = game.shootout.currentTurn;
    const isGoal = (prediction === 'SCORE' && isSuccess) || (prediction === 'SAVE' && !isSuccess);

    const newEvent: GameEvent = {
      id: Math.random().toString(36).substr(2, 9),
      timestamp: Date.now(),
      gameTime: `SO Round ${game.shootout.round}`,
      team: turn,
      position: 'C',
      type: isGoal ? 'SO_GOAL' : 'SO_MISS',
      description: `${isGoal ? 'GOAL!' : 'MISS!'} ${game.shootout.shooterName} vs ${game.shootout.goalieName}`,
      points: pointsDelta,
      userEarned: pointsDelta,
      period: 5,
      homeScoreAtEvent: turn === 'home' && isGoal ? game.homeTeam.score + 1 : game.homeTeam.score,
      awayScoreAtEvent: turn === 'away' && isGoal ? game.awayTeam.score + 1 : game.awayTeam.score,
    };

    if (isGoal) triggerGoalExplosion(turn);
    triggerPointsAnimation(pointsDelta, turn, 'C', true);

    setGame(prev => {
      const nextTurn = prev.shootout.currentTurn === 'away' ? 'home' : 'away';
      const nextRound = nextTurn === 'away' ? prev.shootout.round + 1 : prev.shootout.round;

      const newHomeAttempts = [...prev.shootout.homeAttempts];
      const newAwayAttempts = [...prev.shootout.awayAttempts];
      if (turn === 'home') newHomeAttempts.push(isGoal);
      else newAwayAttempts.push(isGoal);

      const shouldEnd = nextRound > 3 && (
        Math.abs(newHomeAttempts.filter(Boolean).length - newAwayAttempts.filter(Boolean).length) > 0
      ) && nextTurn === 'away';

      return {
        ...prev,
        totalPoints: prev.totalPoints + pointsDelta,
        events: [newEvent, ...prev.events],
        homeTeam: { ...prev.homeTeam, score: turn === 'home' && isGoal ? prev.homeTeam.score + 1 : prev.homeTeam.score },
        awayTeam: { ...prev.awayTeam, score: turn === 'away' && isGoal ? prev.awayTeam.score + 1 : prev.awayTeam.score },
        shootout: {
          ...prev.shootout,
          isActive: !shouldEnd,
          round: nextRound,
          homeAttempts: newHomeAttempts,
          awayAttempts: newAwayAttempts,
          currentTurn: nextTurn,
          shooterName: 'Star Shooter',
          goalieName: 'Brick Wall'
        },
        isPaused: shouldEnd
      };
    });
  };

  const openPicks = () => {
    if (game.waitingForPicks) return;
    setGame(prev => ({ ...prev, waitingForPicks: true, waitingReason: 'Manual Lineup Change', puckPossession: null }));
  };

  const goBackToSelection = () => {
    setHasSelectedGame(false);
  };

  if (!hasSelectedGame) {
    return <GameSelectionScreen games={scheduledGames} sources={scheduleSources} onSelectGame={handleSelectGame} isLoading={isLoadingSchedule} />;
  }

  return (
    <div className="min-h-screen bg-slate-950 text-slate-100 flex flex-col pb-24 relative overflow-hidden">
      {explosions.map(exp => (
        <div key={exp.id} className="fixed inset-0 z-[100] pointer-events-none flex items-center justify-center">
          <div className="absolute inset-0 animate-screen-flash" style={{ backgroundColor: `${exp.color}22` }} />
          <div className="relative">
            <div className="text-8xl font-black oswald uppercase text-white animate-goal-text drop-shadow-[0_0_20px_rgba(255,255,255,0.8)]">GOAL!</div>
            <div className="absolute inset-0 animate-goal-explosion" style={{ background: `radial-gradient(circle, ${exp.color} 0%, transparent 70%)` }} />
          </div>
        </div>
      ))}

      {game.waitingForPicks && !game.shootout.isActive && (
        <SelectionOverlay 
          homeTeam={game.homeTeam} 
          awayTeam={game.awayTeam} 
          onConfirm={handlePicks} 
          events={game.events}
          puckPossession={game.puckPossession}
          floatingPoints={floatingPoints}
          strength={game.strength}
          waitingReason={game.waitingReason}
        />
      )}

      {game.shootout.isActive && (
        <ShootoutOverlay 
          homeTeam={game.homeTeam} 
          awayTeam={game.awayTeam} 
          shootout={game.shootout}
          userPoints={game.totalPoints}
          onBet={handleShootoutBet}
        />
      )}

      <ScoreBoard 
        home={game.homeTeam} 
        away={game.awayTeam} 
        period={game.period} 
        time={game.timeRemaining}
        strength={game.strength}
        penaltyClocks={game.penaltyClocks}
      />

      <main className="flex-1 max-w-6xl mx-auto w-full p-4">
        <div className="mb-6 flex flex-col gap-4">
          <div className="flex justify-between items-center">
            <button 
              onClick={goBackToSelection}
              className="text-[10px] font-black uppercase tracking-widest text-slate-500 hover:text-white transition-colors flex items-center gap-2 group"
            >
              <i className="fa-solid fa-chevron-left group-hover:-translate-x-1 transition-transform"></i>
              Change Game
            </button>

            <div className="flex gap-4">
              {isRealTimeSync && (
                <div className="bg-green-600/20 text-green-400 text-[9px] font-black uppercase tracking-widest px-3 py-1 rounded-full border border-green-500/30 flex items-center gap-2 animate-pulse">
                  <span className="w-1.5 h-1.5 bg-green-500 rounded-full"></span>
                  Live Match Grounding
                </div>
              )}
              {game.shootout.isActive && (
                <div className="bg-red-600/20 text-red-500 text-[9px] font-black uppercase tracking-widest px-3 py-1 rounded-full border border-red-500/30 flex items-center gap-2 animate-bounce">
                  <i className="fa-solid fa-fire"></i>
                  SHOOTOUT WAGERS OPEN
                </div>
              )}
            </div>
          </div>

          <LastEventTicker 
            event={game.events[0]} 
            homeTeam={game.homeTeam} 
            awayTeam={game.awayTeam} 
          />
        </div>

        <div className="flex flex-col lg:flex-row gap-8">

          <div className="flex-1 space-y-8 order-2 lg:order-1">
            <div className="grid grid-cols-2 sm:grid-cols-4 gap-4">
              <div className="bg-slate-900 border border-slate-800 p-4 rounded-xl shadow-lg relative overflow-hidden">
                <div className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-1">Total Points</div>
                <div className="text-3xl font-black text-amber-500 oswald">{game.totalPoints.toLocaleString()}</div>
              </div>
              <div className="bg-slate-900 border border-slate-800 p-4 rounded-xl shadow-lg relative overflow-hidden">
                <div className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-1">Rank</div>
                <div className="text-3xl font-black text-blue-400 oswald">#{game.rank}</div>
              </div>
              <div className="bg-slate-900 border border-slate-800 p-4 rounded-xl shadow-lg hidden sm:block">
                <div className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-1">Game Mode</div>
                <div className={`text-xl font-black oswald uppercase ${game.shootout.isActive ? 'text-red-500' : 'text-white'}`}>
                  {game.shootout.isActive ? 'SHOOTOUT' : game.strength}
                </div>
              </div>
              <div className="bg-slate-900 border border-slate-800 p-4 rounded-xl shadow-lg hidden sm:block">
                <div className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-1">Active Players</div>
                <div className="text-3xl font-black text-slate-300 oswald">{game.totalPlayers.toLocaleString()}</div>
              </div>
            </div>

            <div className="space-y-6">
              <div className="bg-slate-900/50 border border-slate-800 rounded-2xl overflow-hidden flex flex-col">
                <div className="bg-slate-800 px-6 py-4 border-b border-slate-700 flex justify-between items-center">
                  <h2 className="text-sm font-black uppercase tracking-widest text-slate-200 flex items-center gap-2">
                    <i className="fa-solid fa-satellite-dish text-red-500 animate-pulse"></i> POWERPLAY Live Feed
                  </h2>
                  {loadingEvents && <div className="text-[10px] font-bold text-slate-500 uppercase animate-pulse"><i className="fa-solid fa-spinner fa-spin mr-1"></i>Scanning Grounding...</div>}
                </div>
                <div className="overflow-y-auto p-4 space-y-4 max-h-[450px] scroll-smooth">
                  {game.events.length === 0 ? (
                    <div className="h-40 flex flex-col items-center justify-center text-slate-600">
                      <i className="fa-solid fa-hockey-puck text-4xl mb-4 opacity-20"></i>
                      <p className="font-bold uppercase tracking-wider text-[10px]">Puck is currently in the air...</p>
                    </div>
                  ) : (
                    game.events.slice(0, 15).map((event) => {
                      const isUserPositive = (event.userEarned || 0) > 0;
                      const isUserNegative = (event.userEarned || 0) < 0;
                      return (
                        <div key={`live-${event.id}`} className={`flex items-start gap-4 p-4 rounded-xl border transition-all animate-in slide-in-from-right duration-500 relative overflow-hidden ${isUserPositive ? 'bg-green-900/10 border-green-500/40' : isUserNegative ? 'bg-red-900/10 border-red-500/40' : 'bg-slate-800/40 border-slate-700'}`}>
                          <div className={`w-10 h-10 rounded-full flex-shrink-0 flex items-center justify-center font-black text-xs border-2 shadow-lg z-10 ${event.team === 'home' ? 'bg-blue-600 border-blue-400 text-white' : 'bg-amber-500 border-amber-300 text-slate-950'}`}>{event.position}</div>
                          <div className="flex-1 z-10">
                            <div className="text-[9px] font-bold text-slate-500 uppercase mb-1">
                                {event.gameTime} • {event.type.replace('_', ' ')} 
                                {event.strength && event.strength !== '5v5' && <span className="ml-2 text-amber-500">[{event.strength}]</span>}
                                {event.playerNumber && <span className="ml-2 text-white/40">#{event.playerNumber}</span>}
                            </div>
                            <p className="text-sm text-slate-100 font-medium">{event.description}</p>
                          </div>
                          {event.userEarned !== 0 && <div className={`text-right font-black oswald text-xl min-w-[60px] z-10 ${isUserPositive ? 'text-green-400' : 'text-red-400'}`}>{isUserPositive ? '+' : ''}{event.userEarned}</div>}
                        </div>
                      );
                    })
                  )}
                </div>
              </div>

              {game.groundingSources.length > 0 && (
                <div className="bg-slate-900 border border-slate-800 rounded-2xl p-4 shadow-xl">
                  <h4 className="text-[10px] font-black uppercase tracking-widest text-slate-500 mb-3 flex items-center gap-2">
                    <i className="fa-solid fa-link text-blue-500"></i>
                    Latest Grounding References
                  </h4>
                  <div className="flex flex-wrap gap-2">
                    {game.groundingSources.map((source, idx) => (
                      <a 
                        key={`grounding-${idx}`}
                        href={source.uri} 
                        target="_blank" 
                        rel="noopener noreferrer"
                        className="text-[9px] bg-slate-800 hover:bg-slate-700 text-blue-400 border border-slate-700 px-3 py-1 rounded-md transition-all flex items-center gap-1.5"
                      >
                        <i className="fa-solid fa-up-right-from-square text-[7px]"></i>
                        {source.title}
                      </a>
                    ))}
                  </div>
                </div>
              )}

              <PlayByPlayFeed events={game.events} />
            </div>

            <PerformanceSummary events={game.events} />
            <GameLog events={game.events} homeTeam={game.homeTeam} awayTeam={game.awayTeam} />
          </div>

          <div className="lg:w-80 order-1 lg:order-2">
            <div className="lg:sticky lg:top-24 space-y-6 flex flex-col min-h-screen">
              <div className={`bg-slate-900 border border-slate-800 rounded-3xl p-4 shadow-2xl transition-all duration-500 ${game.waitingForPicks || game.shootout.isActive ? 'ring-2 ring-amber-500/30' : ''}`}>
                <div className="flex justify-between items-center mb-4">
                   <div className="text-[9px] font-black text-slate-500 uppercase tracking-widest flex items-center gap-2">
                      Tactical Command
                      <span className={`w-1.5 h-1.5 rounded-full ${game.waitingForPicks || game.shootout.isActive ? 'bg-amber-500 animate-pulse' : 'bg-green-500'}`}></span>
                   </div>
                   <div className={`text-[8px] font-black px-2 py-0.5 rounded uppercase ${game.waitingForPicks || game.shootout.isActive ? 'bg-amber-500/20 text-amber-500' : 'bg-slate-800 text-slate-500'}`}>
                    {game.shootout.isActive ? 'Shootout Betting' : (game.waitingForPicks ? 'Update Lineup' : 'Picks Locked')}
                   </div>
                </div>

                {game.shootout.isActive ? (
                  <div className="p-4 bg-red-900/10 border border-red-500/20 rounded-2xl text-center space-y-2">
                    <i className="fa-solid fa-dice text-2xl text-red-500"></i>
                    <p className="text-xs font-black uppercase text-white">Shootout Active</p>
                    <p className="text-[10px] text-slate-400">Bet on scores or saves to multiply your points.</p>
                  </div>
                ) : (
                  <PickStatus 
                    homeTeam={game.homeTeam} 
                    awayTeam={game.awayTeam} 
                    userPicks={game.userPicks} 
                    floatingPoints={floatingPoints}
                    shotTrajectories={shotTrajectories}
                    isSelecting={game.waitingForPicks}
                    onConfirmPicks={handlePicks}
                    puckPossession={game.puckPossession}
                    strength={game.strength}
                  />
                )}
              </div>

              <div className="bg-slate-900 border border-slate-800 p-5 rounded-2xl">
                <h3 className="text-xs font-black text-slate-200 uppercase tracking-widest mb-4">Wager Mode Key</h3>
                <div className="space-y-2">
                  <div className="flex justify-between text-[10px] font-bold text-amber-500 uppercase"><span>SO Win</span><span>2.0x Wager</span></div>
                  <div className="flex justify-between text-[10px] font-bold text-red-500 uppercase"><span>SO Loss</span><span>-1.0x Wager</span></div>
                </div>
              </div>

              <div className="flex-1">
                <Leaderboard players={leaderboardData} userPoints={game.totalPoints} userRank={game.rank} />
              </div>
            </div>
          </div>
        </div>
      </main>

      <footer className="fixed bottom-0 left-0 right-0 bg-slate-900/90 border-t border-slate-800 p-4 sm:p-6 shadow-2xl z-40 backdrop-blur-md">
        <div className="max-w-6xl mx-auto flex items-center justify-between gap-4">
          <div className="flex items-center gap-6">
            <div>
              <div className="text-[10px] font-bold text-slate-500 uppercase mb-1">POWERPLAY Points</div>
              <div className="text-3xl font-black oswald text-amber-500 leading-none">{game.totalPoints.toLocaleString()}</div>
            </div>
            <div className="h-8 w-[1px] bg-slate-800"></div>
            <div>
              <div className="text-[10px] font-bold text-slate-500 uppercase mb-1">Mode</div>
              <div className="text-2xl font-black oswald text-white leading-none">{game.shootout.isActive ? 'SO' : game.strength}</div>
            </div>
          </div>

          <div className="flex items-center gap-4">
            {!game.shootout.isActive && (
              <button 
                onClick={openPicks} 
                disabled={game.waitingForPicks} 
                className={`px-8 py-3 rounded-xl font-black oswald text-lg uppercase tracking-widest transition-all active:scale-95 ${
                  !game.waitingForPicks 
                  ? 'bg-blue-600 hover:bg-blue-500 text-white shadow-lg shadow-blue-900/30 ring-2 ring-blue-400/50' 
                  : 'bg-slate-800 text-slate-600 border border-slate-700 cursor-not-allowed'
                }`}
              >
                {game.waitingForPicks ? 'Drafting Open' : 'Tactical Change'}
              </button>
            )}
          </div>
        </div>
      </footer>
      <LiveAssistant />
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { Position, TeamInfo, GameEvent, FloatingPoint, OnIceStrength } from '../types';
import { POSITIONS } from '../constants';

interface SelectionOverlayProps {
  homeTeam: TeamInfo;
  awayTeam: TeamInfo;
  onConfirm: (picks: { home: Position; away: Position; homeNumber: number; awayNumber: number }) => void;
  events: GameEvent[];
  puckPossession?: { team: 'home' | 'away'; position: Position } | null;
  floatingPoints?: FloatingPoint[];
  strength: OnIceStrength;
  waitingReason?: string;
}

const PLAYER_DATA: Record<string, Record<Position, { name: string; number: number }[]>> = {
  'Rangers': { 
    'C': [{ name: 'M. Zibanejad', number: 93 }, { name: 'V. Trocheck', number: 16 }, { name: 'F. Chytil', number: 72 }], 
    'LW': [{ name: 'A. Panarin', number: 10 }, { name: 'C. Kreider', number: 20 }, { name: 'W. Cuylle', number: 50 }], 
    'RW': [{ name: 'A. Lafreniere', number: 13 }, { name: 'K. Kakko', number: 24 }, { name: 'J. Vesey', number: 26 }], 
    'LD': [{ name: 'R. Lindgren', number: 55 }, { name: 'K. Miller', number: 79 }, { name: 'Z. Jones', number: 6 }], 
    'RD': [{ name: 'A. Fox', number: 23 }, { name: 'J. Trouba', number: 8 }, { name: 'B. Schneider', number: 4 }], 
    'G': [{ name: 'I. Shesterkin', number: 31 }, { name: 'J. Quick', number: 32 }] 
  },
  'Bruins': { 
    'C': [{ name: 'C. Coyle', number: 13 }, { name: 'P. Zacha', number: 18 }, { name: 'M. Geekie', number: 39 }], 
    'LW': [{ name: 'B. Marchand', number: 63 }, { name: 'J. van Riemsdyk', number: 21 }, { name: 'D. Heinen', number: 43 }], 
    'RW': [{ name: 'D. Pastrnak', number: 88 }, { name: 'J. DeBrusk', number: 74 }, { name: 'T. Frederic', number: 11 }], 
    'LD': [{ name: 'H. Lindholm', number: 27 }, { name: 'M. Lohrei', number: 6 }, { name: 'D. Forbort', number: 28 }], 
    'RD': [{ name: 'C. McAvoy', number: 73 }, { name: 'B. Carlo', number: 25 }, { name: 'K. Shattenkirk', number: 22 }], 
    'G': [{ name: 'J. Swayman', number: 1 }, { name: 'L. Ullmark', number: 35 }] 
  }
};

const SelectionOverlay: React.FC<SelectionOverlayProps> = ({ homeTeam, awayTeam, onConfirm, events, puckPossession, floatingPoints, strength, waitingReason }) => {
  const [awayPick, setAwayPick] = useState<Position | null>(null);
  const [homePick, setHomePick] = useState<Position | null>(null);
  const [awayNum, setAwayNum] = useState<number | null>(null);
  const [homeNum, setHomeNum] = useState<number | null>(null);
  const [showSuccess, setShowSuccess] = useState(false);
  const [activeRoster, setActiveRoster] = useState<{ side: 'home' | 'away'; pos: Position } | null>(null);

  const [hovered, setHovered] = useState<{ side: 'home' | 'away'; pos: Position } | null>(null);
  const [flash, setFlash] = useState<{ side: 'home' | 'away'; pos: Position; type: 'green' | 'red' | 'possession' } | null>(null);
  const prevPossessionRef = useRef<{ team: 'home' | 'away'; position: Position } | null>(null);

  const triggerFlash = (side: 'home' | 'away', pos: Position, type: 'green' | 'red' | 'possession', duration = 1500) => {
    setFlash({ side, pos, type });
    setTimeout(() => setFlash(null), duration);
  };

  useEffect(() => {
    if (puckPossession && (
      puckPossession.team !== prevPossessionRef.current?.team || 
      puckPossession.position !== prevPossessionRef.current?.position
    )) {
      triggerFlash(puckPossession.team, puckPossession.position, 'possession', 1500);
    }
    prevPossessionRef.current = puckPossession || null;
  }, [puckPossession]);

  const handleConfirm = () => {
    if (awayPick && homePick && awayNum !== null && homeNum !== null) {
      setShowSuccess(true);
      setTimeout(() => {
        onConfirm({ 
          home: homePick, 
          away: awayPick, 
          homeNumber: homeNum, 
          awayNumber: awayNum 
        });
      }, 1200);
    }
  };

  const handleRinkClick = (side: 'home' | 'away', pos: Position) => {
    if (showSuccess) return; 
    setActiveRoster({ side, pos });
  };

  const selectPlayer = (player: { name: string, number: number }) => {
    if (!activeRoster) return;
    const { side, pos } = activeRoster;
    if (side === 'home') {
      setHomePick(pos);
      setHomeNum(player.number);
    } else {
      setAwayPick(pos);
      setAwayNum(player.number);
    }
    triggerFlash(side, pos, 'green', 1000);
    setActiveRoster(null);
  };

  const getPlayersForPos = (teamName: string, pos: Position) => {
    return PLAYER_DATA[teamName]?.[pos] || [{ name: `${pos} Prospect`, number: 0 }];
  };

  const getPosStats = (side: 'home' | 'away', pos: Position) => {
    const posEvents = events.filter(e => e.team === side && e.position === pos);
    const goals = posEvents.filter(e => e.type === 'GOAL' || e.type === 'SO_GOAL').length;
    const assists = posEvents.filter(e => e.type === 'ASSIST').length;
    return { goals, assists };
  };

  const getPosCoords = (pos: Position, isHome: boolean) => {
    const baseCoords: Record<Position, { top: string; left: string }> = {
      'G': { top: '50%', left: isHome ? '92%' : '8%' },
      'LD': { top: '30%', left: isHome ? '75%' : '25%' },
      'RD': { top: '70%', left: isHome ? '75%' : '25%' },
      'LW': { top: '22%', left: isHome ? '60%' : '40%' },
      'RW': { top: '78%', left: isHome ? '60%' : '40%' },
      'C': { top: '50%', left: isHome ? '60%' : '40%' },
    };
    return baseCoords[pos];
  };

  const isFormValid = awayPick && homePick && awayNum !== null && homeNum !== null;

  return (
    <div className="fixed inset-0 z-[100] bg-slate-950/95 backdrop-blur-xl flex items-center justify-center p-4 overflow-y-auto">
      <div className="bg-slate-900 border border-slate-700 w-full max-w-5xl rounded-3xl shadow-[0_0_60px_rgba(0,0,0,0.6)] overflow-hidden animate-in fade-in zoom-in duration-500 my-auto relative">

        {/* Success Overlay */}
        {showSuccess && (
          <div className="absolute inset-0 z-[200] bg-slate-950/60 backdrop-blur-md flex flex-col items-center justify-center animate-in fade-in duration-300">
            <div className="flex flex-col items-center gap-6 animate-in zoom-in slide-in-from-bottom-12 duration-500">
              <div className="w-24 h-24 bg-green-500 rounded-full flex items-center justify-center shadow-[0_0_50px_rgba(34,197,94,0.6)] border-4 border-green-400">
                <i className="fa-solid fa-check text-5xl text-white"></i>
              </div>
              <div className="text-center">
                <h3 className="text-5xl font-black oswald uppercase tracking-tighter text-white italic mb-2">Lineup Locked!</h3>
                <p className="text-green-400 text-sm font-black uppercase tracking-[0.4em]">Tactical Data Syncing...</p>
              </div>
            </div>
          </div>
        )}

        {/* Player Roster Selection Overlay */}
        {activeRoster && (
          <div className="absolute inset-0 z-[180] bg-slate-950/80 backdrop-blur-sm flex items-center justify-center p-6 animate-in fade-in duration-200">
            <div className="bg-slate-900 border border-slate-700 w-full max-w-md rounded-2xl shadow-2xl overflow-hidden animate-in zoom-in duration-300">
              <div className="p-4 border-b border-slate-700 flex justify-between items-center bg-slate-800">
                <div className="flex items-center gap-2">
                  <span className="text-xl">{activeRoster.side === 'home' ? homeTeam.logo : awayTeam.logo}</span>
                  <h3 className="text-sm font-black oswald uppercase text-white tracking-widest">Select {activeRoster.pos} Starter</h3>
                </div>
                <button onClick={() => setActiveRoster(null)} className="text-slate-500 hover:text-white transition-colors">
                  <i className="fa-solid fa-xmark"></i>
                </button>
              </div>
              <div className="p-4 space-y-2 max-h-[400px] overflow-y-auto">
                {getPlayersForPos(activeRoster.side === 'home' ? homeTeam.name : awayTeam.name, activeRoster.pos).map((player, idx) => {
                  const teamColor = activeRoster.side === 'home' ? homeTeam.color : awayTeam.color;
                  return (
                    <button
                      key={`${player.number}-${idx}`}
                      onClick={() => selectPlayer(player)}
                      className="w-full flex items-center justify-between p-4 bg-slate-800/50 hover:bg-slate-700 rounded-xl border border-slate-700 transition-all group"
                    >
                      <div className="flex items-center gap-4">
                        <div className="w-10 h-10 rounded-full bg-slate-950 border border-slate-800 flex items-center justify-center text-lg font-black oswald group-hover:border-white transition-colors" style={{ color: teamColor }}>
                          {player.number}
                        </div>
                        <div className="text-left">
                          <div className="text-sm font-black text-white uppercase tracking-tight">{player.name}</div>
                          <div className="text-[10px] font-bold text-slate-500 uppercase">{activeRoster.pos}</div>
                        </div>
                      </div>
                      <div className="w-8 h-8 rounded-full border border-slate-700 flex items-center justify-center text-slate-700 group-hover:border-blue-500 group-hover:text-blue-500 transition-all">
                        <i className="fa-solid fa-plus text-xs"></i>
                      </div>
                    </button>
                  );
                })}
              </div>
            </div>
          </div>
        )}

        {/* Header */}
        <div className="bg-slate-800/80 p-6 border-b border-slate-700 flex flex-col items-center text-center relative overflow-hidden">
          <div className="flex items-center gap-6 mb-2 relative z-10 w-full justify-between max-w-2xl">
            <div className="flex flex-col items-center gap-1 group">
               <span className="text-5xl transition-all duration-300">{awayTeam.logo}</span>
               <span className="text-[10px] font-black oswald text-slate-400 uppercase">{awayTeam.abbreviation}</span>
            </div>

            <div className="flex flex-col items-center">
              <div className="bg-amber-500/10 text-amber-500 text-[10px] font-black px-3 py-1 rounded-full border border-amber-500/20 uppercase tracking-[0.2em] mb-2 animate-pulse">
                {waitingReason || "Lineup Reset"}
              </div>
              <h2 className={`text-3xl font-black oswald uppercase tracking-tighter italic ${strength !== '5v5' ? 'text-amber-500' : 'text-white'}`}>
                {strength !== '5v5' ? `SPECIAL TEAMS: ${strength}` : 'LINEUP BUILDER'}
              </h2>
              <p className="text-slate-400 text-[9px] font-black uppercase tracking-[0.4em]">Pick a specific player for each position</p>
            </div>

            <div className="flex flex-col items-center gap-1 group">
              <span className="text-5xl transition-all duration-300">{homeTeam.logo}</span>
              <span className="text-[10px] font-black oswald text-slate-400 uppercase">{homeTeam.abbreviation}</span>
            </div>
          </div>
        </div>

        {/* Tactical Rink */}
        <div className="relative bg-slate-100 border-b border-slate-400 p-1">
          <div className="relative w-full aspect-[2.4/1] bg-white shadow-inner rounded-sm overflow-hidden border border-slate-300">
            <div className="absolute inset-0 opacity-[0.03] pointer-events-none bg-[url('https://www.transparenttextures.com/patterns/pinstriped-suit.png')]"></div>

            <svg className="absolute inset-0 w-full h-full pointer-events-none" viewBox="0 0 240 100" preserveAspectRatio="none">
              {/* Goal Creases */}
              <path d="M 14.4 42 A 8 8 0 0 1 14.4 58" fill="rgba(37, 99, 235, 0.1)" stroke="rgba(239, 68, 68, 0.4)" strokeWidth="0.5" />
              <path d="M 225.6 42 A 8 8 0 0 0 225.6 58" fill="rgba(37, 99, 235, 0.1)" stroke="rgba(239, 68, 68, 0.4)" strokeWidth="0.5" />
              {/* Lines */}
              <line x1="14.4" y1="0" x2="14.4" y2="100" stroke="rgba(239, 68, 68, 0.6)" strokeWidth="0.8" />
              <line x1="225.6" y1="0" x2="225.6" y2="100" stroke="rgba(239, 68, 68, 0.6)" strokeWidth="0.8" />
              <rect x="84" y="0" width="1.5" height="100" fill="rgba(37, 99, 235, 0.8)" />
              <rect x="154.5" y="0" width="1.5" height="100" fill="rgba(37, 99, 235, 0.8)" />
              <rect x="119.5" y="0" width="1" height="100" fill="rgba(239, 68, 68, 0.8)" />
              <circle cx="120" cy="50" r="15" fill="none" stroke="rgba(37, 99, 235, 0.4)" strokeWidth="0.5" />
              <circle cx="120" cy="50" r="1.5" fill="rgba(37, 99, 235, 0.8)" />
              {/* Circles */}
              <circle cx="48" cy="25" r="15" fill="none" stroke="rgba(239, 68, 68, 0.3)" strokeWidth="0.5" />
              <circle cx="48" cy="75" r="15" fill="none" stroke="rgba(239, 68, 68, 0.3)" strokeWidth="0.5" />
              <circle cx="192" cy="25" r="15" fill="none" stroke="rgba(239, 68, 68, 0.3)" strokeWidth="0.5" />
              <circle cx="192" cy="75" r="15" fill="none" stroke="rgba(239, 68, 68, 0.3)" strokeWidth="0.5" />
            </svg>

            {strength !== '5v5' && <div className="absolute inset-0 bg-amber-500/5 animate-pulse pointer-events-none"></div>}

            <div className="absolute top-6 left-10 oswald font-black uppercase tracking-widest text-3xl pointer-events-none text-slate-100 flex items-center gap-4">
              <span className="text-4xl filter drop-shadow-md">{awayTeam.logo}</span>
              {awayTeam.name}
            </div>
            <div className="absolute top-6 right-10 oswald font-black uppercase tracking-widest text-3xl pointer-events-none text-right text-slate-100 flex items-center gap-4">
              {homeTeam.name}
              <span className="text-4xl filter drop-shadow-md">{homeTeam.logo}</span>
            </div>

            {['away', 'home'].map((side) => 
              POSITIONS.map((pos) => {
                const isHomeSide = side === 'home';
                const coords = getPosCoords(pos.value, isHomeSide);
                const isSelected = isHomeSide ? homePick === pos.value : awayPick === pos.value;
                const selectedNum = isHomeSide ? homeNum : awayNum;
                const isThisHovered = hovered?.side === side && hovered?.pos === pos.value;

                const isManualFlashing = flash?.side === side && flash?.pos === pos.value;
                let flashClass = '';
                let flashStyle: React.CSSProperties = {};
                if (isManualFlashing) {
                  if (flash.type === 'possession') {
                    flashClass = 'animate-possession-pulse';
                    flashStyle = { '--pulse-color': isHomeSide ? homeTeam.color : awayTeam.color } as React.CSSProperties;
                  } else {
                    flashClass = flash.type === 'green' ? 'animate-flash-green' : 'animate-flash-red';
                  }
                }

                const teamColor = isHomeSide ? homeTeam.color : awayTeam.color;
                const posStats = getPosStats(side as 'home' | 'away', pos.value);

                const topVal = parseFloat(coords.top);
                const leftVal = parseFloat(coords.left);
                const showBelow = topVal < 50; 
                let horizontalClass = 'left-1/2 -translate-x-1/2'; 
                if (leftVal < 20) horizontalClass = 'left-0 translate-x-0';
                else if (leftVal > 80) horizontalClass = 'right-0 translate-x-0';

                return (
                  <React.Fragment key={`tactical-container-${side}-${pos.value}`}>
                    <div style={{ top: coords.top, left: coords.left }} className="absolute -translate-x-1/2 -translate-y-1/2 z-20">
                      <button
                        onMouseEnter={() => setHovered({ side: side as 'home' | 'away', pos: pos.value })}
                        onMouseLeave={() => setHovered(null)}
                        onClick={() => handleRinkClick(side as 'home' | 'away', pos.value)}
                        className={`relative w-8 h-8 sm:w-10 sm:h-10 rounded-full flex flex-col items-center justify-center transition-all z-10 shadow-lg ${
                          isSelected
                            ? ('scale-110 ring-4 border-2 border-white text-white')
                            : isThisHovered 
                              ? ('scale-125 border-2 border-slate-400')
                              : 'bg-slate-800 text-white border-2 border-slate-600'
                        } ${flashClass}`}
                        style={{
                          ...(isSelected ? { backgroundColor: teamColor, boxShadow: `0 0 0 4px ${teamColor}4D` } : {}),
                          ...flashStyle
                        }}
                      >
                        <span className="text-[10px] sm:text-sm font-black oswald leading-none">{pos.value}</span>
                        {isSelected && (
                           <div className="absolute -top-1.5 -right-1.5 bg-white text-[7px] font-black px-1.5 py-0.5 rounded-full border shadow-sm transition-all" style={{ color: teamColor, borderColor: teamColor }}>
                            #{selectedNum}
                          </div>
                        )}
                      </button>

                      {isThisHovered && (
                        <div className={`absolute z-[300] w-52 bg-slate-900/98 backdrop-blur-xl border-2 rounded-2xl p-4 shadow-[0_20px_50px_rgba(0,0,0,0.5)] pointer-events-none animate-in zoom-in slide-in-from-top-2 duration-300 ${horizontalClass} ${showBelow ? 'top-full mt-4' : 'bottom-full mb-4'}`} style={{ borderColor: `${teamColor}80`, boxShadow: `0 10px 30px -10px ${teamColor}40` }}>
                          <div className="flex items-center justify-between mb-3">
                            <div className="flex items-center gap-2">
                                <span className="text-xl">{isHomeSide ? homeTeam.logo : awayTeam.logo}</span>
                                <span className="text-[10px] font-black uppercase tracking-widest text-white/50">{isHomeSide ? homeTeam.abbreviation : awayTeam.abbreviation} TACTICAL</span>
                            </div>
                          </div>
                          <div className="text-base font-black text-white oswald uppercase tracking-tight mb-3 border-b border-white/10 pb-2">
                            {isSelected ? PLAYER_DATA[isHomeSide ? homeTeam.name : awayTeam.name]?.[pos.value].find(p => p.number === selectedNum)?.name : `${pos.label} Selection`}
                          </div>
                          <div className="grid grid-cols-2 gap-3">
                            <div className="bg-slate-950/50 p-2 rounded-lg border border-white/5">
                              <span className="text-[8px] font-bold text-slate-500 uppercase block mb-1">Goals</span>
                              <span className="text-lg font-black text-white oswald">{posStats.goals}</span>
                            </div>
                            <div className="bg-slate-950/50 p-2 rounded-lg border border-white/5">
                              <span className="text-[8px] font-bold text-slate-500 uppercase block mb-1">Assists</span>
                              <span className="text-lg font-black text-white oswald">{posStats.assists}</span>
                            </div>
                          </div>
                        </div>
                      )}
                    </div>
                  </React.Fragment>
                );
              })
            )}
          </div>
        </div>

        {/* Footer Selections */}
        <div className="p-8 bg-slate-900 border-t border-slate-700 flex flex-col lg:flex-row items-center justify-between gap-8">
          <div className="flex flex-col sm:flex-row gap-8 lg:gap-12 w-full lg:w-auto">
            {/* Away Selection Box */}
            <div className={`flex flex-col p-4 rounded-2xl border transition-all ${awayPick ? 'bg-slate-800' : 'bg-slate-900/50 border-slate-800'}`} style={awayPick ? { borderColor: `${awayTeam.color}80` } : {}}>
              <span className="text-[11px] font-black text-slate-500 uppercase tracking-[0.2em] mb-3">{awayTeam.abbreviation} Selection</span>
              <div className="flex items-center gap-4">
                <div className={`w-12 h-12 rounded-full flex items-center justify-center font-black oswald text-xl border-2 ${awayPick ? 'border-white text-slate-950 animate-pulse' : 'bg-slate-800 border-slate-700 text-slate-600'}`} style={awayPick ? { backgroundColor: awayTeam.color } : {}}>
                  {awayPick || '?'}
                </div>
                <div className="flex flex-col gap-1">
                  <span className="text-sm font-black text-white">{awayPick ? PLAYER_DATA[awayTeam.name]?.[awayPick].find(p => p.number === awayNum)?.name : 'Tap Rink to Pick'}</span>
                  {awayNum && <span className="text-[10px] font-black text-amber-500">Jersey #{awayNum}</span>}
                </div>
              </div>
            </div>

            {/* Home Selection Box */}
            <div className={`flex flex-col p-4 rounded-2xl border transition-all ${homePick ? 'bg-slate-800' : 'bg-slate-900/50 border-slate-800'}`} style={homePick ? { borderColor: `${homeTeam.color}80` } : {}}>
              <span className="text-[11px] font-black text-slate-500 uppercase tracking-[0.2em] mb-3">{homeTeam.abbreviation} Selection</span>
              <div className="flex items-center gap-4">
                <div className={`w-12 h-12 rounded-full flex items-center justify-center font-black oswald text-xl border-2 ${homePick ? 'border-white text-white animate-pulse' : 'bg-slate-800 border-slate-700 text-slate-600'}`} style={homePick ? { backgroundColor: homeTeam.color } : {}}>
                  {homePick || '?'}
                </div>
                <div className="flex flex-col gap-1">
                  <span className="text-sm font-black text-white">{homePick ? PLAYER_DATA[homeTeam.name]?.[homePick].find(p => p.number === homeNum)?.name : 'Tap Rink to Pick'}</span>
                  {homeNum && <span className="text-[10px] font-black text-blue-400">Jersey #{homeNum}</span>}
                </div>
              </div>
            </div>
          </div>

          <button
            disabled={!isFormValid || showSuccess}
            onClick={handleConfirm}
            className={`w-full lg:w-80 py-6 rounded-2xl font-black oswald text-2xl uppercase tracking-[0.15em] transition-all relative overflow-hidden group ${
              isFormValid && !showSuccess
                ? 'bg-blue-600 hover:bg-blue-500 text-white shadow-[0_0_30px_rgba(37,99,235,0.4)] active:scale-95'
                : 'bg-slate-800 text-slate-600 cursor-not-allowed opacity-50'
            }`}
          >
            <span className="relative z-10">{showSuccess ? 'LOCKED' : (isFormValid ? 'LOCK LINEUP' : 'COMPLETE PICKS')}</span>
            {isFormValid && !showSuccess && <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/10 to-transparent -translate-x-full group-hover:animate-shimmer" />}
          </button>
        </div>
      </div>
      <style>{`
        @keyframes shimmer { 100% { transform: translateX(100%); } }
        @keyframes possession-pulse {
          0% { box-shadow: 0 0 0 0 var(--pulse-color); filter: brightness(1); transform: scale(1); }
          50% { box-shadow: 0 0 40px 20px var(--pulse-color); filter: brightness(1.8); transform: scale(1.3); }
          100% { box-shadow: 0 0 0 0 var(--pulse-color); filter: brightness(1); transform: scale(1); }
        }
        .animate-possession-pulse { animation: possession-pulse 1.5s ease-in-out; }
        .group-hover\\:animate-shimmer { animation: shimmer 1.5s infinite; }
      `}</style>
    </div>
  );
};

export default SelectionOverlay;

import React, { useState, useEffect, useRef } from 'react';
import { Position, TeamInfo, GameEvent, FloatingPoint, OnIceStrength } from '../types';
import { POSITIONS } from '../constants';

interface SelectionOverlayProps {
  homeTeam: TeamInfo;
  awayTeam: TeamInfo;
  onConfirm: (picks: { home: Position; away: Position; homeNumber: number; awayNumber: number }) => void;
  events: GameEvent[];
  puckPossession?: { team: 'home' | 'away'; position: Position } | null;
  floatingPoints?: FloatingPoint[];
  strength: OnIceStrength;
  waitingReason?: string;
}

const PLAYER_DATA: Record<string, Record<Position, { name: string; number: number }[]>> = {
  'Rangers': { 
    'C': [{ name: 'M. Zibanejad', number: 93 }, { name: 'V. Trocheck', number: 16 }, { name: 'F. Chytil', number: 72 }], 
    'LW': [{ name: 'A. Panarin', number: 10 }, { name: 'C. Kreider', number: 20 }, { name: 'W. Cuylle', number: 50 }], 
    'RW': [{ name: 'A. Lafreniere', number: 13 }, { name: 'K. Kakko', number: 24 }, { name: 'J. Vesey', number: 26 }], 
    'LD': [{ name: 'R. Lindgren', number: 55 }, { name: 'K. Miller', number: 79 }, { name: 'Z. Jones', number: 6 }], 
    'RD': [{ name: 'A. Fox', number: 23 }, { name: 'J. Trouba', number: 8 }, { name: 'B. Schneider', number: 4 }], 
    'G': [{ name: 'I. Shesterkin', number: 31 }, { name: 'J. Quick', number: 32 }] 
  },
  'Bruins': { 
    'C': [{ name: 'C. Coyle', number: 13 }, { name: 'P. Zacha', number: 18 }, { name: 'M. Geekie', number: 39 }], 
    'LW': [{ name: 'B. Marchand', number: 63 }, { name: 'J. van Riemsdyk', number: 21 }, { name: 'D. Heinen', number: 43 }], 
    'RW': [{ name: 'D. Pastrnak', number: 88 }, { name: 'J. DeBrusk', number: 74 }, { name: 'T. Frederic', number: 11 }], 
    'LD': [{ name: 'H. Lindholm', number: 27 }, { name: 'M. Lohrei', number: 6 }, { name: 'D. Forbort', number: 28 }], 
    'RD': [{ name: 'C. McAvoy', number: 73 }, { name: 'B. Carlo', number: 25 }, { name: 'K. Shattenkirk', number: 22 }], 
    'G': [{ name: 'J. Swayman', number: 1 }, { name: 'L. Ullmark', number: 35 }] 
  }
};

const SelectionOverlay: React.FC<SelectionOverlayProps> = ({ homeTeam, awayTeam, onConfirm, events, puckPossession, floatingPoints, strength, waitingReason }) => {
  const [awayPick, setAwayPick] = useState<Position | null>(null);
  const [homePick, setHomePick] = useState<Position | null>(null);
  const [awayNum, setAwayNum] = useState<number | null>(null);
  const [homeNum, setHomeNum] = useState<number | null>(null);
  const [showSuccess, setShowSuccess] = useState(false);
  const [activeRoster, setActiveRoster] = useState<{ side: 'home' | 'away'; pos: Position } | null>(null);

  const [hovered, setHovered] = useState<{ side: 'home' | 'away'; pos: Position } | null>(null);
  const [flash, setFlash] = useState<{ side: 'home' | 'away'; pos: Position; type: 'green' | 'red' | 'possession' } | null>(null);
  const prevPossessionRef = useRef<{ team: 'home' | 'away'; position: Position } | null>(null);
  const overlayRef = useRef<HTMLDivElement>(null);

  // Auto-confirm when both sides have made a selection
  useEffect(() => {
    if (homePick && awayPick && homeNum !== null && awayNum !== null && !showSuccess) {
      handleConfirm();
    }
  }, [homePick, awayPick, homeNum, awayNum]);

  const triggerFlash = (side: 'home' | 'away', pos: Position, type: 'green' | 'red' | 'possession', duration = 1500) => {
    setFlash({ side, pos, type });
    setTimeout(() => setFlash(null), duration);
  };

  useEffect(() => {
    if (puckPossession && (
      puckPossession.team !== prevPossessionRef.current?.team || 
      puckPossession.position !== prevPossessionRef.current?.position
    )) {
      triggerFlash(puckPossession.team, puckPossession.position, 'possession', 1500);
    }
    prevPossessionRef.current = puckPossession || null;
  }, [puckPossession]);

  const handleConfirm = () => {
    if (awayPick && homePick && awayNum !== null && homeNum !== null) {
      setShowSuccess(true);
      setTimeout(() => {
        onConfirm({ 
          home: homePick, 
          away: awayPick, 
          homeNumber: homeNum, 
          awayNumber: awayNum 
        });
      }, 1500);
    }
  };

  const handleRinkClick = (side: 'home' | 'away', pos: Position) => {
    if (showSuccess) return; 
    setActiveRoster({ side, pos });
  };

  const selectPlayer = (player: { name: string, number: number }) => {
    if (!activeRoster) return;
    const { side, pos } = activeRoster;
    if (side === 'home') {
      setHomePick(pos);
      setHomeNum(player.number);
    } else {
      setAwayPick(pos);
      setAwayNum(player.number);
    }
    triggerFlash(side, pos, 'green', 1000);
    setActiveRoster(null);
  };

  const getPlayersForPos = (teamName: string, pos: Position) => {
    return PLAYER_DATA[teamName]?.[pos] || [{ name: `${pos} Prospect`, number: 0 }];
  };

  const getPosStats = (side: 'home' | 'away', pos: Position) => {
    const posEvents = events.filter(e => e.team === side && e.position === pos);
    const goals = posEvents.filter(e => e.type === 'GOAL' || e.type === 'SO_GOAL').length;
    const assists = posEvents.filter(e => e.type === 'ASSIST').length;
    return { goals, assists };
  };

  const getPosCoords = (pos: Position, isHome: boolean) => {
    const baseCoords: Record<Position, { top: string; left: string }> = {
      'G': { top: '50%', left: isHome ? '92%' : '8%' },
      'LD': { top: '30%', left: isHome ? '75%' : '25%' },
      'RD': { top: '70%', left: isHome ? '75%' : '25%' },
      'LW': { top: '22%', left: isHome ? '60%' : '40%' },
      'RW': { top: '78%', left: isHome ? '60%' : '40%' },
      'C': { top: '50%', left: isHome ? '60%' : '40%' },
    };
    return baseCoords[pos];
  };

  const isFormValid = awayPick && homePick && awayNum !== null && homeNum !== null;

  return (
    <div className="fixed inset-0 z-[100] bg-slate-950/95 backdrop-blur-xl flex items-center justify-center p-4 overflow-y-auto" ref={overlayRef}>
      <div className="bg-slate-900 border border-slate-700 w-full max-w-5xl rounded-3xl shadow-[0_0_60px_rgba(0,0,0,0.6)] overflow-hidden animate-in fade-in zoom-in duration-500 my-auto relative">

        {/* Success Overlay */}
        {showSuccess && (
          <div className="absolute inset-0 z-[200] bg-slate-950/60 backdrop-blur-md flex flex-col items-center justify-center animate-in fade-in duration-300">
            <div className="flex flex-col items-center gap-6 animate-in zoom-in slide-in-from-bottom-12 duration-500">
              <div className="w-24 h-24 bg-green-500 rounded-full flex items-center justify-center shadow-[0_0_50px_rgba(34,197,94,0.6)] border-4 border-green-400">
                <i className="fa-solid fa-check text-5xl text-white"></i>
              </div>
              <div className="text-center px-4">
                <h3 className="text-5xl font-black oswald uppercase tracking-tighter text-white italic mb-2">Tactical Lock!</h3>
                <p className="text-green-400 text-sm font-black uppercase tracking-[0.4em] animate-pulse">Syncing Lineups to Live Data...</p>
              </div>
            </div>
          </div>
        )}

        {/* Header */}
        <div className="bg-slate-800/80 p-6 border-b border-slate-700 flex flex-col items-center text-center relative overflow-hidden">
          <div className="flex items-center gap-6 mb-2 relative z-10 w-full justify-between max-w-2xl">
            <div className="flex flex-col items-center gap-1 group">
               <span className="text-5xl transition-all duration-300">{awayTeam.logo}</span>
               <span className="text-[10px] font-black oswald text-slate-400 uppercase">{awayTeam.abbreviation}</span>
            </div>

            <div className="flex flex-col items-center">
              <div className="bg-amber-500/10 text-amber-500 text-[10px] font-black px-3 py-1 rounded-full border border-amber-500/20 uppercase tracking-[0.2em] mb-2 animate-pulse">
                {waitingReason || "Lineup Reset"}
              </div>
              <h2 className={`text-3xl font-black oswald uppercase tracking-tighter italic ${strength !== '5v5' ? 'text-amber-500' : 'text-white'}`}>
                {strength !== '5v5' ? `SPECIAL TEAMS: ${strength}` : 'LINEUP BUILDER'}
              </h2>
              <p className="text-slate-400 text-[9px] font-black uppercase tracking-[0.4em]">Tap dots to deploy specific players</p>
            </div>

            <div className="flex flex-col items-center gap-1 group">
              <span className="text-5xl transition-all duration-300">{homeTeam.logo}</span>
              <span className="text-[10px] font-black oswald text-slate-400 uppercase">{homeTeam.abbreviation}</span>
            </div>
          </div>
        </div>

        {/* Tactical Rink */}
        <div className="relative bg-slate-100 border-b border-slate-400 p-1">
          <div className="relative w-full aspect-[2.4/1] bg-white shadow-inner rounded-sm overflow-hidden border border-slate-300">
            <div className="absolute inset-0 opacity-[0.03] pointer-events-none bg-[url('https://www.transparenttextures.com/patterns/pinstriped-suit.png')]"></div>

            <svg className="absolute inset-0 w-full h-full pointer-events-none" viewBox="0 0 240 100" preserveAspectRatio="none">
              <path d="M 14.4 42 A 8 8 0 0 1 14.4 58" fill="rgba(37, 99, 235, 0.1)" stroke="rgba(239, 68, 68, 0.4)" strokeWidth="0.5" />
              <path d="M 225.6 42 A 8 8 0 0 0 225.6 58" fill="rgba(37, 99, 235, 0.1)" stroke="rgba(239, 68, 68, 0.4)" strokeWidth="0.5" />
              <line x1="14.4" y1="0" x2="14.4" y2="100" stroke="rgba(239, 68, 68, 0.6)" strokeWidth="0.8" />
              <line x1="225.6" y1="0" x2="225.6" y2="100" stroke="rgba(239, 68, 68, 0.6)" strokeWidth="0.8" />
              <rect x="84" y="0" width="1.5" height="100" fill="rgba(37, 99, 235, 0.8)" />
              <rect x="154.5" y="0" width="1.5" height="100" fill="rgba(37, 99, 235, 0.8)" />
              <rect x="119.5" y="0" width="1" height="100" fill="rgba(239, 68, 68, 0.8)" />
              <circle cx="120" cy="50" r="15" fill="none" stroke="rgba(37, 99, 235, 0.4)" strokeWidth="0.5" />
              <circle cx="120" cy="50" r="1.5" fill="rgba(37, 99, 235, 0.8)" />
            </svg>

            {strength !== '5v5' && <div className="absolute inset-0 bg-amber-500/5 animate-pulse pointer-events-none"></div>}

            <div className="absolute top-6 left-10 oswald font-black uppercase tracking-widest text-3xl pointer-events-none text-slate-100 flex items-center gap-4">
              <span className="text-4xl filter drop-shadow-md">{awayTeam.logo}</span>
              {awayTeam.name}
            </div>
            <div className="absolute top-6 right-10 oswald font-black uppercase tracking-widest text-3xl pointer-events-none text-right text-slate-100 flex items-center gap-4">
              {homeTeam.name}
              <span className="text-4xl filter drop-shadow-md">{homeTeam.logo}</span>
            </div>

            {['away', 'home'].map((side) => 
              POSITIONS.map((pos) => {
                const isHomeSide = side === 'home';
                const coords = getPosCoords(pos.value, isHomeSide);
                const isSelected = isHomeSide ? homePick === pos.value : awayPick === pos.value;
                const selectedNum = isHomeSide ? homeNum : awayNum;
                const isThisHovered = hovered?.side === side && hovered?.pos === pos.value;
                const isActivePick = activeRoster?.side === side && activeRoster?.pos === pos.value;

                const isManualFlashing = flash?.side === side && flash?.pos === pos.value;
                let flashClass = '';
                let flashStyle: React.CSSProperties = {};
                if (isManualFlashing) {
                  if (flash.type === 'possession') {
                    flashClass = 'animate-possession-pulse';
                    flashStyle = { '--pulse-color': isHomeSide ? homeTeam.color : awayTeam.color } as React.CSSProperties;
                  } else {
                    flashClass = flash.type === 'green' ? 'animate-flash-green' : 'animate-flash-red';
                  }
                }

                const teamColor = isHomeSide ? homeTeam.color : awayTeam.color;
                const posStats = getPosStats(side as 'home' | 'away', pos.value);

                const topVal = parseFloat(coords.top);
                const leftVal = parseFloat(coords.left);
                const showBelow = topVal < 50; 
                let horizontalClass = 'left-1/2 -translate-x-1/2'; 
                if (leftVal < 20) horizontalClass = 'left-0 translate-x-0';
                else if (leftVal > 80) horizontalClass = 'right-0 translate-x-0';

                return (
                  <React.Fragment key={`tactical-container-${side}-${pos.value}`}>
                    <div style={{ top: coords.top, left: coords.left }} className={`absolute -translate-x-1/2 -translate-y-1/2 ${isActivePick ? 'z-[150]' : 'z-20'}`}>
                      <button
                        onMouseEnter={() => setHovered({ side: side as 'home' | 'away', pos: pos.value })}
                        onMouseLeave={() => setHovered(null)}
                        onClick={() => handleRinkClick(side as 'home' | 'away', pos.value)}
                        className={`relative w-8 h-8 sm:w-10 sm:h-10 rounded-full flex flex-col items-center justify-center transition-all z-10 shadow-lg ${
                          isSelected
                            ? ('scale-110 ring-4 border-2 border-white text-white')
                            : isThisHovered || isActivePick
                              ? ('scale-125 border-2 border-slate-400')
                              : 'bg-slate-800 text-white border-2 border-slate-600'
                        } ${flashClass}`}
                        style={{
                          ...(isSelected ? { backgroundColor: teamColor, boxShadow: `0 0 0 4px ${teamColor}4D` } : {}),
                          ...flashStyle
                        }}
                      >
                        <span className="text-[10px] sm:text-sm font-black oswald leading-none">{pos.value}</span>
                        {isSelected && (
                           <div className="absolute -top-1.5 -right-1.5 bg-white text-[7px] font-black px-1.5 py-0.5 rounded-full border shadow-sm transition-all" style={{ color: teamColor, borderColor: teamColor }}>
                            #{selectedNum}
                          </div>
                        )}
                      </button>

                      {/* Unified Roster & Info Popover */}
                      {(isActivePick || (isThisHovered && !activeRoster)) && (
                        <div 
                          className={`absolute z-[300] w-64 bg-slate-900/98 backdrop-blur-xl border-2 rounded-2xl p-4 shadow-[0_20px_50px_rgba(0,0,0,0.5)] animate-in zoom-in slide-in-from-top-2 duration-300 ${horizontalClass} ${showBelow ? 'top-full mt-4' : 'bottom-full mb-4'}`} 
                          style={{ borderColor: `${teamColor}80`, boxShadow: `0 10px 30px -10px ${teamColor}40` }}
                          onMouseEnter={() => !isActivePick && setHovered({ side: side as 'home' | 'away', pos: pos.value })}
                        >
                          <div className="flex items-center justify-between mb-3">
                            <div className="flex items-center gap-2">
                                <span className="text-xl">{isHomeSide ? homeTeam.logo : awayTeam.logo}</span>
                                <span className="text-[10px] font-black uppercase tracking-widest text-white/50">
                                  {isActivePick ? 'SELECT PLAYER' : `${isHomeSide ? homeTeam.abbreviation : awayTeam.abbreviation} TACTICAL`}
                                </span>
                            </div>
                            {isActivePick && (
                              <button onClick={(e) => { e.stopPropagation(); setActiveRoster(null); }} className="text-slate-500 hover:text-white transition-colors">
                                <i className="fa-solid fa-xmark text-xs"></i>
                              </button>
                            )}
                          </div>

                          {isActivePick ? (
                            <div className="space-y-1.5">
                              {getPlayersForPos(isHomeSide ? homeTeam.name : awayTeam.name, pos.value).map((player, idx) => (
                                <button
                                  key={`${player.number}-${idx}`}
                                  onClick={(e) => { e.stopPropagation(); selectPlayer(player); }}
                                  className={`w-full flex items-center justify-between p-2.5 rounded-xl border transition-all group ${selectedNum === player.number ? 'bg-white text-slate-950 border-white' : 'bg-slate-800/50 border-slate-700 hover:border-slate-500 text-white'}`}
                                >
                                  <div className="flex items-center gap-3">
                                    <div className={`w-7 h-7 rounded-full flex items-center justify-center text-[10px] font-black oswald border transition-colors ${selectedNum === player.number ? 'bg-slate-950 text-white border-slate-800' : 'bg-slate-950 border-slate-800 text-white group-hover:border-white'}`} style={{ color: selectedNum === player.number ? '#000' : teamColor }}>
                                      {player.number}
                                    </div>
                                    <span className="text-[11px] font-black uppercase tracking-tight">{player.name}</span>
                                  </div>
                                  <div className={`w-5 h-5 rounded-full border flex items-center justify-center transition-all ${selectedNum === player.number ? 'bg-green-500 border-green-400 text-white' : 'border-slate-700 text-slate-700 group-hover:border-blue-500 group-hover:text-blue-500'}`}>
                                    {selectedNum === player.number ? <i className="fa-solid fa-check text-[8px]"></i> : <i className="fa-solid fa-plus text-[8px]"></i>}
                                  </div>
                                </button>
                              ))}
                            </div>
                          ) : (
                            <>
                              <div className="text-base font-black text-white oswald uppercase tracking-tight mb-3 border-b border-white/10 pb-2">
                                {isSelected ? PLAYER_DATA[isHomeSide ? homeTeam.name : awayTeam.name]?.[pos.value].find(p => p.number === selectedNum)?.name : `${pos.label} Overview`}
                              </div>
                              <div className="grid grid-cols-2 gap-3 mb-1">
                                <div className="bg-slate-950/50 p-2 rounded-lg border border-white/5">
                                  <span className="text-[8px] font-bold text-slate-500 uppercase block mb-1">Goals</span>
                                  <span className="text-lg font-black text-white oswald">{posStats.goals}</span>
                                </div>
                                <div className="bg-slate-950/50 p-2 rounded-lg border border-white/5">
                                  <span className="text-[8px] font-bold text-slate-500 uppercase block mb-1">Assists</span>
                                  <span className="text-lg font-black text-white oswald">{posStats.assists}</span>
                                </div>
                              </div>
                              <div className="text-[9px] font-bold text-slate-500 uppercase tracking-widest text-center mt-3 animate-pulse">
                                <i className="fa-solid fa-hand-pointer mr-1.5"></i> Tap dot to change player
                              </div>
                            </>
                          )}
                        </div>
                      )}
                    </div>
                  </React.Fragment>
                );
              })
            )}
          </div>
        </div>

        {/* Tactical Footer */}
        <div className="p-8 bg-slate-900 border-t border-slate-700 flex flex-col lg:flex-row items-center justify-between gap-8">
          <div className="flex flex-col sm:flex-row gap-8 lg:gap-12 w-full lg:w-auto">
            {/* Away Stats Box */}
            <div className={`flex flex-col p-4 min-w-[200px] rounded-2xl border transition-all ${awayPick ? 'bg-slate-800' : 'bg-slate-900/50 border-slate-800'}`} style={awayPick ? { borderColor: `${awayTeam.color}80` } : {}}>
              <span className="text-[11px] font-black text-slate-500 uppercase tracking-[0.2em] mb-3">{awayTeam.abbreviation} Deployment</span>
              <div className="flex items-center gap-4">
                <div className={`w-12 h-12 rounded-full flex items-center justify-center font-black oswald text-xl border-2 ${awayPick ? 'border-white text-slate-950' : 'bg-slate-800 border-slate-700 text-slate-600'}`} style={awayPick ? { backgroundColor: awayTeam.color } : {}}>
                  {awayPick || '?'}
                </div>
                <div className="flex flex-col">
                  <span className="text-sm font-black text-white">{awayPick ? PLAYER_DATA[awayTeam.name]?.[awayPick].find(p => p.number === awayNum)?.name : 'Awaiting Select'}</span>
                  {awayNum && <span className="text-[10px] font-black text-amber-500">Jersey #{awayNum}</span>}
                </div>
              </div>
            </div>

            {/* Home Stats Box */}
            <div className={`flex flex-col p-4 min-w-[200px] rounded-2xl border transition-all ${homePick ? 'bg-slate-800' : 'bg-slate-900/50 border-slate-800'}`} style={homePick ? { borderColor: `${homeTeam.color}80` } : {}}>
              <span className="text-[11px] font-black text-slate-500 uppercase tracking-[0.2em] mb-3">{homeTeam.abbreviation} Deployment</span>
              <div className="flex items-center gap-4">
                <div className={`w-12 h-12 rounded-full flex items-center justify-center font-black oswald text-xl border-2 ${homePick ? 'border-white text-white' : 'bg-slate-800 border-slate-700 text-slate-600'}`} style={homePick ? { backgroundColor: homeTeam.color } : {}}>
                  {homePick || '?'}
                </div>
                <div className="flex flex-col">
                  <span className="text-sm font-black text-white">{homePick ? PLAYER_DATA[homeTeam.name]?.[homePick].find(p => p.number === homeNum)?.name : 'Awaiting Select'}</span>
                  {homeNum && <span className="text-[10px] font-black text-blue-400">Jersey #{homeNum}</span>}
                </div>
              </div>
            </div>
          </div>

          <div className="flex flex-col items-center gap-3">
             <div className={`text-[10px] font-black uppercase tracking-[0.3em] transition-all duration-500 ${isFormValid ? 'text-green-500 animate-pulse scale-110' : 'text-slate-600'}`}>
                {isFormValid ? '✓ LINEUP COMPLETE - LOCKING...' : 'Select 1 player from each side'}
             </div>
             <div className="w-64 h-2 bg-slate-800 rounded-full overflow-hidden border border-slate-700">
                <div 
                  className="h-full bg-blue-500 transition-all duration-700 ease-out" 
                  style={{ width: isFormValid ? '100%' : awayPick && homePick ? '100%' : awayPick || homePick ? '50%' : '0%' }}
                ></div>
             </div>
          </div>
        </div>
      </div>
      <style>{`
        @keyframes possession-pulse {
          0% { box-shadow: 0 0 0 0 var(--pulse-color); filter: brightness(1); transform: scale(1); }
          50% { box-shadow: 0 0 40px 20px var(--pulse-color); filter: brightness(1.8); transform: scale(1.3); }
          100% { box-shadow: 0 0 0 0 var(--pulse-color); filter: brightness(1); transform: scale(1); }
        }
        .animate-possession-pulse { animation: possession-pulse 1.5s ease-in-out; }
      `}</style>
    </div>
  );
};

export default SelectionOverlay;

import React, { useState, useEffect, useRef } from 'react';
import { Position, TeamInfo, GameEvent, FloatingPoint, OnIceStrength } from '../types';
import { POSITIONS } from '../constants';

interface SelectionOverlayProps {
  homeTeam: TeamInfo;
  awayTeam: TeamInfo;
  onConfirm: (picks: { home: Position; away: Position; homeNumber: number; awayNumber: number }) => void;
  events: GameEvent[];
  puckPossession?: { team: 'home' | 'away'; position: Position } | null;
  floatingPoints?: FloatingPoint[];
  strength: OnIceStrength;
  waitingReason?: string;
}

const PLAYER_DATA: Record<string, Record<Position, { name: string; number: number }[]>> = {
  'Rangers': { 
    'C': [{ name: 'M. Zibanejad', number: 93 }, { name: 'V. Trocheck', number: 16 }, { name: 'F. Chytil', number: 72 }], 
    'LW': [{ name: 'A. Panarin', number: 10 }, { name: 'C. Kreider', number: 20 }, { name: 'W. Cuylle', number: 50 }], 
    'RW': [{ name: 'A. Lafreniere', number: 13 }, { name: 'K. Kakko', number: 24 }, { name: 'J. Vesey', number: 26 }], 
    'LD': [{ name: 'R. Lindgren', number: 55 }, { name: 'K. Miller', number: 79 }, { name: 'Z. Jones', number: 6 }], 
    'RD': [{ name: 'A. Fox', number: 23 }, { name: 'J. Trouba', number: 8 }, { name: 'B. Schneider', number: 4 }], 
    'G': [{ name: 'I. Shesterkin', number: 31 }, { name: 'J. Quick', number: 32 }] 
  },
  'Bruins': { 
    'C': [{ name: 'C. Coyle', number: 13 }, { name: 'P. Zacha', number: 18 }, { name: 'M. Geekie', number: 39 }], 
    'LW': [{ name: 'B. Marchand', number: 63 }, { name: 'J. van Riemsdyk', number: 21 }, { name: 'D. Heinen', number: 43 }], 
    'RW': [{ name: 'D. Pastrnak', number: 88 }, { name: 'J. DeBrusk', number: 74 }, { name: 'T. Frederic', number: 11 }], 
    'LD': [{ name: 'H. Lindholm', number: 27 }, { name: 'M. Lohrei', number: 6 }, { name: 'D. Forbort', number: 28 }], 
    'RD': [{ name: 'C. McAvoy', number: 73 }, { name: 'B. Carlo', number: 25 }, { name: 'K. Shattenkirk', number: 22 }], 
    'G': [{ name: 'J. Swayman', number: 1 }, { name: 'L. Ullmark', number: 35 }] 
  }
};

const SelectionOverlay: React.FC<SelectionOverlayProps> = ({ homeTeam, awayTeam, onConfirm, events, puckPossession, floatingPoints, strength, waitingReason }) => {
  const [awayPick, setAwayPick] = useState<Position | null>(null);
  const [homePick, setHomePick] = useState<Position | null>(null);
  const [awayNum, setAwayNum] = useState<number | null>(null);
  const [homeNum, setHomeNum] = useState<number | null>(null);
  const [showSuccess, setShowSuccess] = useState(false);
  const [activeRoster, setActiveRoster] = useState<{ side: 'home' | 'away'; pos: Position } | null>(null);

  const [hovered, setHovered] = useState<{ side: 'home' | 'away'; pos: Position } | null>(null);
  const [flash, setFlash] = useState<{ side: 'home' | 'away'; pos: Position; type: 'green' | 'red' | 'possession' } | null>(null);
  const prevPossessionRef = useRef<{ team: 'home' | 'away'; position: Position } | null>(null);
  const overlayRef = useRef<HTMLDivElement>(null);

  // Auto-confirm when both sides have made a selection
  useEffect(() => {
    if (homePick && awayPick && homeNum !== null && awayNum !== null && !showSuccess) {
      handleConfirm();
    }
  }, [homePick, awayPick, homeNum, awayNum]);

  const triggerFlash = (side: 'home' | 'away', pos: Position, type: 'green' | 'red' | 'possession', duration = 1500) => {
    setFlash({ side, pos, type });
    setTimeout(() => setFlash(null), duration);
  };

  useEffect(() => {
    if (puckPossession && (
      puckPossession.team !== prevPossessionRef.current?.team || 
      puckPossession.position !== prevPossessionRef.current?.position
    )) {
      triggerFlash(puckPossession.team, puckPossession.position, 'possession', 1500);
    }
    prevPossessionRef.current = puckPossession || null;
  }, [puckPossession]);

  const handleConfirm = () => {
    if (awayPick && homePick && awayNum !== null && homeNum !== null) {
      setShowSuccess(true);
      setTimeout(() => {
        onConfirm({ 
          home: homePick, 
          away: awayPick, 
          homeNumber: homeNum, 
          awayNumber: awayNum 
        });
      }, 1500);
    }
  };

  const handleRinkClick = (side: 'home' | 'away', pos: Position) => {
    if (showSuccess) return; 
    setActiveRoster({ side, pos });
  };

  const selectPlayer = (player: { name: string, number: number }) => {
    if (!activeRoster) return;
    const { side, pos } = activeRoster;
    if (side === 'home') {
      setHomePick(pos);
      setHomeNum(player.number);
    } else {
      setAwayPick(pos);
      setAwayNum(player.number);
    }
    triggerFlash(side, pos, 'green', 1000);
    setActiveRoster(null);
  };

  const getPlayersForPos = (teamName: string, pos: Position) => {
    return PLAYER_DATA[teamName]?.[pos] || [{ name: `${pos} Prospect`, number: 0 }];
  };

  const getPosStats = (side: 'home' | 'away', pos: Position) => {
    const posEvents = events.filter(e => e.team === side && e.position === pos);
    const goals = posEvents.filter(e => e.type === 'GOAL' || e.type === 'SO_GOAL').length;
    const assists = posEvents.filter(e => e.type === 'ASSIST').length;
    return { goals, assists };
  };

  const getPosCoords = (pos: Position, isHome: boolean) => {
    const baseCoords: Record<Position, { top: string; left: string }> = {
      'G': { top: '50%', left: isHome ? '92%' : '8%' },
      'LD': { top: '30%', left: isHome ? '75%' : '25%' },
      'RD': { top: '70%', left: isHome ? '75%' : '25%' },
      'LW': { top: '22%', left: isHome ? '60%' : '40%' },
      'RW': { top: '78%', left: isHome ? '60%' : '40%' },
      'C': { top: '50%', left: isHome ? '60%' : '40%' },
    };
    return baseCoords[pos];
  };

  return (
    <div className="fixed inset-0 z-[100] bg-slate-950/95 backdrop-blur-xl flex items-center justify-center p-4 overflow-y-auto" ref={overlayRef}>
      <div className="bg-slate-900 border border-slate-700 w-full max-w-5xl rounded-3xl shadow-[0_0_60px_rgba(0,0,0,0.6)] overflow-hidden animate-in fade-in zoom-in duration-500 my-auto relative">

        {showSuccess && (
          <div className="absolute inset-0 z-[200] bg-slate-950/60 backdrop-blur-md flex flex-col items-center justify-center animate-in fade-in duration-300">
            <div className="flex flex-col items-center gap-6 animate-in zoom-in slide-in-from-bottom-12 duration-500">
              <div className="w-24 h-24 bg-green-500 rounded-full flex items-center justify-center shadow-[0_0_50px_rgba(34,197,94,0.6)] border-4 border-green-400">
                <i className="fa-solid fa-check text-5xl text-white"></i>
              </div>
              <div className="text-center px-4">
                <h3 className="text-5xl font-black oswald uppercase tracking-tighter text-white italic mb-2">Tactical Lock!</h3>
                <p className="text-green-400 text-sm font-black uppercase tracking-[0.4em] animate-pulse">Syncing Lineups to Live Data...</p>
              </div>
            </div>
          </div>
        )}

        <div className="bg-slate-800/80 p-6 border-b border-slate-700 flex flex-col items-center text-center relative overflow-hidden">
          <div className="flex items-center gap-6 mb-2 relative z-10 w-full justify-between max-w-2xl">
            <div className="flex flex-col items-center gap-1 group">
               <span className="text-5xl transition-all duration-300">{awayTeam.logo}</span>
               <span className="text-[10px] font-black oswald text-slate-400 uppercase">{awayTeam.abbreviation}</span>
            </div>

            <div className="flex flex-col items-center">
              <div className="bg-amber-500/10 text-amber-500 text-[10px] font-black px-3 py-1 rounded-full border border-amber-500/20 uppercase tracking-[0.2em] mb-2 animate-pulse">
                {waitingReason || "Lineup Reset"}
              </div>
              <h2 className={`text-3xl font-black oswald uppercase tracking-tighter italic ${strength !== '5v5' ? 'text-amber-500' : 'text-white'}`}>
                {strength !== '5v5' ? `SPECIAL TEAMS: ${strength}` : 'LINEUP BUILDER'}
              </h2>
              <p className="text-slate-400 text-[9px] font-black uppercase tracking-[0.4em]">Tap dots to deploy specific players</p>
            </div>

            <div className="flex flex-col items-center gap-1 group">
              <span className="text-5xl transition-all duration-300">{homeTeam.logo}</span>
              <span className="text-[10px] font-black oswald text-slate-400 uppercase">{homeTeam.abbreviation}</span>
            </div>
          </div>
        </div>

        <div className="relative bg-slate-100 border-b border-slate-400 p-1">
          <div className="relative w-full aspect-[2.4/1] bg-white shadow-inner rounded-sm overflow-hidden border border-slate-300">
            <div className="absolute inset-0 opacity-[0.03] pointer-events-none bg-[url('https://www.transparenttextures.com/patterns/pinstriped-suit.png')]"></div>

            <svg className="absolute inset-0 w-full h-full pointer-events-none" viewBox="0 0 240 100" preserveAspectRatio="none">
              <path d="M 14.4 42 A 8 8 0 0 1 14.4 58" fill="rgba(37, 99, 235, 0.1)" stroke="rgba(239, 68, 68, 0.4)" strokeWidth="0.5" />
              <path d="M 225.6 42 A 8 8 0 0 0 225.6 58" fill="rgba(37, 99, 235, 0.1)" stroke="rgba(239, 68, 68, 0.4)" strokeWidth="0.5" />
              <line x1="14.4" y1="0" x2="14.4" y2="100" stroke="rgba(239, 68, 68, 0.6)" strokeWidth="0.8" />
              <line x1="225.6" y1="0" x2="225.6" y2="100" stroke="rgba(239, 68, 68, 0.6)" strokeWidth="0.8" />
              <rect x="84" y="0" width="1.5" height="100" fill="rgba(37, 99, 235, 0.8)" />
              <rect x="154.5" y="0" width="1.5" height="100" fill="rgba(37, 99, 235, 0.8)" />
              <rect x="119.5" y="0" width="1" height="100" fill="rgba(239, 68, 68, 0.8)" />
              <circle cx="120" cy="50" r="15" fill="none" stroke="rgba(37, 99, 235, 0.4)" strokeWidth="0.5" />
              <circle cx="120" cy="50" r="1.5" fill="rgba(37, 99, 235, 0.8)" />
            </svg>

            {['away', 'home'].map((side) => 
              POSITIONS.map((pos) => {
                const isHomeSide = side === 'home';
                const coords = getPosCoords(pos.value, isHomeSide);
                const isSelected = isHomeSide ? homePick === pos.value : awayPick === pos.value;
                const selectedNum = isHomeSide ? homeNum : awayNum;
                const selectedPlayer = isSelected ? PLAYER_DATA[isHomeSide ? homeTeam.name : awayTeam.name]?.[pos.value].find(p => p.number === selectedNum) : null;
                const isThisHovered = hovered?.side === side && hovered?.pos === pos.value;
                const isActivePick = activeRoster?.side === side && activeRoster?.pos === pos.value;
                const teamColor = isHomeSide ? homeTeam.color : awayTeam.color;

                const isManualFlashing = flash?.side === side && flash?.pos === pos.value;
                let flashClass = '';
                let flashStyle: React.CSSProperties = {};
                if (isManualFlashing) {
                  if (flash.type === 'possession') {
                    flashClass = 'animate-possession-pulse';
                    flashStyle = { '--pulse-color': teamColor } as React.CSSProperties;
                  } else {
                    flashClass = flash.type === 'green' ? 'animate-flash-green' : 'animate-flash-red';
                  }
                }

                const horizontalClass = parseFloat(coords.left) < 20 ? 'left-0 translate-x-0' : parseFloat(coords.left) > 80 ? 'right-0 translate-x-0' : 'left-1/2 -translate-x-1/2';
                const showBelow = parseFloat(coords.top) < 50;

                return (
                  <div key={`tactical-container-${side}-${pos.value}`} style={{ top: coords.top, left: coords.left }} className={`absolute -translate-x-1/2 -translate-y-1/2 ${isActivePick ? 'z-[150]' : 'z-20'} flex flex-col items-center`}>
                    <button
                      onMouseEnter={() => setHovered({ side: side as 'home' | 'away', pos: pos.value })}
                      onMouseLeave={() => setHovered(null)}
                      onClick={() => handleRinkClick(side as 'home' | 'away', pos.value)}
                      className={`relative w-8 h-8 sm:w-10 sm:h-10 rounded-full flex flex-col items-center justify-center transition-all z-10 shadow-lg ${
                        isSelected
                          ? 'scale-110 ring-4 border-2 border-white text-white'
                          : isThisHovered || isActivePick
                            ? 'scale-125 border-2 border-slate-400'
                            : 'bg-slate-800 text-white border-2 border-slate-600'
                      } ${flashClass}`}
                      style={{
                        ...(isSelected ? { backgroundColor: teamColor, boxShadow: `0 0 0 4px ${teamColor}4D` } : {}),
                        ...flashStyle
                      }}
                    >
                      <span className="text-[10px] sm:text-sm font-black oswald leading-none">
                        {isSelected ? selectedNum : pos.value}
                      </span>
                    </button>

                    {/* Persistent On-Ice Nameplate for Selection */}
                    {isSelected && (
                      <div className="mt-1 bg-slate-900/90 text-[7px] sm:text-[8px] font-black oswald text-white px-1.5 py-0.5 rounded border border-white/20 whitespace-nowrap shadow-sm backdrop-blur-sm animate-in fade-in duration-300">
                        {selectedPlayer?.name.split(' ').pop()}
                      </div>
                    )}

                    {(isActivePick || (isThisHovered && !activeRoster)) && (
                      <div 
                        className={`absolute z-[300] w-64 bg-slate-900/98 backdrop-blur-xl border-2 rounded-2xl p-4 shadow-[0_20px_50px_rgba(0,0,0,0.5)] animate-in zoom-in duration-300 ${horizontalClass} ${showBelow ? 'top-full mt-4' : 'bottom-full mb-4'}`} 
                        style={{ borderColor: `${teamColor}80`, boxShadow: `0 10px 30px -10px ${teamColor}40` }}
                      >
                        <div className="flex items-center justify-between mb-3">
                          <div className="flex items-center gap-2">
                              <span className="text-xl">{isHomeSide ? homeTeam.logo : awayTeam.logo}</span>
                              <span className="text-[10px] font-black uppercase tracking-widest text-white/50">
                                {isActivePick ? 'SELECT PLAYER' : `${isHomeSide ? homeTeam.abbreviation : awayTeam.abbreviation} TACTICAL`}
                              </span>
                          </div>
                          {isActivePick && (
                            <button onClick={(e) => { e.stopPropagation(); setActiveRoster(null); }} className="text-slate-500 hover:text-white transition-colors">
                              <i className="fa-solid fa-xmark text-xs"></i>
                            </button>
                          )}
                        </div>

                        {isActivePick ? (
                          <div className="space-y-1.5">
                            {getPlayersForPos(isHomeSide ? homeTeam.name : awayTeam.name, pos.value).map((player, idx) => (
                              <button
                                key={`${player.number}-${idx}`}
                                onClick={(e) => { e.stopPropagation(); selectPlayer(player); }}
                                className={`w-full flex items-center justify-between p-2.5 rounded-xl border transition-all group ${selectedNum === player.number ? 'bg-white text-slate-950 border-white shadow-[0_0_20px_rgba(255,255,255,0.2)]' : 'bg-slate-800/50 border-slate-700 hover:border-slate-500 text-white'}`}
                              >
                                <div className="flex items-center gap-3">
                                  <div className={`w-7 h-7 rounded-full flex items-center justify-center text-[10px] font-black oswald border transition-colors ${selectedNum === player.number ? 'bg-slate-950 text-white border-slate-800' : 'bg-slate-950 border-slate-800 text-white group-hover:border-white'}`} style={{ color: selectedNum === player.number ? '#000' : teamColor }}>
                                    {player.number}
                                  </div>
                                  <span className="text-[11px] font-black uppercase tracking-tight">{player.name}</span>
                                </div>
                                <div className={`w-5 h-5 rounded-full border flex items-center justify-center transition-all ${selectedNum === player.number ? 'bg-green-500 border-green-400 text-white' : 'border-slate-700 text-slate-700 group-hover:border-blue-500 group-hover:text-blue-500'}`}>
                                  {selectedNum === player.number ? <i className="fa-solid fa-check text-[8px]"></i> : <i className="fa-solid fa-plus text-[8px]"></i>}
                                </div>
                              </button>
                            ))}
                          </div>
                        ) : (
                          <>
                            <div className="text-base font-black text-white oswald uppercase tracking-tight mb-3 border-b border-white/10 pb-2">
                              {isSelected ? selectedPlayer?.name : `${pos.label} Overview`}
                            </div>
                            <div className="grid grid-cols-2 gap-3 mb-1">
                              <div className="bg-slate-950/50 p-2 rounded-lg border border-white/5">
                                <span className="text-[8px] font-bold text-slate-500 uppercase block mb-1">Goals</span>
                                <span className="text-lg font-black text-white oswald">{getPosStats(side as 'home' | 'away', pos.value).goals}</span>
                              </div>
                              <div className="bg-slate-950/50 p-2 rounded-lg border border-white/5">
                                <span className="text-[8px] font-bold text-slate-500 uppercase block mb-1">Assists</span>
                                <span className="text-lg font-black text-white oswald">{getPosStats(side as 'home' | 'away', pos.value).assists}</span>
                              </div>
                            </div>
                            <div className="text-[9px] font-bold text-slate-500 uppercase tracking-widest text-center mt-3 animate-pulse">
                              <i className="fa-solid fa-hand-pointer mr-1.5"></i> Tap dot to change player
                            </div>
                          </>
                        )}
                      </div>
                    )}
                  </div>
                );
              })
            )}
          </div>
        </div>

        <div className="p-8 bg-slate-900 border-t border-slate-700 flex flex-col lg:flex-row items-center justify-between gap-8">
          <div className="flex flex-col sm:flex-row gap-8 lg:gap-12 w-full lg:w-auto">
            <div className={`flex flex-col p-4 min-w-[200px] rounded-2xl border transition-all ${awayPick ? 'bg-slate-800' : 'bg-slate-900/50 border-slate-800'}`} style={awayPick ? { borderColor: `${awayTeam.color}80` } : {}}>
              <span className="text-[11px] font-black text-slate-500 uppercase tracking-[0.2em] mb-3">{awayTeam.abbreviation} Deployment</span>
              <div className="flex items-center gap-4">
                <div className={`w-12 h-12 rounded-full flex items-center justify-center font-black oswald text-xl border-2 ${awayPick ? 'border-white text-slate-950' : 'bg-slate-800 border-slate-700 text-slate-600'}`} style={awayPick ? { backgroundColor: awayTeam.color } : {}}>
                  {awayNum || '?'}
                </div>
                <div className="flex flex-col">
                  <span className="text-sm font-black text-white">{awayPick ? PLAYER_DATA[awayTeam.name]?.[awayPick].find(p => p.number === awayNum)?.name : 'Awaiting Select'}</span>
                  {awayPick && <span className="text-[10px] font-black text-amber-500 uppercase">{awayPick} Position</span>}
                </div>
              </div>
            </div>

