import { GoogleGenAI, Type } from "@google/genai";
import { GameEvent, Position, ScheduledGame } from "../types";
import { SCORING_RULES } from "../constants";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const fetchTodayGames = async (): Promise<ScheduledGame[]> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: "Find today's NHL schedule (current date is " + new Date().toLocaleDateString() + "). Return a list of games including home team, away team, start time, and venue. Include city names, full team names, and short abbreviations like NYR or BOS. Use representative emojis for team logos.",
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            games: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  id: { type: Type.STRING },
                  homeTeam: {
                    type: Type.OBJECT,
                    properties: {
                      name: { type: Type.STRING },
                      city: { type: Type.STRING },
                      abbreviation: { type: Type.STRING },
                      color: { type: Type.STRING, description: "hex color code" },
                      logo: { type: Type.STRING }
                    },
                    required: ['name', 'city', 'abbreviation', 'color', 'logo']
                  },
                  awayTeam: {
                    type: Type.OBJECT,
                    properties: {
                      name: { type: Type.STRING },
                      city: { type: Type.STRING },
                      abbreviation: { type: Type.STRING },
                      color: { type: Type.STRING, description: "hex color code" },
                      logo: { type: Type.STRING }
                    },
                    required: ['name', 'city', 'abbreviation', 'color', 'logo']
                  },
                  startTime: { type: Type.STRING },
                  venue: { type: Type.STRING }
                },
                required: ['id', 'homeTeam', 'awayTeam', 'startTime', 'venue']
              }
            }
          },
          required: ['games']
        }
      }
    });

    const data = JSON.parse(response.text || '{"games": []}');
    return data.games;
  } catch (error) {
    console.error("Error fetching today's games:", error);
    return [
      {
        id: "mock-1",
        homeTeam: { name: "Rangers", city: "New York", abbreviation: "NYR", color: "#0038A8", logo: "🗽" },
        awayTeam: { name: "Bruins", city: "Boston", abbreviation: "BOS", color: "#FFB81C", logo: "🐻" },
        startTime: "7:00 PM ET",
        venue: "Madison Square Garden"
      }
    ];
  }
};

export const fetchSimulatedEvents = async (
  period: number, 
  timeRemaining: string, 
  homeTeam: { name: string; city: string; abbreviation: string }, 
  awayTeam: { name: string; city: string; abbreviation: string }
): Promise<{ 
  events: Partial<GameEvent>[], 
  nextFaceoffTrigger: boolean,
  currentPossession: { team: 'home' | 'away', position: Position } | null,
  realTimeSync: boolean
}> => {
  try {
    const searchPrompt = `Search for the latest live play-by-play for the NHL game: ${awayTeam.city} ${awayTeam.name} vs ${homeTeam.city} ${homeTeam.name}.
    Current state: Period ${period}, ${timeRemaining} remaining.

    If the game is NOT currently live, SIMULATE a highly realistic 8-second sequence of hockey play.
    Simulation Rules:
    1. Generate 2-4 logical events (e.g., Defensive Takeaway -> Pass -> Wing Shot -> Goalie Save).
    2. Ensure positions (C, LW, RW, LD, RD, G) match the actions (e.g., G only makes SAVEs, LD/RD usually BLOCK_SHOTs or HITs).
    3. Include occasional PENALTY or GIVEAWAY events to disrupt play.
    4. Descriptions should be professional and exciting (e.g., "Lindgren steps up with a massive hit along the boards").
    5. Occasionally trigger 'nextFaceoffTrigger' (true) if a goal is scored or a penalty occurs to allow for lineup resets.

    Event types: GOAL, ASSIST, HIT, SHOT, BLOCKED_SHOT, TAKEAWAY, PASS, GIVEAWAY, SAVE, GOAL_AGAINST, PENALTY, SO_GOAL.`;

    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: searchPrompt,
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            events: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  team: { type: Type.STRING, enum: ['home', 'away'] },
                  position: { type: Type.STRING, enum: ['C', 'LW', 'RW', 'LD', 'RD', 'G'] },
                  type: { type: Type.STRING, enum: ['GOAL', 'ASSIST', 'HIT', 'SHOT', 'BLOCKED_SHOT', 'TAKEAWAY', 'PASS', 'GIVEAWAY', 'SAVE', 'GOAL_AGAINST', 'PENALTY', 'SO_GOAL'] },
                  description: { type: Type.STRING },
                  gameTime: { type: Type.STRING }
                },
                required: ['team', 'position', 'type', 'description', 'gameTime']
              }
            },
            nextFaceoffTrigger: { type: Type.BOOLEAN },
            currentPossession: {
              type: Type.OBJECT,
              properties: {
                team: { type: Type.STRING, enum: ['home', 'away'] },
                position: { type: Type.STRING, enum: ['C', 'LW', 'RW', 'LD', 'RD', 'G'] }
              },
              required: ['team', 'position']
            },
            foundRealData: { type: Type.BOOLEAN }
          },
          required: ['events', 'nextFaceoffTrigger', 'currentPossession', 'foundRealData']
        }
      }
    });

    const data = JSON.parse(response.text || '{"events":[], "nextFaceoffTrigger": false, "currentPossession": null, "foundRealData": false}');

    const eventsWithPoints = data.events.map((e: any) => {
      let points = 0;
      if (e.position === 'G') {
        if (e.type === 'SAVE') points = SCORING_RULES.GOALIE.SAVE;
        else if (e.type === 'GOAL_AGAINST') points = SCORING_RULES.GOALIE.GOAL_AGAINST;
        else if (e.type === 'PENALTY') points = SCORING_RULES.SKATER.PENALTY;
        else points = (SCORING_RULES.SKATER as any)[e.type] || 0;
      } else {
        points = (SCORING_RULES.SKATER as any)[e.type] || 0;
        // Shootout goals count as goals
        if (e.type === 'SO_GOAL') points = SCORING_RULES.SKATER.GOAL;
      }
      return { ...e, points, id: Math.random().toString(36).substr(2, 9), timestamp: Date.now() };
    });

    return { 
      events: eventsWithPoints, 
      nextFaceoffTrigger: data.nextFaceoffTrigger || eventsWithPoints.some((e: any) => e.type === 'GOAL' || e.type === 'PENALTY' || e.type === 'SO_GOAL'),
      currentPossession: data.currentPossession,
      realTimeSync: data.foundRealData
    };
  } catch (error) {
    console.error("Error fetching events via search:", error);
    return { events: [], nextFaceoffTrigger: false, currentPossession: null, realTimeSync: false };
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { Position, TeamInfo, GameEvent, FloatingPoint, OnIceStrength } from '../types';
import { POSITIONS } from '../constants';

interface SelectionOverlayProps {
