                      className={`relative w-8 h-8 sm:w-10 sm:h-10 rounded-full flex flex-col items-center justify-center transition-all z-10 shadow-lg ${
                        isSelected
                          ? 'scale-110 ring-4 border-2 border-white text-white'
                          : isThisHovered
                            ? 'scale-125 border-2 border-slate-400'
                            : 'bg-slate-800 text-white border-2 border-slate-600'
                      } ${flashClass}`}
                      style={{
                        ...(isSelected ? { backgroundColor: teamColor, boxShadow: `0 0 0 4px ${teamColor}4D` } : {}),
                        ...flashStyle
                      }}
                    >
                      <span className="text-[10px] sm:text-sm font-black oswald leading-none">
                        {isSelected ? selectedNum : pos.value}
                      </span>
                    </button>

                    {relevantPoints.map(fp => (
                      <div 
                        key={`pt-tag-${fp.id}`}
                        className={`absolute pointer-events-none z-[60] font-black oswald text-[10px] sm:text-xs px-2 py-0.5 rounded-full border-2 shadow-[0_0_20px_rgba(0,0,0,0.5)] animate-point-badge-pop flex items-center gap-1.5 ${fp.points > 0 ? 'bg-green-500 border-green-200 text-white' : 'bg-red-500 border-red-200 text-white'} ${pointTagPos}`}
                        style={{ 
                          top: '10%',
                          boxShadow: `0 0 25px ${fp.points > 0 ? '#22c55e' : '#ef4444'}CC` 
                        }}
                      >
                        <i className={`fa-solid ${fp.points > 0 ? 'fa-caret-up' : 'fa-caret-down'}`}></i>
                        {fp.points > 0 ? '+' : ''}{fp.points}
                      </div>
                    ))}

                    {isSelected && (
                      <div className="mt-1 bg-slate-900/90 text-[7px] sm:text-[8px] font-black oswald text-white px-1.5 py-0.5 rounded border border-white/20 whitespace-nowrap shadow-sm backdrop-blur-sm animate-in fade-in duration-300 pointer-events-none">
                        {selectedPlayer?.name.split(' ').pop()}
                      </div>
                    )}

                    {isThisHovered && (
                      <div 
                        className={`absolute z-[400] w-64 max-w-[calc(100vw-6rem)] bg-slate-900/98 backdrop-blur-2xl border-2 rounded-2xl p-4 shadow-[0_20px_50px_rgba(0,0,0,0.5)] animate-in zoom-in duration-200 pointer-events-none ${tooltipPositionClass}`} 
                        style={{ 
                          borderColor: `${teamColor}A0`, 
                          boxShadow: `0 10px 40px -10px ${teamColor}60` 
                        }}
                      >
                        <div className="flex items-center justify-between mb-3">
                          <div className="flex items-center gap-2">
                              <span className="text-xl">{isHomeSide ? homeTeam.logo : awayTeam.logo}</span>
                              <span className="text-[10px] font-black uppercase tracking-widest text-white/50">
                                {isHomeSide ? homeTeam.abbreviation : awayTeam.abbreviation} TACTICAL INFO
                              </span>
                          </div>
                        </div>

                        <div className="text-base font-black text-white oswald uppercase tracking-tight mb-3 border-b border-white/10 pb-2">
                          {isSelected ? selectedPlayer?.name : `${pos.value} Scout Report`}
                        </div>
                        <div className="grid grid-cols-2 gap-3 mb-1">
                          <div className="bg-slate-950/50 p-2 rounded-lg border border-white/5">
                            <span className="text-[8px] font-bold text-slate-500 uppercase block mb-1">Live Goals</span>
                            <span className="text-lg font-black text-white oswald">{getPosStats(side as 'home' | 'away', pos.value).goals}</span>
                          </div>
                          <div className="bg-slate-950/50 p-2 rounded-lg border border-white/5">
                            <span className="text-[8px] font-bold text-slate-500 uppercase block mb-1">Live Assists</span>
                            <span className="text-lg font-black text-white oswald">{getPosStats(side as 'home' | 'away', pos.value).assists}</span>
                          </div>
                        </div>
                        <div className="text-[9px] font-bold text-slate-500 uppercase tracking-widest text-center mt-3 animate-pulse">
                          <i className="fa-solid fa-hand-pointer mr-1.5"></i> Tap dot to cycle deployment
                        </div>
                      </div>
                    )}
                  </div>
                );
              })
            )}
          </div>
        </div>

        <div className="p-8 bg-slate-900 border-t border-slate-700 flex flex-col lg:flex-row items-center justify-between gap-8 rounded-b-3xl">
          <div className="flex flex-col sm:flex-row gap-8 lg:gap-12 w-full lg:w-auto">
