                                  {isSelected ? 'In Lineup' : 'Available'}
                                </span>
                              </div>
                              <h4 className="text-lg font-black text-white oswald uppercase italic leading-none truncate tracking-tight">
                                {isSelected ? currentSelectedPlayer?.name : previewPlayer.name}
                              </h4>
                              <p className="text-[10px] font-bold text-slate-400 uppercase tracking-tighter mt-1.5 flex items-center gap-1.5">
                                <span className="w-1.5 h-1.5 rounded-full" style={{ backgroundColor: teamColor }}></span>
                                {isHomeSide ? homeTeam.abbreviation : awayTeam.abbreviation} • {isHomeSide ? homeTeam.city : awayTeam.city}
                              </p>
                            </div>
                          </div>
                        </div>
                        <div className="p-4 grid grid-cols-2 gap-3 bg-gradient-to-b from-slate-900/50 to-slate-950/80">
                          <div className="bg-slate-950/50 p-3 rounded-xl border border-white/5 flex flex-col gap-1">
                            <div className="flex items-center gap-2 mb-1">
                              <div className="w-5 h-5 rounded-lg bg-red-500/10 flex items-center justify-center">
                                <i className="fa-solid fa-bullseye text-red-500 text-[10px]"></i>
                              </div>
                              <span className="text-[8px] font-black text-slate-500 uppercase tracking-widest">Live Goals</span>
                            </div>
                            <span className="text-2xl font-black text-white oswald leading-none tabular-nums">{stats.goals}</span>
                          </div>
                          <div className="bg-slate-950/50 p-3 rounded-xl border border-white/5 flex flex-col gap-1">
                            <div className="flex items-center gap-2 mb-1">
                              <div className="w-5 h-5 rounded-lg bg-blue-500/10 flex items-center justify-center">
                                <i className="fa-solid fa-hands-helping text-blue-500 text-[10px]"></i>
                              </div>
                              <span className="text-[8px] font-black text-slate-500 uppercase tracking-widest">Assists</span>
                            </div>
                            <span className="text-2xl font-black text-white oswald leading-none tabular-nums">{stats.assists}</span>
                          </div>
                        </div>
                        <div className="px-4 py-2.5 bg-slate-950 border-t border-white/5 flex items-center justify-center gap-2">
                           <i className="fa-solid fa-hand-pointer text-slate-600 text-[10px] animate-bounce"></i>
