const App: React.FC = () => {
  const [scheduledGames, setScheduledGames] = useState<ScheduledGame[]>([]);
  const [isLoadingSchedule, setIsLoadingSchedule] = useState(false);
  const [hasSelectedGame, setHasSelectedGame] = useState(false);
  const [isRealTimeSync, setIsRealTimeSync] = useState(false);

  const [game, setGame] = useState<GameState>({
    period: 1,
    timeRemaining: '20:00',
    isPaused: false,
    waitingForPicks: true,
    homeTeam: INITIAL_TEAMS.home,
    awayTeam: INITIAL_TEAMS.away,
    userPicks: { home: null, away: null, homeNumber: null, awayNumber: null },
    totalPoints: 0,
    rank: 124,
    totalPlayers: 1542,
    events: [],
    puckPossession: null,
    strength: '5v5',
  });

  const [competitors, setCompetitors] = useState<LeaderboardPlayer[]>(() => {
    return Array.from({ length: 49 }, (_, i) => ({
      id: `comp-${i}`,
      name: `User_${Math.floor(Math.random() * 9000) + 1000}`,
      points: Math.max(0, 15000 - (i * 300) + (Math.random() * 500)),
    }));
  });

  const [floatingPoints, setFloatingPoints] = useState<FloatingPoint[]>([]);
  const [explosions, setExplosions] = useState<GoalExplosion[]>([]);
  const [loadingEvents, setLoadingEvents] = useState(false);
  const [notifPermission, setNotifPermission] = useState<NotificationPermission>(getNotificationStatus());
  const tickerRef = useRef<any>(null);

  useEffect(() => {
    const loadGames = async () => {
      setIsLoadingSchedule(true);
      const games = await fetchTodayGames();
      setScheduledGames(games);
      setIsLoadingSchedule(false);
    };
    loadGames();
  }, []);

  const handleSelectGame = (selected: ScheduledGame) => {
    setGame(prev => ({
      ...prev,
      homeTeam: { ...selected.homeTeam, score: 0 },
      awayTeam: { ...selected.awayTeam, score: 0 },
      events: [],
      totalPoints: 0,
      waitingForPicks: true,
      period: 1,
      timeRemaining: '20:00',
    }));
    setHasSelectedGame(true);
  };

  const leaderboardData = useMemo(() => {
    const userPlayer: LeaderboardPlayer = {
      id: 'user-main',
      name: 'PuckMaster99',
      points: game.totalPoints,
      isUser: true
    };
    return [...competitors, userPlayer];
  }, [competitors, game.totalPoints]);

  useEffect(() => {
    const sorted = [...leaderboardData].sort((a, b) => b.points - a.points);
    const userIndex = sorted.findIndex(p => p.isUser);
    setGame(prev => ({ ...prev, rank: userIndex + 1 }));
  }, [leaderboardData]);

  const updateCompetitors = useCallback(() => {
    setCompetitors(prev => prev.map(comp => {
      const gain = Math.random() > 0.7 ? Math.floor(Math.random() * 1000) : 0;
      return { ...comp, points: comp.points + gain };
    }));
  }, []);

  const triggerGoalExplosion = (team: 'home' | 'away') => {
    const id = Math.random().toString(36).substr(2, 9);
    const color = team === 'home' ? game.homeTeam.color : game.awayTeam.color;
    setExplosions(prev => [...prev, { id, team, color }]);
    setTimeout(() => {
      setExplosions(prev => prev.filter(e => e.id !== id));
    }, 3000);
  };

  const triggerPointsAnimation = (points: number, team: 'home' | 'away', position: Position, isUser: boolean) => {
    const id = Math.random().toString(36).substr(2, 9);
    const newFloatingPoint: FloatingPoint = {
      id,
      points,
      team,
      position,
      isUser,
      xOffset: (Math.random() - 0.5) * 40,
      variant: Math.floor(Math.random() * 3),
    };
    setFloatingPoints(prev => [...prev, newFloatingPoint]);
    setTimeout(() => {
      setFloatingPoints(prev => prev.filter(fp => fp.id !== id));
    }, 2000);
  };

  const processEvents = useCallback(async () => {
    if (loadingEvents || game.waitingForPicks || !hasSelectedGame) return;

    setLoadingEvents(true);
    const result = await fetchSimulatedEvents(
      game.period,
      game.timeRemaining,
      game.homeTeam,
      game.awayTeam
    );

    setIsRealTimeSync(result.realTimeSync);

    let newPoints = 0;
    let currentHomeScore = game.homeTeam.score;
    let currentAwayScore = game.awayTeam.score;
    let goalScored = false;
    let scoringTeamType: 'home' | 'away' | null = null;

    const processedEvents = result.events.map(event => {
      if (event.type === 'GOAL') {
        goalScored = true;
        scoringTeamType = event.team as 'home' | 'away';
        if (event.team === 'home') currentHomeScore++;
        else currentAwayScore++;
      }

      const userPickForTeam = event.team === 'home' ? game.userPicks.home : game.userPicks.away;
      const isUserPick = event.position === userPickForTeam;
      const earned = isUserPick ? (event.points || 0) : 0;

      if (earned !== 0) {
        newPoints += earned;
        triggerPointsAnimation(earned, event.team!, event.position!, true);
      } else if (event.points && event.points !== 0) {
        triggerPointsAnimation(event.points!, event.team!, event.position!, false);
      }

      return { 
        ...event, 
        userEarned: earned, 
        homeScoreAtEvent: currentHomeScore, 
        awayScoreAtEvent: currentAwayScore,
        period: game.period 
      } as GameEvent;
    });

    if (goalScored && scoringTeamType) {
      triggerGoalExplosion(scoringTeamType);
    }

    if (result.nextFaceoffTrigger) {
      sendGameNotification("Face-Off!", "Play stopped. Update your picks now!");
    }

    setGame(prev => ({
      ...prev,
      totalPoints: prev.totalPoints + newPoints,
      events: [...processedEvents, ...prev.events].slice(0, 100),
      homeTeam: { ...prev.homeTeam, score: currentHomeScore },
      awayTeam: { ...prev.awayTeam, score: currentAwayScore },
      waitingForPicks: result.nextFaceoffTrigger,
      puckPossession: result.currentPossession,
    }));

    updateCompetitors();
    setLoadingEvents(false);
  }, [game.period, game.timeRemaining, game.homeTeam, game.awayTeam, game.userPicks, game.waitingForPicks, loadingEvents, game.homeTeam.score, game.awayTeam.score, updateCompetitors, hasSelectedGame]);

  useEffect(() => {
    if (game.waitingForPicks || game.isPaused || !hasSelectedGame) return;
    tickerRef.current = setInterval(() => {
      setGame(prev => {
        const [mins, secs] = prev.timeRemaining.split(':').map(Number);
        let totalSecs = mins * 60 + secs - 12;
        if (totalSecs <= 0) {
          if (prev.period < 3) return { ...prev, period: prev.period + 1, timeRemaining: '20:00', waitingForPicks: true, puckPossession: null };
          return { ...prev, isPaused: true, timeRemaining: '00:00', puckPossession: null };
        }
        const newMins = Math.floor(totalSecs / 60);
        const newSecs = totalSecs % 60;
        return { ...prev, timeRemaining: `${newMins.toString().padStart(2, '0')}:${newSecs.toString().padStart(2, '0')}` };
      });
    }, 1000);
    return () => { if (tickerRef.current) clearInterval(tickerRef.current); };
  }, [game.waitingForPicks, game.isPaused, hasSelectedGame]);

  useEffect(() => {
    if (game.waitingForPicks || game.isPaused || !hasSelectedGame) return;
    const eventInterval = setInterval(() => { processEvents(); }, 8000);
    return () => clearInterval(eventInterval);
  }, [game.waitingForPicks, game.isPaused, processEvents, hasSelectedGame]);

  const handlePicks = async (picks: { home: Position; away: Position; homeNumber: number; awayNumber: number }) => {
    if (notifPermission === 'default') {
      const granted = await requestNotificationPermission();
      setNotifPermission(granted ? 'granted' : 'denied');
    }
    setGame(prev => ({ ...prev, userPicks: picks, waitingForPicks: false }));
  };

  const openPicks = () => {
    if (game.waitingForPicks) return;
    setGame(prev => ({ ...prev, waitingForPicks: true, puckPossession: null }));
  };

  const goBackToSelection = () => {
    setHasSelectedGame(false);
  };

  if (!hasSelectedGame) {
    return <GameSelectionScreen games={scheduledGames} onSelectGame={handleSelectGame} isLoading={isLoadingSchedule} />;
  }

  return (
    <div className="min-h-screen bg-slate-950 text-slate-100 flex flex-col pb-24 relative overflow-hidden">
      {explosions.map(exp => (
        <div key={exp.id} className="fixed inset-0 z-[100] pointer-events-none flex items-center justify-center">
          <div className="absolute inset-0 animate-screen-flash" style={{ backgroundColor: `${exp.color}22` }} />
          <div className="relative">
            <div className="text-8xl font-black oswald uppercase text-white animate-goal-text drop-shadow-[0_0_20px_rgba(255,255,255,0.8)]">GOAL!</div>
            <div className="absolute inset-0 animate-goal-explosion" style={{ background: `radial-gradient(circle, ${exp.color} 0%, transparent 70%)` }} />
          </div>
        </div>
      ))}

      {game.waitingForPicks && (
        <SelectionOverlay 
          homeTeam={game.homeTeam} 
          awayTeam={game.awayTeam} 
          onConfirm={handlePicks} 
          events={game.events}
          puckPossession={game.puckPossession}
          floatingPoints={floatingPoints}
          strength={game.strength}
        />
      )}

      <ScoreBoard home={game.homeTeam} away={game.awayTeam} period={game.period} time={game.timeRemaining} />

      <main className="flex-1 max-w-6xl mx-auto w-full p-4">
        <div className="mb-6 flex justify-between items-center">
          <button 
            onClick={goBackToSelection}
            className="text-[10px] font-black uppercase tracking-widest text-slate-500 hover:text-white transition-colors flex items-center gap-2 group"
          >
            <i className="fa-solid fa-chevron-left group-hover:-translate-x-1 transition-transform"></i>
            Change Game
          </button>

          {isRealTimeSync && (
            <div className="bg-green-600/20 text-green-400 text-[9px] font-black uppercase tracking-widest px-3 py-1 rounded-full border border-green-500/30 flex items-center gap-2 animate-pulse">
               <span className="w-1.5 h-1.5 bg-green-500 rounded-full"></span>
               Live Match Grounding
            </div>
          )}
        </div>

        <div className="flex flex-col lg:flex-row gap-8">
          <div className="flex-1 space-y-8 order-2 lg:order-1">
            <div className="grid grid-cols-2 sm:grid-cols-4 gap-4">
              <div className="bg-slate-900 border border-slate-800 p-4 rounded-xl shadow-lg relative overflow-hidden">
                <div className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-1">Score</div>
                <div className="text-3xl font-black text-amber-500 oswald">{game.totalPoints.toLocaleString()}</div>
              </div>
              <div className="bg-slate-900 border border-slate-800 p-4 rounded-xl shadow-lg relative overflow-hidden">
                <div className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-1">Rank</div>
                <div className="text-3xl font-black text-blue-400 oswald">#{game.rank}</div>
              </div>
              <div className="bg-slate-900 border border-slate-800 p-4 rounded-xl shadow-lg hidden sm:block">
                <div className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-1">Status</div>
                <div className="text-xs font-black text-white uppercase">{game.waitingForPicks ? 'Drafting Lines' : 'POWERPLAY Active'}</div>
              </div>
              <div className="bg-slate-900 border border-slate-800 p-4 rounded-xl shadow-lg hidden sm:block">
                <div className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-1">Active Players</div>
                <div className="text-3xl font-black text-slate-300 oswald">{game.totalPlayers.toLocaleString()}</div>
              </div>
            </div>

            <div className="space-y-6">
              <div className="bg-slate-900/50 border border-slate-800 rounded-2xl overflow-hidden flex flex-col">
                <div className="bg-slate-800 px-6 py-4 border-b border-slate-700 flex justify-between items-center">
                  <h2 className="text-sm font-black uppercase tracking-widest text-slate-200 flex items-center gap-2">
                    <i className="fa-solid fa-satellite-dish text-red-500 animate-pulse"></i> POWERPLAY Live Feed
                  </h2>
                  {loadingEvents && <div className="text-[10px] font-bold text-slate-500 uppercase animate-pulse"><i className="fa-solid fa-spinner fa-spin mr-1"></i>Scanning Grounding...</div>}
                </div>
                <div className="overflow-y-auto p-4 space-y-4 max-h-[450px] scroll-smooth">
                  {game.events.length === 0 ? (
                    <div className="h-40 flex flex-col items-center justify-center text-slate-600">
                      <i className="fa-solid fa-hockey-puck text-4xl mb-4 opacity-20"></i>
                      <p className="font-bold uppercase tracking-wider text-[10px]">Puck is currently in the air...</p>
                    </div>
                  ) : (
                    game.events.slice(0, 15).map((event) => {
                      const isUserPositive = (event.userEarned || 0) > 0;
                      const isUserNegative = (event.userEarned || 0) < 0;
                      return (
                        <div key={`live-${event.id}`} className={`flex items-start gap-4 p-4 rounded-xl border transition-all animate-in slide-in-from-right duration-500 relative overflow-hidden ${isUserPositive ? 'bg-green-900/10 border-green-500/40' : isUserNegative ? 'bg-red-900/10 border-red-500/40' : 'bg-slate-800/40 border-slate-700'}`}>
                          <div className={`w-10 h-10 rounded-full flex-shrink-0 flex items-center justify-center font-black text-xs border-2 shadow-lg z-10 ${event.team === 'home' ? 'bg-blue-600 border-blue-400 text-white' : 'bg-amber-500 border-amber-300 text-slate-950'}`}>{event.position}</div>
                          <div className="flex-1 z-10">
                            <div className="text-[9px] font-bold text-slate-500 uppercase mb-1">{event.gameTime} • {event.type.replace('_', ' ')}</div>
                            <p className="text-sm text-slate-100 font-medium">{event.description}</p>
                          </div>
                          {event.userEarned !== 0 && <div className={`text-right font-black oswald text-xl min-w-[60px] z-10 ${isUserPositive ? 'text-green-400' : 'text-red-400'}`}>{isUserPositive ? '+' : ''}{event.userEarned}</div>}
                        </div>
                      );
                    })
                  )}
                </div>
              </div>

              <PlayByPlayFeed events={game.events} />
            </div>

            <PerformanceSummary events={game.events} />
            <GameLog events={game.events} homeTeam={game.homeTeam} awayTeam={game.awayTeam} />
          </div>

          <div className="lg:w-80 order-1 lg:order-2">
            <div className="lg:sticky lg:top-24 space-y-6 flex flex-col min-h-screen">
              <div className="bg-slate-900 border border-slate-800 rounded-3xl p-4 shadow-xl">
                <div className="flex items-center justify-between mb-3 px-1">
                  <h3 className="text-[10px] font-black uppercase tracking-widest text-slate-500 flex items-center gap-2">
                    <i className="fa-solid fa-clock-rotate-left text-blue-500"></i>
                    Last Few Plays
                  </h3>
                </div>
                <div className="space-y-2">
                  {game.events.length === 0 ? (
                    <div className="py-6 flex flex-col items-center justify-center text-slate-700 bg-slate-950/50 rounded-xl border border-dashed border-slate-800">
                      <p className="text-[8px] font-black uppercase tracking-widest">Waiting for action...</p>
                    </div>
                  ) : (
                    game.events.slice(0, 3).map((event) => (
                      <div key={`sidebar-mini-${event.id}`} className="bg-slate-950/50 border border-slate-800/50 rounded-lg p-2 flex items-center gap-3 animate-in fade-in slide-in-from-right duration-300">
                        <div className={`w-6 h-6 rounded-full flex-shrink-0 flex items-center justify-center text-[8px] font-black border shadow-sm ${event.team === 'home' ? 'bg-blue-600 border-blue-400 text-white' : 'bg-amber-500 border-amber-300 text-slate-950'}`}>
                          {event.position}
                        </div>
                        <div className="flex-1 min-w-0">
                          <div className="flex items-center gap-2 mb-0.5">
                            <span className="text-[7px] font-black text-slate-500 uppercase">{event.gameTime}</span>
                            <span className={`text-[7px] font-black uppercase px-1 rounded ${event.type === 'GOAL' ? 'bg-red-500/20 text-red-500' : 'bg-slate-800 text-slate-600'}`}>{event.type.split('_')[0]}</span>
                          </div>
                          <p className="text-[9px] text-slate-400 font-medium truncate">{event.description}</p>
                        </div>
                      </div>
                    ))
                  )}
                </div>
              </div>

              <div className={`bg-slate-900 border border-slate-800 rounded-3xl p-4 shadow-2xl transition-all duration-500 ${game.waitingForPicks ? 'ring-2 ring-amber-500/30' : ''}`}>
                <div className="flex justify-between items-center mb-4">
                   <div className="text-[9px] font-black text-slate-500 uppercase tracking-widest flex items-center gap-2">
                      Tactical Command
                      <span className={`w-1.5 h-1.5 rounded-full ${game.waitingForPicks ? 'bg-amber-500 animate-pulse' : 'bg-green-500'}`}></span>
                   </div>
                   <div className={`text-[8px] font-black px-2 py-0.5 rounded uppercase ${game.waitingForPicks ? 'bg-amber-500/20 text-amber-500' : 'bg-slate-800 text-slate-500'}`}>
                    {game.waitingForPicks ? 'Update Lineup' : 'Picks Locked'}
                   </div>
                </div>

                <PickStatus 
                  homeTeam={game.homeTeam} 
                  awayTeam={game.awayTeam} 
                  userPicks={game.userPicks} 
                  floatingPoints={floatingPoints}
                  isSelecting={game.waitingForPicks}
                  onConfirmPicks={handlePicks}
                  puckPossession={game.puckPossession}
                  events={game.events} // Passed events
                />
              </div>

              <div className="bg-slate-900 border border-slate-800 p-5 rounded-2xl">
                <h3 className="text-xs font-black text-slate-200 uppercase tracking-widest mb-4">Scoring Key</h3>
                <div className="space-y-2">
                  <div className="flex justify-between text-[10px] font-bold text-slate-500 uppercase"><span>Goal</span><span className="text-green-400">+5000</span></div>
                  <div className="flex justify-between text-[10px] font-bold text-slate-500 uppercase"><span>Assist</span><span className="text-blue-400">+1000</span></div>
                  <div className="flex justify-between text-[10px] font-bold text-slate-500 uppercase"><span>Save</span><span className="text-green-400">+250</span></div>
                  <div className="flex justify-between text-[10px] font-bold text-slate-500 uppercase"><span>Hit/Shot</span><span className="text-slate-300">+200</span></div>
                  <div className="flex justify-between text-[10px] font-bold text-slate-500 uppercase"><span>Giveaway</span><span className="text-red-400">-200</span></div>
                </div>
              </div>

              <div className="flex-1">
                <Leaderboard players={leaderboardData} userPoints={game.totalPoints} userRank={game.rank} />
              </div>
            </div>
          </div>
        </div>
      </main>

      <footer className="fixed bottom-0 left-0 right-0 bg-slate-900/90 border-t border-slate-800 p-4 sm:p-6 shadow-2xl z-40 backdrop-blur-md">
        <div className="max-w-6xl mx-auto flex items-center justify-between gap-4">
          <div className="flex items-center gap-6">
            <div>
              <div className="text-[10px] font-bold text-slate-500 uppercase mb-1">POWERPLAY Points</div>
              <div className="text-3xl font-black oswald text-amber-500 leading-none">{game.totalPoints.toLocaleString()}</div>
            </div>
            <div className="h-8 w-[1px] bg-slate-800"></div>
            <div>
              <div className="text-[10px] font-bold text-slate-500 uppercase mb-1">Current Rank</div>
              <div className="text-2xl font-black oswald text-white leading-none">#{game.rank}</div>
            </div>
          </div>

          <div className="flex items-center gap-4">
            {!game.waitingForPicks && (
              <div className="hidden md:flex flex-col items-end">
                <span className="text-[9px] font-black text-slate-500 uppercase tracking-widest">Picks Locked</span>
                <span className="text-[10px] font-bold text-slate-400 italic">Wait for stoppage to edit</span>
              </div>
            )}
            <button 
              onClick={openPicks} 
              disabled={game.waitingForPicks} 
              className={`px-8 py-3 rounded-xl font-black oswald text-lg uppercase tracking-widest transition-all active:scale-95 ${
                !game.waitingForPicks 
                ? 'bg-blue-600 hover:bg-blue-500 text-white shadow-lg shadow-blue-900/30 ring-2 ring-blue-400/50' 
                : 'bg-slate-800 text-slate-600 border border-slate-700 cursor-not-allowed'
              }`}
            >
              {game.waitingForPicks ? 'Drafting Open' : 'Change Lineup'}
            </button>
          </div>
        </div>
      </footer>

      <style>{`
        @keyframes screen-flash { 0% { opacity: 0; } 10% { opacity: 1; } 100% { opacity: 0; } }
        @keyframes goal-text { 0% { transform: scale(0.5); opacity: 0; filter: blur(10px); } 20% { transform: scale(1.2); opacity: 1; filter: blur(0); } 80% { transform: scale(1.1); opacity: 1; } 100% { transform: scale(1.5); opacity: 0; filter: blur(20px); } }
        @keyframes goal-explosion { 0% { transform: scale(0); opacity: 0.8; } 100% { transform: scale(4); opacity: 0; } }
        .animate-screen-flash { animation: screen-flash 1.5s ease-out forwards; }
        .animate-goal-text { animation: goal-text 2s cubic-bezier(0.17, 0.67, 0.83, 0.67) forwards; }
        .animate-goal-explosion { animation: goal-explosion 1s ease-out forwards; }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { Position, TeamInfo, GameEvent, FloatingPoint, OnIceStrength } from '../types';
import { POSITIONS, PLAYER_DATA } from '../constants';

interface SelectionOverlayProps {
  homeTeam: TeamInfo;
  awayTeam: TeamInfo;
  onConfirm: (picks: { home: Position; away: Position; homeNumber: number; awayNumber: number }) => void;
  events: GameEvent[];
  puckPossession?: { team: 'home' | 'away'; position: Position } | null;
  floatingPoints?: FloatingPoint[];
  strength: OnIceStrength;
  waitingReason?: string;
}

const SelectionOverlay: React.FC<SelectionOverlayProps> = ({ homeTeam, awayTeam, onConfirm, events, puckPossession, floatingPoints, strength, waitingReason }) => {
  const [awayPick, setAwayPick] = useState<Position | null>(null);
  const [homePick, setHomePick] = useState<Position | null>(null);
  const [awayNum, setAwayNum] = useState<number | null>(null);
  const [homeNum, setHomeNum] = useState<number | null>(null);
  const [showSuccess, setShowSuccess] = useState(false);

  const [hovered, setHovered] = useState<{ side: 'home' | 'away'; pos: Position } | null>(null);
  const [flash, setFlash] = useState<{ side: 'home' | 'away'; pos: Position; type: 'green' | 'red' | 'possession' } | null>(null);
  const prevPossessionRef = useRef<{ team: 'home' | 'away'; position: Position } | null>(null);
  const overlayRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (homePick && awayPick && homeNum !== null && awayNum !== null && !showSuccess) {
      handleConfirm();
    }
  }, [homePick, awayPick, homeNum, awayNum]);

  const triggerFlash = (side: 'home' | 'away', pos: Position, type: 'green' | 'red' | 'possession', duration = 1500) => {
    setFlash({ side, pos, type });
    setTimeout(() => setFlash(null), duration);
  };

  useEffect(() => {
    if (puckPossession && (
      puckPossession.team !== prevPossessionRef.current?.team || 
      puckPossession.position !== prevPossessionRef.current?.position
    )) {
      triggerFlash(puckPossession.team, puckPossession.position, 'possession', 1500);
    }
    prevPossessionRef.current = puckPossession || null;
  }, [puckPossession]);

  const handleConfirm = () => {
    if (awayPick && homePick && awayNum !== null && homeNum !== null) {
      setShowSuccess(true);
      setTimeout(() => {
        onConfirm({ 
          home: homePick, 
          away: awayPick, 
          homeNumber: homeNum, 
          awayNumber: awayNum 
        });
      }, 1500);
    }
  };

  const handleRinkClick = (side: 'home' | 'away', pos: Position) => {
    if (showSuccess) return; 

    const teamName = side === 'home' ? homeTeam.name : awayTeam.name;
    const roster = PLAYER_DATA[teamName]?.[pos] || [{ name: `${pos} Prospect`, number: Math.floor(Math.random() * 99) + 1 }];
    if (roster.length === 0) return;

    const currentNum = side === 'home' ? homeNum : awayNum;
    const currentPos = side === 'home' ? homePick : awayPick;

    let nextPlayer;
    if (currentPos !== pos) {
      nextPlayer = roster[0];
    } else {
      const currentIndex = roster.findIndex(p => p.number === currentNum);
      nextPlayer = roster[(currentIndex + 1) % roster.length];
    }

    if (side === 'home') {
      setHomePick(pos);
      setHomeNum(nextPlayer.number);
    } else {
      setAwayPick(pos);
      setAwayNum(nextPlayer.number);
    }

    triggerFlash(side, pos, 'green', 800);
  };

  const getPosStats = (side: 'home' | 'away', pos: Position) => {
    const posEvents = events.filter(e => e.team === side && e.position === pos);
    const goals = posEvents.filter(e => e.type === 'GOAL' || e.type === 'SO_GOAL').length;
    const assists = posEvents.filter(e => e.type === 'ASSIST').length;
    return { goals, assists };
  };

  const getPosCoords = (pos: Position, isHome: boolean) => {
    const baseCoords: Record<Position, { top: string; left: string }> = {
      'G': { top: '50%', left: isHome ? '92%' : '8%' },
      'LD': { top: '30%', left: isHome ? '75%' : '25%' },
      'RD': { top: '70%', left: isHome ? '75%' : '25%' },
      'LW': { top: '22%', left: isHome ? '60%' : '40%' },
      'RW': { top: '78%', left: isHome ? '60%' : '40%' },
      'C': { top: '50%', left: isHome ? '60%' : '40%' },
    };
    return baseCoords[pos];
  };

  const getTooltipPositionClasses = (left: string, top: string) => {
    const l = parseFloat(left);
    const t = parseFloat(top);

    let xClass = 'left-1/2 -translate-x-1/2';
    if (l < 25) {
      xClass = 'left-0 translate-x-2';
    } else if (l > 75) {
      xClass = 'right-0 -translate-x-2';
    }

    const yClass = t < 50 ? 'top-full mt-3' : 'bottom-full mb-3';

    return `${xClass} ${yClass}`;
  };

  const getPointIndicatorPosition = (left: string) => {
    const l = parseFloat(left);
    if (l > 75) return 'right-[120%]';
    return 'left-[120%]';
  };

  const getPlayerName = (teamName: string, pos: Position | null, num: number | null) => {
    if (!pos || num === null) return 'Select Player';
    const player = PLAYER_DATA[teamName]?.[pos]?.find(p => p.number === num);
    return player ? player.name : `${pos} Active`;
  };

  return (
    <div className="fixed inset-0 z-[100] bg-slate-950/95 backdrop-blur-xl flex items-center justify-center p-4 overflow-y-auto" ref={overlayRef}>
      <div className="bg-slate-900 border border-slate-700 w-full max-w-5xl rounded-3xl shadow-[0_0_60px_rgba(0,0,0,0.6)] overflow-visible animate-in fade-in zoom-in duration-500 my-auto relative">

        {showSuccess && (
          <div className="absolute inset-0 z-[200] bg-slate-950/60 backdrop-blur-md flex flex-col items-center justify-center rounded-3xl animate-in fade-in duration-300">
            <div className="flex flex-col items-center gap-6 animate-in zoom-in slide-in-from-bottom-12 duration-500">
              <div className="w-24 h-24 bg-green-500 rounded-full flex items-center justify-center shadow-[0_0_50px_rgba(34,197,94,0.6)] border-4 border-green-400">
                <i className="fa-solid fa-check text-5xl text-white"></i>
              </div>
              <div className="text-center px-4">
                <h3 className="text-5xl font-black oswald uppercase tracking-tighter text-white italic mb-2">Tactical Lock!</h3>
                <p className="text-green-400 text-sm font-black uppercase tracking-[0.4em] animate-pulse">Syncing Lineups to Live Data...</p>
              </div>
            </div>
          </div>
        )}

        <div className="bg-slate-800/80 p-6 border-b border-slate-700 flex flex-col items-center text-center relative overflow-hidden rounded-t-3xl">
          <div className="flex items-center gap-6 mb-2 relative z-10 w-full justify-between max-w-2xl">
            <div className="flex flex-col items-center gap-1 group">
               <span className="text-5xl transition-all duration-300">{awayTeam.logo}</span>
               <span className="text-[10px] font-black oswald text-slate-400 uppercase">{awayTeam.abbreviation}</span>
            </div>

            <div className="flex flex-col items-center">
              <div className="bg-amber-500/10 text-amber-500 text-[10px] font-black px-3 py-1 rounded-full border border-amber-500/20 uppercase tracking-[0.2em] mb-2 animate-pulse">
                {waitingReason || "Lineup Reset"}
              </div>
              <h2 className={`text-3xl font-black oswald uppercase tracking-tighter italic ${strength !== '5v5' ? 'text-amber-500' : 'text-white'}`}>
                {strength !== '5v5' ? `SPECIAL TEAMS: ${strength}` : 'LINEUP BUILDER'}
              </h2>
              <p className="text-slate-400 text-[9px] font-black uppercase tracking-[0.4em]">Tap dots to deploy & cycle players</p>
            </div>

            <div className="flex flex-col items-center gap-1 group">
              <span className="text-5xl transition-all duration-300">{homeTeam.logo}</span>
              <span className="text-[10px] font-black oswald text-slate-400 uppercase">{homeTeam.abbreviation}</span>
            </div>
          </div>
        </div>

        <div className="relative bg-slate-100 border-b border-slate-400 p-1">
          <div className="relative w-full aspect-[2.4/1] bg-white shadow-inner rounded-sm overflow-visible border border-slate-300">
            <div className="absolute inset-0 opacity-[0.03] pointer-events-none bg-[url('https://www.transparenttextures.com/patterns/pinstriped-suit.png')]"></div>

            <svg className="absolute inset-0 w-full h-full pointer-events-none" viewBox="0 0 240 100" preserveAspectRatio="none">
              <path d="M 14.4 42 A 8 8 0 0 1 14.4 58" fill="rgba(37, 99, 235, 0.1)" stroke="rgba(239, 68, 68, 0.4)" strokeWidth="0.5" />
              <path d="M 225.6 42 A 8 8 0 0 0 225.6 58" fill="rgba(37, 99, 235, 0.1)" stroke="rgba(239, 68, 68, 0.4)" strokeWidth="0.5" />
              <line x1="14.4" y1="0" x2="14.4" y2="100" stroke="rgba(239, 68, 68, 0.6)" strokeWidth="0.8" />
              <line x1="225.6" y1="0" x2="225.6" y2="100" stroke="rgba(239, 68, 68, 0.6)" strokeWidth="0.8" />
              <rect x="84" y="0" width="1.5" height="100" fill="rgba(37, 99, 235, 0.8)" />
              <rect x="154.5" y="0" width="1.5" height="100" fill="rgba(37, 99, 235, 0.8)" />
              <rect x="119.5" y="0" width="1" height="100" fill="rgba(239, 68, 68, 0.8)" />
              <circle cx="120" cy="50" r="15" fill="none" stroke="rgba(37, 99, 235, 0.4)" strokeWidth="0.5" />
              <circle cx="120" cy="50" r="1.5" fill="rgba(37, 99, 235, 0.8)" />
            </svg>

            {['away', 'home'].map((side) => 
              POSITIONS.map((pos) => {
                const isHomeSide = side === 'home';
                const coords = getPosCoords(pos.value, isHomeSide);
                const isSelected = isHomeSide ? homePick === pos.value : awayPick === pos.value;
                const selectedNum = isHomeSide ? homeNum : awayNum;
                const teamName = isHomeSide ? homeTeam.name : awayTeam.name;
                const roster = PLAYER_DATA[teamName]?.[pos.value] || [];
                const currentSelectedPlayer = isSelected ? (roster.find(p => p.number === selectedNum) || { name: `${pos.value} Active`, number: selectedNum }) : null;
                const previewPlayer = roster[0] || { name: `${pos.value} Prospect`, number: '??' };

                const isThisHovered = hovered?.side === side && hovered?.pos === pos.value;
                const teamColor = isHomeSide ? homeTeam.color : awayTeam.color;

                const isManualFlashing = flash?.side === side && flash?.pos === pos.value;
                let flashClass = '';
                let flashStyle: React.CSSProperties = {};
                if (isManualFlashing) {
                  if (flash.type === 'possession') {
                    flashClass = 'animate-possession-pulse';
                    flashStyle = { '--pulse-color': teamColor } as React.CSSProperties;
                  } else {
                    flashClass = flash.type === 'green' ? 'animate-flash-green' : 'animate-flash-red';
                  }
                } else if (isSelected) {
                  flashClass = 'animate-selection-pulse';
                  flashStyle = { '--pulse-color': teamColor } as React.CSSProperties;
                }

                const tooltipPositionClass = getTooltipPositionClasses(coords.left, coords.top);
                const pointTagPos = getPointIndicatorPosition(coords.left);
                const relevantPoints = floatingPoints?.filter(fp => fp.team === side && fp.position === pos.value) || [];
                const stats = getPosStats(side as 'home' | 'away', pos.value);

                return (
                  <div key={`tactical-container-${side}-${pos.value}`} style={{ top: coords.top, left: coords.left }} className="absolute -translate-x-1/2 -translate-y-1/2 z-20 flex flex-col items-center overflow-visible">
                    <button
                      onMouseEnter={() => setHovered({ side: side as 'home' | 'away', pos: pos.value })}
                      onMouseLeave={() => setHovered(null)}
                      onClick={() => handleRinkClick(side as 'home' | 'away', pos.value)}
                      className={`relative flex items-center justify-center transition-all z-10 shadow-lg ${
                        isSelected
                          ? 'h-8 sm:h-10 px-2 sm:px-3 rounded-full ring-4 border-2 border-white text-white'
                          : isThisHovered
                            ? 'w-8 h-8 sm:w-10 sm:h-10 rounded-full scale-125 border-2 border-slate-400'
                            : 'w-8 h-8 sm:w-10 sm:h-10 rounded-full bg-slate-800 text-white border-2 border-slate-600'
                      } ${flashClass}`}
                      style={{
                        ...(isSelected ? { backgroundColor: teamColor, boxShadow: `0 0 0 4px ${teamColor}4D` } : {}),
                        ...flashStyle
                      }}
                    >
                      <div className="flex items-center gap-1.5">
                        <span className="text-[11px] sm:text-sm font-black oswald leading-none">
                          {isSelected ? selectedNum : pos.value}
                        </span>
                        {isSelected && (
                          <span className="text-[9px] sm:text-[11px] font-black oswald uppercase tracking-tight border-l border-white/30 pl-1.5 italic whitespace-nowrap">
                            {currentSelectedPlayer?.name.split(' ').pop()}
                          </span>
                        )}
                      </div>
                    </button>

                    {relevantPoints.map(fp => (
                      <div 
                        key={`pt-tag-${fp.id}`}
                        className={`absolute pointer-events-none z-[60] font-black oswald text-[10px] sm:text-xs px-2 py-0.5 rounded-full border-2 shadow-[0_0_20px_rgba(0,0,0,0.5)] animate-point-badge-pop flex items-center gap-1.5 ${fp.points > 0 ? 'bg-green-500 border-green-200 text-white' : 'bg-red-500 border-red-200 text-white'} ${pointTagPos}`}
                        style={{ 
                          top: '10%',
                          boxShadow: `0 0 25px ${fp.points > 0 ? '#22c55e' : '#ef4444'}CC` 
                        }}
                      >
                        <i className={`fa-solid ${fp.points > 0 ? 'fa-caret-up' : 'fa-caret-down'}`}></i>
                        {fp.points > 0 ? '+' : ''}{fp.points}
                      </div>
                    ))}

                    {isThisHovered && (
                      <div 
                        className={`absolute z-[400] w-72 max-w-[calc(100vw-4rem)] bg-slate-900/98 backdrop-blur-2xl border-2 rounded-2xl p-0 shadow-[0_30px_70px_rgba(0,0,0,0.8)] animate-in zoom-in duration-200 pointer-events-none overflow-hidden ${tooltipPositionClass}`} 
                        style={{ 
                          borderColor: `${teamColor}BB`, 
                          boxShadow: `0 15px 50px -10px ${teamColor}30` 
                        }}
                      >
                        <div className="p-4 border-b border-white/5 relative overflow-hidden" style={{ backgroundColor: `${teamColor}10` }}>
                          <div className="absolute top-0 right-0 p-2 opacity-5 scale-150 rotate-12">
                            <span className="text-6xl">{isHomeSide ? homeTeam.logo : awayTeam.logo}</span>
                          </div>
                          <div className="flex items-start gap-4 relative z-10">
                            <div className="flex-shrink-0 w-12 h-12 rounded-xl border-2 border-white/20 flex flex-col items-center justify-center shadow-lg" style={{ backgroundColor: teamColor }}>
                              <span className="text-[9px] font-black oswald text-white/60 leading-none mb-1 uppercase tracking-tighter">Jersey</span>
                              <span className="text-xl font-black oswald text-white leading-none">
                                {isSelected ? currentSelectedPlayer?.number : previewPlayer.number}
                              </span>
                            </div>
                            <div className="flex-1 min-w-0">
                              <div className="flex items-center justify-between gap-2 mb-1">
                                <span className="text-[9px] font-black text-white/50 uppercase tracking-[0.25em] truncate">{pos.label}</span>
                                <span className={`flex-shrink-0 text-[8px] font-black px-1.5 py-0.5 rounded uppercase tracking-widest ${isSelected ? 'bg-green-500/20 text-green-400 border border-green-500/30' : 'bg-slate-800/80 text-slate-500 border border-slate-700/50'}`}>
                                  {isSelected ? 'In Lineup' : 'Available'}
                                </span>
                              </div>
                              <h4 className="text-lg font-black text-white oswald uppercase italic leading-none truncate tracking-tight">
                                {isSelected ? currentSelectedPlayer?.name : previewPlayer.name}
                              </h4>
                              <p className="text-[10px] font-bold text-slate-400 uppercase tracking-tighter mt-1.5 flex items-center gap-1.5">
                                <span className="w-1.5 h-1.5 rounded-full" style={{ backgroundColor: teamColor }}></span>
                                {isHomeSide ? homeTeam.abbreviation : awayTeam.abbreviation} • {isHomeSide ? homeTeam.city : awayTeam.city}
                              </p>
                            </div>
                          </div>
                        </div>
                        <div className="p-4 grid grid-cols-2 gap-3 bg-gradient-to-b from-slate-900/50 to-slate-950/80">
                          <div className="bg-slate-950/50 p-3 rounded-xl border border-white/5 flex flex-col gap-1">
                            <div className="flex items-center gap-2 mb-1">
                              <div className="w-5 h-5 rounded-lg bg-red-500/10 flex items-center justify-center">
                                <i className="fa-solid fa-bullseye text-red-500 text-[10px]"></i>
                              </div>
                              <span className="text-[8px] font-black text-slate-500 uppercase tracking-widest">Live Goals</span>
                            </div>
                            <span className="text-2xl font-black text-white oswald leading-none tabular-nums">{stats.goals}</span>
                          </div>
                          <div className="bg-slate-950/50 p-3 rounded-xl border border-white/5 flex flex-col gap-1">
                            <div className="flex items-center gap-2 mb-1">
                              <div className="w-5 h-5 rounded-lg bg-blue-500/10 flex items-center justify-center">
                                <i className="fa-solid fa-hands-helping text-blue-500 text-[10px]"></i>
                              </div>
                              <span className="text-[8px] font-black text-slate-500 uppercase tracking-widest">Assists</span>
                            </div>
                            <span className="text-2xl font-black text-white oswald leading-none tabular-nums">{stats.assists}</span>
                          </div>
                        </div>
                        <div className="px-4 py-2.5 bg-slate-950 border-t border-white/5 flex items-center justify-center gap-2">
                           <i className="fa-solid fa-hand-pointer text-slate-600 text-[10px] animate-bounce"></i>
                           <span className="text-[9px] font-black text-slate-500 uppercase tracking-widest">
                             {isSelected ? 'Cycle Player Slot' : 'Draft into Lineup'}
                           </span>
                        </div>
                      </div>
                    )}
                  </div>
                );
              })
            )}
          </div>
        </div>

        <div className="p-8 bg-slate-900 border-t border-slate-700 flex flex-col lg:flex-row items-center justify-between gap-8 rounded-b-3xl">
          <div className="flex flex-col sm:flex-row gap-6 lg:gap-8 w-full lg:w-auto">
            <div className={`flex flex-col p-4 min-w-[240px] rounded-2xl border transition-all duration-300 ${awayPick ? 'bg-slate-800/80 shadow-[0_10px_30px_rgba(0,0,0,0.3)]' : 'bg-slate-900/50 border-slate-800'}`} style={awayPick ? { borderColor: `${awayTeam.color}80` } : {}}>
              <span className="text-[10px] font-black text-slate-500 uppercase tracking-[0.25em] mb-4 flex items-center justify-between">
                {awayTeam.abbreviation} TACTICAL PICK
                {awayPick && <span className="text-[9px] font-black px-1.5 py-0.5 rounded bg-slate-950 text-slate-400 border border-slate-700">{awayPick}</span>}
              </span>
              <div className="flex items-center gap-4">
                <div className={`w-14 h-14 rounded-2xl flex-shrink-0 flex items-center justify-center font-black oswald text-2xl border-2 transition-all ${awayPick ? 'border-white/20 text-slate-950 scale-100 shadow-xl' : 'bg-slate-800 border-slate-700 text-slate-600'}`} style={awayPick ? { backgroundColor: awayTeam.color } : {}}>
                  {awayNum || '?'}
                </div>
                <div className="flex flex-col min-w-0">
                  <span className={`text-base font-black oswald uppercase tracking-tight truncate ${awayPick ? 'text-white italic' : 'text-slate-700'}`}>
                    {getPlayerName(awayTeam.name, awayPick, awayNum)}
                  </span>
                  <span className="text-[10px] font-bold text-slate-500 uppercase mt-0.5">
                    {awayPick ? `No. ${awayNum} • Deployed` : 'Awaiting Selection...'}
                  </span>
                </div>
              </div>
            </div>

            <div className={`flex flex-col p-4 min-w-[240px] rounded-2xl border transition-all duration-300 ${homePick ? 'bg-slate-800/80 shadow-[0_10px_30px_rgba(0,0,0,0.3)]' : 'bg-slate-900/50 border-slate-800'}`} style={homePick ? { borderColor: `${homeTeam.color}80` } : {}}>
              <span className="text-[10px] font-black text-slate-500 uppercase tracking-[0.25em] mb-4 flex items-center justify-between">
                {homeTeam.abbreviation} TACTICAL PICK
                {homePick && <span className="text-[9px] font-black px-1.5 py-0.5 rounded bg-slate-950 text-slate-400 border border-slate-700">{homePick}</span>}
              </span>
              <div className="flex items-center gap-4">
                <div className={`w-14 h-14 rounded-2xl flex-shrink-0 flex items-center justify-center font-black oswald text-2xl border-2 transition-all ${homePick ? 'border-white/20 text-white scale-100 shadow-xl' : 'bg-slate-800 border-slate-700 text-slate-600'}`} style={homePick ? { backgroundColor: homeTeam.color } : {}}>
                  {homeNum || '?'}
                </div>
                <div className="flex flex-col min-w-0">
                  <span className={`text-base font-black oswald uppercase tracking-tight truncate ${homePick ? 'text-white italic' : 'text-slate-700'}`}>
                    {getPlayerName(homeTeam.name, homePick, homeNum)}
                  </span>
                  <span className="text-[10px] font-bold text-slate-500 uppercase mt-0.5">
                    {homePick ? `No. ${homeNum} • Deployed` : 'Awaiting Selection...'}
                  </span>
                </div>
              </div>
            </div>
          </div>

          <div className="flex flex-col items-center gap-3">
             <div className={`text-[10px] font-black uppercase tracking-[0.3em] transition-all duration-500 ${awayPick && homePick ? 'text-green-500 animate-pulse scale-110' : 'text-slate-600'}`}>
                {awayPick && homePick ? '✓ LINEUP COMPLETE - LOCKING...' : 'Tap a dot on each side to lock'}
             </div>
             <div className="w-64 h-2 bg-slate-800 rounded-full overflow-hidden border border-slate-700">
                <div 
                  className="h-full bg-blue-500 transition-all duration-700 ease-out" 
                  style={{ width: awayPick && homePick ? '100%' : awayPick || homePick ? '50%' : '0%' }}
                ></div>
             </div>
          </div>
        </div>
      </div>
      <style>{`
        @keyframes possession-pulse {
          0% { box-shadow: 0 0 0 0 var(--pulse-color); filter: brightness(1); transform: scale(1); }
          50% { box-shadow: 0 0 40px 20px var(--pulse-color); filter: brightness(1.8); transform: scale(1.3); }
          100% { box-shadow: 0 0 0 0 var(--pulse-color); filter: brightness(1); transform: scale(1); }
        }
        @keyframes selection-pulse {
          0% { box-shadow: 0 0 0 0 rgba(255, 255, 255, 0.4); }
          50% { box-shadow: 0 0 10px 4px var(--pulse-color); opacity: 0.9; }
          100% { box-shadow: 0 0 0 0 rgba(255, 255, 255, 0.4); }
        }
        @keyframes point-badge-pop {
          0% { transform: scale(0.3) translateY(15px); opacity: 0; filter: blur(4px); }
          15% { transform: scale(1.4) translateY(-8px); opacity: 1; filter: blur(0); }
          30% { transform: scale(1) translateY(0); }
          75% { transform: scale(1) translateY(-15px); opacity: 1; }
          100% { transform: scale(0.7) translateY(-35px); opacity: 0; filter: blur(8px); }
        }
        .animate-possession-pulse { animation: possession-pulse 1.5s ease-in-out; }
        .animate-selection-pulse { animation: selection-pulse 2.5s infinite ease-in-out; }
        .animate-point-badge-pop { animation: point-badge-pop 2.5s cubic-bezier(0.19, 1, 0.22, 1) forwards; }
      `}</style>
    </div>
  );
};

export default SelectionOverlay;
